// Do not edit by hand — regenerate with scripts/generate-bible.

const book: BibleBook = {
  id: 'jeremiah',
  name: 'Jeremias',
  englishName: 'Jeremiah',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'The words of Jeremiah the son of Hilkiah, one of the priests who were in Anathoth in the land of Benjamin.', pt: 'As palavras de Jeremias, filho de Hilquias, um dos sacerdotes que estavam em Anatote, na terra de Benjamim;' },
      { v: 2, en: 'Yahweh’s word came to him in the days of Josiah the son of Amon, king of Judah, in the thirteenth year of his reign.', pt: 'ao qual veio a palavra do Senhor, nos dias de Josias, filho de Amom, rei de Judá, no décimo terceiro ano do seu reinado;' },
      { v: 3, en: 'It came also in the days of Jehoiakim the son of Josiah, king of Judah, to the end of the eleventh year of Zedekiah, the son of Josiah, king of Judah, to the carrying away of Jerusalem captive in the fifth month.', pt: 'e lhe veio também nos dias de Jeoiaquim, filho de Josias, rei de Judá, até o fim do ano undécimo de Zedequias, filho de Josias, rei de Judá, até que Jerusalém foi levada em cativeiro no quinto mês.' },
      { v: 4, en: 'Now Yahweh’s word came to me, saying,', pt: 'Ora veio a mim a palavra do Senhor, dizendo:' },
      { v: 5, en: '“Before I formed you in the womb, I knew you. Before you were born, I sanctified you. I have appointed you a prophet to the nations.”', pt: 'Antes que eu te formasse no ventre te conheci, e antes que saísses da madre te santifiquei; às nações te dei por profeta.' },
      { v: 6, en: 'Then I said, “Ah, Lord Yahweh! Behold, I don’t know how to speak; for I am a child.”', pt: 'Então disse eu: Ah, Senhor Deus! Eis que não sei falar; porque sou um menino.' },
      { v: 7, en: 'But Yahweh said to me, “Don’t say, ‘I am a child;’ for you must go to whomever I send you, and you must say whatever I command you.', pt: 'Mas o Senhor me respondeu: Não digas: Eu sou um menino; porque a todos a quem eu te enviar, irás; e tudo quanto te mandar dirás.' },
      { v: 8, en: 'Don’t be afraid because of them, for I am with you to rescue you,” says Yahweh.', pt: 'Não temas diante deles; pois eu sou contigo para te livrar, diz o Senhor.' },
      { v: 9, en: 'Then Yahweh stretched out his hand, and touched my mouth. Then Yahweh said to me, “Behold, I have put my words in your mouth.', pt: 'Então estendeu o Senhor a mão, e tocou-me na boca; e disse- me o Senhor: Eis que ponho as minhas palavras na tua boca.' },
      { v: 10, en: 'Behold, I have today set you over the nations and over the kingdoms, to uproot and to tear down, to destroy and to overthrow, to build and to plant.”', pt: 'Olha, ponho-te neste dia sobre as nações, e sobre os reinos, para arrancares e derribares, para destruíres e arruinares; e também para edificares e plantares.' },
      { v: 11, en: 'Moreover Yahweh’s word came to me, saying, “Jeremiah, what do you see?” I said, “I see a branch of an almond tree.”', pt: 'E veio a mim a palavra do Senhor, dizendo: Que é que vês, Jeremias? Eu respondi: Vejo uma vara de amendoeira.' },
      { v: 12, en: 'Then Yahweh said to me, “You have seen well; for I watch over my word to perform it.”', pt: 'Então me disse o Senhor: Viste bem; porque eu velo sobre a minha palavra para a cumprir.' },
      { v: 13, en: 'Yahweh’s word came to me the second time, saying, “What do you see?” I said, “I see a boiling cauldron; and it is tipping away from the north.”', pt: 'Veio a mim a palavra do Senhor segunda vez, dizendo: Que é que vês? E eu disse: Vejo uma panela a ferver, que se apresenta da banda do norte.' },
      { v: 14, en: 'Then Yahweh said to me, “Out of the north, evil will break out on all the inhabitants of the land.', pt: 'Ao que me disse o Senhor: Do norte se estenderá o mal sobre todos os habitantes da terra.' },
      { v: 15, en: 'For, behold, I will call all the families of the kingdoms of the north,” says Yahweh. “They will come, and they will each set his throne at the entrance of the gates of Jerusalem, and against all its walls all around, and against all the cities of Judah.', pt: 'Pois estou convocando todas as famílias dos reinos do norte, diz o Senhor; e, vindo, porá cada um o seu trono à entrada das portas de Jerusalém, e contra todos os seus muros em redor e contra todas as cidades de Judá.' },
      { v: 16, en: 'I will utter my judgments against them concerning all their wickedness, in that they have forsaken me, and have burned incense to other gods, and worshiped the works of their own hands.', pt: 'E pronunciarei contra eles os meus juizos, por causa de toda a sua malícia; pois me deixaram a mim, e queimaram incenso a deuses estranhos, e adoraram as obras das suas mãos.' },
      { v: 17, en: '“You therefore put your belt on your waist, arise, and say to them all that I command you. Don’t be dismayed at them, lest I dismay you before them.', pt: 'Tu, pois, cinge os teus lombos, e levanta-te, e dem-lhes tudo quanto eu te ordenar; não desanimes diante deles, para que eu não te desanime diante deles.' },
      { v: 18, en: 'For, behold, I have made you today a fortified city, an iron pillar, and bronze walls, against the whole land, against the kings of Judah, against its princes, against its priests, and against the people of the land.', pt: 'Eis que hoje te ponho como cidade fortificada, e como coluna de ferro e muros de bronze contra toda a terra, contra os reis de Judá, contra os seus príncipes, contra os seus sacerdotes, e contra o povo da terra.' },
      { v: 19, en: 'They will fight against you, but they will not prevail against you; for I am with you”, says Yahweh, “to rescue you.”', pt: 'E eles pelejarão contra ti, mas não prevalecerão; porque eu sou contigo, diz o Senhor, para te livrar.' },
    ],
    2: [
      { v: 1, en: 'Yahweh’s word came to me, saying,', pt: 'Veio a mim a palavra do Senhor, dizendo:' },
      { v: 2, en: '“Go, and proclaim in the ears of Jerusalem, saying, ‘Yahweh says, “I remember for you the kindness of your youth, the love of your weddings; how you went after me in the wilderness, in a land that was not sown.', pt: 'Vai, e clama aos ouvidos de Jerusalém, dizendo: Assim diz o Senhor: Lembro-me, a favor de ti, da devoção da tua mocidade, do amor dos teus desposórios, de como me seguiste no deserto, numa terra não semeada.' },
      { v: 3, en: 'Israel was holiness to Yahweh, the first fruits of his increase. All who devour him will be held guilty. Evil will come on them,”’ says Yahweh.”', pt: 'Então Israel era santo para o Senhor, primícias da sua novidade; todos os que o devoravam eram tidos por culpados; o mal vinha sobre eles, diz o Senhor.' },
      { v: 4, en: 'Hear Yahweh’s word, O house of Jacob, and all the families of the house of Israel!', pt: 'Ouvi a palavra do Senhor, ó casa de Jacó, e todas as famílias da casa de Israel;' },
      { v: 5, en: 'Yahweh says, “What unrighteousness have your fathers found in me, that they have gone far from me, and have walked after worthless vanity, and have become worthless?', pt: 'assim diz o Senhor: Que injustiça acharam em mim vossos pais, para se afastarem de mim, indo após a vaidade, e tornando-se levianos?' },
      { v: 6, en: 'They didn’t say, ‘Where is Yahweh who brought us up out of the land of Egypt, who led us through the wilderness, through a land of deserts and of pits, through a land of drought and of the shadow of death, through a land that no one passed through, and where no man lived?’', pt: 'Eles não perguntaram: Onde está o Senhor, que nos fez subir da terra do Egito? que nos enviou através do deserto, por uma terra de charnecas e de covas, por uma terra de sequidão e densas trevas, por uma terra em que ninguém transitava, nem morava?' },
      { v: 7, en: 'I brought you into a plentiful land, to eat its fruit and its goodness; but when you entered, you defiled my land, and made my heritage an abomination.', pt: 'E eu vos introduzi numa terra fértil, para comerdes o seu fruto e o seu bem; mas quando nela entrastes, contaminastes a minha terra, e da minha herança fizestes uma abominação.' },
      { v: 8, en: 'The priests didn’t say, ‘Where is Yahweh?’ and those who handle the law didn’t know me. The rulers also transgressed against me, and the prophets prophesied by Baal, and followed things that do not profit.', pt: 'Os sacerdotes não disseram: Onde está o Senhor? E os que tratavam da lei não me conheceram, e os governadores prevaricaram contra mim, e os profetas profetizaram por Baal, e andaram após o que é de nenhum proveito.' },
      { v: 9, en: '“Therefore I will yet contend with you,” says Yahweh, “and I will contend with your children’s children.', pt: 'Portanto ainda contenderei convosco, diz o Senhor; e até com os filhos de vossos filhos contenderei.' },
      { v: 10, en: 'For pass over to the islands of Kittim, and see; and send to Kedar, and consider diligently; and see if there has been such a thing.', pt: 'Pois passai às ilhas de Quitim, e vede; enviai a Quedar, e atentai bem; vede se jamais sucedeu coisa semelhante.' },
      { v: 11, en: 'Has a nation changed its gods, which really are no gods? But my people have changed their glory for that which does not profit.', pt: 'Acaso trocou alguma nação os seus deuses, que contudo não são deuses? Mas o meu povo trocou a sua glória por aquilo que é de nenhum proveito.' },
      { v: 12, en: '“Be astonished, you heavens, at this, and be horribly afraid. Be very desolate,” says Yahweh.', pt: 'Espantai-vos disto, ó céus, e horrorizai-vos! ficai verdadeiramente desolados, diz o Senhor.' },
      { v: 13, en: '“For my people have committed two evils: they have forsaken me, the spring of living waters, and cut them out cisterns, broken cisterns, that can hold no water.', pt: 'Porque o meu povo fez duas maldades: a mim me deixaram, o manancial de águas vivas, e cavaram para si cisternas, cisternas rotas, que não retêm as águas.' },
      { v: 14, en: 'Is Israel a slave? Is he born into slavery? Why has he become a captive?', pt: 'Acaso é Israel um servo? E ele um escravo nascido em casa? Por que, pois, veio a ser presa?' },
      { v: 15, en: 'The young lions have roared at him, and yelled. They have made his land waste. His cities are burned up, without inhabitant.', pt: 'Os leões novos rugiram sobre ele, e levantaram a sua voz; e fizeram da terra dele uma desolação; as suas cidades se queimaram, e ninguém habita nelas.' },
      { v: 16, en: 'The children also of Memphis and Tahpanhes have broken the crown of your head.', pt: 'Até os filhos de Mênfis e de Tapanes te quebraram o alto da cabeça.' },
      { v: 17, en: '“Haven’t you brought this on yourself, in that you have forsaken Yahweh your God, when he led you by the way?', pt: 'Porventura não trouxeste isso sobre ti mesmo, deixando o Senhor teu Deus no tempo em que ele te guiava pelo caminho?' },
      { v: 18, en: 'Now what do you gain by going to Egypt, to drink the waters of the Shihor? Or why do you to go on the way to Assyria, to drink the waters of the River?', pt: 'Agora, pois, que te importa a ti o caminho do Egito, para beberes as águas do Nilo? e que te importa a ti o caminho da Assíria, para beberes as águas do Eufrates?' },
      { v: 19, en: '“Your own wickedness will correct you, and your backsliding will rebuke you. Know therefore and see that it is an evil and bitter thing, that you have forsaken Yahweh your God, and that my fear is not in you,” says the Lord, Yahweh of Armies.', pt: 'A tua malícia te castigará, e as tuas apostasias te repreenderão; sabe, pois, e vê, que má e amarga coisa é o teres deixado o Senhor teu Deus, e o não haver em ti o temor de mim, diz o Senhor Deus dos exércitos.' },
      { v: 20, en: '“For long ago I broke off your yoke, and burst your bonds. You said, ‘I will not serve;’ for on every high hill and under every green tree you bowed yourself, playing the prostitute.', pt: 'Já há muito quebraste o teu jugo, e rompeste as tuas ataduras, e disseste: Não servirei: Pois em todo outeiro alto e debaixo de toda árvore frondosa te deitaste, fazendo-te prostituta.' },
      { v: 21, en: 'Yet I had planted you a noble vine, a pure and faithful seed. How then have you turned into the degenerate branches of a foreign vine to me?', pt: 'Todavia eu mesmo te plantei como vide excelente, uma semente inteiramente fiel; como, pois, te tornaste para mim uma planta degenerada, de vida estranha?' },
      { v: 22, en: 'For though you wash yourself with lye, and use much soap, yet your iniquity is marked before me,” says the Lord Yahweh.', pt: 'Pelo que, ainda que te laves com salitre, e uses muito sabão, a mancha da tua iniqüidade está diante de mim, diz o Senhor Deus.' },
      { v: 23, en: '“How can you say, ‘I am not defiled. I have not gone after the Baals’? See your way in the valley. Know what you have done. You are a swift dromedary traversing her ways;', pt: 'Como dizes logo: Não estou contaminada nem andei após Baal? Vê o teu caminho no vale, conhece o que fizeste; dromedária ligeira és, que anda torcendo os seus caminhos;' },
      { v: 24, en: 'a wild donkey used to the wilderness, that sniffs the wind in her craving. When she is in heat, who can turn her away? All those who seek her will not weary themselves. In her month, they will find her.', pt: 'asna selvagem acostumada ao deserto e que no ardor do cio sorve o vento; quem lhe pode impedir o desejo? Dos que a buscarem, nenhum precisa cansar-se; pois no mês dela, achá-la-ão.' },
      { v: 25, en: '“Keep your feet from being bare, and your throat from thirst. But you said, ‘It is in vain. No, for I have loved strangers, and I will go after them.’', pt: 'Evita que o teu pé ande descalço, e que a tua garganta tenha sede. Mas tu dizes: Não há esperança; porque tenho amado os estranhos, e após eles andarei.' },
      { v: 26, en: 'As the thief is ashamed when he is found, so is the house of Israel ashamed; they, their kings, their princes, and their priests, and their prophets;', pt: 'Como fica confundido o ladrão quando o apanham, assim se confundem os da casa de Israel; eles, os seus reis, os seus príncipes, e os seus sacerdotes, e os seus profetas,' },
      { v: 27, en: 'who tell wood, ‘You are my father;’ and a stone, ‘You have given birth to me:’ for they have turned their back to me, and not their face; but in the time of their trouble they will say, ‘Arise, and save us.’', pt: 'que dizem ao pau: Tu és meu pai; e à pedra: Tu me geraste. Porque me viraram as costas, e não o rosto; mas no tempo do seu aperto dir-me-ão: Levanta-te, e salvamos.' },
      { v: 28, en: '“But where are your gods that you have made for yourselves? Let them arise, if they can save you in the time of your trouble: for you have as many gods as you have towns, O Judah.', pt: 'Mas onde estão os teus deuses que fizeste para ti? Que se levantem eles, se te podem livrar no tempo da tua tribulação; porque os teus deuses, ó Judá, são tão numerosos como as tuas cidades.' },
      { v: 29, en: '“Why will you contend with me? You all have transgressed against me,” says Yahweh.', pt: 'Por que disputais comigo? Todos vós transgredistes contra mim diz o Senhor.' },
      { v: 30, en: '“I have struck your children in vain. They received no correction. Your own sword has devoured your prophets, like a destroying lion.', pt: 'Em vão castiguei os vossos filhos; eles não aceitaram a correção; a vossa espada devorou os vossos profetas como um leão destruidor.' },
      { v: 31, en: 'Generation, consider Yahweh’s word. Have I been a wilderness to Israel? Or a land of thick darkness? Why do my people say, ‘We have broken loose. We will come to you no more?’', pt: 'ç geração, considerai vós a palavra do Senhor: Porventura tenho eu sido para Israel um deserto? ou uma terra de espessa escuridão? Por que pois diz o meu povo: Andamos à vontade; não tornaremos mais a ti?' },
      { v: 32, en: '“Can a virgin forget her ornaments, or a bride her attire? Yet my people have forgotten me for days without number.', pt: 'Porventura esquece-se a virgem dos seus enfeites, ou a esposa dos seus cendais? todavia o meu povo se esqueceu de mim por inumeráveis dias.' },
      { v: 33, en: 'How well you prepare your way to seek love! Therefore you have even taught the wicked women your ways.', pt: 'Como ornamentas o teu caminho, para buscares o amor! de sorte que até às malignas ensinaste os teus caminhos.' },
      { v: 34, en: 'Also the blood of the souls of the innocent poor is found in your skirts. You did not find them breaking in; but it is because of all these things.', pt: 'Até nas orlas dos teus vestidos se achou o sangue dos pobres inocentes; e não foi no lugar do arrombamento que os achaste; mas apesar de todas estas coisas,' },
      { v: 35, en: '“Yet you said, ‘I am innocent. Surely his anger has turned away from me.’ “Behold, I will judge you, because you say, ‘I have not sinned.’', pt: 'ainda dizes: Eu sou inocente; certamente a sua ira se desviou de mim. Eis que entrarei em juízo contigo, porquanto dizes: Não pequei.' },
      { v: 36, en: 'Why do you go about so much to change your ways? You will be ashamed of Egypt also, as you were ashamed of Assyria.', pt: 'Por que te desvias tanto, mudando o teu caminho? Também pelo Egito serás envergonhada, como já foste envergonhada pela Assíria.' },
      { v: 37, en: 'You will also leave that place with your hands on your head; for Yahweh has rejected those in whom you trust, and you won’t prosper with them.', pt: 'Também daquele sairás com as mães sobre a tua cabeça; porque o Senhor rejeitou as tuas confianças, e não prosperarás com elas.' },
    ],
    3: [
      { v: 1, en: '“They say, ‘If a man puts away his wife, and she goes from him, and becomes another man’s, should he return to her again?’ Wouldn’t that land be greatly polluted? But you have played the prostitute with many lovers; yet return again to me,” says Yahweh.', pt: 'Eles dizem: Se um homem despedir sua mulher, e ela se desligar dele, e se ajuntar a outro homem, porventura tornará ele mais para ela? Não se poluiria de todo aquela terra? Ora, tu te maculaste com muitos amantes; mas ainda assim, torna para mim, diz o Senbor.' },
      { v: 2, en: '“Lift up your eyes to the bare heights, and see! Where have you not been lain with? You have sat waiting for them by the road, as an Arabian in the wilderness. You have polluted the land with your prostitution and with your wickedness.', pt: 'Levanta os teus olhos aos altos escalvados, e vê: onde é o lugar em que não te prostituíste? Nos caminhos te assentavas, esperando-os, como o árabe no deserto. Manchaste a terra com as tuas devassidões e com a tua malícia.' },
      { v: 3, en: 'Therefore the showers have been withheld and there has been no latter rain; yet you have had a prostitute’s forehead and you refused to be ashamed.', pt: 'Pelo que foram retidas as chuvas copiosas, e não houve chuva tardia; contudo tens a fronte de uma prostituta, e não queres ter vergonha.' },
      { v: 4, en: 'Will you not from this time cry to me, ‘My Father, you are the guide of my youth?’', pt: 'Não me invocaste há pouco, dizendo: Pai meu, tu és o guia da minha mocidade;' },
      { v: 5, en: '“‘Will he retain his anger forever? Will he keep it to the end?’ Behold, you have spoken and have done evil things, and have had your way.”', pt: 'Reterá ele para sempre a sua ira? ou indignar-se-á continuamente? Eis que assim tens dito; porém tens feito todo o mal que pudeste.' },
      { v: 6, en: 'Moreover, Yahweh said to me in the days of Josiah the king, “Have you seen that which backsliding Israel has done? She has gone up on every high mountain and under every green tree, and has played the prostitute there.', pt: 'Disse-me mais o Senhor nos dias do rei Josias: Viste, porventura, o que fez a apóstata Israel, como se foi a todo monte alto, e debaixo de toda árvore frondosa, e ali andou prostituindo-se?' },
      { v: 7, en: 'I said after she had done all these things, ‘She will return to me;’ but she didn’t return; and her treacherous sister Judah saw it.', pt: 'E eu disse: Depois que ela tiver feito tudo isso, voltará para mim. Mas não voltou; e viu isso a sua aleivosa irmã Judá.' },
      { v: 8, en: 'I saw when, for this very cause, that backsliding Israel had committed adultery, I had put her away and given her a bill of divorce, yet treacherous Judah, her sister, had no fear; but she also went and played the prostitute.', pt: 'Sim viu que, por causa de tudo isso, por ter cometido adultério a pérfida Israel, a despedi, e lhe dei o seu libelo de divórcio, que a aleivosa Judá, sua irmã, não temeu; mas se foi e também ela mesma se prostituiu.' },
      { v: 9, en: 'Because she took her prostitution lightly, the land was polluted, and she committed adultery with stones and with wood.', pt: 'E pela leviandade da sua prostituição contaminou a terra, porque adulterou com a pedra e com o pau.' },
      { v: 10, en: 'Yet for all this her treacherous sister, Judah, has not returned to me with her whole heart, but only in pretense,” says Yahweh.', pt: 'Contudo, apesar de tudo isso a sua aleivosa irmã Judá não voltou para mim de todo o seu coração, mas fingidamente, diz o Senhor.' },
      { v: 11, en: 'Yahweh said to me, “Backsliding Israel has shown herself more righteous than treacherous Judah.', pt: 'E o Senhor me disse: A pérfida Israel mostrou-se mais justa do que a aleivosa Judá.' },
      { v: 12, en: 'Go, and proclaim these words toward the north, and say, ‘Return, you backsliding Israel,’ says Yahweh; ‘I will not look in anger on you; for I am merciful,’ says Yahweh. ‘I will not keep anger forever.', pt: 'Vai, pois, e apregoa estas palavras para a banda do norte, e diz: Volta, ó pérfida Israel, diz o Senhor. Não olharei em era para ti; porque misericordioso sou, diz o Senhor, e não conservarei para sempre a minha ira.' },
      { v: 13, en: 'Only acknowledge your iniquity, that you have transgressed against Yahweh your God, and have scattered your ways to the strangers under every green tree, and you have not obeyed my voice,’ says Yahweh.”', pt: 'Somente reconhece a tua iniqüidade: que contra o Senhor teu Deus transgrediste, e estendeste os teus favores para os estranhos debaixo de toda árvore frondosa, e não deste ouvidos à minha voz, diz o Senhor.' },
      { v: 14, en: '“Return, backsliding children,” says Yahweh; “for I am a husband to you. I will take one of you from a city, and two from a family, and I will bring you to Zion.', pt: 'Voltai, ó filhos pérfidos, diz o Senhor; porque eu sou como esposo para vós; e vos tomarei, a um de uma cidade, e a dois de uma família; e vos levarei a Sião;' },
      { v: 15, en: 'I will give you shepherds according to my heart, who will feed you with knowledge and understanding.', pt: 'e vos darei pastores segundo o meu coração, os quais vos apascentarão com ciência e com inteligência.' },
      { v: 16, en: 'It will come to pass, when you are multiplied and increased in the land, in those days,” says Yahweh, “they will no longer say, ‘the ark of Yahweh’s covenant!’ It will not come to mind. They won’t remember it. They won’t miss it, nor will another be made.', pt: 'E quando vos tiverdes multiplicado e frutificado na terra, naqueles dias, diz o Senhor, nunca mais se dirá: A arca do pacto do Senhor; nem lhes virá ela ao pensamento; nem dela se lembrarão; nem a visitarão; nem se fará mais.' },
      { v: 17, en: 'At that time they will call Jerusalem ‘Yahweh’s Throne;’ and all the nations will be gathered to it, to Yahweh’s name, to Jerusalem. They will no longer walk after the stubbornness of their evil heart.', pt: 'Naquele tempo chamarão a Jerusalém o trono do Senhor; e todas as nações se ajuntarão a ela, em nome do Senhor, a Jerusalém; e não mais andarão obstinadamente segundo o propósito do seu coração maligno.' },
      { v: 18, en: 'In those days the house of Judah will walk with the house of Israel, and they will come together out of the land of the north to the land that I gave for an inheritance to your fathers.', pt: 'Naqueles dias andará a casa de Judá com a casa de Israel; e virão juntas da terra do norte, para a terra que dei em herança a vossos pais.' },
      { v: 19, en: '“But I said, ‘How I desire to put you among the children, and give you a pleasant land, a goodly heritage of the armies of the nations!’ and I said, ‘You shall call me “My Father”, and shall not turn away from following me.’', pt: 'Pensei como te poria entre os filhos, e te daria a terra desejável, a mais formosa herança das nações. Também pensei que me chamarias meu Pai, e que de mim não te desviarias.' },
      { v: 20, en: '“Surely as a wife treacherously departs from her husband, so you have dealt treacherously with me, house of Israel,” says Yahweh.', pt: 'Deveras, como a mulher se aparta aleivosamente do seu marido, assim aleivosamente te houveste comigo, ó casa de Israel, diz o Senhor.' },
      { v: 21, en: 'A voice is heard on the bare heights, the weeping and the petitions of the children of Israel; because they have perverted their way, they have forgotten Yahweh their God.', pt: 'Nos altos escalvados se ouve uma voz, o pranto e as súplicas dos filhos de Israel; porque perverteram o seu caminho, e se esqueceram do Senhor seu Deus.' },
      { v: 22, en: 'Return, you backsliding children, and I will heal your backsliding. “Behold, we have come to you; for you are Yahweh our God.', pt: 'Voltai, ó filhos infiéis, eu curarei a vossa infidelidade. Responderam eles: Eis-nos aqui, vimos a ti, porque tu és o Senhor nosso Deus.' },
      { v: 23, en: 'Truly in vain is help from the hills, the tumult on the mountains. Truly the salvation of Israel is in Yahweh our God.', pt: 'Certamente em vão se confia nos outeiros e nas orgias nas montanhas; deveras no Senhor nosso Deus está a salvação de Israel.' },
      { v: 24, en: 'But the shameful thing has devoured the labor of our fathers from our youth, their flocks and their herds, their sons and their daughters.', pt: 'A coisa vergonhosa, porém, devorou o trabalho de nossos pais desde a nossa mocidade os seus rebanhos e os seus gados os seus filhos e as suas filhas.' },
      { v: 25, en: 'Let us lie down in our shame, and let our confusion cover us; for we have sinned against Yahweh our God, we and our fathers, from our youth even to this day. We have not obeyed Yahweh our God’s voice.”', pt: 'Deitemo-nos em nossa vergonha, e cubra-nos a nossa confusão, porque temos pecado contra o Senhor nosso Deus, nós e nossos pais, desde a nossa mocidade até o dia de hoje; e não demos ouvidos à voz do Senhor nosso Deus.' },
    ],
    4: [
      { v: 1, en: '“If you will return, Israel,” says Yahweh, “if you will return to me, and if you will put away your abominations out of my sight; then you will not be removed;', pt: 'Se voltares, ó Israel, diz o Senhor, se voltares para mim e tirares as tuas abominações de diante de mim, e não andares mais vagueando;' },
      { v: 2, en: 'and you will swear, ‘As Yahweh lives,’ in truth, in justice, and in righteousness. The nations will bless themselves in him, and they will glory in him.”', pt: 'e se jurares: Como vive o Senhor, na verdade, na justiça e na retidão; então nele se bendirão as nações, e nele se gloriarão.' },
      { v: 3, en: 'For Yahweh says to the men of Judah and to Jerusalem, “Break up your fallow ground, and don’t sow among thorns.', pt: 'Porque assim diz o Senhor aos homens de Judá e a Jerusalém: Lavrai o vosso terreno alqueivado, e não semeeis entre espinhos.' },
      { v: 4, en: 'Circumcise yourselves to Yahweh, and take away the foreskins of your heart, you men of Judah and inhabitants of Jerusalem; lest my wrath go out like fire, and burn so that no one can quench it, because of the evil of your doings.', pt: 'Circuncidai-vos ao Senhor, e tirai os prepúcios do vosso coração, ó homens de Judá e habitadores de Jerusalém, para que a minha indignação não venha a sair como fogo, e arda de modo que ninguém o possa apagar, por causa da maldade das vossas obras.' },
      { v: 5, en: 'Declare in Judah, and publish in Jerusalem; and say, ‘Blow the trumpet in the land!’ Cry aloud and say, ‘Assemble yourselves! Let us go into the fortified cities!’', pt: 'Anunciai em Judá, e publicai em Jerusalém; e dizei: Tocai a trombeta na terra; gritai em alta voz, dizendo: Ajuntai-vos, e entremos nas cidades fortificadas.' },
      { v: 6, en: 'Set up a standard toward Zion. Flee for safety! Don’t wait; for I will bring evil from the north, and a great destruction.”', pt: 'Arvorai um estandarte no caminho para Sião; buscai refúgio, não demoreis; porque eu trago do norte um mal, sim, uma grande destruição.' },
      { v: 7, en: 'A lion has gone up from his thicket, and a destroyer of nations. He is on his way. He has gone out from his place, to make your land desolate, that your cities be laid waste, without inhabitant.', pt: 'Subiu um leão da sua ramada, um destruidor de nações; ele já partiu, saiu do seu lugar para fazer da tua terra uma desolação, a fim de que as tuas cidades sejam assoladas, e ninguém habite nelas.' },
      { v: 8, en: 'For this, clothe yourself with sackcloth, lament and wail; for the fierce anger of Yahweh hasn’t turned back from us.', pt: 'Por isso cingi-vos de saco, lamentai, e uivai, porque o ardor da ira do Senhor não se desviou de nós.' },
      { v: 9, en: '“It will happen at that day,” says Yahweh, “that the heart of the king will perish, along with the heart of the princes. The priests will be astonished, and the prophets will wonder.”', pt: 'Naquele dia, diz o Senhor, desfalecerá o coração do rei e o coração dos príncipes; os sacerdotes pasmarão, e os profetas se maravilharão.' },
      { v: 10, en: 'Then I said, “Ah, Lord Yahweh! Surely you have greatly deceived this people and Jerusalem, saying, ‘You will have peace;’ whereas the sword reaches to the heart.”', pt: 'Então disse eu: Ah, Senhor Deus! verdadeiramente trouxeste grande ilusão a este povo e a Jerusalém, dizendo: Tereis paz; entretanto a espada penetra-lhe até a alma.' },
      { v: 11, en: 'At that time it will be said to this people and to Jerusalem, “A hot wind from the bare heights in the wilderness toward the daughter of my people, not to winnow, nor to cleanse;', pt: 'Naquele tempo se dirá a este povo e a Jerusalém: Um vento abrasador, vindo dos altos escalvados no deserto, aproxima-se da filha do meu povo, não para cirandar, nem para alimpar,' },
      { v: 12, en: 'a full wind from these will come for me. Now I will also utter judgments against them.”', pt: 'mas um vento forte demais para isto virá da minha parte; agora também pronunciarei eu juízos contra eles.' },
      { v: 13, en: 'Behold, he will come up as clouds, and his chariots will be as the whirlwind. His horses are swifter than eagles. Woe to us! For we are ruined.', pt: 'Eis que vem subindo como nuvens, como o redemoinho são os seus carros; os seus cavalos são mais ligeiros do que as águias. Ai de nós! pois estamos arruinados!' },
      { v: 14, en: 'Jerusalem, wash your heart from wickedness, that you may be saved. How long will your evil thoughts lodge within you?', pt: 'Lava o teu coração da maldade, ó Jerusalém, para que sejas salva; até quando permanecerão em ti os teus maus pensamentos?' },
      { v: 15, en: 'For a voice declares from Dan, and publishes evil from the hills of Ephraim:', pt: 'Porque uma voz anuncia desde Dã, e proclama a calamidade desde o monte de Efraim.' },
      { v: 16, en: '“Tell the nations; behold, publish against Jerusalem, ‘Watchers come from a far country, and raise their voice against the cities of Judah.', pt: 'Anunciai isto às nações; eis, proclamai contra Jerusalém que vigias vêm de uma terra remota; eles levantam a voz contra as cidades de Judá.' },
      { v: 17, en: 'As keepers of a field, they are against her all around, because she has been rebellious against me,’” says Yahweh.', pt: 'Como guardas de campo estão contra ela ao redor; porquanto ela se rebelou contra mim, diz o Senhor.' },
      { v: 18, en: '“Your way and your doings have brought these things to you. This is your wickedness; for it is bitter, for it reaches to your heart.”', pt: 'O teu caminho e as tuas obras te trouxeram essas coisas; essa e a tua iniquidade, e amargosa é, chegando até o coração.' },
      { v: 19, en: 'My anguish, my anguish! I am pained at my very heart! My heart trembles within me. I can’t hold my peace, because you have heard, O my soul, the sound of the trumpet, the alarm of war.', pt: 'Ah, entranhas minhas, entranhas minhas! Eu me torço em dores! Paredes do meu coração! O meu coração se aflige em mim. Não posso calar; porque tu, ó minha alma, ouviste o som da trombeta e o alarido da guerra.' },
      { v: 20, en: 'Destruction on destruction is decreed, for the whole land is laid waste. Suddenly my tents are destroyed, and my curtains gone in a moment.', pt: 'Destruição sobre destruição se apregoa; porque já toda a terra está assolada; de repente são destruídas as minhas tendas, e as minhas cortinas num momento.' },
      { v: 21, en: 'How long will I see the standard and hear the sound of the trumpet?', pt: 'Até quando verei o estandarte, e ouvirei a voz da trombeta?' },
      { v: 22, en: '“For my people are foolish. They don’t know me. They are foolish children, and they have no understanding. They are skillful in doing evil, but they don’t know how to do good.”', pt: 'Deveras o meu povo é insensato, já me não conhece; são filhos obtusos, e não entendidos; são sábios para fazerem o mal, mas não sabem fazer o bem.' },
      { v: 23, en: 'I saw the earth, and, behold, it was waste and void; and the heavens, and they had no light.', pt: 'Observei a terra, e eis que era sem forma e vazia; também os céus, e não tinham a sua luz.' },
      { v: 24, en: 'I saw the mountains, and behold, they trembled, and all the hills moved back and forth.', pt: 'Observei os montes, e eis que estavam tremendo; e todos os outeiros estremeciam.' },
      { v: 25, en: 'I saw, and behold, there was no man, and all the birds of the sky had fled.', pt: 'Observei e eis que não havia homem algum, e todas as aves do céu tinham fugido.' },
      { v: 26, en: 'I saw, and behold, the fruitful field was a wilderness, and all its cities were broken down at the presence of Yahweh, before his fierce anger.', pt: 'Vi também que a terra fértil era um deserto, e todas as suas cidades estavam derrubadas diante do Senhor, diante do furor da sua ira.' },
      { v: 27, en: 'For Yahweh says, “The whole land will be a desolation; yet will I not make a full end.', pt: 'Pois assim diz o Senhor: Toda a terra ficará assolada; de todo, porém, não a consumirei.' },
      { v: 28, en: 'For this the earth will mourn, and the heavens above be black; because I have spoken it. I have planned it, and I have not repented, neither will I turn back from it.”', pt: 'Por isso lamentará a terra, e os céus em cima se enegrecerão; porquanto assim o disse eu, assim o propus, e não me arrependi, nem me desviarei disso.' },
      { v: 29, en: 'Every city flees for the noise of the horsemen and archers. They go into the thickets, and climb up on the rocks. Every city is forsaken, and not a man dwells therein.', pt: 'Ao clamor dos cavaleiros e dos flecheiros fogem todas as cidades; entram pelas matas, e trepam pelos penhascos; todas as cidades ficam desamparadas, e já ninguém habita nelas.' },
      { v: 30, en: 'You, when you are made desolate, what will you do? Though you clothe yourself with scarlet, though you deck yourself with ornaments of gold, though you enlarge your eyes with makeup, you make yourself beautiful in vain. Your lovers despise you. They seek your life.', pt: 'Agora, pois, ó assolada, que farás? Embora te vistas de escarlate, e te adornes com enfeites de ouro, embora te pintes em volta dos olhos com antimônio, debalde te farias bela; os teus amantes te desprezam, e procuram tirar-te a vida.' },
      { v: 31, en: 'For I have heard a voice as of a woman in travail, the anguish as of her who gives birth to her first child, the voice of the daughter of Zion, who gasps for breath, who spreads her hands, saying, “Woe is me now! For my soul faints before the murderers.”', pt: 'Pois ouvi uma voz, como a de mulher que está de parto, a angústia como a de quem dá à luz o seu primeiro filho; a voz da filha de Sião, ofegante, que estende as mãos, dizendo: Ai de mim agora! porque a minha alma desfalece por causa dos assassinos.' },
    ],
    5: [
      { v: 1, en: '“Run back and forth through the streets of Jerusalem, and see now, and know, and seek in its wide places, if you can find a man, if there is anyone who does justly, who seeks truth, then I will pardon her.', pt: 'Dai voltas às ruas de Jerusalém, e vede agora, e informai- vos, e buscai pelas suas praças a ver se podeis achar um homem, se há alguém que pratique a justiça, que busque a verdade; e eu lhe perdoarei a ela.' },
      { v: 2, en: 'Though they say, ‘As Yahweh lives,’ surely they swear falsely.”', pt: 'E ainda que digam: Vive o Senhor; de certo falsamente juram.' },
      { v: 3, en: 'O Yahweh, don’t your eyes look on truth? You have stricken them, but they were not grieved. You have consumed them, but they have refused to receive correction. They have made their faces harder than a rock. They have refused to return.', pt: 'ç Senhor, acaso não atentam os teus olhos para a verdade? feriste-os, porém não lhes doeu; consumiste-os, porém recusaram receber a correção; endureceram as suas faces mais do que uma rocha; recusaram-se a voltar.' },
      { v: 4, en: 'Then I said, “Surely these are poor. They are foolish; for they don’t know the way of Yahweh, nor the law of their God.', pt: 'Então disse eu: Deveras eles são uns pobres; são insensatos, pois não sabem o caminho do Senhor, nem a justiça do seu Deus.' },
      { v: 5, en: 'I will go to the great men, and will speak to them; for they know the way of Yahweh, and the law of their God.” But these with one accord have broken the yoke, and burst the bonds.', pt: 'Irei aos grandes, e falarei com eles; porque eles sabem o caminho do Senhor, e a justiça do seu Deus; mas aqueles de comum acordo quebraram o jugo, e romperam as ataduras.' },
      { v: 6, en: 'Therefore a lion out of the forest will kill them, a wolf of the evenings will destroy them, a leopard will watch against their cities. Everyone who goes out there will be torn in pieces, because their transgressions are many, and their backsliding has increased.', pt: 'Por isso um leão do bosque os matará, um lobo dos desertos os destruirá; um leopardo vigia contra as suas cidades; todo aquele que delas sair será despedaçado; porque são muitas as suas transgressões, e multiplicadas as suas apostasias.' },
      { v: 7, en: '“How can I pardon you? Your children have forsaken me, and sworn by what are no gods. When I had fed them to the full, they committed adultery, and assembled themselves in troops at the prostitutes’ houses.', pt: 'Como poderei perdoar-te? pois teus filhos me abandonaram a mim, e juraram pelos que não são deuses; quando eu os tinha fartado, adulteraram, e em casa de meretrizes se ajuntaram em bandos.' },
      { v: 8, en: 'They were as fed horses roaming at large. Everyone neighed after his neighbor’s wife.', pt: 'Como cavalos de lançamento bem nutridos, andavam rinchando cada um à mulher do seu próximo.' },
      { v: 9, en: 'Shouldn’t I punish them for these things?” says Yahweh. “Shouldn’t my soul be avenged on such a nation as this?', pt: 'Acaso não hei de castigá-los por causa destas coisas? diz o Senhor; ou não hei de vingar-me de uma nação como esta?' },
      { v: 10, en: '“Go up on her walls, and destroy; but don’t make a full end. Take away her branches, for they are not Yahweh’s.', pt: 'Subi aos seus muros, e destruí-os; não façais, porém, uma destruição final; tirai os seus ramos; porque não são do Senhor.' },
      { v: 11, en: 'For the house of Israel and the house of Judah have dealt very treacherously against me,” says Yahweh.', pt: 'Porque aleivosissimamente se houveram contra mim a casa de Israel e a casa de Judá, diz o Senhor.' },
      { v: 12, en: 'They have denied Yahweh, and said, “It is not he. Evil will won’t come on us. We won’t see sword or famine.', pt: 'Negaram ao Senhor, e disseram: Não é ele; nenhum mal nos sobrevirá; nem veremos espada nem fome.' },
      { v: 13, en: 'The prophets will become wind, and the word is not in them. Thus it will be done to them.”', pt: 'E até os profetas se farão como vento, e a palavra não está com eles; assim se lhes fará.' },
      { v: 14, en: 'Therefore Yahweh, the God of Armies says, “Because you speak this word, behold, I will make my words in your mouth fire, and this people wood, and it will devour them.', pt: 'Portanto assim diz o Senhor, o Deus dos exércitos: Porquanto proferis tal palavra, eis que converterei em fogo as minhas palavras na tua boca, e este povo em lenha, de modo que o fogo o consumirá.' },
      { v: 15, en: 'Behold, I will bring a nation on you from far away, house of Israel,” says Yahweh. “It is a mighty nation. It is an ancient nation, a nation whose language you don’t know and don’t understand what they say.', pt: 'Eis que trago sobre vós uma nação de longe, ó casa de Israel, diz o Senhor; é uma nação durável, uma nação antiga, uma nação cuja língua ignoras, e não entenderás o que ela falar.' },
      { v: 16, en: 'Their quiver is an open tomb. They are all mighty men.', pt: 'A sua aljava é como uma sepultura aberta; todos eles são valentes.' },
      { v: 17, en: 'They will eat up your harvest and your bread, which your sons and your daughters should eat. They will eat up your flocks and your herds. They will eat up your vines and your fig trees. They will beat down your fortified cities in which you trust with the sword.', pt: 'E comerão a tua sega e o teu pão, que teus filhos e tuas filhas haviam de comer; comerão os teus rebanhos e o teu gado; comerão a tua vide e a tua figueira; as tuas cidades fortificadas, em que confias, abatê-las-ão à espada.' },
      { v: 18, en: '“But even in those days,” says Yahweh, “I will not make a full end of you.', pt: 'Contudo, ainda naqueles dias, diz o Senhor, não farei de vós uma destruição final.' },
      { v: 19, en: 'It will happen, when you say, ‘Why has Yahweh our God done all these things to us?’ Then you shall say to them, ‘Just as you have forsaken me, and served foreign gods in your land, so you will serve strangers in a land that is not yours.’', pt: 'E quando disserdes: Por que nos fez o Senhor nosso Deus todas estas coisas? então lhes dirás: Como vós me deixastes, e servistes deuses estranhos na vossa terra, assim servireis estrangeiros, em terra que não e vossa.' },
      { v: 20, en: '“Declare this in the house of Jacob, and publish it in Judah, saying,', pt: 'Anunciai isto na casa de Jacó, e proclamai-o em Judá, dizendo:' },
      { v: 21, en: '‘Hear this now, foolish people without understanding; who have eyes, and don’t see; who have ears, and don’t hear:', pt: 'Ouvi agora isto, ó povo insensato e sem entendimento, que tendes olhos e não vedes, que tendes ouvidos e não ouvis:' },
      { v: 22, en: 'Don’t you fear me?’ says Yahweh ‘Won’t you tremble at my presence, who have placed the sand for the bound of the sea, by a perpetual decree, that it can’t pass it? Though its waves toss themselves, yet they can’t prevail. Though they roar, they still can’t pass over it.’', pt: 'Não me temeis a mim? diz o Senhor; não tremeis diante de mim, que pus a areia por limite ao mar, por ordenança eterna, que ele não pode passar? Ainda que se levantem as suas ondas, não podem prevalecer; ainda que bramem, não a podem traspassar.' },
      { v: 23, en: '“But this people has a revolting and a rebellious heart. They have revolted and gone.', pt: 'Mas este povo é de coração obstinado e rebelde; rebelaram-se e foram-se.' },
      { v: 24, en: 'They don’t say in their heart, ‘Let us now fear Yahweh our God, who gives rain, both the former and the latter, in its season; who preserves to us the appointed weeks of the harvest.’', pt: 'E não dizem no seu coração: Temamos agora ao Senhor nosso Deus, que dá chuva, tanto a temporã como a tardia, a seu tempo, e nos conserva as semanas determinadas da sega.' },
      { v: 25, en: '“Your iniquities have turned away these things, and your sins have withheld good from you.', pt: 'As vossas iniqüidades desviaram estas coisas, e os vossos pecados apartaram de vos o bem.' },
      { v: 26, en: 'For among my people are found wicked men. They watch, as fowlers lie in wait. They set a trap. They catch men.', pt: 'Porque ímpios se acham entre o meu povo; andam espiando, como espreitam os passarinheiros. Armam laços, apanham os homens.' },
      { v: 27, en: 'As a cage is full of birds, so are their houses full of deceit. Therefore they have become great, and grew rich.', pt: 'Qual gaiola cheia de pássaros, assim as suas casas estão cheias de dolo; por isso se engrandeceram, e enriqueceram.' },
      { v: 28, en: 'They have grown fat. They shine; yes, they excel in deeds of wickedness. They don’t plead the cause, the cause of the fatherless, that they may prosper; and they don’t judge the right of the needy.', pt: 'Engordaram-se, estão nédios; também excedem o limite da maldade; não julgam com justiça a causa dos órfãos, para que prospere, nem defendem o direito dos necessitados.' },
      { v: 29, en: '“Shouldn’t I punish for these things?” says Yahweh. “Shouldn’t my soul be avenged on such a nation as this?', pt: 'Acaso não hei de trazer o castigo por causa destas coisas? diz o senhor; ou não hei de vingar-me de uma nação como esta?' },
      { v: 30, en: '“An astonishing and horrible thing has happened in the land.', pt: 'Coisa espantosa e horrenda tem-se feito na terra:' },
      { v: 31, en: 'The prophets prophesy falsely, and the priests rule by their own authority; and my people love to have it so. What will you do in the end of it?', pt: 'os profetas profetizam falsamente, e os sacerdotes dominam por intermédio deles; e o meu povo assim o deseja. Mas que fareis no fim disso?' },
    ],
    6: [
      { v: 1, en: '“Flee for safety, you children of Benjamin, out of the middle of Jerusalem! Blow the trumpet in Tekoa and raise up a signal on Beth Haccherem, for evil looks out from the north with a great destruction.', pt: 'Fugi para segurança vossa, filhos de Benjamim, do meio de Jerusalém! Tocai a buzina em Tecoa, e levantai o sinal sobre Bete- Haquerem; porque do norte vem surgindo um grande mal, sim, uma grande destruição.' },
      { v: 2, en: 'I will cut off the beautiful and delicate one, the daughter of Zion.', pt: 'A formosa e delicada, a filha de Sião, eu a exterminarei.' },
      { v: 3, en: 'Shepherds with their flocks will come to her. They will pitch their tents against her all around. They will feed everyone in his place.”', pt: 'Contra ela virão pastores com os seus rebanhos; levantarão contra ela as suas tendas em redor e apascentarão, cada um no seu lugar.' },
      { v: 4, en: '“Prepare war against her! Arise, and let us go up at noon. Woe to us! For the day declines, for the shadows of the evening are stretched out.', pt: 'Preparai a guerra contra ela; levantai-vos, e subamos ao meio-dia. Ai de nós! que ja declina o dia, que já se vão estendendo as sombras da tarde.' },
      { v: 5, en: 'Arise, and let us go up by night, and let us destroy her palaces.”', pt: 'Levantai-vos, e subamos de noite, e destruamos os seus palácios.' },
      { v: 6, en: 'For Yahweh of Armies said, “Cut down trees, and cast up a mound against Jerusalem. This is the city to be visited. She is wholly oppression within herself.', pt: 'Porque assim diz o Senhor dos exércitos: Cortai as suas árvores, e levantai uma tranqueira contra Jerusalém. Esta é a cidade que há de ser castigada; só opressão há no meio dela.' },
      { v: 7, en: 'As a well produces its waters, so she produces her wickedness. Violence and destruction is heard in her. Sickness and wounds are continually before me.', pt: 'Como o poço conserva frescas as suas águas, assim ela conserva fresca a sua maldade; violência e estrago se ouvem nela; enfermidade e feridas há diante de mim continuadamente.' },
      { v: 8, en: 'Be instructed, Jerusalem, lest my soul be alienated from you; lest I make you a desolation, an uninhabited land.”', pt: 'Sê avisada, ó Jerusalém, para que não me aparte de ti; para que eu não te faça uma assolação, uma terra não habitada.' },
      { v: 9, en: 'Yahweh of Armies says, “They will thoroughly glean the remnant of Israel like a vine. Turn again your hand as a grape gatherer into the baskets.”', pt: 'Assim diz o Senhor dos exércitos: Na verdade respigarão o resto de Israel como uma vinha; torna a tua mão, como o vindimador, aos ramos.' },
      { v: 10, en: 'To whom should I speak and testify, that they may hear? Behold, their ear is uncircumcised, and they can’t listen. Behold, Yahweh’s word has become a reproach to them. They have no delight in it.', pt: 'A quem falarei e testemunharei, para que ouçam? eis que os seus ouvidos estão incircuncisos, e eles não podem ouvir; eis que a palavra do Senhor se lhes tornou em opróbrio; nela não têm prazer.' },
      { v: 11, en: 'Therefore I am full of Yahweh’s wrath. I am weary with holding it in. “Pour it out on the children in the street, and on the assembly of young men together; for even the husband with the wife will be taken, the aged with him who is full of days.', pt: 'Pelo que estou cheio de furor do Senhor; estou cansado de o conter; derrama-o sobre os meninos pelas ruas, e sobre a assembléia dos jovens também; porque até o marido com a mulher serão presos, e o velho com o que está cheio de dias.' },
      { v: 12, en: 'Their houses will be turned to others, their fields and their wives together; for I will stretch out my hand on the inhabitants of the land, says Yahweh.”', pt: 'As suas casas passarão a outros, como também os seus campos e as suas mulheres; porque estenderei a minha mão contra os habitantes da terra, diz o Senhor.' },
      { v: 13, en: '“For from their least even to their greatest, everyone is given to covetousness. From the prophet even to the priest, everyone deals falsely.', pt: 'Porque desde o menor deles até o maior, cada um se dá à avareza; e desde o profeta até o sacerdote, cada um procede perfidamente.' },
      { v: 14, en: 'They have healed also the hurt of my people superficially, saying, ‘Peace, peace!’ when there is no peace.', pt: 'Também se ocupam em curar superficialmente a ferida do meu povo, dizendo: Paz, paz; quando não há paz.' },
      { v: 15, en: 'Were they ashamed when they had committed abomination? No, they were not at all ashamed, neither could they blush. Therefore they will fall among those who fall. When I visit them, they will be cast down,” says Yahweh.', pt: 'Porventura se envergonharam por terem cometido abominação? Não, de maneira alguma; nem tampouco sabem que coisa é envergonhar- se. Portanto cairão entre os que caem; quando eu os visitar serão derribados, diz o Senhor.' },
      { v: 16, en: 'Yahweh says, “Stand in the ways and see, and ask for the old paths, ‘Where is the good way?’ and walk in it, and you will find rest for your souls. But they said, ‘We will not walk in it.’', pt: 'Assim diz o Senhor: Ponde-vos nos caminhos, e vede, e perguntai pelas veredas antigas, qual é o bom caminho, e andai por ele; e achareis descanso para as vossas almas. Mas eles disseram: Não andaremos nele.' },
      { v: 17, en: 'I set watchmen over you, saying, ‘Listen to the sound of the trumpet!’ But they said, ‘We will not listen!’', pt: 'Também pus atalaias sobre vós dizendo: Estai atentos à voz da buzina. Mas disseram: Não escutaremos.' },
      { v: 18, en: 'Therefore hear, you nations, and know, congregation, what is among them.', pt: 'Portanto ouvi, vós, nações, e informa-te tu, ó congregação, do que se faz entre eles!' },
      { v: 19, en: 'Hear, earth! Behold, I will bring evil on this people, even the fruit of their thoughts, because they have not listened to my words; and as for my law, they have rejected it.', pt: 'Ouve tu, ó terra! Eis que eu trarei o mal sobre este povo, o próprio fruto dos seus pensamentos; porque não estão atentos às minhas palavras; e quanto à minha lei, rejeitaram-na.' },
      { v: 20, en: 'To what purpose does frankincense from Sheba come to me, and the sweet cane from a far country? Your burnt offerings are not acceptable, and your sacrifices are not pleasing to me.”', pt: 'Para que, pois, me vem o incenso de Sabá, ou a melhor cana aromática de terras remotas? Vossos holocaustos não são aceitáveis, nem me agradam os vossos sacrifícios.' },
      { v: 21, en: 'Therefore Yahweh says, “Behold, I will lay stumbling blocks before this people. The fathers and the sons together will stumble against them. The neighbor and his friend will perish.”', pt: 'Portanto assim diz o Senhor: Eis que armarei tropeços a este povo, e tropeçarão neles pais e filhos juntamente; o vizinho e o seu amigo perecerão.' },
      { v: 22, en: 'Yahweh says, “Behold, a people comes from the north country. A great nation will be stirred up from the uttermost parts of the earth.', pt: 'Assim diz o Senhor: Eis que um povo vem da terra do norte, e uma grande nação se levanta das extremidades da terra.' },
      { v: 23, en: 'They take hold of bow and spear. They are cruel, and have no mercy. Their voice roars like the sea, and they ride on horses, everyone set in array, as a man to the battle, against you, daughter of Zion.”', pt: 'Arco e lança trarão; são cruéis, e não usam de misericórdia; a sua voz ruge como o mar, e em cavalos vêm montados, dispostos como homens para a batalha, contra ti, ó filha de Sião.' },
      { v: 24, en: 'We have heard its report. Our hands become feeble. Anguish has taken hold of us, and pains as of a woman in labor.', pt: 'Ao ouvirmos a notícia disso, afrouxam-se as nossas mãos; apoderam-se de nós angústia e dores, como as de parturiente.' },
      { v: 25, en: 'Don’t go out into the field, nor walk by the way; for the sword of the enemy and terror are on every side.', pt: 'Não saiais ao campo, nem andeis pelo caminho; porque espada do inimigo e espanto há por todos os lados.' },
      { v: 26, en: 'Daughter of my people, clothe yourself with sackcloth, and wallow in ashes! Mourn, as for an only son, most bitter lamentation, for the destroyer will suddenly come on us.', pt: 'ç filha do meu povo, cingi-te de saco, e revolve-te na cinza; pranteia como por um filho único, em pranto de grande amargura; porque de repente virá o destruidor sobre nós.' },
      { v: 27, en: '“I have made you a tester of metals and a fortress among my people, that you may know and try their way.', pt: 'Por acrisolador e examinador te pus entre o meu povo, para que proves e examines o seu caminho.' },
      { v: 28, en: 'They are all grievous rebels, going around to slander. They are brass and iron. All of them deal corruptly.', pt: 'Todos eles são os mais rebeldes, e andam espalhando calúnias; são bronze e ferro; todos eles andam corruptamente.' },
      { v: 29, en: 'The bellows blow fiercely. The lead is consumed in the fire. In vain they go on refining, for the wicked are not plucked away.', pt: 'Já o fole se queimou; o chumbo se consumiu com o fogo; debalde continuam a fundição, pois os maus não são arrancados.' },
      { v: 30, en: 'Men will call them rejected silver, because Yahweh has rejected them.”', pt: 'Prata rejeitada lhes chamam, porque o Senhor os rejeitou.' },
    ],
    7: [
      { v: 1, en: 'The word that came to Jeremiah from Yahweh, saying,', pt: 'A palavra que da parte do Senhor veio a Jeremias, dizendo:' },
      { v: 2, en: '“Stand in the gate of Yahweh’s house, and proclaim this word there, and say, ‘Hear Yahweh’s word, all you of Judah, who enter in at these gates to worship Yahweh.’”', pt: 'Põe-te à porta da casa do Senhor, e proclama ali esta palavra, e dize: Ouvi a palavra do Senhor, todos de Judá, os que entrais por estas portas, para adorardes ao Senhor.' },
      { v: 3, en: 'Yahweh of Armies, the God of Israel says, “Amend your ways and your doings, and I will cause you to dwell in this place.', pt: 'Assim diz o Senhor dos exércitos, o Deus de Israel: Emendai os vossos caminhos e as vossas obras, e vos farei habitar neste lugar.' },
      { v: 4, en: 'Don’t trust in lying words, saying, ‘Yahweh’s temple, Yahweh’s temple, Yahweh’s temple, are these.’', pt: 'Não vos fieis em palavras falsas, dizendo: Templo do Senhor, templo do Senhor, templo do Senhor são estes.' },
      { v: 5, en: 'For if you thoroughly amend your ways and your doings, if you thoroughly execute justice between a man and his neighbor;', pt: 'Mas, se deveras emendardes os vossos caminhos e as vossas obras; se deveras executardes a justiça entre um homem e o seu proximo;' },
      { v: 6, en: 'if you don’t oppress the foreigner, the fatherless, and the widow, and don’t shed innocent blood in this place, and don’t walk after other gods to your own hurt;', pt: 'se não oprimirdes o estrangeiro, e o órfão, e a viúva, nem derramardes sangue inocente neste lugar, nem andardes após outros deuses para vosso próprio mal,' },
      { v: 7, en: 'then I will cause you to dwell in this place, in the land that I gave to your fathers, from of old even forever more.', pt: 'então eu vos farei habitar neste lugar, na terra que dei a vossos pais desde os tempos antigos e para sempre.' },
      { v: 8, en: 'Behold, you trust in lying words that can’t profit.', pt: 'Eis que vós confiais em palavras falsas, que para nada são proveitosas.' },
      { v: 9, en: 'Will you steal, murder, commit adultery, swear falsely, burn incense to Baal, and walk after other gods that you have not known,', pt: 'Furtareis vós, e matareis, e cometereis adultério, e jurareis falsamente, e queimareis incenso a Baal, e andareis após outros deuses que não conhecestes,' },
      { v: 10, en: 'then come and stand before me in this house, which is called by my name, and say, ‘We are delivered;’ that you may do all these abominations?', pt: 'e então vireis, e vos apresentareis diante de mim nesta casa, que se chama pelo meu nome, e direis: Somos livres para praticardes ainda todas essas abominações?' },
      { v: 11, en: 'Has this house, which is called by my name, become a den of robbers in your eyes? Behold, I myself have seen it,” says Yahweh.', pt: 'Tornou-se, pois, esta casa, que se chama pelo meu nome, uma caverna de salteadores aos vossos olhos? Eis que eu, eu mesmo, vi isso, diz o Senhor.' },
      { v: 12, en: '“But go now to my place which was in Shiloh, where I caused my name to dwell at the first, and see what I did to it for the wickedness of my people Israel.', pt: 'Mas ide agora ao meu lugar, que estava em Siló, onde, ao princípio, fiz habitar o meu nome, e vede o que lhe fiz, por causa da maldade do meu povo Israel.' },
      { v: 13, en: 'Now, because you have done all these works,” says Yahweh, “and I spoke to you, rising up early and speaking, but you didn’t hear; and I called you, but you didn’t answer;', pt: 'Agora, pois, porquanto fizestes todas estas obras, diz o Senhor, e quando eu vos falei insistentemente, vós não ouvistes, e quando vos chamei, não respondestes,' },
      { v: 14, en: 'therefore I will do to the house which is called by my name, in which you trust, and to the place which I gave to you and to your fathers, as I did to Shiloh.', pt: 'farei também a esta casa, que se chama pelo meu nome, na qual confiais, e a este lugar, que vos dei a vós e a vossos pais, como fiz a Siló.' },
      { v: 15, en: 'I will cast you out of my sight, as I have cast out all your brothers, even the whole offspring of Ephraim.', pt: 'E eu vos lançarei da minha presença, como lancei todos os vossos irmãos, toda a linhagem de Efraim.' },
      { v: 16, en: '“Therefore don’t pray for this people. Don’t lift up a cry or prayer for them or make intercession to me; for I will not hear you.', pt: 'Tu, pois, não ores por este povo, nem levantes por ele clamor ou oração, nem me importunes; pois eu não te ouvirei.' },
      { v: 17, en: 'Don’t you see what they do in the cities of Judah and in the streets of Jerusalem?', pt: 'Não vês tu o que eles andam fazendo nas cidades de Judá, e nas ruas de Jerusalém?' },
      { v: 18, en: 'The children gather wood, and the fathers kindle the fire, and the women knead the dough, to make cakes to the queen of the sky, and to pour out drink offerings to other gods, that they may provoke me to anger.', pt: 'Os filhos apanham a lenha, e os pais acendem o fogo, e as mulheres amassam a farinha para fazerem bolos à rainha do céu, e oferecem libações a outros deuses, a fim de me provocarem à ira.' },
      { v: 19, en: 'Do they provoke me to anger?” says Yahweh. “Don’t they provoke themselves, to the confusion of their own faces?”', pt: 'Acaso é a mim que eles provocam à ira? diz o Senhor; não se provocam a si mesmos, para a sua própria confusão?' },
      { v: 20, en: 'Therefore thus says the Lord Yahweh: “Behold, my anger and my wrath will be poured out on this place, on man, on animal, on the trees of the field, and on the fruit of the ground; and it will burn and will not be quenched.”', pt: 'Portanto assim diz o Senhor Deus: Eis que a minha ira e o meu furor se derramarão sobre este lugar, sobre os homens e sobre os animais, sobre as árvores do campo e sobre os frutos da terra; sim, acender-se-á, e não se apagará.' },
      { v: 21, en: 'Yahweh of Armies, the God of Israel says: “Add your burnt offerings to your sacrifices and eat meat.', pt: 'Assim diz o Senhor dos exércitos, o Deus de Israel: Ajuntai os vossos holocaustos aos vossos sacrifícios, e comei a carne.' },
      { v: 22, en: 'For I didn’t speak to your fathers or command them in the day that I brought them out of the land of Egypt concerning burnt offerings or sacrifices;', pt: 'Pois não falei a vossos pais no dia em que os tirei da terra do Egito, nem lhes ordenei coisa alguma acerca de holocaustos ou sacrifícios.' },
      { v: 23, en: 'but this thing I commanded them, saying, ‘Listen to my voice, and I will be your God, and you shall be my people; and walk in all the way that I command you, that it may be well with you.’', pt: 'Mas isto lhes ordenei: Dai ouvidos à minha voz, e eu serei o vosso Deus, e vós sereis o meu povo; andai em todo o caminho que eu vos mandar, para que vos vá bem.' },
      { v: 24, en: 'But they didn’t listen or turn their ear, but walked in their own counsels and in the stubbornness of their evil heart, and went backward, and not forward.', pt: 'Mas não ouviram, nem inclinaram os seus ouvidos; porém andaram nos seus próprios conselhos, no propósito do seu coração malvado; e andaram para trás, e não para diante.' },
      { v: 25, en: 'Since the day that your fathers came out of the land of Egypt to this day, I have sent to you all my servants the prophets, daily rising up early and sending them.', pt: 'Desde o dia em que vossos pais saíram da terra do Egito, até hoje, tenho-vos enviado insistentemente todos os meus servos, os profetas, dia após dia;' },
      { v: 26, en: 'Yet they didn’t listen to me or incline their ear, but made their neck stiff. They did worse than their fathers.', pt: 'contudo não me deram ouvidos, nem inclinaram os seus ouvidos, mas endureceram a sua cerviz. Fizeram pior do que seus pais.' },
      { v: 27, en: '“You shall speak all these words to them, but they will not listen to you. You shall also call to them, but they will not answer you.', pt: 'Dir-lhes-ás pois todas estas palavras, mas não te darão ouvidos; chamá-los-ás, mas não te responderão.' },
      { v: 28, en: 'You shall tell them, ‘This is the nation that has not listened to Yahweh their God’s voice, nor received instruction. Truth has perished, and is cut off from their mouth.’', pt: 'E lhes dirás: Esta é a nação que não obedeceu a voz do Senhor seu Deus e não aceitou a correção; já pereceu a verdade, e está exterminada da sua boca.' },
      { v: 29, en: 'Cut off your hair, and throw it away, and take up a lamentation on the bare heights; for Yahweh has rejected and forsaken the generation of his wrath.', pt: 'Corta os teus cabelos, Jerusalém, e lança-os fora, e levanta um pranto sobre os altos escalvados; porque o Senhor já rejeitou e desamparou esta geração, objeto do seu furor.' },
      { v: 30, en: '“For the children of Judah have done that which is evil in my sight,” says Yahweh. “They have set their abominations in the house which is called by my name, to defile it.', pt: 'Porque os filhos de Judá fizeram o que era mau aos meus olhos, diz o Senhor; puseram as suas abominações na casa que se chama pelo meu nome, para a contaminarem.' },
      { v: 31, en: 'They have built the high places of Topheth, which is in the valley of the son of Hinnom, to burn their sons and their daughters in the fire; which I didn’t command, nor did it come into my mind.', pt: 'E edificaram os altos de Tofete, que está no Vale do filho de Hinom, para queimarem no fogo a seus filhos e a suas filhas, o que nunca ordenei, nem me veio à mente.' },
      { v: 32, en: 'Therefore behold, the days come”, says Yahweh, “that it will no more be called ‘Topheth’ or ‘The valley of the son of Hinnom’, but ‘The valley of Slaughter’; for they will bury in Topheth until there is no place to bury.', pt: 'Portanto, eis que vêm os dias, diz o Senhor, em que não se chamará mais Tofete, nem Vale do filho de Hinom, mas o Vale da Matança; pois enterrarão em Tofete, por não haver mais outro lugar.' },
      { v: 33, en: 'The dead bodies of this people will be food for the birds of the sky, and for the animals of the earth. No one will frighten them away.', pt: 'E os cadáveres deste povo servirão de pasto às aves do céu e aos animais da terra; e ninguém os enxotará.' },
      { v: 34, en: 'Then I will cause to cease from the cities of Judah, and from the streets of Jerusalem, the voice of mirth and the voice of gladness, the voice of the bridegroom and the voice of the bride; for the land will become a waste.”', pt: 'E farei cessar nas cidades de Judá, e nas ruas de Jerusalém, a voz de gozo e a voz de alegria, a voz de noivo e a voz de noiva; porque a terra se tornará em desolação.' },
    ],
    8: [
      { v: 1, en: '“At that time,” says Yahweh, “they will bring out the bones of the kings of Judah, the bones of his princes, the bones of the priests, the bones of the prophets, and the bones of the inhabitants of Jerusalem, out of their graves.', pt: 'Naquele tempo, diz o Senhor, tirarão para fora das suas sepulturas os ossos dos reis de Judá, e os ossos dos seus príncipes, e os ossos dos sacerdotes, e os ossos dos profetas, e os ossos dos habitantes de Jerusalém;' },
      { v: 2, en: 'They will spread them before the sun, the moon, and all the army of the sky, which they have loved, which they have served, after which they have walked, which they have sought, and which they have worshiped. They will not be gathered or be buried. They will be for dung on the surface of the earth.', pt: 'e serão expostos ao sol, e à lua, e a todo o exército do céu, a quem eles amaram, e a quem serviram , e após quem andaram, e a quem buscaram, e a quem adoraram; não serão recolhidos nem sepultados; serão como esterco sobre a face da terra.' },
      { v: 3, en: 'Death will be chosen rather than life by all the residue that remain of this evil family, that remain in all the places where I have driven them,” says Yahweh of Armies.', pt: 'E será escolhida antes a morte do que a vida por todos os que restarem desta raça maligna, que ficarem em todos os lugares onde os lancei, diz o senhor dos exércitos.' },
      { v: 4, en: '“Moreover you shall tell them, ‘Yahweh says: “‘Do men fall, and not rise up again? Does one turn away, and not return?', pt: 'Dize-lhes mais: Assim diz o Senhor: porventura cairão os homens, e não se levantarão? desviar-se-ão, e não voltarão?' },
      { v: 5, en: 'Why then have the people of Jerusalem fallen back by a perpetual backsliding? They cling to deceit. They refuse to return.', pt: 'Por que, pois, se desvia este povo de Jerusalém com uma apostasia contínua? ele retém o engano, recusa-se a voltar.' },
      { v: 6, en: 'I listened and heard, but they didn’t say what is right. No one repents of his wickedness, saying, “What have I done?” Everyone turns to his course, as a horse that rushes headlong in the battle.', pt: 'Eu escutei e ouvi; não falam o que é reto; ninguém há que se arrependa da sua maldade, dizendo: Que fiz eu? Cada um se desvia na sua carreira, como um cavalo que arremete com ímpeto na batalha.' },
      { v: 7, en: 'Yes, the stork in the sky knows her appointed times. The turtledove, the swallow, and the crane observe the time of their coming; but my people don’t know Yahweh’s law.', pt: 'Até a cegonha no céu conhece os seus tempos determinados; e a rola, a andorinha, e o grou observam o tempo da sua arribação; mas o meu povo não conhece a ordenança do Senhor.' },
      { v: 8, en: '“‘How do you say, “We are wise, and Yahweh’s law is with us?” But, behold, the false pen of the scribes has worked falsely.', pt: 'Como pois dizeis: Nós somos sábios, e a lei do Senhor está conosco? Mas eis que a falsa pena dos escribas a converteu em mentira.' },
      { v: 9, en: 'The wise men are disappointed. They are dismayed and trapped. Behold, they have rejected Yahweh’s word. What kind of wisdom is in them?', pt: 'Os sábios são envergonhados, espantados e presos; rejeitaram a palavra do Senhor; que sabedoria, pois, têm eles?' },
      { v: 10, en: 'Therefore will I give their wives to others, and their fields to those who will possess them. For everyone from the least even to the greatest is given to covetousness; from the prophet even to the priest everyone deals falsely.', pt: 'Portanto darei suas mulheres a outros, e os seus campos aos conquistadores; porque desde o menor até o maior, cada um deles se dá à avareza; desde o profeta até o sacerdote, cada qual usa de falsidade.' },
      { v: 11, en: 'They have healed the hurt of the daughter of my people slightly, saying, “Peace, peace,” when there is no peace.', pt: 'E curam a ferida da filha de meu povo le23' },
      { v: 12, en: 'Were they ashamed when they had committed abomination? No, they were not at all ashamed. They couldn’t blush. Therefore they will fall among those who fall. In the time of their visitation they will be cast down, says Yahweh.', pt: 'Porventura se envergonham de terem cometido abominação? Não; de maneira alguma se envergonham, nem sabem que coisa é envergonhar- se. Portanto cairão entre os que caem; e no tempo em que eu os visitar, serão derribados, diz o Senhor.' },
      { v: 13, en: '“‘I will utterly consume them, says Yahweh. No grapes will be on the vine, no figs on the fig tree, and the leaf will fade. The things that I have given them will pass away from them.’”', pt: 'Quando eu os colheria, diz o Senhor, já não há uvas na vide, nem figos na figueira; até a folha está caída; e aquilo mesmo que lhes dei se foi deles.' },
      { v: 14, en: '“Why do we sit still? Assemble yourselves, and let us enter into the fortified cities, and let us be silent there; for Yahweh our God has put us to silence, and given us water of gall to drink, because we have sinned against Yahweh.', pt: 'Por que nos assentamos ainda? juntai-vos e entremos nas cidades fortes, e ali pereçamos; pois o Senhor nosso Deus nos destinou a perecer e nos deu a beber água de fel; porquanto pecamos contra o Senhor.' },
      { v: 15, en: 'We looked for peace, but no good came; and for a time of healing, and behold, dismay!', pt: 'Esperamos a paz, porém não chegou bem algum; e o tempo da cura, e eis o terror.' },
      { v: 16, en: 'The snorting of his horses is heard from Dan. The whole land trembles at the sound of the neighing of his strong ones; for they have come, and have devoured the land and all that is in it; the city and those who dwell therein.”', pt: 'Já desde Dã se ouve o resfolegar dos seus cavalos; a terra toda estremece à voz dos rinchos dos seus ginetes; porque vêm e devoram a terra e quanto nela há, a cidade e os que nela habitam.' },
      { v: 17, en: '“For, behold, I will send serpents, adders among you, which will not be charmed; and they will bite you,” says Yahweh.', pt: 'Pois eis que envio entre vós serpentes, basiliscos, contra os quais não há encantamento; e eles vos morderão, diz o Senhor.' },
      { v: 18, en: 'Oh that I could comfort myself against sorrow! My heart is faint within me.', pt: 'Oxalá que eu pudesse consolar-me na minha tristeza! O meu coração desfalece dentro de mim.' },
      { v: 19, en: 'Behold, the voice of the cry of the daughter of my people from a land that is very far off: “Isn’t Yahweh in Zion? Isn’t her King in her?” “Why have they provoked me to anger with their engraved images, and with foreign idols?”', pt: 'Eis o clamor da filha do meu povo, de toda a extensão da terra; Não está o Senhor em Sião? Não está nela o seu rei? Por que me provocaram a ira com as suas imagens esculpidas, com vaidades estranhas?' },
      { v: 20, en: '“The harvest is past. The summer has ended, and we are not saved.”', pt: 'Passou a sega, findou o verão, e nós não estamos salvos.' },
      { v: 21, en: 'For the hurt of the daughter of my people, I am hurt. I mourn. Dismay has taken hold of me.', pt: 'Estou quebrantado pela ferida da filha do meu povo; ando de luto; o espanto apoderou-se de mim.' },
      { v: 22, en: 'Is there no balm in Gilead? Is there no physician there? Why then isn’t the health of the daughter of my people recovered?', pt: 'Porventura não há bálsamo em Gileade? ou não se acha lá médico? Por que, pois, não se realizou a cura da filha do meu povo?' },
    ],
    9: [
      { v: 1, en: 'Oh that my head were waters, and my eyes a spring of tears, that I might weep day and night for the slain of the daughter of my people!', pt: 'Oxalá a minha cabeça se tornasse em águas, e os meus olhos numa fonte de lágrimas, para que eu chorasse de dia e de noite os mortos da filha do meu povo!' },
      { v: 2, en: 'Oh that I had in the wilderness a lodging place of wayfaring men; that I might leave my people, and go from them! For they are all adulterers, an assembly of treacherous men.', pt: 'Oxalá que eu tivesse no deserto uma estalagem de viandantes, para poder deixar o meu povo, e me apartar dele! porque todos eles são adúlteros, um bando de aleivosos.' },
      { v: 3, en: '“They bend their tongue, as their bow, for falsehood. They have grown strong in the land, but not for truth; for they proceed from evil to evil, and they don’t know me,” says Yahweh.', pt: 'E encurvam a língua, como se fosse o seu arco, para a mentira; fortalecem-se na terra, mas não para a verdade; porque avançam de malícia em malícia, e a mim me não conhecem, diz o Senhor.' },
      { v: 4, en: '“Everyone beware of his neighbor, and don’t trust in any brother; for every brother will utterly supplant, and every neighbor will go around with slanders.', pt: 'Guardai-vos cada um do seu próximo, e de irmão nenhum vos fieis; porque todo irmão não faz mais do que enganar, e todo próximo anda caluniando.' },
      { v: 5, en: 'Everyone will deceive their neighbors, and will not speak the truth. They have taught their tongue to speak lies. They weary themselves commiting iniquity.', pt: 'E engana cada um a seu próximo, e nunca fala a verdade; ensinaram a sua língua a falar a mentira; andam-se cansando em praticar a iniqüidade.' },
      { v: 6, en: 'Your habitation is in the middle of deceit. Through deceit, they refuse to know me,” says Yahweh.', pt: 'A tua habitação está no meio do engano; pelo engano recusam-se a conhecer-me, diz o Senhor.' },
      { v: 7, en: 'Therefore Yahweh of Armies says, “Behold, I will melt them and test them; for how should I deal with the daughter of my people?', pt: 'Portanto assim diz o Senhor dos exércitos: Eis que eu os fundirei e os provarei; pois, de que outra maneira poderia proceder com a filha do meu povo?' },
      { v: 8, en: 'Their tongue is a deadly arrow. It speaks deceit. One speaks peaceably to his neighbor with his mouth, but in his heart, he waits to ambush him.', pt: 'uma flecha mortífera é a língua deles; fala engano; com a sua boca fala cada um de paz com o seu próximo, mas no coração arma-lhe ciladas.' },
      { v: 9, en: 'Shouldn’t I punish them for these things?” says Yahweh. “Shouldn’t my soul be avenged on a nation such as this?', pt: 'Não hei de castigá-los por estas coisas? diz o Senhor; ou não me vingarei de uma nação tal como esta?' },
      { v: 10, en: 'I will weep and wail for the mountains, and lament for the pastures of the wilderness, because they are burned up, so that no one passes through; Men can’t hear the voice of the livestock. Both the birds of the sky and the animals have fled. They are gone.', pt: 'Pelos montes levantai choro e pranto, e pelas pastagens do deserto lamentação; porque já estão queimadas, de modo que ninguém passa por elas; nem se ouve mugido de gado; desde as aves dos céus até os animais, fugiram e se foram.' },
      { v: 11, en: '“I will make Jerusalem heaps, a dwelling place of jackals. I will make the cities of Judah a desolation, without inhabitant.”', pt: 'E farei de Jerusalém montões de pedras, morada de chacais, e das cidades de Judá farei uma desolação, de sorte que fiquem sem habitantes.' },
      { v: 12, en: 'Who is wise enough to understand this? Who is he to whom the mouth of Yahweh has spoken, that he may declare it? Why has the land perished and burned up like a wilderness, so that no one passes through?', pt: 'Quem é o homem sábio, que entenda isto? e a quem falou a boca do Senhor, para que o possa anunciar? Por que razão pereceu a terra, e se queimou como um deserto, de sorte que ninguém passa por ela?' },
      { v: 13, en: 'Yahweh says, “Because they have forsaken my law which I set before them, and have not obeyed my voice, neither walked therein,', pt: 'E diz o Senhor: porque deixaram a minha lei, que lhes pus diante, e não deram ouvidos à minha voz, nem andaram nela,' },
      { v: 14, en: 'but have walked after the stubbornness of their own heart, and after the Baals, which their fathers taught them.”', pt: 'antes andaram obstinadamente segundo o seu próprio coração, e após baalins, como lhes ensinaram os seus pais.' },
      { v: 15, en: 'Therefore Yahweh of Armies, the God of Israel, says, “Behold, I will feed them, even this people, with wormwood, and give them water of gall to drink.', pt: 'Portanto assim diz o Senhor dos exércitos, Deus de Israel: Eis que darei de comer losna a este povo, e lhe darei a beber água de fel.' },
      { v: 16, en: 'I will scatter them also among the nations, whom neither they nor their fathers have known; and I will send the sword after them, until I have consumed them.”', pt: 'Também os espalharei por entre nações que nem eles nem seus pais conheceram; e mandarei a espada após eles, até que venha a consumi-los.' },
      { v: 17, en: 'Yahweh of Armies says, “Consider, and call for the mourning women, that they may come; and send for the skillful women, that they may come.', pt: 'Assim diz o Senhor dos exércitos: Considerai, e chamai as carpideiras, para que venham; e mandai procurar mulheres hábeis, para que venham também;' },
      { v: 18, en: 'Let them make haste, and take up a wailing for us, that our eyes may run down with tears, and our eyelids gush out with waters.', pt: 'e se apressem, e levantem o seu lamento sobre nós, para que se desfaçam em lágrimas os nossos olhos, e as nossas pálpebras destilem águas.' },
      { v: 19, en: 'For a voice of wailing is heard out of Zion, ‘How we are ruined! We are greatly confounded, because we have forsaken the land, because they have cast down our dwellings.’”', pt: 'Porque uma voz de pranto se ouviu de Sião: Como estamos arruinados! Estamos mui envergonhados, por termos deixado a terra, e por terem eles transtornado as nossas moradas.' },
      { v: 20, en: 'Yet hear Yahweh’s word, you women. Let your ear receive the word of his mouth. Teach your daughters wailing, and everyone her neighbor lamentation.', pt: 'Contudo ouvi, vós, mulheres, a palavra do Senhor, e recebam os vossos ouvidos a palavra da sua boca; e ensinai a vossas filhas o pranto, e cada uma à sua vizinha a lamentação.' },
      { v: 21, en: 'For death has come up into our windows. It has entered into our palaces to cut off the children from outside, and the young men from the streets.', pt: 'Pois a morte subiu pelas nossas janelas, e entrou em nossos palácios, para exterminar das ruas as crianças, e das praças os mancebos.' },
      { v: 22, en: 'Speak, “Yahweh says, “‘The dead bodies of men will fall as dung on the open field, and as the handful after the harvester; and no one will gather them.’”', pt: 'Fala: Assim diz o Senhor: Até os cadáveres dos homens cairão como esterco sobre a face do campo, e como gavela atrás do segador, e não há quem a recolha.' },
      { v: 23, en: 'Yahweh says, “Don’t let the wise man glory in his wisdom. Don’t let the mighty man glory in his might. Don’t let the rich man glory in his riches.', pt: 'Assim diz o Senhor: Não se glorie o sábio na sua sabedoria, nem se glorie o forte na sua força; não se glorie o rico nas suas riquezas;' },
      { v: 24, en: 'But let him who glories glory in this, that he has understanding, and knows me, that I am Yahweh who exercises loving kindness, justice, and righteousness, in the earth; for I delight in these things,” says Yahweh.', pt: 'mas o que se gloriar, glorie-se nisto: em entender, e em me conhecer, que eu sou o Senhor, que faço benevolência, juízo e justiça na terra; porque destas coisas me agrado, diz o Senhor.' },
      { v: 25, en: '“Behold, the days come,” says Yahweh, “that I will punish all those who are circumcised only in their flesh:', pt: 'Eis que vêm dias, diz o Senhor, em que castigarei a todo circuncidado pela sua incircuncisão:' },
      { v: 26, en: 'Egypt, Judah, Edom, the children of Ammon, Moab, and all who have the corners of their hair cut off, who dwell in the wilderness; for all the nations are uncircumcised, and all the house of Israel are uncircumcised in heart.”', pt: 'ao Egito, a Judá e a Edom, aos filhos de Amom e a Moabe, e a todos os que cortam os cantos da sua cabeleira e habitam no deserto; pois todas as nações são incircuncisas, e toda a casa de Israel é incircuncisa de coração.' },
    ],
    10: [
      { v: 1, en: 'Hear the word which Yahweh speaks to you, house of Israel!', pt: 'Ouvi a palavra que o Senhor vos fala a vós, ó casa de Israel.' },
      { v: 2, en: 'Yahweh says, “Don’t learn the way of the nations, and don’t be dismayed at the signs of the sky; for the nations are dismayed at them.', pt: 'Assim diz o Senhor: Não aprendais o caminho das nações, nem vos espanteis com os sinais do céu; porque deles se espantam as nações,' },
      { v: 3, en: 'For the customs of the peoples are vanity; for one cuts a tree out of the forest, the work of the hands of the workman with the ax.', pt: 'pois os costumes dos povos são vaidade; corta-se do bosque um madeiro e se lavra com machado pelas mãos do artífice.' },
      { v: 4, en: 'They deck it with silver and with gold. They fasten it with nails and with hammers, so that it can’t move.', pt: 'Com prata e com ouro o enfeitam, com pregos e com martelos o firmam, para que não se mova.' },
      { v: 5, en: 'They are like a palm tree, of turned work, and don’t speak. They must be carried, because they can’t move. Don’t be afraid of them; for they can’t do evil, neither is it in them to do good.”', pt: 'São como o espantalho num pepinal, e não podem falar; necessitam de quem os leve, porquanto não podem andar. Não tenhais receio deles, pois não podem fazer o mal, nem tampouco têm poder de fazer o bem.' },
      { v: 6, en: 'There is no one like you, Yahweh. You are great, and your name is great in might.', pt: 'Ninguém há semelhante a ti, ó Senhor; és grande, e grande é o teu nome em poder.' },
      { v: 7, en: 'Who shouldn’t fear you, King of the nations? For it belongs to you. Because among all the wise men of the nations, and in all their royal estate, there is no one like you.', pt: 'Quem te não temeria a ti, ó Rei das nações? pois a ti se deve o temor; porquanto entre todos os sábios das nações, e em todos os seus reinos ninguém há semelhante a ti.' },
      { v: 8, en: 'But they are together brutish and foolish, instructed by idols! It is just wood.', pt: 'Mas eles todos são embrutecidos e loucos; a instrução dos ídolos é como o madeiro.' },
      { v: 9, en: 'There is silver beaten into plates, which is brought from Tarshish, and gold from Uphaz, the work of the engraver and of the hands of the goldsmith. Their clothing is blue and purple. They are all the work of skillful men.', pt: 'Trazem de Társis prata em chapas, e ouro de Ufaz, trabalho do artífice, e das mãos do fundidor; seus vestidos são de azul e púrpura; obra de peritos são todos eles.' },
      { v: 10, en: 'But Yahweh is the true God. He is the living God, and an everlasting King. At his wrath, the earth trembles. The nations aren’t able to withstand his indignation.', pt: 'Mas o Senhor é o verdadeiro Deus; ele é o Deus vivo e o Rei eterno, ao seu furor estremece a terra, e as nações não podem suportar a sua indignação.' },
      { v: 11, en: '“You shall say this to them: ‘The gods that have not made the heavens and the earth will perish from the earth, and from under the heavens.’”', pt: 'Assim lhes direis: Os deuses que não fizeram os céus e a terra, esses perecerão da terra e de debaixo dos céus.' },
      { v: 12, en: 'God has made the earth by his power. He has established the world by his wisdom, and by his understanding has he stretched out the heavens.', pt: 'Ele fez a terra pelo seu poder; ele estabeleceu o mundo por sua sabedoria e com a sua inteligência estendeu os céus.' },
      { v: 13, en: 'When he utters his voice, the waters in the heavens roar, and he causes the vapors to ascend from the ends of the earth. He makes lightnings for the rain, and brings the wind out of his treasuries.', pt: 'Quando ele faz soar a sua voz, logo há tumulto de águas nos céus, e ele faz subir das extremidades da terra os vapores; faz os relâmpagos para a chuva, e dos seus tesouros faz sair o vento.' },
      { v: 14, en: 'Every man has become brutish and without knowledge. Every goldsmith is disappointed by his engraved image; for his molten image is falsehood, and there is no breath in them.', pt: 'Todo homem se embruteceu e não tem conhecimento; da sua imagem esculpida envergonha-se todo fundidor; pois as suas imagens fundidas são falsas, e nelas não há fôlego.' },
      { v: 15, en: 'They are vanity, a work of delusion. In the time of their visitation they will perish.', pt: 'Vaidade são, obra de enganos; no tempo da sua visitação virão a perecer.' },
      { v: 16, en: 'The portion of Jacob is not like these; for he is the maker of all things; and Israel is the tribe of his inheritance: Yahweh of Armies is his name.', pt: 'Não é semelhante a estes aquele que é a porção de Jacó; porque ele é o que forma todas as coisas, e Israel é a tribo da sua herança. Senhor dos exércitos é o seu nome.' },
      { v: 17, en: 'Gather up your wares out of the land, you who live under siege.', pt: 'Tira do chão a tua trouxa, ó tu que habitas em lugar sitiado.' },
      { v: 18, en: 'For Yahweh says, “Behold, I will sling out the inhabitants of the land at this time, and will distress them, that they may feel it.”', pt: 'Pois assim diz o Senhor: Eis que desta vez arrojarei como se fora com uma funda os moradores da terra, e os angustiarei, para que venham a senti-lo.' },
      { v: 19, en: 'Woe is me because of my injury! My wound is serious; but I said, “Truly this is my grief, and I must bear it.”', pt: 'Ai de mim, por causa do meu quebrantamento! a minha chaga me causa grande dor; mas eu havia dito: Certamente isto é minha enfermidade, e eu devo suporta-la.' },
      { v: 20, en: 'My tent has been destroyed, and all my cords are broken. My children have gone away from me, and they are no more. There is no one to spread my tent any more, to set up my curtains.', pt: 'A minha tenda está destruída, e todas as minhas cordas estão rompidas; os meus filhos foram-se de mim, e não existem; ninguém há mais que estire a minha tenda, e que levante as minhas cortinas.' },
      { v: 21, en: 'For the shepherds have become brutish, and have not inquired of Yahweh. Therefore they have not prospered, and all their flocks have scattered.', pt: 'Pois os pastores se embruteceram, e não buscaram ao Senhor; por isso não prosperaram, e todos os seus rebanhos se acham dispersos.' },
      { v: 22, en: 'The voice of news, behold, it comes, and a great commotion out of the north country, to make the cities of Judah a desolation, a dwelling place of jackals.', pt: 'Eis que vem uma voz de rumor, um grande tumulto da terra do norte, para fazer das cidades de Judá uma assolação, uma morada de chacais.' },
      { v: 23, en: 'Yahweh, I know that the way of man is not in himself. It is not in man who walks to direct his steps.', pt: 'Eu sei, ó Senhor, que não é do homem o seu caminho; nem é do homem que caminha o dirigir os seus passos.' },
      { v: 24, en: 'Yahweh, correct me, but gently; not in your anger, lest you reduce me to nothing.', pt: 'Corrige-me, ó Senhor, mas com medida justa; não na tua ira, para que não me reduzas a nada.' },
      { v: 25, en: 'Pour out your wrath on the nations that don’t know you, and on the families that don’t call on your name; for they have devoured Jacob. Yes, they have devoured him, consumed him, and have laid waste his habitation.', pt: 'Derrama a tua indignação sobre as nações que não te conhecem, e sobre as famílias que não invocam o teu nome; porque devoraram a Jacó; sim, devoraram-no e consumiram-no, e assolaram a sua morada.' },
    ],
    11: [
      { v: 1, en: 'The word that came to Jeremiah from Yahweh, saying,', pt: 'A palavra que veio a Jeremias, da parte do Senhor, dizendo:' },
      { v: 2, en: '“Hear the words of this covenant, and speak to the men of Judah, and to the inhabitants of Jerusalem;', pt: 'Ouvi as palavras deste pacto, e falai aos homens de Judá, e aos habitantes de Jerusalém.' },
      { v: 3, en: 'and say to them, Yahweh, the God of Israel says: ‘Cursed is the man who doesn’t hear the words of this covenant,', pt: 'Dize-lhes pois: Assim diz o Senhor, o Deus de Israel: Maldito o homem que não ouvir as palavras deste pacto,' },
      { v: 4, en: 'which I commanded your fathers in the day that I brought them out of the land of Egypt, out of the iron furnace,’ saying, ‘Obey my voice, and do them, according to all which I command you; so you shall be my people, and I will be your God;', pt: 'que ordenei a vossos pais no dia em que os tirei da terra do Egito, da fornalha de ferro, dizendo: Ouvi a minha voz, e fazei conforme a tudo que vos mando; assim vós sereis o meu povo, e eu serei o vosso Deus;' },
      { v: 5, en: 'that I may establish the oath which I swore to your fathers, to give them a land flowing with milk and honey,’ as it is today.” Then answered I, and said, “Amen, Yahweh.”', pt: 'para que eu confirme o juramento que fiz a vossos pais de dar-lhes uma terra que manasse leite e mel, como se vê neste dia. Então eu respondi, e disse: Amém, ó Senhor.' },
      { v: 6, en: 'Yahweh said to me, “Proclaim all these words in the cities of Judah, and in the streets of Jerusalem, saying, ‘Hear the words of this covenant, and do them.', pt: 'Disse-me, pois, o Senhor: Proclama todas estas palavras nas cidades de Judá, e nas ruas de Jerusalém, dizendo: Ouvi as palavras deste pacto, e cumpri-as.' },
      { v: 7, en: 'For I earnestly protested to your fathers in the day that I brought them up out of the land of Egypt, even to this day, rising early and protesting, saying, “Obey my voice.”', pt: 'Porque com instância admoestei a vossos pais, no dia em que os tirei da terra do Egito, até o dia de hoje, protestando persistentemente e dizendo: Ouvi a minha voz.' },
      { v: 8, en: 'Yet they didn’t obey, nor turn their ear, but everyone walked in the stubbornness of their evil heart. Therefore I brought on them all the words of this covenant, which I commanded them to do, but they didn’t do them.’”', pt: 'Mas não ouviram, nem inclinaram os seus ouvidos; antes andaram cada um na obstinação do seu coração malvado; pelo que eu trouxe sobre eles todas as palavras deste pacto, as quais lhes ordenei que cumprissem, mas não o fizeram.' },
      { v: 9, en: 'Yahweh said to me, “A conspiracy is found among the men of Judah, and among the inhabitants of Jerusalem.', pt: 'Disse-me mais o Senhor: Uma conspiração se achou entre os homens de Judá, e entre os habitantes de Jerusalém.' },
      { v: 10, en: 'They have turned back to the iniquities of their forefathers, who refused to hear my words. They have gone after other gods to serve them. The house of Israel and the house of Judah have broken my covenant which I made with their fathers.', pt: 'Tornaram às iniqüidades de seus primeiros pais, que recusaram ouvir as minhas palavras; até se foram após outros deuses para os servir; a casa de Israel e a casa de Judá quebrantaram o meu pacto, que fiz com seus pais.' },
      { v: 11, en: 'Therefore Yahweh says, ‘Behold, I will bring evil on them, which they will not be able to escape; and they will cry to me, but I will not listen to them.', pt: 'Portanto assim diz o Senhor: Eis que estou trazendo sobre eles uma calamidade de que não pederão escapar; clamarão a mim, mas eu não os ouvirei.' },
      { v: 12, en: 'Then the cities of Judah and the inhabitants of Jerusalem will go and cry to the gods to which they offer incense, but they will not save them at all in the time of their trouble.', pt: 'Então irão as cidades de Judá e os habitantes de Jerusalém e clamarão aos deuses a que eles queimam incenso; estes, porém, de maneira alguma os livrarão no tempo da sua calamidade.' },
      { v: 13, en: 'For according to the number of your cities are your gods, Judah; and according to the number of the streets of Jerusalem have you set up altars to the shameful thing, even altars to burn incense to Baal.’', pt: 'Pois, segundo o número das tuas cidades, são os teus deuses, ó Judá; e, segundo o número das ruas de Jerusalém, tendes levantado altares à impudência, altares para queimardes incenso a Baal.' },
      { v: 14, en: '“Therefore don’t pray for this people. Don’t lift up cry or prayer for them; for I will not hear them in the time that they cry to me because of their trouble.', pt: 'Tu, pois, não ores por este povo, nem levantes por eles clamor nem oração; porque não os ouvirei no tempo em que eles clamarem a mim por causa da sua calamidade.' },
      { v: 15, en: 'What has my beloved to do in my house, since she has behaved lewdly with many, and the holy flesh has passed from you? When you do evil, then you rejoice.”', pt: 'Que direito tem a minha amada na minha casa, visto que com muitos tem cometido grande abominação, e as carnes santas se desviaram de ti? Quando tu fazes mal, então andas saltando de prazer.' },
      { v: 16, en: 'Yahweh called your name, “A green olive tree, beautiful with goodly fruit.” With the noise of a great roar he has kindled fire on it, and its branches are broken.', pt: 'Denominou-te o Senhor oliveira verde, formosa por seus deliciosos frutos; mas agora, à voz dum grande tumulto, acendeu fogo nela, e se quebraram os seus ramos.' },
      { v: 17, en: 'For Yahweh of Armies, who planted you, has pronounced evil against you, because of the evil of the house of Israel and of the house of Judah, which they have done to themselves in provoking me to anger by offering incense to Baal.', pt: 'Porque o Senhor dos exércitos, que te plantou, pronunciou contra ti uma calamidade, por causa do grande mal que a casa de Israel e a casa de Judá fizeram, pois me provocaram à ira, queimando icenso a Baal.' },
      { v: 18, en: 'Yahweh gave me knowledge of it, and I knew it. Then you showed me their doings.', pt: 'E o Senhor mo fez saber, e eu o soube; então me fizeste ver as suas ações.' },
      { v: 19, en: 'But I was like a gentle lamb that is led to the slaughter. I didn’t know that they had devised plans against me, saying, “Let us destroy the tree with its fruit, and let us cut him off from the land of the living, that his name may be no more remembered.”', pt: 'Mas eu era como um manso cordeiro, que se leva à matança; não sabia que era contra mim que maquinavam, dizendo: Destruamos a árvore com o seu fruto, e cortemo-lo da terra dos viventes, para que não haja mais memória do seu nome.' },
      { v: 20, en: 'But, Yahweh of Armies, who judges righteously, who tests the heart and the mind, I will see your vengeance on them; for to you I have revealed my cause.', pt: 'Mas, ó Senhor dos exércitos, justo Juiz, que provas o coração e a mente, permite que eu veja a tua vingança sobre eles; pois a ti descobri a minha causa.' },
      { v: 21, en: '“Therefore Yahweh says concerning the men of Anathoth, who seek your life, saying, ‘You shall not prophesy in Yahweh’s name, that you not die by our hand;’', pt: 'Portanto assim diz o Senhor acerca dos homens de Anatote, que procuram a tua vida, dizendo: Não profetizes no nome do Senhor, para que não morras às nossas mãos;' },
      { v: 22, en: 'therefore Yahweh of Armies says, ‘Behold, I will punish them. The young men will die by the sword. Their sons and their daughters will die by famine.', pt: 'por isso assim diz o Senhor dos exércitos: Eis que eu os punirei; os mancebos morrerão à espada, os seus filhos e as suas filhas morrerão de fome.' },
      { v: 23, en: 'There will be no remnant to them, for I will bring evil on the men of Anathoth, even the year of their visitation.’”', pt: 'E não ficará deles um resto; pois farei vir sobre os homens de Anatote uma calamidade, sim, o ano da sua punição.' },
    ],
    12: [
      { v: 1, en: 'You are righteous, Yahweh, when I contend with you; yet I would like to reason the cause with you. Why does the way of the wicked prosper? Why are they all at ease who deal very treacherously?', pt: 'Justo és, ó Senhor, ainda quando eu pleiteio contigo; contudo pleitearei a minha causa diante de ti. Por que prospera o caminho dos ímpios? Por que vivem em paz todos os que procedem aleivosamente?' },
      { v: 2, en: 'You have planted them. Yes, they have taken root. They grow. Yes, they produce fruit. You are near in their mouth, and far from their heart.', pt: 'Plantaste-os, e eles se arraigaram; medram, dão também fruto; chegado estás à sua boca, porém longe do seu coração.' },
      { v: 3, en: 'But you, Yahweh, know me. You see me, and test my heart toward you. Pull them out like sheep for the slaughter, and prepare them for the day of slaughter.', pt: 'Mas tu, ó Senhor, me conheces, tu me vês, e provas o meu coração para contigo; tira-os como a ovelhas para o matadouro, e separa-os para o dia da matança.' },
      { v: 4, en: 'How long will the land mourn, and the herbs of the whole country wither? Because of the wickedness of those who dwell therein, the animals and birds are consumed; because they said, “He won’t see our latter end.”', pt: 'Até quando lamentará a terra, e se secará a erva de todo o campo? Por causa da maldade dos que nela habitam, perecem os animais e as aves; porquanto disseram: Ele nào vera o nosso fim.' },
      { v: 5, en: '“If you have run with the footmen, and they have wearied you, then how can you contend with horses? Though in a land of peace you are secure, yet how will you do in the pride of the Jordan?', pt: 'Se te fatigas correndo com homens que vão a pé, então como poderás competir com cavalos? Se foges numa terra de paz, como hás de fazer na soberba do Jordão?' },
      { v: 6, en: 'For even your brothers, and the house of your father, even they have dealt treacherously with you! Even they have cried aloud after you! Don’t believe them, though they speak beautiful words to you.', pt: 'Pois até os teus irmãos, e a casa de teu pai, eles mesmos se houveram aleivosamente contigo; eles mesmos clamam após ti em altas vozes. Não te fies neles, ainda que te digam coisas boas.' },
      { v: 7, en: '“I have forsaken my house. I have cast off my heritage. I have given the dearly beloved of my soul into the hand of her enemies.', pt: 'Desamparei a minha casa, abandonei a minha herança; entreguei a amada da minha alma na mão de seus inimigos.' },
      { v: 8, en: 'My heritage has become to me as a lion in the forest. She has uttered her voice against me. Therefore I have hated her.', pt: 'Tornou-se a minha herança para mim como leão numa floresta; levantou a sua voz contra mim, por isso eu a odeio.' },
      { v: 9, en: 'Is my heritage to me as a speckled bird of prey? Are the birds of prey against her all around? Go, assemble all the animals of the field. Bring them to devour.', pt: 'Acaso é para mim a minha herança como uma ave de rapina de varias cores? Andam as aves de rapina contra ela em redor? Ide, pois, ajuntai a todos os animais do campo, trazei-os para a devorarem.' },
      { v: 10, en: 'Many shepherds have destroyed my vineyard. They have trodden my portion under foot. They have made my pleasant portion a desolate wilderness.', pt: 'Muitos pastores destruíram a minha vinha, pisaram o meu quinhão; tornaram em desolado deserto o meu quinhão aprazível.' },
      { v: 11, en: 'They have made it a desolation. It mourns to me, being desolate. The whole land is made desolate, because no one cares.', pt: 'Em assolação o tornaram; ele, desolado, clama a mim. Toda a terra está assolada, mas ninguém toma isso a peito.' },
      { v: 12, en: 'Destroyers have come on all the bare heights in the wilderness; for the sword of Yahweh devours from the one end of the land even to the other end of the land. No flesh has peace.', pt: 'Sobre todos os altos escalvados do deserto vieram destruidores, porque a espada do Senhor devora desde uma até outra extremidade da terra; não há paz para nenhuma carne.' },
      { v: 13, en: 'They have sown wheat, and have reaped thorns. They have exhausted themselves, and profit nothing. You will be ashamed of your fruits, because of Yahweh’s fierce anger.”', pt: 'Semearam trigo, mas segaram espinhos; cansaram-se, mas de nada se aproveitaram; haveis de ser envergonhados das vossas colheitas, por causa do ardor da ira do Senhor.' },
      { v: 14, en: 'Yahweh says, “Concerning all my evil neighbors, who touch the inheritance which I have caused my people Israel to inherit: Behold, I will pluck them up from off their land, and will pluck up the house of Judah from among them.', pt: 'Assim diz o Senhor acerca de todos os meus maus vizinhos, que tocam a minha herança que fiz herdar ao meu povo Israel: Eis que os arrancarei da sua terra, e a casa de Judá arrancarei do meio deles.' },
      { v: 15, en: 'It will happen, that after I have plucked them up, I will return and have compassion on them. I will bring them again, every man to his heritage, and every man to his land.', pt: 'E depois de os haver eu arrancado, tornarei, e me compadecerei deles, e os farei voltar cada um à sua herança, e cada um à sua terra.' },
      { v: 16, en: 'It will happen, if they will diligently learn the ways of my people, to swear by my name, ‘As Yahweh lives;’ even as they taught my people to swear by Baal; then will they be built up in the middle of my people.', pt: 'E será que, se diligentemente aprenderem os caminhos do meu povo, jurando pelo meu nome: Vive o Senhor; como ensinaram o meu povo a jurar por Baal; então edificar-se-ão no meio do meu povo.' },
      { v: 17, en: 'But if they will not hear, then I will pluck up that nation, plucking up and destroying it,” says Yahweh.', pt: 'Mas, se não quiserem ouvir, totalmente arrancarei a tal nação, e a farei perecer, diz o Senhor.' },
    ],
    13: [
      { v: 1, en: 'Yahweh said to me, “Go, and buy yourself a linen belt, and put it on your waist, and don’t put it in water.”', pt: 'Assim me disse o Senhor: Vai, e compra-te um cinto de linho, e põe-no sobre os teus lombos, mas não o metas na água.' },
      { v: 2, en: 'So I bought a belt according to Yahweh’s word, and put it on my waist.', pt: 'E comprei o cinto, conforme a palavra do Senhor, e o pus sobre os meus lombos.' },
      { v: 3, en: 'Yahweh’s word came to me the second time, saying,', pt: 'Então me veio a palavra do Senhor pela segunda vez, dizendo:' },
      { v: 4, en: '“Take the belt that you have bought, which is on your waist, and arise, go to the Euphrates, and hide it there in a cleft of the rock.”', pt: 'Toma o cinto que compraste e que trazes sobre os teus lombos, e levanta-te, vai ao Eufrates, e esconde-o ali na fenda duma rocha.' },
      { v: 5, en: 'So I went, and hid it by the Euphrates, as Yahweh commanded me.', pt: 'Fui, pois, e escondi-o junto ao Eufrates, como o Senhor me havia ordenado.' },
      { v: 6, en: 'After many days, Yahweh said to me, “Arise, go to the Euphrates, and take the belt from there, which I commanded you to hide there.”', pt: 'E passados muitos dias, me disse o Senhor: Levanta-te, vai ao Eufrates, e toma dali o cinto que te ordenei que escondesses ali.' },
      { v: 7, en: 'Then I went to the Euphrates, and dug, and took the belt from the place where I had hidden it; and behold, the belt was ruined. It was profitable for nothing.', pt: 'Então fui ao Eufrates, e cavei, e tomei o cinto do lugar onde e havia escondido; e eis que o cinto tinha apodrecido, e para nada prestava.' },
      { v: 8, en: 'Then Yahweh’s word came to me, saying,', pt: 'Então veio a mim a palavra do Senhor, dizendo:' },
      { v: 9, en: '“Yahweh says, ‘In this way I, will ruin the pride of Judah, and the great pride of Jerusalem.', pt: 'Assim diz o Senhor: Do mesmo modo farei apodrecer a soberba de Judá, e a grande soberba de Jerusalém.' },
      { v: 10, en: 'This evil people, who refuse to hear my words, who walk in the stubbornness of their heart, and have gone after other gods to serve them, and to worship them, will even be as this belt, which is profitable for nothing.', pt: 'Este povo maligno, que se recusa a ouvir as minhas palavras, que caminha segundo a teimosia do seu coração, e que anda após deuses alheios, para os servir, e para os adorar, será tal como este cinto, que para nada presta.' },
      { v: 11, en: 'For as the belt clings to the waist of a man, so I have caused the whole house of Israel and the whole house of Judah to cling to me,’ says Yahweh; ‘that they may be to me for a people, for a name, for praise, and for glory; but they would not hear.’', pt: 'Pois, assim como se liga o cinto aos lombos do homem, assim eu liguei a mim toda a casa de Israel, e toda a casa de Judá, diz o Senhor, para me serem por povo, e por nome, e por louvor, e por glória; mas não quiseram ouvir:' },
      { v: 12, en: '“Therefore you shall speak to them this word: ‘Yahweh, the God of Israel says, “Every bottle should be filled with wine.”’ They will tell you, ‘Do we not certainly know that every bottle should be filled with wine?’', pt: 'Pelo que lhes dirás esta palavra: Assim diz o Senhor Deus de Israel: Todo o odre se encherá de vinho. E dir-te-ão: Acaso não sabemos nós muito bem que todo o odre se encherá de vinho?' },
      { v: 13, en: 'Then tell them, ‘Yahweh says, “Behold, I will fill all the inhabitants of this land, even the kings who sit on David’s throne, the priests, the prophets, and all the inhabitants of Jerusalem, with drunkenness.', pt: 'Então lhes dirás: Assim diz o Senhor: Eis que eu encherei de embriaguez a todos os habitantes desta terra, mesmo aos reis que se assentam sobre o trono de Davi, e aos sacerdotes, e aos profetas, e a todos os habitantes de Jerusalém.' },
      { v: 14, en: 'I will dash them one against another, even the fathers and the sons together,” says Yahweh: “I will not pity, spare, or have compassion, that I should not destroy them.”’”', pt: 'E atirá-los-ei uns contra os outros, mesmo os pais juntamente com os filhos, diz o Senhor; não terei pena nem pouparei, nem terei deles compaixão para não os destruir.' },
      { v: 15, en: 'Hear, and give ear. Don’t be proud, for Yahweh has spoken.', pt: 'Escutai, e inclinai os ouvidos; não vos ensoberbeçais, porque o Senhor falou.' },
      { v: 16, en: 'Give glory to Yahweh your God, before he causes darkness, and before your feet stumble on the dark mountains, and, while you look for light, he turns it into the shadow of death, and makes it deep darkness.', pt: 'Dai glória ao Senhor vosso Deus, antes que venha a escuridão e antes que tropecem vossos pés nos montes tenebrosos; antes que, esperando vós luz, ele a mude em densas trevas, e a reduza a profunda escuridão.' },
      { v: 17, en: 'But if you will not hear it, my soul will weep in secret for your pride. My eye will weep bitterly, and run down with tears, because Yahweh’s flock has been taken captive.', pt: 'Mas, se não ouvirdes, a minha alma chorará em oculto, por causa da vossa soberba; e amargamente chorarão os meus olhos, e se desfarão em lágrimas, porque o rebanho do Senhor se vai levado cativo.' },
      { v: 18, en: 'Say to the king and to the queen mother, “Humble yourselves. Sit down, for your crowns have come down, even the crown of your glory.', pt: 'Dize ao rei e à rainha-mãe: Humilhai-vos, sentai-vos no chão; porque de vossas cabeças já caiu a coroa de vossa glória.' },
      { v: 19, en: 'The cities of the South is shut up, and there is no one to open them. Judah is carried away captive: all of it. It is wholly carried away captive.', pt: 'As cidades do Negebe estão fechadas, e não há quem as abra; todo o Judá é levado cativo, sim, inteiramente cativo.' },
      { v: 20, en: 'Lift up your eyes, and see those who come from the north. Where is the flock that was given to you, your beautiful flock?', pt: 'Levantai os vossos olhos, e vede os que vêm do norte; onde está o rebanho que se te deu, o teu lindo rebanho?' },
      { v: 21, en: 'What will you say, when he sets over you as head those whom you have yourself taught to be friends to you? Won’t sorrows take hold of you, as of a woman in travail?', pt: 'Que dirás, quando ele puser sobre ti como cabeça os que ensinaste a serem teus amigos? Não te tomarão as dores, como as duma mulher que está de parto?' },
      { v: 22, en: 'If you say in your heart, “Why have these things come on me?” Your skirts are uncovered because of the greatness of your iniquity, and your heels suffer violence.', pt: 'Se disseres no teu coração: Por que me sobrevieram estas coisas? Pela multidão das tuas iniqüidades se descobriram as tuas fraldas, e os teus calcanhares sofrem violência.' },
      { v: 23, en: 'Can the Ethiopian change his skin, or the leopard his spots? Then may you also do good, who are accustomed to do evil.', pt: 'pode o etíope mudar a sua pele, ou o leopardo as suas malhas? então podereis também vós fazer o bem, habituados que estais a fazer o mal.' },
      { v: 24, en: '“Therefore I will scatter them, as the stubble that passes away, by the wind of the wilderness.', pt: 'Pelo que os espalharei como o restolho que passa arrebatado pelo vento do deserto.' },
      { v: 25, en: 'This is your lot, the portion measured to you from me,” says Yahweh, “because you have forgotten me, and trusted in falsehood.”', pt: 'Esta é a tua sorte, a porção que te é medida por mim, diz o Senhor; porque te esqueceste de mim, e confiaste em mentiras.' },
      { v: 26, en: 'Therefore will I also uncover your skirts on your face, and your shame will appear.', pt: 'Assim também eu levantarei as tuas fraldas sobre o teu rosto, e aparecerá a tua ignominia.' },
      { v: 27, en: 'I have seen your abominations, even your adulteries, and your neighing, the lewdness of your prostitution, on the hills in the field. Woe to you, Jerusalem! You will not be made clean. How long will it yet be?”', pt: 'Os teus adultérios, e os teus rinchos, e a enormidade da tua prostituição, essas abominações tuas, eu as tenho visto sobre os outeiros no campo. Ai de ti, Jerusalém! até quando não te purificarás?' },
    ],
    14: [
      { v: 1, en: 'This is Yahweh’s word that came to Jeremiah concerning the drought.', pt: 'A palavra do Senhor, que veio a Jeremias, a respeito da seca.' },
      { v: 2, en: '“Judah mourns, and its gates languish. They sit in black on the ground. The cry of Jerusalem goes up.', pt: 'Judá chora, e as suas portas estão enfraquecidas; eles se sentam de luto no chão; e o clamor de Jerusalém já vai subindo.' },
      { v: 3, en: 'Their nobles send their little ones to the waters. They come to the cisterns, and find no water. They return with their vessels empty. They are disappointed and confounded, and cover their heads.', pt: 'E os seus nobres mandam os seus inferiores buscar água; estes vão às cisternas, e não acham água; voltam com os seus cântaros vazios; ficam envergonhados e confundidos, e cobrem as suas cabeças.' },
      { v: 4, en: 'Because of the ground which is cracked, because no rain has been in the land, the plowmen are disappointed. They cover their heads.', pt: 'Por causa do solo ressecado, pois que não havia chuva sobre a terra, os lavradores ficam envergonhados e cobrem as suas cabeças.' },
      { v: 5, en: 'Yes, the doe in the field also calves and forsakes her young, because there is no grass.', pt: 'Pois até a cerva no campo pare, e abandona sua cria, porquanto não há erva.' },
      { v: 6, en: 'The wild donkeys stand on the bare heights. They pant for air like jackals. Their eyes fail, because there is no vegetation.', pt: 'E os asnos selvagens se põem nos altos escalvados e, ofegantes, sorvem o ar como os chacais; desfalecem os seus olhos, porquanto não ha erva.' },
      { v: 7, en: 'Though our iniquities testify against us, work for your name’s sake, Yahweh; for our rebellions are many. We have sinned against you.', pt: 'Posto que as nossas iniqüidades testifiquem contra nós, ó Senhor, opera tu por amor do teu nome; porque muitas são as nossas rebeldias; contra ti havemos pecado.' },
      { v: 8, en: 'You hope of Israel, its Savior in the time of trouble, why should you be as a foreigner in the land, and as a wayfaring man who turns aside to stay for a night?', pt: 'ç esperança de Israel, e Redentor seu no tempo da angústia! por que serias como um estrangeiro na terra? e como o viandante que arma a sua tenda para passar a noite?' },
      { v: 9, en: 'Why should you be like a scared man, as a mighty man who can’t save? Yet you, Yahweh, are in the middle of us, and we are called by your name. Don’t leave us.', pt: 'Por que serias como homem surpreendido, como valoroso que não pode livrar? Mas tu estás no meio de nós, Senhor, e nós somos chamados pelo teu nome; não nos desampares.' },
      { v: 10, en: 'Yahweh says to this people, “Even so they have loved to wander. They have not restrained their feet. Therefore Yahweh does not accept them. Now he will remember their iniquity, and punish them for their sins.”', pt: 'Assim diz o Senhor acerca deste povo: Pois que tanto gostaram de andar errantes, e não detiveram os seus pés, por isso o Senhor não os aceita, mas agora se lembrará da iniqüidade deles, e visitará os seus pecados.' },
      { v: 11, en: 'Yahweh said to me, “Don’t pray for this people for their good.', pt: 'Disse-me ainda o Senhor: Não rogues por este povo para seu bem.' },
      { v: 12, en: 'When they fast, I will not hear their cry; and when they offer burnt offering and meal offering, I will not accept them; but I will consume them by the sword, by famine, and by pestilence.”', pt: 'Quando jejuarem, não ouvirei o seu clamor, e quando oferecerem holocaustos e oblações, não me agradarei deles; antes eu os consumirei pela espada, e pela fome e pela peste.' },
      { v: 13, en: 'Then I said, “Ah, Lord Yahweh! Behold, the prophets tell them, ‘You will not see the sword, neither will you have famine; but I will give you assured peace in this place.’”', pt: 'Então disse eu: Ah! Senhor Deus, eis que os profetas lhes dizem: Não vereis espada, e não tereis fome; antes vos darei paz verdadeira neste lugar.' },
      { v: 14, en: 'Then Yahweh said to me, “The prophets prophesy lies in my name. I didn’t send them. I didn’t command them. I didn’t speak to them. They prophesy to you a lying vision, divination, and a thing of nothing, and the deceit of their own heart.', pt: 'E disse-me o Senhor: Os profetas profetizam mentiras em meu nome; não os enviei, nem lhes dei ordem, nem lhes falei. Visão falsa, adivinhação, vaidade e o engano do seu coração é o que eles vos profetizam.' },
      { v: 15, en: 'Therefore Yahweh says concerning the prophets who prophesy in my name, but I didn’t send them, yet they say, ‘Sword and famine will not be in this land.’ Those prophets will be consumed by sword and famine.', pt: 'Portanto assim diz o Senhor acerca dos profetas que profetizam em meu nome, sem que eu os tenha mandado, e que dizem: Nem espada, nem fome haverá nesta terra: Â espada e à fome serão consumidos esses profetas.' },
      { v: 16, en: 'The people to whom they prophesy will be cast out in the streets of Jerusalem because of the famine and the sword. They will have no one to bury them—them, their wives, their sons, or their daughters, for I will pour their wickedness on them.', pt: 'E o povo a quem eles profetizam será lançado nas ruas de Jerusalém, por causa da fome e da espada; e não haverá quem os sepulte a eles, a suas mulheres, a seus filhos e a suas filhas; porque derramarei sobre eles a sua maldade.' },
      { v: 17, en: '“You shall say this word to them: “‘Let my eyes run down with tears night and day, and let them not cease; for the virgin daughter of my people is broken with a great breach, with a very grievous wound.', pt: 'Portanto lhes dirás esta palavra: Os meus olhos derramem lágrimas de noite e de dia, e não cessem; porque a virgem filha do meu povo está gravemente ferida, de mui dolorosa chaga.' },
      { v: 18, en: 'If I go out into the field, then, behold, the slain with the sword! If I enter into the city, then, behold, those who are sick with famine! For both the prophet and the priest go about in the land, and have no knowledge.’”', pt: 'Se eu saio ao campo, eis os mortos à espada, e, se entro na cidade, eis os debilitados pela fome; o profeta e o sacerdote percorrem a terra, e nada sabem.' },
      { v: 19, en: 'Have you utterly rejected Judah? Has your soul loathed Zion? Why have you struck us, and there is no healing for us? We looked for peace, but no good came; and for a time of healing, and behold, dismay!', pt: 'Porventura já de todo rejeitaste a Judá? Aborrece a tua alma a Sião? Por que nos feriste, de modo que não há cura para nós? Aguardamos a paz, e não chegou bem algum; e o tempo da cura, e eis o pavor!' },
      { v: 20, en: 'We acknowledge, Yahweh, our wickedness, and the iniquity of our fathers; for we have sinned against you.', pt: 'Ah, Senhor! reconhecemos a nossa impiedade e a iniqüidade de nossos pais; pois contra ti havemos pecado.' },
      { v: 21, en: 'Do not abhor us, for your name’s sake. Do not disgrace the throne of your glory. Remember, and don’t break your covenant with us.', pt: 'Não nos desprezes, por amor do teu nome; não tragas opróbrio sobre o trono da tua glória; lembra-te, e não anules o teu pacto conosco.' },
      { v: 22, en: 'Are there any among the vanities of the nations that can cause rain? Or can the sky give showers? Aren’t you he, Yahweh our God? Therefore we will wait for you; for you have made all these things.', pt: 'Há, porventura, entre os deuses falsos das nações, algum que faça chover? Ou podem os céus dar chuvas? Não és tu, ó Senhor, nosso Deus? Portanto em ti esperaremos; pois tu tens feito todas estas coisas.' },
    ],
    15: [
      { v: 1, en: 'Then Yahweh said to me, “Though Moses and Samuel stood before me, yet my mind would not be toward this people. Cast them out of my sight, and let them go out!', pt: 'Disse-me, porém, o Senhor: Ainda que Moisés e Samuel se pusessem diante de mim, não poderia estar a minha alma com este povo. Lança-os de diante da minha face, e saiam eles.' },
      { v: 2, en: 'It will happen, when they tell you, ‘Where shall we go out?’ Then you shall tell them, ‘Yahweh says: “Such as are for death, to death; such as are for the sword, to the sword; such as are for the famine, to the famine; and such as are for captivity, to captivity.”’', pt: 'E quando te perguntarem: Para onde iremos? dir-lhes-ás: Assim diz o Senhor: Os que para a morte, para a morte; e os que para a espada, para a espada; e os que para a fome, para a fome; e os que para o cativeiro, para o cativeiro.' },
      { v: 3, en: '“I will appoint over them four kinds,” says Yahweh: “the sword to kill, the dogs to tear, the birds of the sky, and the animals of the earth, to devour and to destroy.', pt: 'Pois os visitarei com quatro gêneros de destruidores, diz o Senhor: com espada para matar, e com cães, para os dilacerarem, e com as aves do céu e os animais da terra, para os devorarem e destruírem.' },
      { v: 4, en: 'I will cause them to be tossed back and forth among all the kingdoms of the earth, because of Manasseh, the son of Hezekiah, king of Judah, for that which he did in Jerusalem.', pt: 'Entregá-los-ei para serem um espetáculo horrendo perante todos os reinos da terra, por causa de Manassés, filho de Ezequias, rei de Judá, por tudo quanto fez em Jerusalém.' },
      { v: 5, en: 'For who will have pity on you, Jerusalem? Who will mourn you? Who will come to ask of your welfare?', pt: 'Pois quem se compadecerá de ti, ó Jerusalém? ou quem se entristecerá por ti? Quem se desviará para perguntar pela tua paz?' },
      { v: 6, en: 'You have rejected me,” says Yahweh. “You have gone backward. Therefore I have stretched out my hand against you, and destroyed you. I am weary of showing compassion.', pt: 'Tu me rejeitaste, diz o Senhor, voltaste para trás; por isso estenderei a minha mão contra ti, e te destruirei; estou cansado de me abrandar.' },
      { v: 7, en: 'I have winnowed them with a fan in the gates of the land. I have bereaved them of children. I have destroyed my people. They didn’t return from their ways.', pt: 'E os padejei com a pá nas portas da terra; desfilhei, destruí o meu povo; não voltaram dos seus caminhos.' },
      { v: 8, en: 'Their widows are increased more than the sand of the seas; I have brought on them against the mother of the young men a destroyer at noonday. I have caused anguish and terrors to fall on her suddenly.', pt: 'As suas viúvas mais se me têm multiplicado do que a areia dos mares; trouxe ao meio-dia um destruidor sobre eles, até sobre a mãe de jovens; fiz que caísse de repente sobre ela angústia e terrores.' },
      { v: 9, en: 'She who has borne seven languishes. She has given up the spirit. Her sun has gone down while it was yet day. She has been disappointed and confounded. I will deliver their residue to the sword before their enemies,” says Yahweh.', pt: 'A que dava à luz sete se enfraqueceu: expirou a sua alma; pôs-se-lhe o sol sendo ainda dia; ela se confundiu, e se envergonhou; e os que ficarem deles eu os entregarei à espada, diante dos seus inimigos, diz o Senhor.' },
      { v: 10, en: 'Woe is me, my mother, that you have borne me, a man of strife, and a man of contention to the whole earth! I have not lent, neither have men lent to me; yet every one of them curses me.', pt: 'Ai de mim, minha mãe! porque me deste à luz, homem de rixas e homem de contendas para toda a terra. Nunca lhes emprestei com usura, nem eles me emprestaram a mim com usura, todavia cada um deles me amaldiçoa.' },
      { v: 11, en: 'Yahweh said, “Most certainly I will strengthen you for good. Most certainly I will cause the enemy to make supplication to you in the time of evil and in the time of affliction.', pt: 'Assim seja, ó Senhor, se jamais deixei de suplicar-te pelo bem deles, ou de rogar-te pelo inimigo no tempo da calamidade e no tempo da angústia.' },
      { v: 12, en: 'Can one break iron, even iron from the north, and brass?', pt: 'Pode alguém quebrar o ferro, o ferro do Norte, e o bronze?' },
      { v: 13, en: 'I will give your substance and your treasures for a plunder without price, and that for all your sins, even in all your borders.', pt: 'As tuas riquezas e os teus tesouros, eu os entregarei sem preço ao saque; e isso por todos os teus pecados, mesmo em todos os teus limites.' },
      { v: 14, en: 'I will make them to pass with your enemies into a land which you don’t know; for a fire is kindled in my anger, which will burn on you.”', pt: 'E farei que sirvas os teus inimigos numa terra que não conheces; porque o fogo se acendeu em minha ira, e sobre vós arderá.' },
      { v: 15, en: 'Yahweh, you know. Remember me, visit me, and avenge me of my persecutors. You are patient, so don’t take me away. Know that for your sake I have suffered reproach.', pt: 'Tu, ó Senhor, me conheces; lembra-te de mim, visita-me, e vinga-me dos meus perseguidores; não me arrebates, por tua longanimidade. Sabe que por amor de ti tenho sofrido afronta.' },
      { v: 16, en: 'Your words were found, and I ate them. Your words were to me a joy and the rejoicing of my heart, for I am called by your name, Yahweh, God of Armies.', pt: 'Acharam-se as tuas palavras, e eu as comi; e as tuas palavras eram para mim o gozo e alegria do meu coração; pois levo o teu nome, ó Senhor Deus dos exércitos.' },
      { v: 17, en: 'I didn’t sit in the assembly of those who make merry and rejoice. I sat alone because of your hand, for you have filled me with indignation.', pt: 'Não me assentei na roda dos que se alegram, nem me regozijei. Sentei-me a sós sob a tua mão, pois me encheste de indignação.' },
      { v: 18, en: 'Why is my pain perpetual, and my wound incurable, which refuses to be healed? Will you indeed be to me as a deceitful brook, like waters that fail?', pt: 'Por que é perpétua a minha dor, e incurável a minha ferida, que se recusa a ser curada? Serás tu para mim como ribeiro ilusório e como águas inconstantes?' },
      { v: 19, en: 'Therefore Yahweh says, “If you return, then I will bring you again, that you may stand before me; and if you take out the precious from the vile, you will be as my mouth. They will return to you, but you will not return to them.', pt: 'Portanto assim diz o Senhor: Se tu voltares, então te restaurarei, para estares diante de mim; e se apartares o precioso do vil, serás como a minha boca; tornem-se eles a ti, mas não voltes tu a eles.' },
      { v: 20, en: 'I will make you to this people a fortified bronze wall. They will fight against you, but they will not prevail against you; for I am with you to save you and to deliver you,” says Yahweh.', pt: 'E eu te porei contra este povo como forte muro de bronze; eles pelejarão contra ti, mas não prevalecerão contra ti; porque eu sou contigo para te salvar, para te livrar, diz o Senhor.' },
      { v: 21, en: '“I will deliver you out of the hand of the wicked, and I will redeem you out of the hand of the terrible.”', pt: 'E arrebatar-te-ei da mão dos iníquos, e livrar-te-ei da mão dos cruéis.' },
    ],
    16: [
      { v: 1, en: 'Yahweh’s word came also to me, saying,', pt: 'E veio a mim a palavra do Senhor, dizendo:' },
      { v: 2, en: '“You shall not take a wife, neither shall you have sons or daughters, in this place.”', pt: 'Não tomarás a ti mulher, nem terás filhos nem filhas neste lugar.' },
      { v: 3, en: 'For Yahweh says concerning the sons and concerning the daughters who are born in this place, and concerning their mothers who bore them, and concerning their fathers who became their father in this land:', pt: 'Pois assim diz o Senhor acerca dos filhos e das filhas que nascerem neste lugar, acerca de suas mães, que os tiverem, e de seus pais que os gerarem nesta terra:' },
      { v: 4, en: '“They will die grievous deaths: they will not be lamented, neither will they be buried. They will be as dung on the surface of the ground. They will be consumed by the sword and by famine. Their dead bodies will be food for the birds of the sky and for the animals of the earth.”', pt: 'Morrerão de enfermidades dolorosas, e não serão pranteados nem sepultados; serão como esterco sobre a face da terra; pela espada e pela fome serão consumidos, e os seus cadáveres servirão de pasto para as aves do céu e para os animais da terra.' },
      { v: 5, en: 'For Yahweh says, “Don’t enter into the house of mourning. Don’t go to lament. Don’t bemoan them, for I have taken away my peace from this people,” says Yahweh, “even loving kindness and tender mercies.', pt: 'Pois assim diz o Senhor: Não entres na casa que está de luto, nem vás a lamentá-los, nem te compadeças deles; porque deste povo, diz o Senhor, retirei a minha paz, benignidade e misericórdia.' },
      { v: 6, en: 'Both great and small will die in this land. They will not be buried. Men won’t lament for them, cut themselves, or make themselves bald for them.', pt: 'E morrerão nesta terra tanto grandes como pequenos; não serão sepultados, e não os prantearão, nem se farão por eles incisões, nem por eles se raparão os cabelos;' },
      { v: 7, en: 'Men won’t break bread for them in mourning, to comfort them for the dead. Men won’t give them the cup of consolation to drink for their father or for their mother.', pt: 'nem pão se dará aos que estiverem de luto, para os consolar sobre os mortos; nem se lhes dará a beber o copo da consolação pelo pai ou pela mãe.' },
      { v: 8, en: '“You shall not go into the house of feasting to sit with them, to eat and to drink.”', pt: 'Não entres na casa do banquete, para te assentares com eles a comer e a beber.' },
      { v: 9, en: 'For Yahweh of Armies, the God of Israel says: “Behold, I will cause to cease out of this place, before your eyes and in your days, the voice of mirth and the voice of gladness, the voice of the bridegroom and the voice of the bride.', pt: 'Pois assim diz o Senhor dos exércitos, o Deus de Israel: Eis que perante os vossos olhos, e em vossos dias, farei cessar deste lugar a voz de gozo e a voz de alegria, a voz do noivo e a voz da noiva.' },
      { v: 10, en: 'It will happen, when you tell this people all these words, and they ask you, ‘Why has Yahweh pronounced all this great evil against us?’ or ‘What is our iniquity? or ‘What is our sin that we have committed against Yahweh our God?’', pt: 'E quando anunciares a este povo todas estas palavras, e eles te disserem: Por que pronuncia o Senhor sobre :nós todo este grande mal? Qual é a nossa iniqüidade? Qual é o pecado que cometemos contra o Senhor nosso Deus?' },
      { v: 11, en: 'then you shall tell them, ‘Because your fathers have forsaken me,’ says Yahweh, ‘and have walked after other gods, have served them, have worshiped them, have forsaken me, and have not kept my law.', pt: 'Então lhes dirás: Porquanto vossos pais me deixaram, diz o Senhor, e se foram após outros deuses, e os serviram e adoraram, e a mim me deixaram, e não guardaram a minha lei;' },
      { v: 12, en: 'You have done evil more than your fathers, for behold, you each walk after the stubbornness of his evil heart, so that you don’t listen to me.', pt: 'e vós fizestes pior do que vossos pais; pois eis que andais, cada um de vós, após o pensamento obstinado do seu mau coração, recusando ouvir-me a mim;' },
      { v: 13, en: 'Therefore will I cast you out of this land into the land that you have not known, neither you nor your fathers. There you will serve other gods day and night, for I will show you no favor.’', pt: 'portanto eu vos lançarei fora desta terra, para uma terra que não conhecestes, nem vós nem vossos pais; e ali servireis a deuses estranhos de dia e de noite; pois não vos concederei favor algum.' },
      { v: 14, en: '“Therefore behold, the days come,” says Yahweh, “that it will no more be said, ‘As Yahweh lives, who brought up the children of Israel out of the land of Egypt;’', pt: 'Portanto, eis que dias vêm, diz o Senhor, em que não se dirá mais: Vive o Senhor: que fez subir os filhos de Israel da terra do Egito;' },
      { v: 15, en: 'but, ‘As Yahweh lives, who brought up the children of Israel from the land of the north, and from all the countries where he had driven them.’ I will bring them again into their land that I gave to their fathers.', pt: 'mas sim: Vive o Senhor, que fez subir os filhos de Israel da terra do norte, e de todas as terras para onde os tinha lançado; porque eu os farei voltar à sua terra, que dei a seus pais.' },
      { v: 16, en: '“Behold, I will send for many fishermen,” says Yahweh, “and they will fish them up. Afterward I will send for many hunters, and they will hunt them from every mountain, from every hill, and out of the clefts of the rocks.', pt: 'Eis que mandarei vir muitos pescadores, diz o Senhor, os quais os pescarão; e depois mandarei vir muitos caçadores, os quais os caçarão de todo monte, e de todo outeiro, e até das fendas das rochas.' },
      { v: 17, en: 'For my eyes are on all their ways. They are not hidden from my face. Their iniquity isn’t concealed from my eyes.', pt: 'Pois os meus olhos estão sobre todos os seus caminhos; não se acham eles escondidos da minha face, nem está a sua iniqüidade encoberta aos meus olhos.' },
      { v: 18, en: 'First I will recompense their iniquity and their sin double, because they have polluted my land with the carcasses of their detestable things, and have filled my inheritance with their abominations.”', pt: 'E eu retribuirei em dobro a sua iniqüidade e o seu pecado, porque contaminaram a minha terra com os vultos inertes dos seus ídolos detestáveis, e das suas abominações encheram a minha herança.' },
      { v: 19, en: 'Yahweh, my strength, and my stronghold, and my refuge in the day of affliction, the nations will come to you from the ends of the earth, and will say, “Our fathers have inherited nothing but lies, vanity and things in which there is no profit.', pt: 'ç Senhor, força minha e fortaleza minha, e refúgio meu no dia da angústia, a ti virão as nações desde as extremidades da terra, e dirão: Nossos pais herdaram só mentiras, e vaidade, em que não havia proveito.' },
      { v: 20, en: 'Should a man make to himself gods, which yet are no gods?”', pt: 'Pode um homem fazer para si deuses? Esses tais não são deuses!' },
      { v: 21, en: '“Therefore behold, I will cause them to know, this once I will cause them to know my hand and my might. Then they will know that my name is Yahweh.”', pt: 'Portanto, eis que lhes farei conhecer, sim desta vez lhes farei conhecer o meu poder e a minha força; e saberão que o meu nome é Jeová.' },
    ],
    17: [
      { v: 1, en: '“The sin of Judah is written with a pen of iron, and with the point of a diamond. It is engraved on the tablet of their heart, and on the horns of your altars.', pt: 'O pecado de Judá está escrito com um ponteiro de ferro; com ponta de diamante está gravado na tábua do seu coração e nas pontas dos seus altares;' },
      { v: 2, en: 'Even their children remember their altars and their Asherah poles by the green trees on the high hills.', pt: 'enquanto seus filhos se lembram dos seus altares, e dos seus aserins, junto às árvores frondosas, sobre os altos outeiros,' },
      { v: 3, en: 'My mountain in the field, I will give your substance and all your treasures for a plunder, and your high places, because of sin, throughout all your borders.', pt: 'nas montanhas no campo aberto, a tua riqueza e todos os teus tesouros dá-los-ei como despojo por causa do pecado, em todos os teus termos.' },
      { v: 4, en: 'You, even of yourself, will discontinue from your heritage that I gave you. I will cause you to serve your enemies in the land which you don’t know, for you have kindled a fire in my anger which will burn forever.”', pt: 'Assim tu, por ti mesmo, te privarás da tua herança que te dei; e far-te-ei servir os teus inimigos, na terra que não conheces; porque acendeste um fogo na minha ira, o qual arderá para sempre.' },
      { v: 5, en: 'Yahweh says: “Cursed is the man who trusts in man, relies on strength of flesh, and whose heart departs from Yahweh.', pt: 'Assim diz o Senhor: Maldito o varão que confia no homem, e faz da carne o seu braço, e aparta o seu coração do Senhor!' },
      { v: 6, en: 'For he will be like a bush in the desert, and will not see when good comes, but will inhabit the parched places in the wilderness, an uninhabited salt land.', pt: 'Pois é como o junípero no deserto, e não verá vir bem algum; antes morará nos lugares secos do deserto, em terra salgada e inabitada.' },
      { v: 7, en: '“Blessed is the man who trusts in Yahweh, and whose confidence is in Yahweh.', pt: 'Bendito o varão que confia no Senhor, e cuja esperança é o Senhor.' },
      { v: 8, en: 'For he will be as a tree planted by the waters, who spreads out its roots by the river, and will not fear when heat comes, but its leaf will be green; and will not be concerned in the year of drought. It won’t cease from yielding fruit.', pt: 'Porque é como a árvore plantada junto às águas, que estende as suas raízes para o ribeiro, e não receia quando vem o calor, mas a sua folha fica verde; e no ano de sequidão não se afadiga, nem deixa de dar fruto.' },
      { v: 9, en: 'The heart is deceitful above all things and it is exceedingly corrupt. Who can know it?', pt: 'Enganoso é o coração, mais do que todas as coisas, e perverso; quem o poderá conhecer?' },
      { v: 10, en: '“I, Yahweh, search the mind. I try the heart, even to give every man according to his ways, according to the fruit of his doings.”', pt: 'Eu, o Senhor, esquadrinho a mente, eu provo o coração; e isso para dar a cada um segundo os seus caminhos e segundo o fruto das suas ações.' },
      { v: 11, en: 'As the partridge that sits on eggs which she has not laid, so is he who gets riches, and not by right. In the middle of his days, they will leave him. At his end, he will be a fool.', pt: 'Como a perdiz que ajunta pintainhos que não são do seu ninho, assim é aquele que ajunta riquezas, mas não retamente; no meio de seus dias as deixará, e no seu fim se mostrará insensato.' },
      { v: 12, en: 'A glorious throne, set on high from the beginning, is the place of our sanctuary.', pt: 'Um trono glorioso, posto bem alto desde o princípio, é o lugar do nosso santuário.' },
      { v: 13, en: 'Yahweh, the hope of Israel, all who forsake you will be disappointed. Those who depart from me will be written in the earth, because they have forsaken Yahweh, the spring of living waters.', pt: 'ç Senhor, esperança de Israel, todos aqueles que te abandonarem serão envergonhados. Os que se apartam de ti serão escritos sobre a terra; porque abandonam o Senhor, a fonte das águas vivas.' },
      { v: 14, en: 'Heal me, O Yahweh, and I will be healed. Save me, and I will be saved; for you are my praise.', pt: 'Cura-me, ó Senhor, e serei curado; salva-me, e serei salvo; pois tu és o meu louvor.' },
      { v: 15, en: 'Behold, they tell me, “Where is Yahweh’s word? Let it be fulfilled now.”', pt: 'Eis que eles me dizem: Onde está a palavra do Senhor? venha agora.' },
      { v: 16, en: 'As for me, I have not hurried from being a shepherd after you. I haven’t desired the woeful day. You know. That which came out of my lips was before your face.', pt: 'Quanto a mim, não instei contigo para enviares sobre eles o mal, nem tampouco desejei o dia calamitoso; tu o sabes; o que saiu dos meus lábios estava diante de tua face.' },
      { v: 17, en: 'Don’t be a terror to me. You are my refuge in the day of evil.', pt: 'Não me sejas por espanto; meu refúgio és tu no dia da calamidade.' },
      { v: 18, en: 'Let them be disappointed who persecute me, but let not me be disappointed. Let them be dismayed, but don’t let me be dismayed. Bring on them the day of evil, and destroy them with double destruction.', pt: 'Envergonhem-se os que me perseguem, mas não me envergonhe eu; assombrem-se eles, mas não me assombre eu; traze sobre eles o dia da calamidade, e destrói-os com dobrada destruição.' },
      { v: 19, en: 'Yahweh said this to me: “Go, and stand in the gate of the children of the people, through which the kings of Judah come in and by which they go out, and in all the gates of Jerusalem.', pt: 'Assim me disse o Senhor: Vai, e põe-te na porta de Benjamim, pela qual entram os reis de Judá, e pela qual saem, como também em todas as portas de Jerusalém.' },
      { v: 20, en: 'Tell them, ‘Hear Yahweh’s word, you kings of Judah, and all Judah, and all the inhabitants of Jerusalem, that enter in by these gates:', pt: 'E dize-lhes: Ouvi a palavra do Senhor, vós, reis de Judá e todo o Judá, e todos os moradores de Jerusalém, que entrais por estas portas;' },
      { v: 21, en: 'Yahweh says, “Be careful, and bear no burden on the Sabbath day, nor bring it in by the gates of Jerusalem.', pt: 'assim diz o Senhor: Guardai-vos a vós mesmos, e não tragais cargas no dia de sábado, nem as introduzais pelas portas de Jerusalém;' },
      { v: 22, en: 'Don’t carry a burden out of your houses on the Sabbath day. Don’t do any work, but make the Sabbath day holy, as I commanded your fathers.', pt: 'nem tireis cargas de vossas casas no dia de sábado, nem façais trabalho algum; antes santificai o dia de sábado, como eu ordenei a vossos pais.' },
      { v: 23, en: 'But they didn’t listen. They didn’t turn their ear, but made their neck stiff, that they might not hear, and might not receive instruction.', pt: 'Mas eles não escutaram, nem inclinaram os seus ouvidos; antes endureceram a sua cerviz, para não ouvirem, e para não receberem instrução.' },
      { v: 24, en: 'It will happen, if you diligently listen to me,” says Yahweh, “to bring in no burden through the gates of this city on the Sabbath day, but to make the Sabbath day holy, to do no work therein;', pt: 'Mas se vós diligentemente me ouvirdes, diz o Senhor, não introduzindo cargas pelas portas desta cidade no dia de sábado, e santificardes o dia de sábado, não fazendo nele trabalho algum,' },
      { v: 25, en: 'then there will enter in by the gates of this city kings and princes sitting on David’s throne, riding in chariots and on horses, they, and their princes, the men of Judah, and the inhabitants of Jerusalem; and this city will remain forever.', pt: 'então entrarão pelas portas desta cidade reis e príncipes, que se assentem sobre o trono de Davi, andando em carros e montados em cavalos, eles e seus príncipes, os homens de Judá, e os moradores de Jerusalém; e esta cidade será para sempre habitada.' },
      { v: 26, en: 'They will come from the cities of Judah, and from the places around Jerusalem, from the land of Benjamin, from the lowland, from the hill country, and from the South, bringing burnt offerings, sacrifices, meal offerings, and frankincense, and bringing sacrifices of thanksgiving, to Yahweh’s house.', pt: 'E virão das cidades de Judá, e dos arredores de Jerusalém, e da terra de Benjamim, e da planície, e da região montanhosa, e do e sul, trazendo à casa do Senhor holocaustos, e sacrifícios, e ofertas de cereais, e incenso, trazendo também sacrifícios de ação de graças.' },
      { v: 27, en: 'But if you will not listen to me to make the Sabbath day holy, and not to bear a burden and enter in at the gates of Jerusalem on the Sabbath day, then I will kindle a fire in its gates, and it will devour the palaces of Jerusalem. It will not be quenched.”’”', pt: 'Mas, se não me ouvirdes, para santificardes o dia de sábado, e para não trazerdes carga alguma, quando entrardes pelas portas de Jerusalém no dia de sábado, então acenderei fogo nas suas portas, o qual consumirá os palácios de Jerusalém, e não se apagará.' },
    ],
    18: [
      { v: 1, en: 'The word which came to Jeremiah from Yahweh, saying,', pt: 'A palavra que veio do Senhor a Jeremias, dizendo:' },
      { v: 2, en: '“Arise, and go down to the potter’s house, and there I will cause you to hear my words.”', pt: 'Levanta-te, e desce à casa do oleiro, e lá te farei ouvir as minhas palavras.' },
      { v: 3, en: 'Then I went down to the potter’s house, and behold, he was making something on the wheels.', pt: 'Desci, pois, à casa do oleiro, e eis que ele estava ocupado com a sua obra sobre as rodas.' },
      { v: 4, en: 'When the vessel that he made of the clay was marred in the hand of the potter, he made it again another vessel, as seemed good to the potter to make it.', pt: 'Como o vaso, que ele fazia de barro, se estragou na mão do oleiro, tornou a fazer dele outro vaso, conforme pareceu bem aos seus olhos fazer.' },
      { v: 5, en: 'Then Yahweh’s word came to me, saying,', pt: 'Então veio a mim a palavra do Senhor, dizendo:' },
      { v: 6, en: '“House of Israel, can’t I do with you as this potter?” says Yahweh. “Behold, as the clay in the potter’s hand, so are you in my hand, house of Israel.', pt: 'Não poderei eu fazer de vós como fez este oleiro, ó casa de Israel? diz o Senhor. Eis que, como o barro na mão do oleiro, assim sois vós na minha mão, ó casa de Israel.' },
      { v: 7, en: 'At the instant I speak concerning a nation, and concerning a kingdom, to pluck up and to break down and to destroy it;', pt: 'Se em qualquer tempo eu falar acerca duma nação, e acerca dum reino, para arrancar, para derribar e para destruir,' },
      { v: 8, en: 'if that nation, concerning which I have spoken, turns from their evil, I will repent of the evil that I thought to do to them.', pt: 'e se aquela nação, contra a qual falar, se converter da sua maldade, também eu me arrependerei do mal que intentava fazer-lhe.' },
      { v: 9, en: 'At the instant I speak concerning a nation, and concerning a kingdom, to build and to plant it;', pt: 'E se em qualquer tempo eu falar acerca duma nação e acerca dum reino, para edificar e para plantar,' },
      { v: 10, en: 'if they do that which is evil in my sight, that they not obey my voice, then I will repent of the good with which I said I would benefit them.', pt: 'se ela fizer o mal diante dos meus olhos, não dando ouvidos à minha voz, então me arrependerei do bem que lhe intentava fazer.' },
      { v: 11, en: '“Now therefore, speak to the men of Judah, and to the inhabitants of Jerusalem, saying, ‘Yahweh says: “Behold, I frame evil against you, and devise a plan against you. Everyone return from his evil way now, and amend your ways and your doings.”’', pt: 'Ora pois, fala agora aos homens de Judá, e aos moradores de Jerusalém, dizendo: Assim diz o senhor: Eis que estou forjando mal contra vós, e projeto um plano contra vós; convertei-vos pois agora cada um do seu mau caminho, e emendai os vossos caminhos e as vossas ações.' },
      { v: 12, en: 'But they say, ‘It is in vain; for we will walk after our own plans, and we will each follow the stubbornness of his evil heart.’”', pt: 'Mas eles dizem: Não há esperança; porque após os nossos projetos andaremos, e cada um fará segundo o propósito obstinado do seu mau coraçao.' },
      { v: 13, en: 'Therefore Yahweh says: “Ask now among the nations, ‘Who has heard such things?’ The virgin of Israel has done a very horrible thing.', pt: 'Portanto assim diz o Senhor: Perguntai agora entre as nações quem ouviu tais coisas? coisa mui horrenda fez a virgem de Israel!' },
      { v: 14, en: 'Will the snow of Lebanon fail from the rock of the field? Will the cold waters that flow down from afar be dried up?', pt: 'Acaso desaparece a neve do Líbano dos penhascos do Siriom? Serão esgotadas as águas frias que vêm dos montes?' },
      { v: 15, en: 'For my people have forgotten me. They have burned incense to false gods. They have been made to stumble in their ways, in the ancient paths, to walk in byways, in a way not built up;', pt: 'Contudo o meu povo se tem esquecido de mim, queimando incenso a deuses falsos; fizeram-se tropeçar nos seus caminhos, e nas veredas antigas, para que andassem por atalhos não aplainados;' },
      { v: 16, en: 'to make their land an astonishment, and a perpetual hissing. Everyone who passes thereby will be astonished, and shake his head.', pt: 'para fazerem da sua terra objeto de espanto e de perpétuos assobios; todo aquele que passa por ela se espanta, e meneia a cabeça.' },
      { v: 17, en: 'I will scatter them as with an east wind before the enemy. I will show them the back, and not the face, in the day of their calamity.', pt: 'Com vento oriental os espalharei diante do inimigo; mostrar-lhes-ei as costas e não o rosto, no dia da sua calamidade.' },
      { v: 18, en: 'Then they said, “Come, and let us devise plans against Jeremiah; for the law won’t perish from the priest, nor counsel from the wise, nor the word from the prophet. Come, and let us strike him with the tongue, and let us not give heed to any of his words.”', pt: 'Então disseram: Vinde, e maquinemos projetos contra Jeremias; pois não perecerá a lei do sacerdote, nem o conselho do sábio, nem a palavra do profeta. Vinde, e firâmo-lo com a língua, e não atendamos a nenhuma das suas palavras.' },
      { v: 19, en: 'Give heed to me, Yahweh, and listen to the voice of those who contend with me.', pt: 'Atende-me, ó Senhor, e ouve a voz dos que contendem comigo.' },
      { v: 20, en: 'Should evil be recompensed for good? For they have dug a pit for my soul. Remember how I stood before you to speak good for them, to turn away your wrath from them.', pt: 'Porventura pagar-se-á mal por bem? Contudo cavaram uma cova para a minha vida. Lembra-te de que eu compareci na tua presença, para falar a favor deles, para desviar deles a tua indignação.' },
      { v: 21, en: 'Therefore deliver up their children to the famine, and give them over to the power of the sword. Let their wives become childless, and widows. Let their men be killed, and their young men struck by the sword in battle.', pt: 'Portanto entrega seus filhos à fome, e entrega-os ao poder da espada, e sejam suas mulheres roubadas dos filhos, e fiquem viúvas; e sejam seus maridos feridos de morte, e os seus jovens mortos à espada na peleja.' },
      { v: 22, en: 'Let a cry be heard from their houses, when you bring a troop suddenly on them; for they have dug a pit to take me, and hidden snares for my feet.', pt: 'Seja ouvido o clamor que vem de suas casas, quando de repente trouxeres tropas sobre eles; porque cavaram uma cova para prender-me e armaram laços aos meus pés.' },
      { v: 23, en: 'Yet, Yahweh, you know all their counsel against me to kill me. Don’t forgive their iniquity. Don’t blot out their sin from your sight, Let them be overthrown before you. Deal with them in the time of your anger.', pt: 'Mas tu, ó Senhor, sabes todo o seu conselho contra mim para matar-me. Não perdoes a sua iniquidade, nem apagues o seu pecado de diante da tua face; mas sejam transtornados diante de ti; trata-os assim no tempo da tua ira.' },
    ],
    19: [
      { v: 1, en: 'Thus said Yahweh, “Go, and buy a potter’s earthen bottle, and take some of the elders of the people, and of the elders of the priests;', pt: 'Assim disse o Senhor: Vai, e compra uma botija de oleiro, e leva contigo alguns anciãos do povo e alguns anciãos dos sacerdotes;' },
      { v: 2, en: 'and go out to the valley of the son of Hinnom, which is by the entry of the gate Harsith, and proclaim there the words that I will tell you.', pt: 'e sai ao vale do filho de Hinom, que está à entrada da Porta Harsite, e apregoa ali as palavras que eu te disser;' },
      { v: 3, en: 'Say, ‘Hear Yahweh’s word, kings of Judah, and inhabitants of Jerusalem: Yahweh of Armies, the God of Israel says, “Behold, I will bring evil on this place, which whoever hears, his ears will tingle.', pt: 'e dirás: Ouvi a palavra do Senhor, ó reis de Judá, e moradores de Jerusalém. Assim diz o Senhor dos exércitos, o Deus de Israel: Eis que trarei sobre este lugar uma calamidade tal que fará retinir os ouvidos de quem quer que dela ouvir.' },
      { v: 4, en: 'Because they have forsaken me, and have defiled this place, and have burned incense in it to other gods, that they didn’t know, they and their fathers and the kings of Judah, and have filled this place with the blood of innocents,', pt: 'Porquanto me deixaram, e profanaram este lugar, queimando nele incenso a outros deuses, que nunca conheceram, nem eles nem seus pais, nem os reis de Judá; e encheram este lugar de sangue de inocentes.' },
      { v: 5, en: 'and have built the high places of Baal, to burn their sons in the fire for burnt offerings to Baal; which I didn’t command, nor speak, which didn’t even enter into my mind:', pt: 'E edificaram os altos de Baal, para queimarem seus filhos no fogo em holocaustos a Baal; o que nunca lhes ordenei, nem falei, nem entrou no meu pensamento.' },
      { v: 6, en: 'therefore, behold, the days come,” says Yahweh, “that this place will no more be called ‘Topheth’, nor ‘The Valley of the son of Hinnom’, but ‘The valley of Slaughter’.', pt: 'Por isso eis que dias vêm, diz o Senhor, em que este lugar não se chamara mais Tofete, nem o vale do filho de Hinom, mas o vale da matança.' },
      { v: 7, en: '“‘“I will make the counsel of Judah and Jerusalem void in this place. I will cause them to fall by the sword before their enemies, and by the hand of those who seek their life. I will give their dead bodies to be food for the birds of the sky and for the animals of the earth.', pt: 'E tornarei vão o conselho de Judá e de Jerusalém neste lugar, e os farei cair à espada diante de seus inimigos e pela mão dos que procuram tirar-lhes a vida. Darei os seus cadaveres por pasto as aves do céu e aos animais da terra.' },
      { v: 8, en: 'I will make this city an astonishment and a hissing. Everyone who passes by it will be astonished and hiss because of all its plagues.', pt: 'E farei esta cidade objeto de espanto e de assobios; todo aquele que passar por ela se espantará, e assobiará, por causa de todas as suas pragas.' },
      { v: 9, en: 'I will cause them to eat the flesh of their sons and the flesh of their daughters. They will each eat the flesh of his friend in the siege and in the distress, with which their enemies, and those who seek their life, will distress them.”’', pt: 'E lhes farei comer a carne de seus filhos, e a carne de suas filhas, e comerá cada um a carne do seu próximo, no cerco e no aperto em que os apertarão os seus inimigos, e os que procuram tirar-lhes a vida.' },
      { v: 10, en: '“Then you shall break the bottle in the sight of the men who go with you,', pt: 'Então quebrarás a botija à vista dos homens que foram contigo,' },
      { v: 11, en: 'and shall tell them, ‘Yahweh of Armies says: “Even so I will break this people and this city, as one breaks a potter’s vessel, that can’t be made whole again. They will bury in Topheth, until there is no place to bury.', pt: 'e lhes dirás: Assim diz o Senhor dos exércitos: Deste modo quebrarei eu a este povo, e a esta cidade, como se quebra o vaso do oleiro, de sorte que não pode mais refazer-se; e os enterrarão em Tofete, porque não haverá outro lugar para os enterrar.' },
      { v: 12, en: 'Thus will I do to this place,” says Yahweh, “and to its inhabitants, even making this city as Topheth.', pt: 'Assim farei a este lugar e aos seus moradores, diz o Senhor; sim, porei esta cidade como Tofete.' },
      { v: 13, en: 'The houses of Jerusalem, and the houses of the kings of Judah, which are defiled, will be as the place of Topheth, even all the houses on whose roofs they have burned incense to all the army of the sky, and have poured out drink offerings to other gods.”’”', pt: 'E as casas de Jerusalém, e as casas dos reis de Judá, serão imundas como o lugar de Tofete, como também todas as casas, sobre cujos terraços queimaram incenso a todo o exército dos céus, e ofereceram libações a deuses estranhos.' },
      { v: 14, en: 'Then Jeremiah came from Topheth, where Yahweh had sent him to prophesy; and he stood in the court of Yahweh’s house, and said to all the people:', pt: 'Então voltou Jeremias de Tofete, aonde o tinha enviado o Senhor a profetizar; e pôs-se em pé no átrio da casa do Senhor, e disse a todo o povo:' },
      { v: 15, en: '“Yahweh of Armies, the God of Israel says, ‘Behold, I will bring on this city and on all its towns all the evil that I have pronounced against it, because they have made their neck stiff, that they may not hear my words.’”', pt: 'Assim diz o Senhor dos exércitos, o Deus de Israel: Eis que trarei sobre esta cidade, e sobre todas as suas cercanias, todo o mal que pronunciei contra ela, porquanto endureceram a sua cerviz, para não ouvirem as minhas palavras.' },
    ],
    20: [
      { v: 1, en: 'Now Pashhur, the son of Immer the priest, who was chief officer in Yahweh’s house, heard Jeremiah prophesying these things.', pt: 'Ora Pasur, filho de Imer, o sacerdote, que era superintendente da casa do Senhor, ouviu Jeremias profetizar estas coisas.' },
      { v: 2, en: 'Then Pashhur struck Jeremiah the prophet, and put him in the stocks that were in the upper gate of Benjamin, which was in Yahweh’s house.', pt: 'Então feriu Pasur ao profeta Jeremias, e o meteu no cepo que está na porta superior de Benjamim, na casa do Senhor.' },
      { v: 3, en: 'On the next day, Pashhur released Jeremiah out of the stocks. Then Jeremiah said to him, “Yahweh has not called your name Pashhur, but Magormissabib.', pt: 'No dia seguinte, quando Pasur o tirou do cepo Jeremias lhe disse: O Senhor não te chama Pasur, mas Magor-Missabibe.' },
      { v: 4, en: 'For Yahweh says, ‘Behold, I will make you a terror to yourself and to all your friends. They will fall by the sword of their enemies, and your eyes will see it. I will give all Judah into the hand of the king of Babylon, and he will carry them captive to Babylon, and will kill them with the sword.', pt: 'Porque assim diz o Senhor: Eis que farei de ti um terror para ti mesmo, e para todos os teus amigos. Eles cairão à espada de seus inimigos, e teus olhos o verão. Entregarei Judá todo na mão do rei de Babilônia; ele os levará cativos para Babilônia, e matá-los-á à espada.' },
      { v: 5, en: 'Moreover I will give all the riches of this city, and all its gains, and all its precious things, yes, I will give all the treasures of the kings of Judah into the hand of their enemies. They will make them captives, take them, and carry them to Babylon.', pt: 'Também entregarei todas as riquezas desta cidade, todos os seus lucros, e todas as suas coisas preciosas, sim, todos os tesouros dos reis de Judá na mão de seus inimigos, que os saquearão e, tomando-os, os levarão a Babilônia.' },
      { v: 6, en: 'You, Pashhur, and all who dwell in your house will go into captivity. You will come to Babylon, and there you will die, and there you will be buried, you, and all your friends, to whom you have prophesied falsely.’”', pt: 'E tu, Pasur, e todos os moradores da tua casa ireis para o cativeiro; e virás para Babilônia, e ali morrerás, e ali serás sepultado, tu, e todos os teus amigos, aos quais profetizaste falsamente.' },
      { v: 7, en: 'Yahweh, you have persuaded me, and I was persuaded. You are stronger than I, and have prevailed. I have become a laughing-stock all day. Everyone mocks me.', pt: 'Seduziste-me, ó Senhor, e deixei-me seduzir; mais forte foste do que eu, e prevaleceste; sirvo de escárnio o dia todo; cada um deles zomba de mim.' },
      { v: 8, en: 'For as often as I speak, I cry out; I cry, “Violence and destruction!” because Yahweh’s word has been made a reproach to me, and a derision, all day.', pt: 'Pois sempre que falo, grito, clamo: Violência e destruição; porque se tornou a palavra do Senhor um opróbrio para mim, e um ludíbrio o dia todo.' },
      { v: 9, en: 'If I say, I will not make mention of him, or speak any more in his name, then there is in my heart as it were a burning fire shut up in my bones, and I am weary with holding it in, and I can’t.', pt: 'Se eu disser: Não farei menção dele, e não falarei mais no seu nome, então há no meu coração um como fogo ardente, encerrado nos meus ossos, e estou fatigado de contê-lo, e não posso mais.' },
      { v: 10, en: 'For I have heard the defaming of many, “Terror on every side! Denounce, and we will denounce him!” say all my familiar friends, those who watch for my fall. “Perhaps he will be persuaded, and we will prevail against him, and we will take our revenge on him.”', pt: 'Pois ouço a difamação de muitos, terror por todos os lados! Denunciai-o! Denunciemo-lo! dizem todos os meus íntimos amigos, aguardando o meu manquejar; bem pode ser que se deixe enganar; então prevaleceremos contra ele e nos vingaremos dele.' },
      { v: 11, en: 'But Yahweh is with me as an awesome mighty one. Therefore my persecutors will stumble, and they won’t prevail. They will be utterly disappointed, because they have not dealt wisely, even with an everlasting dishonor which will never be forgotten.', pt: 'Mas o Senhor está comigo como um guerreiro valente; por isso tropeçarão os meus perseguidores, e não prevalecerão; ficarão muito confundidos, porque não alcançarão êxito, sim, terão uma confusão perpétua que nunca será esquecida.' },
      { v: 12, en: 'But, Yahweh of Armies, who tests the righteous, who sees the heart and the mind, let me see your vengeance on them; for to you I have revealed my cause.', pt: 'Tu pois, ó Senhor dos exércitos, que provas o justo, e vês os pensamentos e o coração, permite que eu veja a tua vingança sobre eles; porque te confiei a minha causa.' },
      { v: 13, en: 'Sing to Yahweh! Praise Yahweh, for he has delivered the soul of the needy from the hand of evildoers.', pt: 'Cantai ao Senhor, louvai ao Senhor; pois livrou a alma do necessitado da mão dos malfeitores.' },
      { v: 14, en: 'Cursed is the day in which I was born. Don’t let the day in which my mother bore me be blessed.', pt: 'Maldito o dia em que nasci; não seja bendito o dia em que minha mãe me deu à luz.' },
      { v: 15, en: 'Cursed is the man who brought news to my father, saying, “A boy is born to you,” making him very glad.', pt: 'Maldito o homem que deu as novas a meu pai, dizendo: Nasceu- te um filho, alegrando-o com isso grandemente.' },
      { v: 16, en: 'Let that man be as the cities which Yahweh overthrew, and didn’t repent. Let him hear a cry in the morning, and shouting at noontime;', pt: 'E seja esse homem como as cidades que o senhor destruiu sem piedade; e ouça ele um clamor pela manhã, e um alarido ao meio-dia.' },
      { v: 17, en: 'because he didn’t kill me from the womb. So my mother would have been my grave, and her womb always great.', pt: 'Por que não me matou na madre? assim minha mãe teria sido a minha sepultura, e teria ficado grávida perpetuamente!' },
      { v: 18, en: 'Why did I come out of the womb to see labor and sorrow, that my days should be consumed with shame?', pt: 'Por que saí da madre, para ver trabalho e tristeza, e para que se consumam na vergonha os meus dias?' },
    ],
    21: [
      { v: 1, en: 'The word which came to Jeremiah from Yahweh, when king Zedekiah sent to him Pashhur the son of Malchijah, and Zephaniah the son of Maaseiah, the priest, saying,', pt: 'A palavra que veio a Jeremias da parte do Senhor, quando o rei Zedequias lhe enviou Pasur, filho de Malquias, e Sofonias, filho de Maaséias, o sacerdote, dizendo:' },
      { v: 2, en: '“Please inquire of Yahweh for us; for Nebuchadnezzar king of Babylon makes war against us. Perhaps Yahweh will deal with us according to all his wondrous works, that he may withdraw from us.”', pt: 'Pergunta agora por nós ao Senhor, por que Nabucodonozor, rei de Babilônia, guerreia contra nós; porventura o Senhor nos tratará segundo todas as suas maravilhas, e fará que o rei se retire de nós.' },
      { v: 3, en: 'Then Jeremiah said to them, “Tell Zedekiah:', pt: 'Então Jeremias lhes respondeu: Assim direis a Zedequias:' },
      { v: 4, en: '‘Yahweh, the God of Israel says, “Behold, I will turn back the weapons of war that are in your hands, with which you fight against the king of Babylon, and against the Chaldeans who besiege you outside the walls; and I will gather them into the middle of this city.', pt: 'Assim diz o Senhor, o Deus de Israel: Eis que virarei contra vos as armas de guerra, que estão nas vossas mãos, com que vós pelejais contra o rei de Babilônia e contra os caldeus, que vos estão sitiando ao redor dos muros, e ajuntá-los-ei no meio desta cidade.' },
      { v: 5, en: 'I myself will fight against you with an outstretched hand and with a strong arm, even in anger, in wrath, and in great indignation.', pt: 'E eu mesmo pelejarei contra vós com mão estendida, e com braço forte, e em ira, e em furor, e em grande indignação.' },
      { v: 6, en: 'I will strike the inhabitants of this city, both man and animal. They will die of a great pestilence.', pt: 'E ferirei os habitantes desta cidade, tanto os homens como os animais; de grande peste morrerão.' },
      { v: 7, en: 'Afterward,” says Yahweh, “I will deliver Zedekiah king of Judah, his servants, and the people, even those who are left in this city from the pestilence, from the sword, and from the famine, into the hand of Nebuchadnezzar king of Babylon, and into the hand of their enemies, and into the hand of those who seek their life. He will strike them with the edge of the sword. He will not spare them, have pity, or have mercy.”’', pt: 'E depois disso, diz o Senhor, entregarei Zedequias, rei de Judá, e seus servos, e o povo, e os que desta cidade restarem da peste, e da espada, e da fome, sim entregá-los-ei na mão de Nabucodonozor, rei de Babilônia, e na mão de seus inimigos, e na mão dos que procuram tirar-lhes a vida; e ele os passará ao fio da espada; não os poupará, nem se compadecerá, nem terá misericordia.' },
      { v: 8, en: '“You shall say to this people, ‘Yahweh says: “Behold, I set before you the way of life and the way of death.', pt: 'E a este povo dirás: Assim diz o Senhor: Eis que ponho diante de vós o caminho da vida e o caminho da morte.' },
      { v: 9, en: 'He who remains in this city will die by the sword, by the famine, and by the pestilence; but he who goes out, and passes over to the Chaldeans who besiege you, he will live, and he will escape with his life.', pt: 'O que ficar nesta cidade há de morrer à espada, ou de fome, ou de peste; mas o que sair, e se render aos caldeus, que vos cercam, viverá, e terá a sua vida por despojo.' },
      { v: 10, en: 'For I have set my face on this city for evil, and not for good,” says Yahweh. “It will be given into the hand of the king of Babylon, and he will burn it with fire.”’', pt: 'Porque pus o meu rosto contra esta cidade para mal, e não para bem, diz o Senhor; na mão do rei de Babilônia se entregará, e ele a queimará a fogo.' },
      { v: 11, en: '“Concerning the house of the king of Judah, hear Yahweh’s word:', pt: 'E à casa do rei de Judá dirás: Ouvi a palavra do Senhor:' },
      { v: 12, en: 'House of David, Yahweh says, ‘Execute justice in the morning, and deliver him who is robbed out of the hand of the oppressor, lest my wrath go out like fire, and burn so that no one can quench it, because of the evil of your doings.', pt: 'O casa de Davi, assim diz o Senhor: Executai justiça pela manhã, e livrai o espoliado da mão do opressor, para que não saia o meu furor como fogo, e se acenda, sem que haja quem o apague, por causa da maldade de vossas ações.' },
      { v: 13, en: 'Behold, I am against you, O inhabitant of the valley, and of the rock of the plain,’ says Yahweh. ‘You that say, “Who would come down against us?” or “Who would enter into our homes?”', pt: 'Eis que eu sou contra ti, ó moradora do vale, ó rocha da campina, diz o Senhor; contra vós que dizeis: Quem descerá contra nós? ou: Quem entrará nas nossas moradas?' },
      { v: 14, en: 'I will punish you according to the fruit of your doings, says Yahweh; and I will kindle a fire in her forest, and it will devour all that is around her.’”', pt: 'E eu vos castigarei segundo o fruto das vossas ações, diz o Senhor; e no seu bosque acenderei fogo que consumirá a tudo o que está em redor dela.' },
    ],
    22: [
      { v: 1, en: 'Yahweh said, “Go down to the house of the king of Judah, and speak this word, there:', pt: 'Assim diz o Senhor: Desce à casa do rei de Judá, e anuncia ali esta palavra.' },
      { v: 2, en: '‘Hear Yahweh’s word, king of Judah, who sits on David’s throne, you, your servants, and your people who enter in by these gates.', pt: 'E dize: Ouve a palavra do Senhor, ó rei de Judá, que te assentas no trono de Davi; ouvi, tu, e os teus servos, e o teu povo, que entrais por estas portas.' },
      { v: 3, en: 'Yahweh says: “Execute justice and righteousness, and deliver him who is robbed out of the hand of the oppressor. Do no wrong. Do no violence to the foreigner, the fatherless, or the widow. Don’t shed innocent blood in this place.', pt: 'Assim diz o Senhor: Exercei o juízo e a justiça, e livrai o espoliado da mão do opressor. Não façais nenhum mal ou violencia ao estrangeiro, nem ao orfão, nem a viúva; não derrameis sangue inocente neste lugar.' },
      { v: 4, en: 'For if you do this thing indeed, then kings sitting on David’s throne will enter in by the gates of this house, riding in chariots and on horses, he, his servants, and his people.', pt: 'Pois se deveras cumprirdes esta palavra, entrarão pelas portas desta casa reis que se assentem sobre o trono de Davi, andando em carros e montados em cavalos, eles, e os seus servos, e o seu povo.' },
      { v: 5, en: 'But if you will not hear these words, I swear by myself,” says Yahweh, “that this house will become a desolation.”’”', pt: 'Mas se não derdes ouvidos a estas palavras, por mim mesmo tenho jurado, diz o Senhor, que esta casa se tornará em assolação.' },
      { v: 6, en: 'For Yahweh says concerning the house of the king of Judah: “You are Gilead to me, the head of Lebanon. Yet surely I will make you a wilderness, cities which are not inhabited.', pt: 'Pois assim diz o Senhor acerca da casa do rei de Judá: Tu és para mim Gileade, e a cabeça do Líbano; todavia certamente farei de ti um deserto e cidades desabitadas.' },
      { v: 7, en: 'I will prepare destroyers against you, everyone with his weapons, and they will cut down your choice cedars, and cast them into the fire.', pt: 'E prepararei contra ti destruidores, cada um com as suas armas; os quais cortarão os teus cedros escolhidos, e os lançarão no fogo.' },
      { v: 8, en: '“Many nations will pass by this city, and they will each ask his neighbor, ‘Why has Yahweh done this to this great city?’', pt: 'E muitas nações passarão por esta cidade, e dirá cada um ao seu companheiro: Por que procedeu o Senhor assim com esta grande cidade?' },
      { v: 9, en: 'Then they will answer, ‘Because they abandoned the covenant of Yahweh their God, worshiped other gods, and served them.’”', pt: 'Então responderão: Porque deixaram o pacto do Senhor seu Deus, e adoraram a outros deuses, e os serviram.' },
      { v: 10, en: 'Don’t weep for the dead. Don’t bemoan him; but weep bitterly for him who goes away, for he will return no more, and not see his native country.', pt: 'Não choreis o morto, nem o lastimeis; mas chorai amargamente aquele que sai; porque não voltará mais, nem verá a terra onde nasceu.' },
      { v: 11, en: 'For Yahweh says touching Shallum the son of Josiah, king of Judah, who reigned instead of Josiah his father, and who went out of this place: “He won’t return there any more.', pt: 'Pois assim diz o Senhor acerca de Salum, filho de Josias, rei de Judá, que reinou em lugar de Josias seu pai, que saiu deste lugar: Nunca mais voltará para cá,' },
      { v: 12, en: 'But in the place where they have led him captive, there will he die. He will see this land no more.”', pt: 'mas no lugar para onde o levaram cativo morrerá, e nunca mais verá esta terra.' },
      { v: 13, en: '“Woe to him who builds his house by unrighteousness, and his rooms by injustice; who uses his neighbor’s service without wages, and doesn’t give him his hire;', pt: 'Ai daquele que edifica a sua casa com iniqüidade, e os seus aposentos com injustiça; que se serve do trabalho do seu próximo sem remunerá-lo, e não lhe dá o salário;' },
      { v: 14, en: 'who says, ‘I will build myself a wide house and spacious rooms,’ and cuts out windows for himself; with a cedar ceiling, and painted with red.', pt: 'que diz: Edificarei para mim uma casa espaçosa, e aposentos largos; e que lhe abre janelas, forrando-a de cedro, e pintando-a de vermelhão.' },
      { v: 15, en: '“Should you reign, because you strive to excel in cedar? Didn’t your father eat and drink, and do justice and righteousness? Then it was well with him.', pt: 'Acaso reinarás tu, porque procuras exceder no uso de cedro? O teu pai não comeu e bebeu, e não exercitou o juízo e a justiça? Por isso lhe sucedeu bem.' },
      { v: 16, en: 'He judged the cause of the poor and needy; so it was well, then. Wasn’t this to know me?” says Yahweh.', pt: 'Julgou a causa do pobre e necessitado; então lhe sucedeu bem. Porventura não é isso conhecer-me? diz o Senhor.' },
      { v: 17, en: 'But your eyes and your heart are only for your covetousness, for shedding innocent blood, for oppression, and for doing violence.”', pt: 'Mas os teus olhos e o teu coração não atentam senão para a tua ganância, e para derramar sangue inocente, e para praticar a opressão e a violência.' },
      { v: 18, en: 'Therefore Yahweh says concerning Jehoiakim the son of Josiah, king of Judah: “They won’t lament for him, saying, ‘Ah my brother!’ or, ‘Ah sister!’ They won’t lament for him, saying ‘Ah lord!’ or, ‘Ah his glory!’', pt: 'Portanto assim diz o Senhor acerca de Jeoiaquim, filho de Josias, rei de Judá: Não o lamentarão, dizendo: Ai, meu irmão! ou: Ai, minha irmã! nem o lamentarão, dizendo: Ai, Senhor! ou: Ai, sua majestade!' },
      { v: 19, en: 'He will be buried with the burial of a donkey, drawn and cast out beyond the gates of Jerusalem.”', pt: 'Com a sepultura de jumento será sepultado, sendo arrastado e lançado fora das portas de Jerusalém.' },
      { v: 20, en: '“Go up to Lebanon, and cry. Lift up your voice in Bashan, and cry from Abarim; for all your lovers have been destroyed.', pt: 'Sobe ao Líbano, e clama, e levanta a tua voz em Basã, e clama desde Abarim; porque são destruídos todos os teus namorados.' },
      { v: 21, en: 'I spoke to you in your prosperity; but you said, ‘I will not listen.’ This has been your way from your youth, that you didn’t obey my voice.', pt: 'Falei contigo no tempo da tua prosperidade; mas tu disseste: Não escutarei. Este tem sido o teu caminho, desde a tua mocidade, o não obedeceres à minha voz.' },
      { v: 22, en: 'The wind will feed all your shepherds, and your lovers will go into captivity. Surely then you will be ashamed and confounded for all your wickedness.', pt: 'O vento apascentará todos os teus pastores, e os teus namorados irão para o cativeiro; certamente então te confundirás,' },
      { v: 23, en: 'Inhabitant of Lebanon, who makes your nest in the cedars, how greatly to be pitied you will be when pangs come on you, the pain as of a woman in travail!', pt: 'e tu, que habitas no Líbano, aninhada nos cedros, como hás de gemer, quando te vierem as dores, os ais como da que está de parto!' },
      { v: 24, en: '“As I live,” says Yahweh, “though Coniah the son of Jehoiakim king of Judah were the signet on my right hand, yet would I pluck you from there.', pt: 'Vivo eu, diz o Senhor, ainda que Conias, filho de Jeoiaquim, rei de Judá, fosse o anel do selo da minha mão direita, contudo eu dali te arrancaria;' },
      { v: 25, en: 'I would give you into the hand of those who seek your life, and into the hand of them of whom you are afraid, even into the hand of Nebuchadnezzar king of Babylon, and into the hand of the Chaldeans.', pt: 'e te entregaria na mão dos que procuram tirar-te a vida, e na mão daqueles diante dos quais tu temes, a saber, na mão de Nabucodonozor, rei de Babilônia, e na mão dos caldeus.' },
      { v: 26, en: 'I will cast you out with your mother who bore you into another country, where you were not born; and there you will die.', pt: 'A ti e a tua mãe, que te deu à luz, lançar-vos-ei para uma terra estranha, em que não nascestes, e ali morrereis.' },
      { v: 27, en: 'But to the land to which their soul longs to return, there they will not return.”', pt: 'Mas à terra para a qual eles almejam voltar, para lá não voltarão.' },
      { v: 28, en: 'Is this man Coniah a despised broken vessel? Is he a vessel in which no one delights? Why are they cast out, he and his offspring, and cast into a land which they don’t know?', pt: 'E este homem Conias algum vaso desprezado e quebrado, um vaso de que ninguém se agrada? Por que razão foram ele e a sua linhagem arremessados e arrojados para uma terra que não conhecem?' },
      { v: 29, en: 'O earth, earth, earth, hear Yahweh’s word!', pt: 'ç terra, terra, terra; ouve a palavra do Senhor.' },
      { v: 30, en: 'Yahweh says, “Record this man as childless, a man who will not prosper in his days; for no more will a man of his offspring prosper, sitting on David’s throne, and ruling in Judah.”', pt: 'Assim diz o Senhor: Escrevei que este homem fica sem filhos, homem que não prosperará nos seus dias; pois nenhum da sua linhagem prosperará para assentar-se sobre o trono de Davi e reinar daqui em diante em Judá.' },
    ],
    23: [
      { v: 1, en: '“Woe to the shepherds who destroy and scatter the sheep of my pasture!” says Yahweh.', pt: 'Ai dos pastores que destroem e dispersam as ovelhas do meu pasto, diz o Senhor.' },
      { v: 2, en: 'Therefore Yahweh, the God of Israel, says against the shepherds who feed my people: “You have scattered my flock, driven them away, and have not visited them. Behold, I will visit on you the evil of your doings,” says Yahweh.', pt: 'Portanto assim diz o Senhor, o Deus de Israel, acerca dos pastores que apascentam o meu povo: Vós dispersastes as minhas ovelhas, e as afugentastes, e não as visitastes. Eis que visitarei sobre vós a maldade das vossas ações, diz o Senhor.' },
      { v: 3, en: '“I will gather the remnant of my flock out of all the countries where I have driven them, and will bring them again to their folds; and they will be fruitful and multiply.', pt: 'E eu mesmo recolherei o resto das minhas ovelhas de todas as terras para onde as tiver afugentado, e as farei voltar aos seus apriscos; e frutificarão, e se multiplicarão.' },
      { v: 4, en: 'I will set up shepherds over them, who will feed them. They will no longer be afraid or dismayed, neither will any be lacking,” says Yahweh.', pt: 'E levantarei sobre elas pastores que as apascentem, e nunca mais temerão, nem se assombrarão, e nem uma delas faltará, diz o Senhor.' },
      { v: 5, en: '“Behold, the days come,” says Yahweh, “that I will raise to David a righteous Branch, and he will reign as king and deal wisely, and will execute justice and righteousness in the land.', pt: 'Eis que vêm dias, diz o Senhor, em que levantarei a Davi um Renovo justo; e, sendo rei, reinará e procederá sabiamente, executando o juízo e a justiça na terra.' },
      { v: 6, en: 'In his days Judah will be saved, and Israel will dwell safely. This is his name by which he will be called: Yahweh our righteousness.', pt: 'Nos seus dias Judá será salvo, e Israel habitará seguro; e este é o nome de que será chamado: O SENHOR JUSTIÇA NOSSA.' },
      { v: 7, en: '“Therefore behold, the days come,” says Yahweh, “that they will no more say, ‘As Yahweh lives, who brought up the children of Israel out of the land of Egypt;’', pt: 'Portanto, eis que vêm dias, diz o Senhor, em que nunca mais dirão: Vive o Senhor, que tirou os filhos de Israel da terra do Egito;' },
      { v: 8, en: 'but, ‘As Yahweh lives, who brought up and who led the offspring of the house of Israel out of the north country, and from all the countries where I had driven them.’ Then they will dwell in their own land.”', pt: 'mas: Vive o Senhor, que tirou e que trouxe a linhagem da casa de Israel da terra do norte, e de todas as terras para onde os tinha arrojado; e eles habitarão na sua terra.' },
      { v: 9, en: 'Concerning the prophets: My heart within me is broken. All my bones shake. I am like a drunken man, and like a man whom wine has overcome, because of Yahweh, and because of his holy words.', pt: 'Quanto aos profetas. O meu coração está quebrantado dentro de mim; todos os meus ossos estremecem; sou como um homem embriagado, e como um homem vencido do vinho, por causa do Senhor, e por causa das suas santas palavras.' },
      { v: 10, en: 'For the land is full of adulterers; for because of the curse the land mourns. The pastures of the wilderness have dried up. Their course is evil, and their might is not right;', pt: 'Pois a terra está cheia de adúlteros; por causa da maldição a terra chora, e os pastos do deserto se secam. A sua carreira é má, e a sua força não é reta.' },
      { v: 11, en: 'for both prophet and priest are profane. Yes, in my house I have found their wickedness,” says Yahweh.', pt: 'Porque tanto o profeta como o sacerdote são profanos; até na minha casa achei a sua maldade, diz o Senhor.' },
      { v: 12, en: 'Therefore their way will be to them as slippery places in the darkness. They will be driven on, and fall therein; for I will bring evil on them, even the year of their visitation,” says Yahweh.', pt: 'Portanto o seu caminho lhes será como veredas escorregadias na escuridão; serão empurrados e cairão nele; porque trarei sobre eles mal, o ano mesmo da sua punição, diz o Senhor.' },
      { v: 13, en: '“I have seen folly in the prophets of Samaria. They prophesied by Baal, and caused my people Israel to err.', pt: 'Nos profetas de Samária bem vi eu insensatez; profetizavam da parte de Baal, e faziam errar o meu povo Israel.' },
      { v: 14, en: 'In the prophets of Jerusalem I have also seen a horrible thing: they commit adultery and walk in lies. They strengthen the hands of evildoers, so that no one returns from his wickedness. They have all become to me as Sodom, and its inhabitants as Gomorrah.”', pt: 'Mas nos profetas de Jerusalém vejo uma coisa horrenda: cometem adultérios, e andam com falsidade, e fortalecem as mãos dos malfeitores, de sorte que não se convertam da sua maldade; eles têm- se tornado para mim como Sodoma, e os moradores dela como Gomorra.' },
      { v: 15, en: 'Therefore Yahweh of Armies says concerning the prophets: “Behold, I will feed them with wormwood, and make them drink the water of gall; for from the prophets of Jerusalem ungodliness has gone out into all the land.”', pt: 'Portanto assim diz o Senhor dos exércitos acerca dos profetas: Eis que lhes darei a comer losna, e lhes farei beber águas de fel; porque dos profetas de Jerusalém saiu a contaminação sobre toda a terra.' },
      { v: 16, en: 'Yahweh of Armies says, “Don’t listen to the words of the prophets who prophesy to you. They teach you vanity. They speak a vision of their own heart, and not out of the mouth of Yahweh.', pt: 'Assim diz o Senhor dos exércitos: Não deis ouvidos as palavras dos profetas, que vos profetizam a vós, ensinando-vos vaidades; falam da visão do seu coração, não da boca do Senhor.' },
      { v: 17, en: 'They say continually to those who despise me, ‘Yahweh has said, “You will have peace;”’ and to everyone who walks in the stubbornness of his own heart they say, ‘No evil will come on you.’', pt: 'Dizem continuamente aos que desprezam a palavra do Senhor: Paz tereis; e a todo o que anda na teimosia do seu coração, dizem: Não virá mal sobre vós.' },
      { v: 18, en: 'For who has stood in the council of Yahweh, that he should perceive and hear his word? Who has listened to my word, and heard it?', pt: 'Pois quem dentre eles esteve no concílio do Senhor, para que percebesse e ouvisse a sua palavra, ou quem esteve atento e escutou a sua palavra?' },
      { v: 19, en: 'Behold, Yahweh’s storm, his wrath, has gone out. Yes, a whirling storm: It will burst on the head of the wicked.', pt: 'Eis a tempestade do Senhor! A sua indignação, qual tempestade devastadora, já saiu; descarregar-se-á sobre a cabeça dos impios.' },
      { v: 20, en: 'Yahweh’s anger will not return until he has executed, and until he has performed the intents of his heart. In the latter days, you will understand it perfectly.', pt: 'Não retrocederá a ira do Senhor, até que ele tenha executado e cumprido os seus desígnios. Nos últimos dias entendereis isso claramente.' },
      { v: 21, en: 'I didn’t send these prophets, yet they ran. I didn’t speak to them, yet they prophesied.', pt: 'Não mandei esses profetas, contudo eles foram correndo; não lhes falei a eles, todavia eles profetizaram.' },
      { v: 22, en: 'But if they had stood in my council, then they would have caused my people to hear my words, and would have turned them from their evil way, and from the evil of their doings.', pt: 'Mas se tivessem assistido ao meu concílio, então teriam feito o meu povo ouvir as minhas palavras, e o teriam desviado do seu mau caminho, e da maldade das suas ações.' },
      { v: 23, en: '“Am I a God at hand,” says Yahweh, “and not a God afar off?', pt: 'Sou eu apenas Deus de perto, diz o Senhor, e não também Deus de longe?' },
      { v: 24, en: 'Can anyone hide himself in secret places so that I can’t see him?” says Yahweh. “Don’t I fill heaven and earth?” says Yahweh.', pt: 'Esconder-se-ia alguém em esconderijos, de modo que eu não o veja? diz o Senhor. Porventura não encho eu o céu e a terra? diz o Senhor.' },
      { v: 25, en: '“I have heard what the prophets have said, who prophesy lies in my name, saying, ‘I had a dream! I had a dream!’', pt: 'Tenho ouvido o que dizem esses profetas que profetizam mentiras em meu nome, dizendo: Sonhei, sonhei.' },
      { v: 26, en: 'How long will this be in the heart of the prophets who prophesy lies, even the prophets of the deceit of their own heart?', pt: 'Até quando se achará isso no coração dos profetas que profetizam mentiras, e que profetizam do engano do seu próprio coração?' },
      { v: 27, en: 'They intend to cause my people to forget my name by their dreams which they each tell his neighbor, as their fathers forgot my name because of Baal.', pt: 'Os quais cuidam fazer com que o meu povo se esqueça do meu nome pelos seus sonhos que cada um conta ao seu próximo, assim como seus pais se esqueceram do meu nome por causa de Baal.' },
      { v: 28, en: 'The prophet who has a dream, let him tell a dream; and he who has my word, let him speak my word faithfully. What is the straw to the wheat?” says Yahweh.', pt: 'O profeta que tem um sonho conte o sonho; e aquele que tem a minha palavra, fale fielmente a minha palavra. Que tem a palha com o trigo? diz o Senhor.' },
      { v: 29, en: '“Isn’t my word like fire?” says Yahweh; “and like a hammer that breaks the rock in pieces?', pt: 'Não é a minha palavra como fogo, diz o Senhor, e como um martelo que esmiúça a pedra?' },
      { v: 30, en: '“Therefore behold, I am against the prophets,” says Yahweh, “who each steal my words from his neighbor.', pt: 'Portanto, eis que eu sou contra os profetas, diz o Senhor, que furtam as minhas palavras, cada um ao seu próximo.' },
      { v: 31, en: 'Behold, I am against the prophets,” says Yahweh, “who use their tongues, and say, ‘He says.’', pt: 'Eis que eu sou contra os profetas, diz o Senhor, que usam de sua própria linguagem, e dizem: Ele disse.' },
      { v: 32, en: 'Behold, I am against those who prophesy lying dreams,” says Yahweh, “who tell them, and cause my people to err by their lies, and by their vain boasting; yet I didn’t send them or command them. They don’t profit this people at all,” says Yahweh.', pt: 'Eis que eu sou contra os que profetizam sonhos mentirosos, diz o Senhor, e os contam, e fazem errar o meu povo com as suas mentiras e com a sua vã jactância; pois eu não os enviei, nem lhes dei ordem; e eles não trazem proveito algum a este povo, diz o Senhor.' },
      { v: 33, en: '“When this people, or the prophet, or a priest, asks you, saying, ‘What is the message from Yahweh?’ Then you shall tell them, ‘“What message? I will cast you off,” says Yahweh.’', pt: 'Quando pois te perguntar este povo, ou um profeta, ou um sacerdote, dizendo: Qual é a profecia do Senhor? Então lhes dirás: Qual a profecia! que eu vos arrojarei, diz o Senhor.' },
      { v: 34, en: 'As for the prophet, the priest, and the people, who say, ‘The message from Yahweh,’ I will even punish that man and his household.', pt: 'E, quanto ao profeta, e ao sacerdote, e ao povo, que disser: A profecia do Senhor; eu castigarei aquele homem e a sua casa.' },
      { v: 35, en: 'You will say everyone to his neighbor, and everyone to his brother, ‘What has Yahweh answered?’ and, ‘What has Yahweh said?’', pt: 'Assim direis, cada um ao seu próximo, e cada um ao seu irmão: Que respondeu o Senhor? e: Que falou o Senhor?' },
      { v: 36, en: 'You will mention the message from Yahweh no more: for every man’s own word has become his message; for you have perverted the words of the living God, of Yahweh of Armies, our God.', pt: 'Mas nunca mais fareis menção da profecia do Senhor, porque a cada um lhe servirá de profecia a sua própria palavra; pois torceis as palavras do Deus vivo, do Senhor dos exércitos, o nosso Deus.' },
      { v: 37, en: 'You will say to the prophet, ‘What has Yahweh answered you?’ and, ‘What has Yahweh spoken?’', pt: 'Assim dirás ao profeta: Que te respondeu o Senhor? e: Que falou o Senhor?' },
      { v: 38, en: 'Although you say, ‘The message from Yahweh;’ therefore Yahweh says: ‘Because you say this word, “The message from Yahweh,” and I have sent to you, telling you not to say, “The message from Yahweh;”', pt: 'Se, porém, disserdes: A profecia do Senhor; assim diz o Senhor: Porque dizeis esta palavra: A profecia do Senhor, quando eu mandei dizer-vos: Não direis: A profecia do Senhor;' },
      { v: 39, en: 'therefore, behold, I will utterly forget you, and I will cast you off, and the city that I gave to you and to your fathers, away from my presence.', pt: 'por isso, eis que certamente eu vos levantarei, e vos lançarei fora da minha presença, a vós e a cidade que vos dei a vós e a vossos pais;' },
      { v: 40, en: 'I will bring an everlasting reproach on you, and a perpetual shame, which will not be forgotten.’”', pt: 'e porei sobre vós perpétuo opróbrio, e eterna vergonha, que não será esquecida.' },
    ],
    24: [
      { v: 1, en: 'Yahweh showed me, and behold, two baskets of figs were set before Yahweh’s temple, after Nebuchadnezzar king of Babylon had carried away captive Jeconiah the son of Jehoiakim, king of Judah, and the princes of Judah, with the craftsmen and smiths, from Jerusalem, and had brought them to Babylon.', pt: 'Fez-me o Senhor ver, e vi dois cestos de figos, postos diante do templo do Senhor. Sucedeu isso depois que Nabucodonozor, rei de Babilônia, levara em cativeiro a Jeconias, filho de Jeoiaquim, rei de Judá, e os príncipes de Judá, e os carpinteiros, e os ferreiros de Jerusalém, e os trouxera a Babilonia.' },
      { v: 2, en: 'One basket had very good figs, like the figs that are first-ripe; and the other basket had very bad figs, which could not be eaten, they were so bad.', pt: 'Um cesto tinha figos muito bons, como os figos temporãos; mas o outro cesto tinha figos muito ruins, que não se podiam comer, de ruins que eram.' },
      { v: 3, en: 'Then Yahweh asked me, “What do you see, Jeremiah?” I said, “Figs. The good figs are very good, and the bad are very bad, so bad that can’t be eaten.”', pt: 'E perguntou-me o Senhor: Que vês tu, Jeremias? E eu respondi: Figos; os figos bons, muito bons, e os ruins, muito ruins, que não se podem comer, de ruins que são.' },
      { v: 4, en: 'Yahweh’s word came to me, saying,', pt: 'Então veio a mim a palavra do Senhor, dizendo:' },
      { v: 5, en: '“Yahweh, the God of Israel says: ‘Like these good figs, so I will regard the captives of Judah, whom I have sent out of this place into the land of the Chaldeans, for good.', pt: 'Assim diz o Senhor, o Deus de Israel: Como a estes bons figos, assim atentarei com favor para os exilados de Judá, os quais eu enviei deste lugar para a terra dos caldeus.' },
      { v: 6, en: 'For I will set my eyes on them for good, and I will bring them again to this land. I will build them, and not pull them down. I will plant them, and not pluck them up.', pt: 'Porei os meus olhos sobre eles, para seu bem, e os farei voltar a esta terra. Edificá-los-ei, e não os demolirei; e plantá-los-ei, e não os arrancarei.' },
      { v: 7, en: 'I will give them a heart to know me, that I am Yahweh. They will be my people, and I will be their God; for they will return to me with their whole heart.', pt: 'E dar-lhes-ei coração para que me conheçam, que eu sou o Senhor; e eles serão o meu povo, e eu serei o seu Deus; pois se voltarão para mim de todo o seu coração.' },
      { v: 8, en: '“‘As the bad figs, which can’t be eaten, they are so bad,’ surely Yahweh says, ‘So I will give up Zedekiah the king of Judah, and his princes, and the remnant of Jerusalem, who remain in this land, and those who dwell in the land of Egypt.', pt: 'E como os figos ruins, que não se podem comer, de ruins que são, certamente assim diz o Senhor: Do mesmo modo entregarei Zedequias, rei de Judá, e os seus príncipes, e o resto de Jerusalém, que ficou de resto nesta terra, e os que habitam na terra do Egito;' },
      { v: 9, en: 'I will even give them up to be tossed back and forth among all the kingdoms of the earth for evil; to be a reproach and a proverb, a taunt and a curse, in all places where I will drive them.', pt: 'eu farei que sejam espetáculo horrendo, uma ofensa para todos os reinos da terra, um opróbrio e provérbio, um escárnio, e uma maldição em todos os lugares para onde os arrojarei.' },
      { v: 10, en: 'I will send the sword, the famine, and the pestilence, among them, until they are consumed from off the land that I gave to them and to their fathers.’”', pt: 'E enviarei entre eles a espada, a fome e a peste, até que sejam consumidos de sobre a terra que lhes dei a eles e a seus pais.' },
    ],
    25: [
      { v: 1, en: 'The word that came to Jeremiah concerning all the people of Judah, in the fourth year of Jehoiakim the son of Josiah, king of Judah (the same was the first year of Nebuchadnezzar king of Babylon),', pt: 'A palavra que veio a Jeremias acerca de todo o povo de Judá, no ano quarto de Jeoiaquim, filho de Josias, rei de Judá (que era o primeiro ano de Nabucodonozor, rei de Babilônia,' },
      { v: 2, en: 'which Jeremiah the prophet spoke to all the people of Judah, and to all the inhabitants of Jerusalem:', pt: 'a qual anunciou o profeta Jeremias a todo o povo de Judá, e a todos os habitantes de Jerusalém, dizendo:' },
      { v: 3, en: 'From the thirteenth year of Josiah the son of Amon, king of Judah, even to this day, these twenty-three years, Yahweh’s word has come to me, and I have spoken to you, rising up early and speaking; but you have not listened.', pt: 'Desde o ano treze de Josias, filho de Amom, rei de Judá, até o dia de hoje, período de vinte e três anos, tem vindo a mim a palavra do Senhor, e vo-la tenho anunciado, falando-vos insistentemente; mas vós não tendes escutado.' },
      { v: 4, en: 'Yahweh has sent to you all his servants the prophets, rising up early and sending them (but you have not listened or inclined your ear to hear),', pt: 'Também o Senhor vos tem enviado com insistência todos os seus servos, os profetas mas vós não escutastes, nem inclinastes os vossos ouvidos para ouvir,' },
      { v: 5, en: 'saying, “Return now everyone from his evil way, and from the evil of your doings, and dwell in the land that Yahweh has given to you and to your fathers, from of old and even forever more.', pt: 'quando vos diziam: Convertei-vos agora cada um do seu mau caminho, e da maldade das suas ações, e habitai na terra que o Senhor vos deu e a vossos pais, desde os tempos antigos e para sempre;' },
      { v: 6, en: 'Don’t go after other gods to serve them or worship them, and don’t provoke me to anger with the work of your hands; then I will do you no harm.”', pt: 'e não andeis após deuses alheios para os servirdes, e para os adorardes, nem me provoqueis à ira com a obra de vossas mãos; e não vos farei mal algum.' },
      { v: 7, en: '“Yet you have not listened to me,” says Yahweh; “that you may provoke me to anger with the work of your hands to your own hurt.”', pt: 'Todavia não me escutastes, diz o Senhor, mas me provocastes à ira com a obra de vossas mãos, para vosso mal.' },
      { v: 8, en: 'Therefore Yahweh of Armies says: “Because you have not heard my words,', pt: 'Portanto assim diz o Senhor dos exércitos: Visto que não escutastes as minhas palavras' },
      { v: 9, en: 'behold, I will send and take all the families of the north,” says Yahweh, “and I will send to Nebuchadnezzar the king of Babylon, my servant, and will bring them against this land, and against its inhabitants, and against all these nations around. I will utterly destroy them, and make them an astonishment, and a hissing, and perpetual desolations.', pt: 'eis que eu enviarei, e tomarei a todas as famílias do Norte, diz o Senhor, como também a Nabucodonozor, rei de Babilônia, meu servo, e os trarei sobre esta terra, e sobre os seus moradores, e sobre todas estas nações em redor. e os destruirei totalmente, e farei que sejam objeto de espanto, e de assobio, e de perpétuo opróbrio.' },
      { v: 10, en: 'Moreover I will take from them the voice of mirth and the voice of gladness, the voice of the bridegroom and the voice of the bride, the sound of the millstones, and the light of the lamp.', pt: 'E farei cessar dentre eles a voz de gozo e a voz de alegria, a voz do noivo e a voz da noiva, o som das mós e a luz do candeeiro.' },
      { v: 11, en: 'This whole land will be a desolation, and an astonishment; and these nations will serve the king of Babylon seventy years.', pt: 'E toda esta terra virá a ser uma desolação e um espanto; e estas nações servirão ao rei de Babilônia setenta anos.' },
      { v: 12, en: '“It will happen, when seventy years are accomplished, that I will punish the king of Babylon and that nation,” says Yahweh, “for their iniquity. I will make the land of the Chaldeans desolate forever.', pt: 'Acontecerá, porém, que quando se cumprirem os setenta anos, castigarei o rei de Babilônia, e esta nação, diz o Senhor, castigando a sua iniqüidade, e a terra dos caldeus; farei dela uma desolação perpetua.' },
      { v: 13, en: 'I will bring on that land all my words which I have pronounced against it, even all that is written in this book, which Jeremiah has prophesied against all the nations.', pt: 'E trarei sobre aquela terra todas as minhas palavras, que tenho proferido contra ela, tudo quanto está escrito neste livro, que profetizou Jeremias contra todas as nações.' },
      { v: 14, en: 'For many nations and great kings will make bondservants of them, even of them. I will recompense them according to their deeds, and according to the work of their hands.”', pt: 'Porque deles, sim, deles mesmos muitas nações e grandes reis farão escravos; assim lhes retribuirei segundo os seus feitos, e segundo as obras das suas mãos.' },
      { v: 15, en: 'For Yahweh, the God of Israel, says to me: “Take this cup of the wine of wrath from my hand, and cause all the nations to whom I send you to drink it.', pt: 'Pois assim me disse o Senhor, o Deus de Israel: Toma da minha mão este cálice do vinho de furor, e faze que dele bebam todas as nações, às quais eu te enviar.' },
      { v: 16, en: 'They will drink, and reel back and forth, and be insane, because of the sword that I will send among them.”', pt: 'Beberão, e cambalearão, e enlouquecerão, por causa da espada, que eu enviarei entre eles.' },
      { v: 17, en: 'Then took I the cup at Yahweh’s hand, and made all the nations to drink, to whom Yahweh had sent me:', pt: 'Então tomei o cálice da mão do Senhor, e fiz que bebessem todas as nações, às quais o Senhor me enviou:' },
      { v: 18, en: 'Jerusalem, and the cities of Judah, with its kings and its princes, to make them a desolation, an astonishment, a hissing, and a curse, as it is today;', pt: 'a Jerusalém, e às cidades de Judá, e aos seus reis, e aos seus principes, para fazer deles uma desolação, um espanto, um assobio e uma maldição, como hoje se ve;' },
      { v: 19, en: 'Pharaoh king of Egypt, with his servants, his princes, and all his people;', pt: 'a Faraó, rei do Egito, e a seus servos, e a seus príncipes, e a todo o seu povo;' },
      { v: 20, en: 'and all the mixed people, and all the kings of the land of Uz, all the kings of the Philistines, Ashkelon, Gaza, Ekron, and the remnant of Ashdod;', pt: 'e a todo o povo misto, e a todos os reis da terra de Uz, e a todos os reis da terra dos filisteus, a Asquelom, a Gaza, a Ecrom, e ao que resta de Asdode;' },
      { v: 21, en: 'Edom, Moab, and the children of Ammon;', pt: 'e a Edom, a Moabe, e aos filhos de Amom;' },
      { v: 22, en: 'and all the kings of Tyre, all the kings of Sidon, and the kings of the isle which is beyond the sea;', pt: 'e a todos os reis de Tiro, e a todos os reis de Sidom, e aos reis das terras dalém do mar;' },
      { v: 23, en: 'Dedan, Tema, Buz, and all who have the corners of their beard cut off;', pt: 'a Dedã, a Tema, a Buz e a todos os que cortam os -cantos da cabeleira;' },
      { v: 24, en: 'and all the kings of Arabia, all the kings of the mixed people who dwell in the wilderness;', pt: 'a todos os reis da Arábia, e a todos os reis do povo misto que habita no deserto;' },
      { v: 25, en: 'and all the kings of Zimri, all the kings of Elam, and all the kings of the Medes;', pt: 'a todos os reis de Zinri, a todos os reis de Elão, e a todos os reis da Média;' },
      { v: 26, en: 'and all the kings of the north, far and near, one with another; and all the kingdoms of the world, which are on the surface of the earth. The king of Sheshach will drink after them.', pt: 'a todos os reis do Norte, os de perto e os de longe, tanto um como o outro, e a todos os reinos da terra, que estão sobre a face da terra; e o rei de Sesaque beberá depois deles.' },
      { v: 27, en: '“You shall tell them, ‘Yahweh of Armies, the God of Israel says: “Drink, and be drunk, vomit, fall, and rise no more, because of the sword which I will send among you.”’', pt: 'Pois lhes dirás: Assim diz o Senhor dos exércitos, o Deus de Israel: Bebei, e embebedai-vos, e vomitai, e caí, e não torneis a levantar, por causa da espada que eu vos enviarei.' },
      { v: 28, en: 'It shall be, if they refuse to take the cup at your hand to drink, then you shall tell them, ‘Yahweh of Armies says: “You shall surely drink.', pt: 'Se recusarem tomar o copo da tua mão para beber, então lhes dirás: Assim diz o Senhor dos exércitos: Certamente bebereis.' },
      { v: 29, en: 'For, behold, I begin to work evil at the city which is called by my name; and should you be utterly unpunished? You will not be unpunished; for I will call for a sword on all the inhabitants of the earth, says Yahweh of Armies.”’', pt: 'Pois eis que sobre a cidade que se chama pelo meu nome, eu começo a trazer a calamidade; e haveis vós de ficar totalmente impunes? Não ficareis impunes; porque eu chamo a espada sobre todos os moradores da terra, diz o Senhor dos exércitos.' },
      { v: 30, en: '“Therefore prophesy against them all these words, and tell them, “‘Yahweh will roar from on high, and utter his voice from his holy habitation. He will mightily roar against his fold. He will give a shout, as those who tread grapes, against all the inhabitants of the earth.', pt: 'Tu pois lhes profetizarás todas estas palavras, e lhes dirás: O Senhor desde o alto bramirá, e fará ouvir a sua voz desde a sua santa morada; bramirá fortemente contra a sua habitação; dará brados, como os que pisam as uvas, contra todos os moradores da terra.' },
      { v: 31, en: 'A noise will come even to the end of the earth; for Yahweh has a controversy with the nations. He will enter into judgment with all flesh. As for the wicked, he will give them to the sword,”’ says Yahweh.”', pt: 'Chegará o estrondo até a extremidade da terra, porque o Senhor tem contenda com as nações, entrará em juízo com toda a carne; quanto aos ímpios, ele os entregará a espada, diz o Senhor.' },
      { v: 32, en: 'Yahweh of Armies says, “Behold, evil will go out from nation to nation, and a great storm will be raised up from the uttermost parts of the earth.”', pt: 'Assim diz o Senhor dos exércitos: Eis que o mal passa de nação para nação, e grande tempestade se levantará dos confins da terra.' },
      { v: 33, en: 'The slain of Yahweh will be at that day from one end of the earth even to the other end of the earth. They won’t be lamented. They won’t be gathered or buried. They will be dung on the surface of the ground.', pt: 'E os mortos do Senhor naquele dia se encontrarão desde uma extremidade da terra até a outra; não serão pranteados, nem recolhidos, nem sepultados; mas serão como esterco sobre a superfície da terra.' },
      { v: 34, en: 'Wail, you shepherds, and cry. Wallow in dust, you leader of the flock; for the days of your slaughter and of your dispersions have fully come, and you will fall like fine pottery.', pt: 'Uivai, pastores, e clamai; e revolvei-vos na cinza, vós que sois os principais do rebanho; pois já se cumpriram os vossos dias para serdes mortos, e eu vos despedaçarei, e vós então caireis como carneiros escolhidos.' },
      { v: 35, en: 'The shepherds will have no way to flee. The leader of the flock will have no escape.', pt: 'E não haverá refúgio para os pastores, nem lugar para onde escaparem os principais do rebanho.' },
      { v: 36, en: 'A voice of the cry of the shepherds, and the wailing of the leader of the flock, for Yahweh destroys their pasture.', pt: 'Eis a voz de grito dos pastores, o uivo dos principais do rebanho; porque o Senhor está devastando o pasto deles.' },
      { v: 37, en: 'The peaceful folds are brought to silence because of the fierce anger of Yahweh.', pt: 'E as suas malhadas pacíficas são reduzidas a silêncio, por causa do furor da ira do Senhor.' },
      { v: 38, en: 'He has left his covert, as the lion; for their land has become an astonishment because of the fierceness of the oppression, and because of his fierce anger.', pt: 'Deixou como leão o seu covil; porque a sua terra se tornou em desolação, por causa do furor do opressor, e por causa do furor da sua ira.' },
    ],
    26: [
      { v: 1, en: 'In the beginning of the reign of Jehoiakim the son of Josiah, king of Judah, this word came from Yahweh:', pt: 'No princípio do reino de Jeoiaquim, filho de Josias, rei de Judá, veio da parte do Senhor esta palavra, dizendo:' },
      { v: 2, en: '“Yahweh says: ‘Stand in the court of Yahweh’s house, and speak to all the cities of Judah, which come to worship in Yahweh’s house, all the words that I command you to speak to them. Don’t omit a word.', pt: 'Assim diz o Senhor: Põe-te no átrio da casa do Senhor e dize a todas as cidades de Judá que vêm adorar na casa do Senhor, todas as palavras que te mando que lhes fales; não omitas uma só palavra.' },
      { v: 3, en: 'It may be they will listen, and every man turn from his evil way; that I may relent from the evil which I intend to do to them because of the evil of their doings.’', pt: 'Bem pode ser que ouçam, e se convertam cada um do seu mau caminho, para que eu desista do mal que intento fazer-lhes por causa da maldade das suas ações.' },
      { v: 4, en: 'You shall tell them, “Yahweh says: ‘If you will not listen to me, to walk in my law, which I have set before you,', pt: 'Dize-lhes pois: Assim diz o Senhor: Se não me derdes ouvidos para andardes na minha lei, que pus diante de vós,' },
      { v: 5, en: 'to listen to the words of my servants the prophets, whom I send to you, even rising up early and sending them, but you have not listened;', pt: 'e para ouvirdes as palavras dos meus servos, os profetas, que eu com insistência vos envio, mas não ouvistes;' },
      { v: 6, en: 'then I will make this house like Shiloh, and will make this city a curse to all the nations of the earth.”’”', pt: 'então farei que esta casa seja como Siló, e farei desta cidade uma maldição para todas as nações da terra.' },
      { v: 7, en: 'The priests and the prophets and all the people heard Jeremiah speaking these words in Yahweh’s house.', pt: 'E ouviram os sacerdotes, e os profetas, e todo o povo, a Jeremias, anunciando estas palavras na casa do Senhor.' },
      { v: 8, en: 'When Jeremiah had finished speaking all that Yahweh had commanded him to speak to all the people, the priests and the prophets and all the people seized him, saying, “You shall surely die!', pt: 'Tendo Jeremias acabado de dizer tudo quanto o Senhor lhe havia ordenado que dissesse a todo o povo, pegaram nele os sacerdotes, e os profetas, e todo o povo, dizendo: Certamente morrerás.' },
      { v: 9, en: 'Why have you prophesied in Yahweh’s name, saying, ‘This house will be like Shiloh, and this city will be desolate, without inhabitant?’” All the people were crowded around Jeremiah in Yahweh’s house.', pt: 'Por que profetizaste em nome do Senhor, dizendo: Será como Siló esta casa, e esta cidade ficará assolada e desabitada? E ajuntou-se todo o povo contra Jeremias, na casa do Senhor.' },
      { v: 10, en: 'When the princes of Judah heard these things, they came up from the king’s house to Yahweh’s house; and they sat in the entry of the new gate of Yahweh’s house.', pt: 'Quando os príncipes de Judá ouviram estas coisas, subiram da casa do rei à casa do Senhor, e se assentaram à entrada da porta nova do Senhor.' },
      { v: 11, en: 'Then the priests and the prophets spoke to the princes and to all the people, saying, “This man is worthy of death; for he has prophesied against this city, as you have heard with your ears.”', pt: 'Então falaram os sacerdotes e os profetas aos príncipes e a todo povo, dizendo: Este homem é réu de morte, porque profetizou contra esta cidade, como ouvistes com os vossos proprios ouvidos.' },
      { v: 12, en: 'Then Jeremiah spoke to all the princes and to all the people, saying, “Yahweh sent me to prophesy against this house and against this city all the words that you have heard.', pt: 'E falou Jeremias a todos os príncipes e a todo o povo, dizendo: O Senhor enviou-me a profetizar contra esta casa, e contra esta cidade, todas as palavras que ouvistes.' },
      { v: 13, en: 'Now therefore amend your ways and your doings, and obey Yahweh your God’s voice; then Yahweh will relent from the evil that he has pronounced against you.', pt: 'Agora, pois, melhorai os vossos caminhos e as vossas ações, e ouvi a voz do Senhor vosso Deus, e o Senhor desistirá do mal que falou contra vós.' },
      { v: 14, en: 'But as for me, behold, I am in your hand. Do with me what is good and right in your eyes.', pt: 'Quanto a mim, eis que estou nas vossas mãos; fazei de mim conforme o que for bom e reto aos vossos olhos.' },
      { v: 15, en: 'Only know for certain that, if you put me to death, you will bring innocent blood on yourselves, on this city, and on its inhabitants; for in truth Yahweh has sent me to you to speak all these words in your ears.”', pt: 'Sabei, porém, com certeza que, se me matardes a mim, trareis sangue inocente sobre vós, e sobre esta cidade, e sobre os seus habitantes; porque, na verdade, o Senhor me enviou a vós, para dizer aos vossos ouvidos todas estas palavras.' },
      { v: 16, en: 'Then the princes and all the people said to the priests and to the prophets: “This man is not worthy of death; for he has spoken to us in the name of Yahweh our God.”', pt: 'Então disseram os príncipes e todo o povo aos sacerdotes e aos profetas: Este homem não é réu de morte, porque em nome do Senhor, nosso Deus, nos falou.' },
      { v: 17, en: 'Then certain of the elders of the land rose up, and spoke to all the assembly of the people, saying,', pt: 'Também se levantaram alguns dos anciãos da terra, e falaram a toda a assembléia do povo, dizendo:' },
      { v: 18, en: '“Micah the Morashtite prophesied in the days of Hezekiah king of Judah; and he spoke to all the people of Judah, saying, ‘Yahweh of Armies says: “‘Zion will be plowed as a field, and Jerusalem will become heaps, and the mountain of the house as the high places of a forest.’', pt: 'Miquéias, o morastita, profetizou nos dias de Ezequias, rei de Judá, e falou a todo o povo de Judá, dizendo: Assim diz o Senhor dos exércitos: Sião será lavrada como um campo, e Jerusalém se tornará em montões de ruínas, e o monte desta casa como os altos de um bosque.' },
      { v: 19, en: 'Did Hezekiah king of Judah and all Judah put him to death? Didn’t he fear Yahweh, and entreat the favor of Yahweh, and Yahweh relented of the disaster which he had pronounced against them? We would commit great evil against our own souls that way!”', pt: 'Mataram-no, porventura, Ezequias, rei de Judá, e todo o Judá? Antes não temeu este ao Senhor, e não implorou o favor do Senhor? e não se arrependeu o Senhor do mal que falara contra eles? Mas nós estamos fazendo um grande mal contra as nossas almas.' },
      { v: 20, en: 'There was also a man who prophesied in Yahweh’s name, Uriah the son of Shemaiah of Kiriath Jearim; and he prophesied against this city and against this land according to all the words of Jeremiah.', pt: 'Também houve outro homem que profetizava em nome do Senhor: Urias, filho de Semaías, de Quiriate-Jearim, o qual profetizou contra esta cidade, e contra esta terra, conforme todas as palavras de Jeremias;' },
      { v: 21, en: 'When Jehoiakim the king, with all his mighty men and all the princes heard his words, the king sought to put him to death; but when Uriah heard it, he was afraid, and fled, and went into Egypt.', pt: 'e quando o rei Jeoiaquim, e todos os seus valentes, e todos os príncipes, ouviram as palavras dele, procurou o rei matá-lo; mas quando Urias o ouviu, temeu, e fugiu, e foi para o Egito;' },
      { v: 22, en: 'Then Jehoiakim the king sent men into Egypt, Elnathan the son of Achbor, and certain men with him, into Egypt;', pt: 'mas o rei Jeoiaquim enviou ao Egito certos homens; Elnatã, filho de Acbor, e outros com ele,' },
      { v: 23, en: 'and they fetched Uriah out of Egypt, and brought him to Jehoiakim the king, who killed him with the sword, and cast his dead body into the graves of the common people.', pt: 'os quais tiraram a Urias do Egito, e o trouxeram ao rei Jeoiaquim, que o matou à espada, e lançou o seu cadáver nas sepulturas da plebe.' },
      { v: 24, en: 'But the hand of Ahikam the son of Shaphan was with Jeremiah, so that they didn’t give him into the hand of the people to put him to death.', pt: 'Porém Aicão, filho de Safã, deu apoio a Jeremias, de sorte que não foi entregue na mão do povo, para ser morto.' },
    ],
    27: [
      { v: 1, en: 'In the beginning of the reign of Jehoiakim the son of Josiah, king of Judah, this word came to Jeremiah from Yahweh, saying,', pt: 'No princípio do reinado de Zedequias, filho de Josias, rei de Judá, veio esta palavra a Jeremias da parte do Senhor, dizendo:' },
      { v: 2, en: 'Yahweh says to me: “Make bonds and bars, and put them on your neck.', pt: 'Assim me disse o Senhor: Faze-te brochas e canzis e põe-nos ao teu pescoço.' },
      { v: 3, en: 'Then send them to the king of Edom, to the king of Moab, to the king of the children of Ammon, to the king of Tyre, and to the king of Sidon, by the hand of the messengers who come to Jerusalem to Zedekiah king of Judah.', pt: 'Depois envia-os ao rei de Edom, e ao rei de Moabe, e ao rei dos filhos de Amom, e ao rei de Tiro, e ao rei de Sidom, pela mão dos mensageiros que são vindos a Jerusalém a ter com zedequias, rei de Judá;' },
      { v: 4, en: 'Give them a command to their masters, saying, ‘Yahweh of Armies, the God of Israel says, “You shall tell your masters:', pt: 'e lhes darás uma mensageem para seus senhores, dizendo: Assim diz o Senhor dos exércitos, o Deus de Israel: Assim direis a vossos senhores:' },
      { v: 5, en: '‘I have made the earth, the men, and the animals that are on the surface of the earth by my great power and by my outstretched arm. I give it to whom it seems right to me.', pt: 'Sou eu que, com o meu grande poder e o meu braço estendido, fiz a terra com os homens e os animais que estão sobre a face da terra; e a dou a quem me apraz.' },
      { v: 6, en: 'Now I have given all these lands into the hand of Nebuchadnezzar the king of Babylon, my servant. I have also given the animals of the field to him to serve him.', pt: 'E agora eu entreguei todas estas terras na mão de Nabucodonozor, rei de Babilônia, meu servo; e ainda até os animais do campo lhe dei, para que o sirvam.' },
      { v: 7, en: 'All the nations will serve him, his son, and his son’s son, until the time of his own land comes. Then many nations and great kings will make him their bondservant.', pt: 'Todas as nações o servirão a ele, e a seu filho, e ao filho de seu filho, até que venha o tempo da sua própria terra; e então muitas nações e grandes reis se servirão dele.' },
      { v: 8, en: '“‘“‘It will happen that I will punish the nation and the kingdom which will not serve the same Nebuchadnezzar king of Babylon, and that will not put their neck under the yoke of the king of Babylon,’ says Yahweh, ‘with the sword, with famine, and with pestilence, until I have consumed them by his hand.', pt: 'A nação e o reino que não servirem a Nabucodonozor, rei de Babilônia, e que não puserem o seu pescoço debaixo do jugo do rei de Babilônia, punirei com a espada, com a fome, e com a peste a essa nação, diz o Senhor, até que eu os tenha consumido pela mão dele.' },
      { v: 9, en: 'But as for you, don’t listen to your prophets, to your diviners, to your dreams, to your soothsayers, or to your sorcerers, who speak to you, saying, “You shall not serve the king of Babylon;”', pt: 'Não deis ouvidos, pois, aos vossos profetas, e aos vossos adivinhadores, e aos vossos sonhos, e aos vossos agoureiros, e aos vossos encantadores, que vos dizem: Não servireis o rei de Babilônia;' },
      { v: 10, en: 'for they prophesy a lie to you, to remove you far from your land, so that I would drive you out, and you would perish.', pt: 'porque vos profetizam a mentira, para serdes removidos para longe da vossa terra, e eu vos expulsarei dela, e vós perecereis.' },
      { v: 11, en: 'But the nation that brings their neck under the yoke of the king of Babylon and serves him, that nation I will let remain in their own land,’ says Yahweh; ‘and they will till it and dwell in it.’”’”', pt: 'Mas a nação que meter o seu pescoço sob o jugo do rei de Babilônia, e o servir, eu a deixarei na sua terra, diz o Senhor; e lavrá-la-á e habitará nela.' },
      { v: 12, en: 'I spoke to Zedekiah king of Judah according to all these words, saying, “Bring your necks under the yoke of the king of Babylon, and serve him and his people, and live.', pt: 'E falei com Zedequias, rei de Judá, conforme todas estas palavras: Metei os vossos pescoços no jugo do rei de Babilônia, e servi-o, a ele e ao seu povo, e vivei.' },
      { v: 13, en: 'Why will you die, you and your people, by the sword, by the famine, and by the pestilence, as Yahweh has spoken concerning the nation that will not serve the king of Babylon?', pt: 'Por que morrereis tu e o teu povo, à espada, de fome, e de peste, como o Senhor disse acerca da nação que não servir ao rei de Babilônia?' },
      { v: 14, en: 'Don’t listen to the words of the prophets who speak to you, saying, ‘You shall not serve the king of Babylon;’ for they prophesy a lie to you.', pt: 'Não deis ouvidos às palavras dos profetas que vos dizem: Não servireis ao rei de Babilônia; porque vos profetizam a mentira.' },
      { v: 15, en: 'For I have not sent them,” says Yahweh, “but they prophesy falsely in my name; that I may drive you out, and that you may perish, you, and the prophets who prophesy to you.”', pt: 'Pois não os enviei, diz o Senhor, mas eles profetizam falsamente em meu nome; para que eu vos lance fora, e venhais a perecer, vós e os profetas que vos profetizam.' },
      { v: 16, en: 'Also I spoke to the priests and to all this people, saying, Yahweh says, “Don’t listen to the words of your prophets who prophesy to you, saying, ‘Behold, the vessels of Yahweh’s house will now shortly be brought again from Babylon;’ for they prophesy a lie to you.', pt: 'Então falei aos sacerdotes, e a todo este povo, dizendo: Assim diz o Senhor: Não deis ouvidos às palavras dos vossos profetas, que vos profetizam dizendo: Eis que os utensílios da casa do senhor cedo voltarão de Babilônia; pois eles vos profetizam a mentira.' },
      { v: 17, en: 'Don’t listen to them. Serve the king of Babylon, and live. Why should this city become a desolation?', pt: 'Não lhes deis ouvidos; servi ao rei de Babilônia, e vivei. Por que se tornaria esta cidade em assolação?' },
      { v: 18, en: 'But if they are prophets, and if Yahweh’s word is with them, let them now make intercession to Yahweh of Armies, that the vessels which are left in Yahweh’s house, in the house of the king of Judah, and at Jerusalem, don’t go to Babylon.', pt: 'Se, porém, são profetas, e se está com eles a palavra do Senhor, intercedam agora junto ao Senhor dos exércitos, para que os utensílios que ficaram na casa do Senhor, e na casa do rei de Judá, e em Jerusalém, não vão para Babilônia.' },
      { v: 19, en: 'For Yahweh of Armies says concerning the pillars, concerning the sea, concerning the bases, and concerning the rest of the vessels that are left in this city,', pt: 'Pois assim diz o Senhor dos exércitos acerca das colunas, e do mar, e das bases, e dos demais utensílios que ficaram na cidade,' },
      { v: 20, en: 'which Nebuchadnezzar king of Babylon didn’t take when he carried away captive Jeconiah the son of Jehoiakim, king of Judah, from Jerusalem to Babylon, and all the nobles of Judah and Jerusalem;', pt: 'os quais Nabucodonozor, rei de Babilônia, não levou, quando transportou de Jerusalém para Babilônia a Jeconias, filho de Jeoiaquim, rei de Judá, como também a todos os nobres de Judá e de Jerusalém;' },
      { v: 21, en: 'yes, Yahweh of Armies, the God of Israel, says concerning the vessels that are left in Yahweh’s house, and in the house of the king of Judah, and at Jerusalem:', pt: 'assim pois diz o Senhor dos exércitos, o Deus de Israel, acerca dos utensílios que ficaram na casa do Senhor, e na casa do rei de Judá, e em Jerusalém:' },
      { v: 22, en: '‘They will be carried to Babylon, and there they will be, until the day that I visit them,’ says Yahweh; ‘then I will bring them up, and restore them to this place.’”', pt: 'Para Babilônia serão levados, e ali ficarão até o dia em que eu os visitar, diz o Senhor; então os farei subir, e os restituirei a este lugar.' },
    ],
    28: [
      { v: 1, en: 'That same year, in the beginning of the reign of Zedekiah king of Judah, in the fourth year, in the fifth month, Hananiah the son of Azzur, the prophet, who was of Gibeon, spoke to me in Yahweh’s house, in the presence of the priests and of all the people, saying,', pt: 'E sucedeu no mesmo ano, no princípio do reinado de Zedequias, rei de Judá, no ano quarto, no mês quinto, que Hananias, filho de Azur, o profeta de Gibeão, me falou, na casa do Senhor, na presença dos sacerdotes e de todo o povo dizendo:' },
      { v: 2, en: '“Yahweh of Armies, the God of Israel, says, ‘I have broken the yoke of the king of Babylon.', pt: 'Assim fala o Senhor dos exércitos, o Deus de Israel, dizendo: Eu quebrarei o jugo do rei de Babilônia.' },
      { v: 3, en: 'Within two full years will I bring again into this place all the vessels of Yahweh’s house, that Nebuchadnezzar king of Babylon took away from this place, and carried to Babylon.', pt: 'Dentro de dois anos, eu tornarei a trazer a este lugar todos os utensílios da casa do Senhor, que deste lugar tomou Nabucodonozor, rei de Babilônia, levando-os para Babilônia.' },
      { v: 4, en: 'I will bring again to this place Jeconiah the son of Jehoiakim, king of Judah, with all the captives of Judah, who went to Babylon,’ says Yahweh; ‘for I will break the yoke of the king of Babylon.’”', pt: 'Também a Jeconias, filho de Jeoiaquim rei de Judá, e a todos os do cativeiro de, Judá, que entraram em Babilônia, eu os tornarei a trazer a este lugar, diz o Senhor; porque hei de quebrar o jugo do rei de Babilônia.' },
      { v: 5, en: 'Then the prophet Jeremiah said to the prophet Hananiah in the presence of the priests, and in the presence of all the people who stood in Yahweh’s house,', pt: 'Então falou o profeta Jeremias ao profeta Hananias, na presença dos sacerdotes, e na presença de todo o povo que estava na casa do Senhor.' },
      { v: 6, en: 'even the prophet Jeremiah said, “Amen! May Yahweh do so. May Yahweh perform your words which you have prophesied, to bring again the vessels of Yahweh’s house, and all those who are captives, from Babylon to this place.', pt: 'Disse pois Jeremias, o profeta: Amém! assim faça o Senhor; cumpra o Senhor as tuas palavras, que profetizaste, e torne ele a trazer os utensílios da casa do Senhor, e todos os do cativeiro, de Babilônia para este lugar.' },
      { v: 7, en: 'Nevertheless listen now to this word that I speak in your ears, and in the ears of all the people:', pt: 'Mas ouve agora esta palavra, que eu falo aos teus ouvidos e aos ouvidos de todo o povo:' },
      { v: 8, en: 'The prophets who have been before me and before you of old prophesied against many countries, and against great kingdoms, of war, of evil, and of pestilence.', pt: 'Os profetas que houve antes de mim e antes de ti, desde a antigüidade, profetizaram contra muitos países e contra grandes reinos, acerca de guerra, de fome e de peste.' },
      { v: 9, en: 'The prophet who prophesies of peace, when the word of the prophet happens, then the prophet will be known, that Yahweh has truly sent him.”', pt: 'Quanto ao profeta que profetuar de paz, quando se cumprir a palavra desse profeta, então será conhecido que o Senhor na verdade enviou o profeta.' },
      { v: 10, en: 'Then Hananiah the prophet took the bar from off the prophet Jeremiah’s neck, and broke it.', pt: 'Então o profeta Hananias tomou o canzil do pescoço do profeta Jeremias e o quebrou.' },
      { v: 11, en: 'Hananiah spoke in the presence of all the people, saying, “Yahweh says: ‘Even so I will break the yoke of Nebuchadnezzar king of Babylon from off the neck of all the nations within two full years.’” Then the prophet Jeremiah went his way.', pt: 'E falou Hananias na presença de todo o povo, dizendo: Isto diz o Senhor: Assim dentro de dois anos quebrarei o jugo de Nabucodonozor, rei de Babilônia, de sobre o pescoço de todas as nações. E Jeremias, o profeta, se foi seu caminho.' },
      { v: 12, en: 'Then Yahweh’s word came to Jeremiah, after Hananiah the prophet had broken the bar from off the neck of the prophet Jeremiah, saying,', pt: 'Então veio a palavra do Senhor a Jeremias, depois de ter o profeta Hananias quebrado o jugo de sobre o pescoço do profeta Jeremias, dizendo:' },
      { v: 13, en: '“Go, and tell Hananiah, saying, ‘Yahweh says, “You have broken the bars of wood, but you have made in their place bars of iron.”', pt: 'Vai, e fala a Hananias, dizendo: Assim diz o Senhor: Jugos de madeira quebraste, mas em vez deles farei jugos de ferro' },
      { v: 14, en: 'For Yahweh of Armies, the God of Israel says, “I have put a yoke of iron on the neck of all these nations, that they may serve Nebuchadnezzar king of Babylon; and they will serve him. I have also given him the animals of the field.”’”', pt: 'Pois assim diz o Senhor dos exércitos o Deus de Israel Jugo de ferro pus sobre o, pescoço de todas estas nações, para servirem a Nabucodonozor, rei de Babilônia, e o servirão; e até os animais do campo lhe dei.' },
      { v: 15, en: 'Then the prophet Jeremiah said to Hananiah the prophet, “Listen, Hananiah! Yahweh has not sent you, but you make this people trust in a lie.', pt: 'Então disse o profeta Jeremias ao profeta Hananias: Ouve agora, Hananias: O Senhor não te enviou, mas tu fazes que este povo confie numa mentira.' },
      { v: 16, en: 'Therefore Yahweh says, ‘Behold, I will send you away from off the surface of the earth. This year you will die, because you have spoken rebellion against Yahweh.’”', pt: 'Pelo que assim diz o Senhor: Eis que te lançarei de sobre a face da terra. Este ano morrerás, porque pregaste rebelião contra o Senhor.' },
      { v: 17, en: 'So Hananiah the prophet died the same year in the seventh month.', pt: 'Morreu, pois, Hananias, o profeta, no mesmo ano, no sétimo mês.' },
    ],
    29: [
      { v: 1, en: 'Now these are the words of the letter that Jeremiah the prophet sent from Jerusalem to the residue of the elders of the captivity, and to the priests, to the prophets, and to all the people whom Nebuchadnezzar had carried away captive from Jerusalem to Babylon,', pt: 'Ora, são estas as palavras da carta que Jeremias, o profeta, enviou de Jerusalém, aos que restavam dos anciãos do cativeiro, como também aos sacerdotes, e aos profetas, e a todo o povo, que Nabucodonozor levara cativos de Jerusalém para Babilônia,' },
      { v: 2, en: '(after Jeconiah the king, the queen mother, the eunuchs, the princes of Judah and Jerusalem, the craftsmen, and the smiths, had departed from Jerusalem),', pt: 'depois de terem saído de Jerusalém o rei Jeconias, e a rainha-mãe, e os eunucos, e os príncipes de Judá e Jerusalém e os artífices e os ferreiros.' },
      { v: 3, en: 'by the hand of Elasah the son of Shaphan, and Gemariah the son of Hilkiah, (whom Zedekiah king of Judah sent to Babylon to Nebuchadnezzar king of Babylon). It said:', pt: 'Veio por mão de Elasa, filho de Safã, e de Gemarias, filho de Hilquias, os quais Zedequias, rei de Judá, enviou a Babilônia, a Nabucodonozor, rei de Babilônia; eis as palavras da carta:' },
      { v: 4, en: 'Yahweh of Armies, the God of Israel, says to all the captives whom I have caused to be carried away captive from Jerusalem to Babylon:', pt: 'Assim diz o Senhor dos exércitos, o Deus de Israel, a todos os do cativeiro, que eu fiz levar cativos de Jerusalém para Babilônia:' },
      { v: 5, en: '“Build houses and dwell in them. Plant gardens and eat their fruit.', pt: 'Edificai casas e habitai-as; plantai jardins, e comei o seu fruto.' },
      { v: 6, en: 'Take wives and father sons and daughters. Take wives for your sons, and give your daughters to husbands, that they may bear sons and daughters. Multiply there, and don’t be diminished.', pt: 'Tomai mulheres e gerai filhos e filhas; também tomai mulheres para vossos filhos, e dai vossas filhas a maridos, para que tenham filhos e filhas; assim multiplicai-vos ali, e não vos diminuais.' },
      { v: 7, en: 'Seek the peace of the city where I have caused you to be carried away captive, and pray to Yahweh for it; for in its peace you will have peace.”', pt: 'E procurai a paz da cidade, para a qual fiz que fôsseis levados cativos, e orai por ela ao Senhor: porque na sua paz vós tereis paz.' },
      { v: 8, en: 'For Yahweh of Armies, the God of Israel says: “Don’t let your prophets who are among you and your diviners deceive you. Don’t listen to your dreams which you cause to be dreamed.', pt: 'Pois assim diz o Senhor dos exércitos, o Deus de Israel: Não vos enganem os vossos profetas que estão no meio de vós, nem os vossos adivinhadores; nem deis ouvidos aos vossos sonhos, que vós sonhais;' },
      { v: 9, en: 'For they prophesy falsely to you in my name. I have not sent them,” says Yahweh.', pt: 'porque eles vos profetizam falsamente em meu nome; não os enviei, diz o Senhor.' },
      { v: 10, en: 'For Yahweh says, “After seventy years are accomplished for Babylon, I will visit you and perform my good word toward you, in causing you to return to this place.', pt: 'Porque assim diz o Senhor: Certamente que passados setenta anos em Babilônia, eu vos visitarei, e cumprirei sobre vós a minha boa palavra, tornando a trazer-vos a este lugar.' },
      { v: 11, en: 'For I know the thoughts that I think toward you,” says Yahweh, “thoughts of peace, and not of evil, to give you hope and a future.', pt: 'Pois eu bem sei os planos que estou projetando para vós, diz o Senhor; planos de paz, e não de mal, para vos dar um futuro e uma esperança.' },
      { v: 12, en: 'You shall call on me, and you shall go and pray to me, and I will listen to you.', pt: 'Então me invocareis, e ireis e orareis a mim, e eu vos ouvirei.' },
      { v: 13, en: 'You shall seek me, and find me, when you search for me with all your heart.', pt: 'Buscar-me-eis, e me achareis, quando me buscardes de todo o vosso coração.' },
      { v: 14, en: 'I will be found by you,” says Yahweh, “and I will turn again your captivity, and I will gather you from all the nations, and from all the places where I have driven you, says Yahweh. I will bring you again to the place from where I caused you to be carried away captive.”', pt: 'E serei achado de vós, diz o Senhor, e farei voltar os vossos cativos, e congregarvos-ei de todas as nações, e de todos os lugares para onde vos lancei, diz o Senhor; e tornarei a trazer-vos ao lugar de onde vos transportei.' },
      { v: 15, en: 'Because you have said, “Yahweh has raised us up prophets in Babylon;”', pt: 'Porque dizeis: O Senhor nos levantou profetas em Babilônia;' },
      { v: 16, en: 'Yahweh says concerning the king who sits on David’s throne, and concerning all the people who dwell in this city, your brothers who haven’t gone with you into captivity;', pt: 'portanto assim diz o Senhor a respeito do rei que se assenta no trono de Davi, e de todo o povo que habita nesta cidade, vossos irmãos, que não saíram convosco para o cativeiro;' },
      { v: 17, en: 'Yahweh of Armies says: “Behold, I will send on them the sword, the famine, and the pestilence, and will make them like rotten figs that can’t be eaten, they are so bad.', pt: 'assim diz o Senhor dos exércitos: Eis que enviarei entre eles a espada, a fome e a peste e fá-los-ei como a figos péssimos, que não se podem comer, de ruins que são.' },
      { v: 18, en: 'I will pursue after them with the sword, with the famine, and with the pestilence, and will deliver them to be tossed back and forth among all the kingdoms of the earth, to be an object of horror, an astonishment, a hissing, and a reproach among all the nations where I have driven them,', pt: 'E persegui-los-ei com a espada, com a fome e com a peste; farei que sejam um espetáculo de terror para todos os reinos da terra, e para serem um motivo de execração, de espanto, de assobio, e de opróbrio entre todas as nações para onde os tiver lançado,' },
      { v: 19, en: 'because they have not listened to my words,” says Yahweh, “with which I sent to them my servants the prophets, rising up early and sending them; but you would not hear,” says Yahweh.', pt: 'porque não deram ouvidos às minhas palavras, diz o Senhor, as quais lhes enviei com insistência pelos meus servos, os profetas; mas vós não escutastes, diz o Senhor.' },
      { v: 20, en: 'Hear therefore Yahweh’s word, all you captives, whom I have sent away from Jerusalem to Babylon.', pt: 'Ouvi, pois, a palavra do Senhor, vós todos os do cativeiro que enviei de Jerusalém para Babilônia.' },
      { v: 21, en: 'Yahweh of Armies, the God of Israel, says concerning Ahab the son of Kolaiah, and concerning Zedekiah the son of Maaseiah, who prophesy a lie to you in my name: “Behold, I will deliver them into the hand of Nebuchadnezzar king of Babylon; and he will kill them before your eyes.', pt: 'Assim diz o Senhor dos exércitos, o Deus de Israel, acerca de Acabe, filho de Colaías, e de Zedequias, filho de Maaséias, que vos profetizam falsamente em meu nome: Eis que os entregarei na mão de Nabucodonozor, rei de Babilônia, e ele os matará diante dos vossos olhos.' },
      { v: 22, en: 'A curse will be taken up about them by all the captives of Judah who are in Babylon, saying, ‘Yahweh make you like Zedekiah and like Ahab, whom the king of Babylon roasted in the fire;’', pt: 'E por causa deles será formulada uma maldição por todos os exilados de Judá que estão em Babilônia, dizendo: O Senhor te faça como a Zedequias, e como a Acabe, os quais o rei de Babilônia assou no fogo;' },
      { v: 23, en: 'because they have done foolish things in Israel, and have committed adultery with their neighbors’ wives, and have spoken words in my name falsely, which I didn’t command them. I am he who knows, and am witness,” says Yahweh.', pt: 'porque fizeram insensatez em Israel, cometendo adultério com as mulheres de seus próximos, e anunciando falsamente em meu nome palavras que não lhes mandei. Eu o sei, e sou testemunha disso, diz o Senhor.' },
      { v: 24, en: 'Concerning Shemaiah the Nehelamite you shall speak, saying,', pt: 'E a Semaías, o neelamita, falarás, dizendo:' },
      { v: 25, en: '“Yahweh of Armies, the God of Israel, says, ‘Because you have sent letters in your own name to all the people who are at Jerusalem, and to Zephaniah the son of Maaseiah, the priest, and to all the priests, saying,', pt: 'Assim diz o Senhor dos exércitos, o Deus de Israel: Porquanto enviaste em teu próprio nome cartas a todo o povo que está em Jerusalém, como também a Sofonias, filho de Maaséias, o sacerdote, e a todos os sacerdotes, dizendo:' },
      { v: 26, en: '“Yahweh has made you priest in the place of Jehoiada the priest, that there may be officers in Yahweh’s house, for every man who is crazy, and makes himself a prophet, that you should put him in the stocks and in shackles.', pt: 'O Senhor te pôs por sacerdote em lugar de Jeoiada, o sacerdote, para que fosses encarregado da casa do Senhor, sobre todo homem obsesso que profetiza, para o lançares na prisão e no tronco;' },
      { v: 27, en: 'Now therefore, why have you not rebuked Jeremiah of Anathoth, who makes himself a prophet to you,', pt: 'agora, pois, por que não repreendeste a Jeremias, o anatotita, que vos profetiza?' },
      { v: 28, en: 'because he has sent to us in Babylon, saying, The captivity is long. Build houses, and dwell in them. Plant gardens, and eat their fruit?”’”', pt: 'Pois que até nos mandou dizer em Babilônia: O cativeiro muito há de durar; edificai casas, e habitai-as; e plantai jardins, e comei do seu fruto.' },
      { v: 29, en: 'Zephaniah the priest read this letter in the hearing of Jeremiah the prophet.', pt: 'E lera Sofonias, o sacerdote, esta carta aos ouvidos de Jeremias, o profeta.' },
      { v: 30, en: 'Then Yahweh’s word came to Jeremiah, saying,', pt: 'Então veio a palavra do Senhor a Jeremias, dizendo:' },
      { v: 31, en: '“Send to all of the captives, saying, ‘Yahweh says concerning Shemaiah the Nehelamite: “Because Shemaiah has prophesied to you, and I didn’t send him, and he has caused you to trust in a lie;”', pt: 'Manda a todos os do cativeiro, dizendo: Assim diz o Senhor acerca de Semaías, o neelamita: Porquanto Semaías vos profetizou, quando eu não o enviei, e vos fez confiar numa mentira,' },
      { v: 32, en: 'therefore Yahweh says, “Behold, I will punish Shemaiah the Nehelamite and his offspring. He will not have a man to dwell among this people. He won’t see the good that I will do to my people,” says Yahweh, “because he has spoken rebellion against Yahweh.”’”', pt: 'portanto assim diz o Senhor: Eis que castigarei a Semaías, o neelamita, e a sua descendência; ele não terá varão que habite entre este povo, nem verá ele o bem que hei de fazer ao meu povo, diz o Senhor, porque pregou rebelião contra o Senhor.' },
    ],
    30: [
      { v: 1, en: 'The word that came to Jeremiah from Yahweh, saying,', pt: 'A palavra que do Senhor veio a Jeremias, dizendo:' },
      { v: 2, en: '“Yahweh, the God of Israel, says, ‘Write all the words that I have spoken to you in a book.', pt: 'Assim diz o Senhor, Deus de Israel: Escreve num livro todas as palavras que te falei;' },
      { v: 3, en: 'For, behold, the days come,’ says Yahweh, ‘that I will reverse the captivity of my people Israel and Judah,’ says Yahweh. ‘I will cause them to return to the land that I gave to their fathers, and they will possess it.’”', pt: 'pois eis que vêm os dias, diz o Senhor, em que farei voltar do cativeiro o meu povo Israel e Judá, diz o Senhor; e tornarei a trazê-los à terra que dei a seus pais, e a possuirão.' },
      { v: 4, en: 'These are the words that Yahweh spoke concerning Israel and concerning Judah.', pt: 'E estas são as palavras que disse o Senhor, acerca de Israel e de Judá.' },
      { v: 5, en: 'For Yahweh says: “We have heard a voice of trembling; a voice of fear, and not of peace.', pt: 'Assim, pois, diz o Senhor: Ouvimos uma voz de tremor, de temor mas não de paz.' },
      { v: 6, en: 'Ask now, and see whether a man travails with child. Why do I see every man with his hands on his waist, as a woman in travail, and all faces are turned pale?', pt: 'Perguntai, pois, e vede, se um homem pode dar à luz. Por que, pois, vejo a cada homem com as mãos sobre os lombos como a que está de parto? Por que empalideceram todos os rostos?' },
      { v: 7, en: 'Alas! for that day is great, so that none is like it. It is even the time of Jacob’s trouble; but he will be saved out of it.', pt: 'Ah! porque aquele dia é tão grande, que não houve outro semelhante! É tempo de angústia para Jacó; todavia, há de ser livre dela.' },
      { v: 8, en: 'It will come to pass in that day, says Yahweh of Armies, that I will break his yoke from off your neck, and will burst your bonds. Strangers will no more make them their bondservants;', pt: 'E será naquele dia, diz o Senhor dos exércitos, que eu quebrarei o jugo de sobre o seu pescoço, e romperei as suas brochas. Nunca mais se servirão dele os estrangeiros;' },
      { v: 9, en: 'but they will serve Yahweh their God, and David their king, whom I will raise up to them.', pt: 'mas ele servirá ao Senhor, seu Deus, como também a Davi, seu rei, que lhe levantarei.' },
      { v: 10, en: 'Therefore don’t be afraid, O Jacob my servant, says Yahweh. Don’t be dismayed, Israel. For, behold, I will save you from afar, and save your offspring from the land of their captivity. Jacob will return, and will be quiet and at ease. No one will make him afraid.', pt: 'Não temas pois tu, servo meu, Jacó, diz o Senhor, nem te espantes, ó Israel; pois eis que te livrarei de terras longinquas, se à tua descendência da terra do seu cativeiro; e Jacó voltará, e ficará tranqüilo e sossegado, e não haverá quem o atemorize.' },
      { v: 11, en: 'For I am with you, says Yahweh, to save you; for I will make a full end of all the nations where I have scattered you, but I will not make a full end of you; but I will correct you in measure, and will in no way leave you unpunished.”', pt: 'Porque eu sou contigo, diz o Senhor, para te salvar; porquanto darei fim cabal a todas as nações entre as quais te espalhei; a ti, porém, não darei fim, mas castigar-te-ei com medida justa, e de maneira alguma te terei por inocente.' },
      { v: 12, en: 'For Yahweh says, “Your hurt is incurable. Your wound is grievous.', pt: 'Porque assim diz o Senhor: Incurável é a tua fratura, e gravíssima a tua ferida.' },
      { v: 13, en: 'There is no one to plead your cause, that you may be bound up. You have no healing medicines.', pt: 'Não há quem defenda a tua causa; para a tua ferida não há remédio nem cura.' },
      { v: 14, en: 'All your lovers have forgotten you. They don’t seek you. For I have wounded you with the wound of an enemy, with the chastisement of a cruel one, for the greatness of your iniquity, because your sins were increased.', pt: 'Todos os teus amantes se esqueceram de ti; não te procuram; pois te feri com ferida de inimigo, e com castigo de quem é cruel, porque é grande a tua culpa, e têm-se multiplicado os teus pecados.' },
      { v: 15, en: 'Why do you cry over your injury? Your pain is incurable. For the greatness of your iniquity, because your sins have increased, I have done these things to you.', pt: 'Por que gritas por causa da tua fratura? tua dor é incurável. Por ser grande a tua culpa, e por se terem multiplicado os teus pecados, é que te fiz estas coisas.' },
      { v: 16, en: 'Therefore all those who devour you will be devoured. All your adversaries, everyone of them, will go into captivity. Those who plunder you will be plunder. I will make all who prey on you become prey.', pt: 'Portanto todos os que te devoram serão devorados, e todos os teus adversários irão, todos eles, para o cativeiro; e os que te roubam serão roubados, e a todos os que te saqueiam entregarei ao saque.' },
      { v: 17, en: 'For I will restore health to you, and I will heal you of your wounds,” says Yahweh; “because they have called you an outcast, saying, ‘It is Zion, whom no man seeks after.’”', pt: 'Pois te restaurarei a saúde e te sararei as feridas, diz o Senhor; porque te chamaram a repudiada, dizendo: É Sião, à qual já ninguém procura.' },
      { v: 18, en: 'Yahweh says: “Behold, I will reverse the captivity of Jacob’s tents, and have compassion on his dwelling places. The city will be built on its own hill, and the palace will be inhabited in its own place.', pt: 'Assim diz o Senhor: Eis que acabarei o cativeiro das tendas de Jacó, e apiedarme-ei das suas moradas; e a cidade será reedificada sobre o seu montão, e o palácio permanecerá como habitualmente.' },
      { v: 19, en: 'Thanksgiving will proceed out of them with the voice of those who make merry. I will multiply them, and they will not be few; I will also glorify them, and they will not be small.', pt: 'E sairá deles ação de graças e a voz dos que se alegram; e multiplicá-los-ei, e não serão diminuídos; glorificá-los-ei, e não serão apoucados.' },
      { v: 20, en: 'Their children also will be as before, and their congregation will be established before me. I will punish all who oppress them.', pt: 'E seus filhos serão como na antigüidade, e a sua congregação será estabelecida diante de mim, e castigarei todos os seus opressores.' },
      { v: 21, en: 'Their prince will be one of them, and their ruler will proceed from among them. I will cause him to draw near, and he will approach to me; for who is he who has had boldness to approach to me?” says Yahweh.', pt: 'E o seu príncipe será deles, e o seu governador sairá do meio deles; e o farei aproximar, e ele se chegará a mim. Pois quem por si mesmo ousaria chegar-se a mim? diz o Senhor.' },
      { v: 22, en: '“You shall be my people, and I will be your God.', pt: 'E vós sereis o meu povo, e eu serei o vosso Deus.' },
      { v: 23, en: 'Behold, Yahweh’s storm, his wrath, has gone out, a sweeping storm: it will burst on the head of the wicked.', pt: 'Eis a tempestade do Senhor! A sua indignação já saiu, uma tempestade varredora; cairá cruelmente sobre a cabeça dos impios.' },
      { v: 24, en: 'The fierce anger of Yahweh will not return until he has accomplished, and until he has performed the intentions of his heart. In the latter days you will understand it.”', pt: 'Não retrocederá o furor da ira do Senhor, até que ele tenha executado, e até que tenha cumprido os desígnios do seu coração. Nos últimos dias entendereis isso.' },
    ],
    31: [
      { v: 1, en: '“At that time,” says Yahweh, “I will be the God of all the families of Israel, and they will be my people.”', pt: 'Naquele tempo, diz o Senhor, serei o Deus de todas as famílias de Israel, e elas serão o meu povo.' },
      { v: 2, en: 'Yahweh says, “The people who survive the sword found favor in the wilderness; even Israel, when I went to cause him to rest.”', pt: 'Assim diz o Senhor: O povo que escapou da espada achou graça no deserto. Eu irei e darei descanso a Israel.' },
      { v: 3, en: 'Yahweh appeared of old to me, saying, “Yes, I have loved you with an everlasting love. Therefore I have drawn you with loving kindness.', pt: 'De longe o Senhor me apareceu, dizendo: Pois que com amor eterno te amei, também com benignidade te atraí.' },
      { v: 4, en: 'I will build you again, and you will be built, O virgin of Israel. You will again be adorned with your tambourines, and will go out in the dances of those who make merry.', pt: 'De novo te edificarei, e serás edificada ó virgem de Israel! ainda serás adornada com os teus adufes, e sairás nas danças dos que se alegram.' },
      { v: 5, en: 'Again you will plant vineyards on the mountains of Samaria. The planters will plant, and will enjoy its fruit.', pt: 'Ainda plantarás vinhas nos montes de Samária; os plantadores plantarão e gozarão dos frutos.' },
      { v: 6, en: 'For there will be a day that the watchmen on the hills of Ephraim cry, ‘Arise, and let us go up to Zion to Yahweh our God.’”', pt: 'Pois haverá um dia em que gritarão os vigias sobre o monte de Efraim: Levantai-vos, e subamos a Sião, ao Senhor nosso Deus.' },
      { v: 7, en: 'For Yahweh says, “Sing with gladness for Jacob, and shout for the chief of the nations. Publish, praise, and say, ‘Yahweh, save your people, the remnant of Israel!’', pt: 'Pois assim diz o Senhor: Cantai sobre Jacó com alegria, e exultai por causa da principal das nações; proclamai, cantai louvores, e dizei: Salva, Senhor, o teu povo, o resto de Israel.' },
      { v: 8, en: 'Behold, I will bring them from the north country, and gather them from the uttermost parts of the earth, along with the blind and the lame, the woman with child and her who travails with child together. They will return as a great company.', pt: 'Eis que os trarei da terra do norte e os congregarei das extremidades da terra; e com eles os cegos e aleijados, as mulheres grávidas e as de parto juntamente; em grande companhia voltarão para cá.' },
      { v: 9, en: 'They will come with weeping. I will lead them with petitions. I will cause them to walk by rivers of waters, in a straight way in which they won’t stumble; for I am a father to Israel. Ephraim is my firstborn.', pt: 'Virão com choro, e com súplicas os levarei; guiá-los-ei aos ribeiros de águas, por caminho direito em que não tropeçarão; porque sou um pai para Israel, e Efraim é o meu primogênito.' },
      { v: 10, en: '“Hear Yahweh’s word, you nations, and declare it in the distant islands. Say, ‘He who scattered Israel will gather him, and keep him, as a shepherd does his flock.’', pt: 'Ouvi a palavra do Senhor, ó nações, e anunciai-a nas longinquas terras maritimas, e dizei: Aquele que espalhou a Israel o congregará e o guardará, como o pastor ao seu rebanho.' },
      { v: 11, en: 'For Yahweh has ransomed Jacob, and redeemed him from the hand of him who was stronger than he.', pt: 'Pois o Senhor resgatou a Jacó, e o livrou da mão do que era mais forte do que ele.' },
      { v: 12, en: 'They will come and sing in the height of Zion, and will flow to the goodness of Yahweh, to the grain, to the new wine, to the oil, and to the young of the flock and of the herd. Their soul will be as a watered garden. They will not sorrow any more at all.', pt: 'E virão, e cantarão de júbilo nos altos de Sião, e ficarão radiantes pelos bens do Senhor, pelo trigo, o mosto, e o azeite, pelos cordeiros e os bezerros; e a sua vida será como um jardim regado, e nunca mais desfalecerão.' },
      { v: 13, en: 'Then the virgin will rejoice in the dance; the young men and the old together; for I will turn their mourning into joy, and will comfort them, and make them rejoice from their sorrow.', pt: 'Então a virgem se alegrará na dança, como também os mancebos e os velhos juntamente; porque tornarei o seu pranto em gozo, e os consolarei, e lhes darei alegria em lugar de tristeza.' },
      { v: 14, en: 'I will satiate the soul of the priests with fatness, and my people will be satisfied with my goodness,” says Yahweh.', pt: 'E saciarei de gordura a alma dos sacerdotes, e o meu povo se fartará dos meus bens, diz o Senhor.' },
      { v: 15, en: 'Yahweh says: “A voice is heard in Ramah, lamentation and bitter weeping, Rachel weeping for her children. She refuses to be comforted for her children, because they are no more.”', pt: 'Assim diz o Senhor: Ouviu-se um clamor em Ramá, lamentação e choro amargo. Raquel chora a seus filhos, e não se deixa consolar a respeito deles, porque já não existem.' },
      { v: 16, en: 'Yahweh says: “Refrain your voice from weeping, and your eyes from tears; for your work will be rewarded,” says Yahweh. “They will come again from the land of the enemy.', pt: 'Assim diz o Senhor: Reprime a tua voz do choro, e das lágrimas os teus olhos; porque há galardão para o teu trabalho, diz o Senhor, e eles voltarão da terra do imimigo.' },
      { v: 17, en: 'There is hope for your latter end,” says Yahweh. “Your children will come again to their own territory.', pt: 'E há esperança para o teu futuro, diz o Senhor; pois teus filhos voltarão para os seus termos.' },
      { v: 18, en: '“I have surely heard Ephraim grieving thus, ‘You have chastised me, and I was chastised, as an untrained calf. Turn me, and I will be turned; for you are Yahweh my God.', pt: 'Bem ouvi eu que Efraim se queixava, dizendo: Castigaste-me e fui castigado, como novilho ainda não domado; restaura-me, para que eu seja restaurado, pois tu és o Senhor meu Deus.' },
      { v: 19, en: 'Surely after that I was turned. I repented. After that I was instructed. I struck my thigh. I was ashamed, yes, even confounded, because I bore the reproach of my youth.’', pt: 'Na verdade depois que me desviei, arrependi-me; e depois que fui instruído, bati na minha coxa; fiquei confundido e envergonhado, porque suportei o opróbrio da minha mocidade.' },
      { v: 20, en: 'Is Ephraim my dear son? Is he a darling child? For as often as I speak against him, I still earnestly remember him. therefore my heart yearns for him. I will surely have mercy on him,” says Yahweh.', pt: 'Não é Efraim meu filho querido? filhinho em quem me deleito? Pois quantas vezes falo contra ele, tantas vezes me lembro dele solicitamente; por isso se comovem por ele as minhas entranhas; deveras me compadecerei dele, diz o Senhor.' },
      { v: 21, en: '“Set up road signs. Make guideposts. Set your heart toward the highway, even the way by which you went. Turn again, virgin of Israel. Turn again to these your cities.', pt: 'Põe-te marcos, faze postes que te guiem; dirige a tua atenção à estrada, ao caminho pelo qual foste; regressa, ó virgem de Israel, regressa a estas tuas cidades.' },
      { v: 22, en: 'How long will you go here and there, you backsliding daughter? For Yahweh has created a new thing in the earth: a woman will encompass a man.”', pt: 'Até quando andarás errante, ó filha rebelde? pois o senhor criou uma coisa nova na terra: uma mulher protege a um varão.' },
      { v: 23, en: 'Yahweh of Armies, the God of Israel, says: “Yet again they will use this speech in the land of Judah and in its cities, when I reverse their captivity: ‘Yahweh bless you, habitation of righteousness, mountain of holiness.’', pt: 'Assim diz o Senhor dos exércitos, o Deus de Israel: Ainda dirão esta palavra na terra de Judá, e nas suas cidades, quando eu acabar o seu cativeiro: O Senhor te abençoe, ó morada de justiça, ó monte de santidade!' },
      { v: 24, en: 'Judah and all its cities will dwell therein together, the farmers, and those who go about with flocks.', pt: 'E nela habitarão Judá, e todas as suas cidades juntamente; como também os lavradores e os que pastoreiam os rebanhos.' },
      { v: 25, en: 'For I have satiated the weary soul, and I have replenished every sorrowful soul.”', pt: 'Pois saciarei a alma cansada, e fartarei toda alma desfalecida.' },
      { v: 26, en: 'On this I awakened, and saw; and my sleep was sweet to me.', pt: 'Nisto acordei, e olhei; e o meu sono foi doce para mim.' },
      { v: 27, en: '“Behold, the days come,” says Yahweh, “that I will sow the house of Israel and the house of Judah with the seed of man and with the seed of animal.', pt: 'Eis que os dias vêm, diz o Senhor, em que semearei de homens e de animais a casa de Israel e a casa de Judá.' },
      { v: 28, en: 'It will happen that, like as I have watched over them to pluck up and to break down and to overthrow and to destroy and to afflict, so will I watch over them to build and to plant,” says Yahweh.', pt: 'E será que, como vigiei sobre eles para arrancar e derribar, para transtornar, destruir, e afligir, assim vigiarei sobre eles para edificar e para plantar, diz o Senhor.' },
      { v: 29, en: '“In those days they will say no more, “‘The fathers have eaten sour grapes, and the children’s teeth are set on edge.’', pt: 'Naqueles dias não dirão mais: Os pais comeram uvas verdes, e os dentes dos filhos se embotaram.' },
      { v: 30, en: 'But everyone will die for his own iniquity. Every man who eats the sour grapes, his teeth will be set on edge.', pt: 'Pelo contrário, cada um morrerá pela sua própria iniqüidade; de todo homem que comer uvas verdes, é que os dentes se embotarão.' },
      { v: 31, en: '“Behold, the days come,” says Yahweh, “that I will make a new covenant with the house of Israel, and with the house of Judah:', pt: 'Eis que os dias vêm, diz o Senhor, em que farei um pacto novo com a casa de Israel e com a casa de Judá,' },
      { v: 32, en: 'not according to the covenant that I made with their fathers in the day that I took them by the hand to bring them out of the land of Egypt; which covenant of mine they broke, although I was a husband to them,” says Yahweh.', pt: 'não conforme o pacto que fiz com seus pais, no dia em que os tomei pela mão, para os tirar da terra do Egito, esse meu pacto que eles invalidaram, apesar de eu os haver desposado, diz o Senhor.' },
      { v: 33, en: '“But this is the covenant that I will make with the house of Israel after those days,” says Yahweh: I will put my law in their inward parts, and I will write it in their heart. I will be their God, and they shall be my people.', pt: 'Mas este é o pacto que farei com a casa de Israel depois daqueles dias, diz o Senhor: Porei a minha lei no seu interior, e a escreverei no seu coração; e eu serei o seu Deus e eles serão o meu povo.' },
      { v: 34, en: 'They will no longer each teach his neighbor, and every man teach his brother, saying, ‘Know Yahweh;’ for they will all know me, from their least to their greatest,” says Yahweh: “for I will forgive their iniquity, and I will remember their sin no more.”', pt: 'E não ensinarão mais cada um a seu próximo, nem cada um a seu irmão, dizendo: Conhecei ao Senhor; porque todos me conhecerão, desde o menor deles até o maior, diz o Senhor; pois lhes perdoarei a sua iniqüidade, e não me lembrarei mais dos seus pecados.' },
      { v: 35, en: 'Yahweh, who gives the sun for a light by day, and the ordinances of the moon and of the stars for a light by night, who stirs up the sea, so that its waves roar; Yahweh of Armies is his name, says:', pt: 'Assim diz o Senhor, que dá o sol para luz do dia, e a ordem estabelecida da lua e das estrelas para luz da noite, que agita o mar, de modo que bramem as suas ondas; o Senhor dos exércitos é o seu nome:' },
      { v: 36, en: '“If these ordinances depart from before me,” says Yahweh, “then the offspring of Israel also will cease from being a nation before me forever.”', pt: 'Se esta ordem estabelecida falhar diante de mim, diz o Senhor, deixará também a linhagem de Israel de ser uma nação diante de mim para sempre.' },
      { v: 37, en: 'Yahweh says: “If heaven above can be measured, and the foundations of the earth searched out beneath, then I will also cast off all the offspring of Israel for all that they have done,” says Yahweh.', pt: 'Assim diz o Senhor: Se puderem ser medidos os céus lá em cima, e sondados os fundamentos da terra cá em baixo, também eu rejeitarei toda a linhagem de Israel, por tudo quanto eles têm feito, diz o Senhor.' },
      { v: 38, en: '“Behold, the days come,” says Yahweh, “that the city will be built to Yahweh from the tower of Hananel to the gate of the corner.', pt: 'Eis que vêm os dias, diz o Senhor, em que esta cidade será reedificada para o Senhor, desde a torre de Hananel até a porta da esquina.' },
      { v: 39, en: 'The measuring line will go out further straight onward to the hill Gareb, and will turn toward Goah.', pt: 'E a linha de medir estender-se-á para diante, até o outeiro de Garebe, e dará volta até Goa.' },
      { v: 40, en: 'The whole valley of the dead bodies and of the ashes, and all the fields to the brook Kidron, to the corner of the horse gate toward the east, will be holy to Yahweh. It will not be plucked up or thrown down any more forever.”', pt: 'E o vale inteiro dos cadáveres e da cinza, e todos os campos até o ribeiro de Cedrom, até a esquina da porta dos cavalos para o oriente, tudo será santo ao Senhor; nunca mais será arrancado nem derribado.' },
    ],
    32: [
      { v: 1, en: 'The word that came to Jeremiah from Yahweh in the tenth year of Zedekiah king of Judah, which was the eighteenth year of Nebuchadnezzar.', pt: 'A palavra que veio a Jeremias da parte do Senhor, no ano décimo de Zedequias, rei de Judá, o qual foi o ano dezoito de Nabucodonozor.' },
      { v: 2, en: 'Now at that time the king of Babylon’s army was besieging Jerusalem. Jeremiah the prophet was shut up in the court of the guard, which was in the king of Judah’s house.', pt: 'Ora, cercava então o exército do rei de Babilônia a Jerusalém; e Jeremias, o profeta, se achava encerrado no pátio da guarda que estava na casa do rei de Judá;' },
      { v: 3, en: 'For Zedekiah king of Judah had shut him up, saying, “Why do you prophesy, and say, ‘Yahweh says, “Behold, I will give this city into the hand of the king of Babylon, and he will take it;', pt: 'pois Zedequias, rei de Judá, o havia encarcerado, dizendo: Por que profetizas , dizendo: Assim diz o Senhor: Eis que entrego esta cidade na mão do rei de Babilônia, e ele a tomará;' },
      { v: 4, en: 'and Zedekiah king of Judah won’t escape out of the hand of the Chaldeans, but will surely be delivered into the hand of the king of Babylon, and will speak with him mouth to mouth, and his eyes will see his eyes;', pt: 'e Zedequias, rei de Judá, não escapará das mãos dos caldeus, mas certamente será entregue na mão do rei de Babilônia, e com ele falará boca a boca, e os seus olhos verão os olhos dele;' },
      { v: 5, en: 'and he will bring Zedekiah to Babylon, and he will be there until I visit him,” says Yahweh: “though you fight with the Chaldeans, you will not prosper?”’”', pt: 'e ele levará para Babilônia a Zedequias, que ali estará até que eu o visite, diz o Senhor, e, ainda que pelejeis contra os caldeus, não ganhareis?' },
      { v: 6, en: 'Jeremiah said, “Yahweh’s word came to me, saying,', pt: 'Disse pois Jeremias: Veio a mim a palavra do Senhor, dizendo:' },
      { v: 7, en: '‘Behold, Hanamel the son of Shallum your uncle will come to you, saying, “Buy my field that is in Anathoth; for the right of redemption is yours to buy it.”’”', pt: 'Eis que Hanamel, filho de Salum, teu tio, virá a ti, dizendo: Compra o meu campo que está em Anatote, pois tens o direito de resgate; a ti compete comprá-lo.' },
      { v: 8, en: '“So Hanamel my uncle’s son came to me in the court of the guard according to Yahweh’s word, and said to me, ‘Please buy my field that is in Anathoth, which is in the land of Benjamin; for the right of inheritance is yours, and the redemption is yours. Buy it for yourself.’ “Then I knew that this was Yahweh’s word.', pt: 'Veio, pois, a mim Hanamel, filho de meu tio, segundo a palavra do Senhor, ao pátio da guarda, e me disse: Compra o meu campo que está em Anatote, na terra de Benjamim; porque teu é o direito de herança e teu é o de resgate; compra-o para ti. Então entendi que isto era a palavra do Senhor.' },
      { v: 9, en: 'I bought the field that was in Anathoth of Hanamel my uncle’s son, and weighed him the money, even seventeen shekels of silver.', pt: 'Comprei, pois, de Hanamel, filho de meu tio, o campo que está em Anatote; e pesei-lhe o dinheiro, dezessete siclos de prata.' },
      { v: 10, en: 'I signed the deed, sealed it, called witnesses, and weighed the money in the balances to him.', pt: 'Assinei a escritura e a selei, chamei testemunhas, e pesei-lhe o dinheiro numa balança.' },
      { v: 11, en: 'So I took the deed of the purchase, both that which was sealed, containing the terms and conditions, and that which was open;', pt: 'E tomei a escritura da compra, que continha os termos e as condições, tanto a que estava selada, como a cópia que estava aberta,' },
      { v: 12, en: 'and I delivered the deed of the purchase to Baruch the son of Neriah, the son of Mahseiah, in the presence of Hanamel my uncle’s son, and in the presence of the witnesses who subscribed the deed of the purchase, before all the Jews who sat in the court of the guard.', pt: 'e as dei a Baruque, filho de Nerias, filho de Maséias, na presença de Hanamel, filho de meu tio, e na presença das testemunhas que subscreveram a escritura da compra, à vista de todos os judeus que estavam sentados no pátio da guarda.' },
      { v: 13, en: '“I commanded Baruch before them, saying,', pt: 'E dei ordem a Banique, na presença deles, dizendo:' },
      { v: 14, en: 'Yahweh of Armies, the God of Israel says: ‘Take these deeds, this deed of the purchase which is sealed, and this deed which is open, and put them in an earthen vessel, that they may last many days.’', pt: 'Assim diz o Senbor dos exércitos, o Deus de Israel: Toma estas escrituras de compra, tanto a selada, como a aberta, e mete-as num vaso de barro, para que se possam conservar muitos dias;' },
      { v: 15, en: 'For Yahweh of Armies, the God of Israel says: ‘Houses and fields and vineyards will yet again be bought in this land.’', pt: 'pois assim diz o Senhor dos exércitos, o Deus de Israel: Ainda se comprarão casas, e campos, e vinhas nesta terra.' },
      { v: 16, en: 'Now after I had delivered the deed of the purchase to Baruch the son of Neriah, I prayed to Yahweh, saying,', pt: 'E depois que dei a escritura da compra a Banique, filho de Nerias, orei ao Senhor, dizendo:' },
      { v: 17, en: '“Ah Lord Yahweh! Behold, you have made the heavens and the earth by your great power and by your outstretched arm. There is nothing too hard for you,', pt: 'Ah! Senhor Deus! És tu que fizeste os céus e a terra com o teu grande poder, e com o teu braço estendido! Nada há que te seja demasiado difícil!' },
      { v: 18, en: 'who show loving kindness to thousands, and repay the iniquity of the fathers into the bosom of their children after them; the great, the mighty God, Yahweh of Armies is his name;', pt: 'Usas de benignidade para com milhares e tornas a iniqüidade dos pais ao seio dos filhos depois deles; tu és o grande, o poderoso Deus cujo nome é o Senhor dos exércitos.' },
      { v: 19, en: 'great in counsel, and mighty in work; whose eyes are open to all the ways of the sons of men, to give everyone according to his ways, and according to the fruit of his doings;', pt: 'Grande em conselho, e poderoso em obras, cujos olhos estão abertos sobre todos os caminhos dos filhos dos homens, para dares a cada um segundo os seus caminhos e segundo o fruto das suas obras;' },
      { v: 20, en: 'who performed signs and wonders in the land of Egypt, even to this day, both in Israel and among other men; and made yourself a name, as it is today;', pt: 'puseste sinais e maravilhas na terra do Egito até o dia de hoje, tanto em Israel, como entre os outros homens; e te fizeste um nome, qual tu tens neste dia.' },
      { v: 21, en: 'and brought your people Israel out of the land of Egypt with signs, with wonders, with a strong hand, with an outstretched arm, and with great terror;', pt: 'E tiraste o teu povo Israel da terra do Egito, com sinais e com maravilhas, e com mão forte, e com braço estendido, e com grande terror;' },
      { v: 22, en: 'and gave them this land, which you swore to their fathers to give them, a land flowing with milk and honey.', pt: 'e lhes deste esta terra, que juraste a seus pais que lhes havias de dar, terra que mana leite e mel.' },
      { v: 23, en: 'They came in and possessed it, but they didn’t obey your voice and didn’t walk in your law. They have done nothing of all that you commanded them to do. Therefore you have caused all this evil to come upon them.', pt: 'E entraram nela, e a possuíram; mas não obedeceram à tua voz, nem andaram na tua lei; de tudo o que lhes mandaste fazer, eles não fizeram nada; pelo que ordenaste lhes sucedesse todo este mal.' },
      { v: 24, en: '“Behold, siege ramps have come to the city to take it. The city is given into the hand of the Chaldeans who fight against it, because of the sword, of the famine, and of the pestilence. What you have spoken has happened. Behold, you see it.', pt: 'Eis aqui os valados! já vieram contra a cidade para tomá-la e a cidade está entregue na mão dos caldeus que pelejam contra ela, pela espada, pela fome e pela peste. O que disseste se cumpriu, e eis aqui o estás presenciando.' },
      { v: 25, en: 'You have said to me, Lord Yahweh, ‘Buy the field for money, and call witnesses;’ whereas the city is given into the hand of the Chaldeans.”', pt: 'Contudo tu me disseste, ó Senhor Deus: Compra-te o campo por dinheiro, e chama testemunhas, embora a cidade já esteja dada na mão dos caldeus:' },
      { v: 26, en: 'Then Yahweh’s word came to Jeremiah, saying,', pt: 'Então veio a palavra do Senhor a Jeremias, dizendo:' },
      { v: 27, en: '“Behold, I am Yahweh, the God of all flesh. Is there anything too hard for me?', pt: 'Eis que eu sou o Senhor, o Deus de toda a carne; acaso há alguma coisa demasiado difícil para mim?' },
      { v: 28, en: 'Therefore Yahweh says: Behold, I will give this city into the hand of the Chaldeans, and into the hand of Nebuchadnezzar king of Babylon, and he will take it.', pt: 'Portanto assim diz o Senhor: Eis que eu entrego esta cidade na mão dos caldeus, e na mão de Nabucodonozor, rei de Babilônia, e ele a tomará.' },
      { v: 29, en: 'The Chaldeans, who fight against this city, will come and set this city on fire, and burn it with the houses on whose roofs they have offered incense to Baal, and poured out drink offerings to other gods, to provoke me to anger.', pt: 'E os caldeus que pelejam contra esta cidade entrarão nela, e lhe porão fogo, e a queimarão, juntamente com as casas sobre cujos terraços queimaram incenso a Baal e ofereceram libações a outros deuses, para me provocarem a ira.' },
      { v: 30, en: '“For the children of Israel and the children of Judah have done only that which was evil in my sight from their youth; for the children of Israel have only provoked me to anger with the work of their hands, says Yahweh.', pt: 'Pois os filhos de Israel e os filhos de Judá têm feito desde a sua mocidade tão somente o que era mau aos meus olhos; pois os filhos de Israel nada têm feito senão provocar-me à ira com as obras das suas mãos, diz o Senhor.' },
      { v: 31, en: 'For this city has been to me a provocation of my anger and of my wrath from the day that they built it even to this day, so that I should remove it from before my face,', pt: 'Na verdade esta cidade, desde o dia em que a edificaram e até o dia de hoje, tem provocado a minha ira e o meu furor, de sorte que eu a removerei de diante de mim,' },
      { v: 32, en: 'because of all the evil of the children of Israel and of the children of Judah, which they have done to provoke me to anger: they, their kings, their princes, their priests, their prophets, the men of Judah, and the inhabitants of Jerusalem.', pt: 'por causa de toda a maldade dos filhos de Israel e dos filhos de Judá, que fizeram para me provocarem à ira, eles e os seus reis, os seus príncipes, os seus sacerdotes e os seus profetas, como também os homens de Judá e os moradores de Jerusalém.' },
      { v: 33, en: 'They have turned their backs to me, and not their faces. Although I taught them, rising up early and teaching them, yet they have not listened to receive instruction.', pt: 'E viraram para mim as costas, e não o rosto; ainda que eu os ensinava, com insistência, eles não deram ouvidos para receberem instrução.' },
      { v: 34, en: 'But they set their abominations in the house which is called by my name, to defile it.', pt: 'Mas puseram as suas abominações na casa que se chama pelo meu nome, para a profanarem.' },
      { v: 35, en: 'They built the high places of Baal, which are in the valley of the son of Hinnom, to cause their sons and their daughters to pass through fire to Molech; which I didn’t command them. It didn’t even come into my mind, that they should do this abomination, to cause Judah to sin.”', pt: 'Também edificaram os altos de Baal, que estão no vale do filho de Hinom, para fazerem passar seus filhos e suas filhas pelo fogo a Moloque; o que nunca lhes ordenei, nem me passou pela mente, que fizessem tal abominação, para fazerem pecar a Judá.' },
      { v: 36, en: 'Now therefore Yahweh, the God of Israel, says concerning this city, about which you say, “It is given into the hand of the king of Babylon by the sword, by the famine, and by the pestilence:”', pt: 'E por isso agora assim diz o Senhor, o Deus de Israel, acerca desta cidade, da qual vós dizeis: Já está dada na mão do rei de Babilônia, pela espada, e pela fome, e pela peste:' },
      { v: 37, en: '“Behold, I will gather them out of all the countries where I have driven them in my anger, and in my wrath, and in great indignation; and I will bring them again to this place. I will cause them to dwell safely.', pt: 'Eis que eu os congregarei de todos os países para onde os tenho lançado na minha ira, e no meu furor e na minha grande indignação; e os tornarei a trazer a este lugar, e farei que habitem nele seguramente.' },
      { v: 38, en: 'Then they will be my people, and I will be their God.', pt: 'E eles serão o meu povo, e eu serei o seu Deus.' },
      { v: 39, en: 'I will give them one heart and one way, that they may fear me forever, for their good, and the good of their children after them.', pt: 'E lhes darei um só coração, e um só caminho, para que me temam para sempre, para seu bem e o bem de seus filhos, depois deles;' },
      { v: 40, en: 'I will make an everlasting covenant with them, that I will not turn away from following them, to do them good. I will put my fear in their hearts, that they may not depart from me.', pt: 'e farei com eles um pacto eterno de não me desviar de fazer-lhes o bem; e porei o meu temor no seu coração, para que nunca se apartem de mim.' },
      { v: 41, en: 'Yes, I will rejoice over them to do them good, and I will plant them in this land assuredly with my whole heart and with my whole soul.”', pt: 'E alegrar-me-ei por causa deles, fazendo-lhes o bem; e os plantarei nesta terra, com toda a fidelidade do meu coração e da minha alma.' },
      { v: 42, en: 'For Yahweh says: “Just as I have brought all this great evil on this people, so will I bring on them all the good that I have promised them.', pt: 'Pois assim diz o Senhor: Como eu trouxe sobre este povo todo este grande mal, assim eu trarei sobre eles todo o bem que lhes tenho prometido.' },
      { v: 43, en: 'Fields will be bought in this land, about which you say, ‘It is desolate, without man or animal. It is given into the hand of the Chaldeans.’', pt: 'E comprar-se-ão campos nesta terra, da qual vós dizeis: E uma desolação, sem homens nem animais; está entregue na mão dos caldeus.' },
      { v: 44, en: 'Men will buy fields for money, sign the deeds, seal them, and call witnesses, in the land of Benjamin, and in the places around Jerusalem, in the cities of Judah, in the cities of the hill country, in the cities of the lowland, and in the cities of the South; for I will cause their captivity to be reversed,” says Yahweh.', pt: 'Comprarão campos por dinheiro, assinarão escrituras e as selarão, e chamarão testemunhas, na terra de Benjamim, e nos lugares ao redor de Jerusalém, e nas cidades de Judá e nas cidades da região montanhosa, e nas cidades das planícies e nas cidades do Sul porque os farei voltar do cativeiro, diz o Senhor.' },
    ],
    33: [
      { v: 1, en: 'Moreover Yahweh’s word came to Jeremiah the second time, while he was still locked up in the court of the guard, saying,', pt: 'E veio a palavra do Senhor a Jeremias, segunda vez, estando ele ainda encarcerado no pátio da guarda, dizendo:' },
      { v: 2, en: '“Yahweh who does it, Yahweh who forms it to establish it—Yahweh is his name, says:', pt: 'Assim diz o Senhor que faz isto, o Senhor que forma isto, para o estabelecer; o Senhor é o seu nome.' },
      { v: 3, en: '‘Call to me, and I will answer you, and will show you great and difficult things, which you don’t know.’', pt: 'Clama a mim, e responder-te-ei, e anunciar-te-ei coisas grandes e ocultas, que não sabes.' },
      { v: 4, en: 'For Yahweh, the God of Israel, says concerning the houses of this city and concerning the houses of the kings of Judah, which are broken down to make a defense against the mounds and against the sword;', pt: 'Pois assim diz o Senhor, o Deus de Israel, acerca das casas desta cidade, e acerca das casas dos reis de Judá, que foram demolidas para fazer delas uma defesa contra os valados e contra a espada;' },
      { v: 5, en: 'while men come to fight with the Chaldeans, and to fill them with the dead bodies of men, whom I have killed in my anger and in my wrath, and for all whose wickedness I have hidden my face from this city:', pt: 'entrementes os caldeus estão entrando a pelejar para os encher de cadáveres de homens que ferirei na minha ira e no meu furor; porquanto escondi o meu rosto desta cidade, por causa de toda a sua maldade.' },
      { v: 6, en: '‘Behold, I will bring it health and cure, and I will cure them; and I will reveal to them abundance of peace and truth.', pt: 'Eis que lhe trarei a ela saúde e cura, e os sararei, e lhes manifestarei abundância de paz e de segurança.' },
      { v: 7, en: 'I will cause the captivity of Judah and the captivity of Israel to return, and will build them, as at the first.', pt: 'E farei voltar do cativeiro os exilados de Judá e de Israel, e os edificarei como ao princípio.' },
      { v: 8, en: 'I will cleanse them from all their iniquity by which they have sinned against me. I will pardon all their iniquities by which they have sinned against me and by which they have transgressed against me.', pt: 'E os purificarei de toda a iniqüidade do seu pecado contra mim; e perdoarei todas as suas iniqüidades, com que pecaram e transgrediram contra mim.' },
      { v: 9, en: 'This city will be to me for a name of joy, for praise, and for glory, before all the nations of the earth, which will hear all the good that I do to them, and will fear and tremble for all the good and for all the peace that I provide to it.’”', pt: 'E esta cidade me servirá de nome de gozo, de louvor e de glória, diante de todas as nações da terra que ouvirem de todo o bem que eu lhe faço; e espantar-se-ão e perturbar-se-ão por causa de todo o bem, e por causa de toda a paz que eu lhe dou.' },
      { v: 10, en: 'Yahweh says: “Yet again there will be heard in this place, about which you say, ‘It is waste, without man and without animal, even in the cities of Judah, and in the streets of Jerusalem, that are desolate, without man and without inhabitant and without animal,’', pt: 'Assim diz o Senhor: Neste lugar do qual vós dizeis: E uma desolação, sem homens nem animais, sim, nas cidades de Judá, e nas ruas de Jerusalém, que estão assoladas, sem homens, sem moradores e sem animais, ainda se ouvira' },
      { v: 11, en: 'the voice of joy and the voice of gladness, the voice of the bridegroom and the voice of the bride, the voice of those who say, ‘Give thanks to Yahweh of Armies, for Yahweh is good, for his loving kindness endures forever;’ who bring thanksgiving into Yahweh’s house. For I will cause the captivity of the land to be reversed as at the first,” says Yahweh.', pt: 'a voz de gozo e a voz de alegria, a voz de noivo e a voz de noiva, e a voz dos que dizem: Dai graças ao Senhor dos exércitos, porque bom é o Senhor, porque a sua benignidade dura para sempre; também se ouvirá a voz dos que trazem à casa do Senhor sacrifícios de ação de graças. Pois farei voltar a esta terra os seus exilados como no princípio, diz o Senhor.' },
      { v: 12, en: 'Yahweh of Armies says: “Yet again there will be in this place, which is waste, without man and without animal, and in all its cities, a habitation of shepherds causing their flocks to lie down.', pt: 'Assim diz o Senhor dos exércitos: Ainda neste lugar, que está deserto, sem homens, e sem animais, e em todas as suas cidades, haverá uma morada de pastores que façam repousar aos seus rebanhos.' },
      { v: 13, en: 'In the cities of the hill country, in the cities of the lowland, in the cities of the South, in the land of Benjamin, in the places around Jerusalem, and in the cities of Judah, the flocks will again pass under the hands of him who counts them,” says Yahweh.', pt: 'Nas cidades da região montanhosa, nas cidades das planícies, e nas cidades do sul, e na terra de Benjamim, e nos contornos de Jerusalém, e nas cidades de Judá, ainda passarão os rebanhos pelas mãos dos contadores, diz o Senhor.' },
      { v: 14, en: '“Behold, the days come,” says Yahweh, “that I will perform that good word which I have spoken concerning the house of Israel and concerning the house of Judah.', pt: 'Eis que vêm os dias, diz o Senhor, em que cumprirei a boa palavra que falei acerca da casa de Israel e acerca da casa de Judá.' },
      { v: 15, en: '“In those days and at that time, I will cause a Branch of righteousness to grow up to David. He will execute justice and righteousness in the land.', pt: 'Naqueles dias e naquele tempo farei que brote a Davi um Renovo de justiça; ele executará juízo e justiça na terra.' },
      { v: 16, en: 'In those days Judah will be saved, and Jerusalem will dwell safely. This is the name by which she will be called: Yahweh our righteousness.”', pt: 'Naqueles dias Judá será salvo e Jerusalém habitará em segurança; e este é o nome que lhe chamarão: O SENHOR É NOSSA JUSTIÇA.' },
      { v: 17, en: 'For Yahweh says: “David will never lack a man to sit on the throne of the house of Israel.', pt: 'Pois assim diz o Senhor: Nunca faltará a Davi varão que se assente sobre o trono da casa de Israel;' },
      { v: 18, en: 'The priests the Levites won’t lack a man before me to offer burnt offerings, to burn meal offerings, and to do sacrifice continually.”', pt: 'nem aos sacerdotes levíticos faltará varão diante de mim para oferecer holocaustos, e queimar ofertas de cereais e oferecer sacrifícios continuamente.' },
      { v: 19, en: 'Yahweh’s word came to Jeremiah, saying,', pt: 'E veio a palavra do Senhor a Jeremias, dizendo:' },
      { v: 20, en: '“Yahweh says: ‘If you can break my covenant of the day and my covenant of the night, so that there will not be day and night in their time;', pt: 'Assim diz o Senhor: se puderdes invalidar o meu pacto com o dia, e o meu pacto com a noite, de tal modo que não haja dia e noite a seu tempo,' },
      { v: 21, en: 'then may my covenant also be broken with David my servant, that he won’t have a son to reign on his throne; and with the Levites the priests, my ministers.', pt: 'também se poderá invalidar o meu pacto com Davi, meu servo, para que não tenha filho que reine no seu trono; como também o pacto com os sacerdotes levíticos, meus ministros.' },
      { v: 22, en: 'As the army of the sky can’t be counted, and the sand of the sea can’t be measured; so I will multiply the offspring of David my servant and the Levites who minister to me.’”', pt: 'Assim como não se pode contar o exército dos céus, nem medir-se a areia do mar, assim multiplicarei a descendência de Davi, meu servo, e os levitas, que ministram diante de mim.' },
      { v: 23, en: 'Yahweh’s word came to Jeremiah, saying,', pt: 'E veio ainda a palavra do Senhor a Jeremias, dizendo:' },
      { v: 24, en: '“Don’t consider what this people has spoken, saying, ‘Has Yahweh cast off the two families which he chose?’ Thus they despise my people, that they should be no more a nation before them.”', pt: 'Acaso não observaste o que este povo está dizendo: As duas famílias que o Senhor escolheu, agora as rejeitou? Assim desprezam o meu povo, como se não fora um povo diante deles.' },
      { v: 25, en: 'Yahweh says: “If my covenant of day and night fails, if I have not appointed the ordinances of heaven and earth;', pt: 'Assim diz o Senhor: Se o meu pacto com o dia e com a noite não permanecer, e se eu não tiver determinado as ordenanças dos céus e da terra,' },
      { v: 26, en: 'then I will also cast away the offspring of Jacob, and of David my servant, so that I will not take of his offspring to be rulers over the offspring of Abraham, Isaac, and Jacob: for I will cause their captivity to be reversed and will have mercy on them.”', pt: 'também rejeitarei a descendência de Jacó, e de Davi, meu servo, de modo que não tome da sua descendência os que dominem sobre a descendência de Abraão, Isaque, e Jacó; pois eu os farei voltar do seu cativeiro, e apiedar-me-ei deles.' },
    ],
    34: [
      { v: 1, en: 'The word which came to Jeremiah from Yahweh, when Nebuchadnezzar king of Babylon, with all his army, all the kingdoms of the earth that were under his dominion, and all the peoples, were fighting against Jerusalem and against all its cities, saying:', pt: 'A palavra que da parte do Senhor veio a Jeremias, quando Nabucodonozor, rei de Babilônia, e todo o seu exército, e todos os reinos da terra que estavam sob o domínio da sua mão, e todos os povos, pelejavam contra Jerusalém, e contra todas as suas cidades, dizendo:' },
      { v: 2, en: '“Yahweh, the God of Israel, says, ‘Go, and speak to Zedekiah king of Judah, and tell him, Yahweh says, “Behold, I will give this city into the hand of the king of Babylon and he will burn it with fire.', pt: 'Assim diz o Senhor, Deus de Israel: Vai, e fala a Zedequias, rei de Judá, e dize-lhe: Assim diz o Senhor: Eis que estou prestes a entregar esta cidade na mão do rei de Babilônia, o qual a queimará a fogo.' },
      { v: 3, en: 'You won’t escape out of his hand, but will surely be taken and delivered into his hand. Your eyes will see the eyes of the king of Babylon, and he will speak with you mouth to mouth. You will go to Babylon.”’', pt: 'E tu não escaparás da sua mão; mas certamente serás preso e entregue na sua mão; e teus olhos verão os olhos do rei de Babilônia, e ele te falará boca a boca, e irás a Babilônia.' },
      { v: 4, en: '“Yet hear Yahweh’s word, O Zedekiah king of Judah: Yahweh says concerning you, ‘You won’t die by the sword.', pt: 'Todavia ouve a palavra do Senhor, ó Zedequias, rei de Judá; assim diz o Senhor acerca de ti: Não morrerás à espada;' },
      { v: 5, en: 'You will die in peace; and with the burnings of your fathers, the former kings who were before you, so they will make a burning for you. They will lament you, saying, “Ah Lord!” for I have spoken the word,’ says Yahweh.”', pt: 'em paz morrerás, e como queimavam perfumes a teus pais, os reis precedentes, que foram antes de ti, assim tos queimarão a ti; e te prantearão, dizendo: Ah Senhor! Pois eu disse a palavra, diz o Senhor.' },
      { v: 6, en: 'Then Jeremiah the prophet spoke all these words to Zedekiah king of Judah in Jerusalem,', pt: 'E anunciou Jeremias, o profeta, a Zedequias, rei de Judá, todas estas palavras, em Jerusalém,' },
      { v: 7, en: 'when the king of Babylon’s army was fighting against Jerusalem, and against all the cities of Judah that were left, against Lachish and against Azekah; for these alone remained of the cities of Judah as fortified cities.', pt: 'quando o exército do rei de Babilônia pelejava contra Jerusalém, e contra todas as cidades de Judá, que ficaram de resto, contra Laquis e contra Azeca; porque dentre as cidades de Judá, só estas haviam ficado como cidades fortificadas.' },
      { v: 8, en: 'The word came to Jeremiah from Yahweh, after king Zedekiah had made a covenant with all the people who were at Jerusalem, to proclaim liberty to them;', pt: 'A palavra que da parte do Senhor veio a Jeremias, depois que o rei Zedequias fez um pacto com todo o povo que estava em Jerusalém, para lhe fazer proclamação de liberdade,' },
      { v: 9, en: 'that every man should let his male servant, and every man his female servant, who is a Hebrew or a Hebrewess, go free; that no one should make bondservants of them, of a Jew his brother.', pt: 'para que cada um libertasse o seu escravo, e cada um a sua escrava, hebreu ou hebréia, de maneira que ninguém se servisse mais dos judeus, seus irmãos, como escravos.' },
      { v: 10, en: 'All the princes and all the people obeyed who had entered into the covenant, that everyone should let his male servant, and everyone his female servant go free, that no one should make bondservants of them any more. They obeyed and let them go;', pt: 'E obedeceram todos os príncipes e todo o povo que haviam entrado no pacto de libertarem cada qual o seu escravo, e cada qual a sua escrava, de maneira a não se servirem mais deles, sim, obedeceram e os libertaram.' },
      { v: 11, en: 'but afterwards they turned, and caused the servants and the handmaids, whom they had let go free, to return, and brought them into subjection for servants and for handmaids.', pt: 'Mas depois se arrependeram, e fizeram voltar os escravos e as escravas que haviam libertado, e tornaram a escravizá-los.' },
      { v: 12, en: 'Therefore Yahweh’s word came to Jeremiah from Yahweh, saying,', pt: 'Veio, pois, a palavra do Senhor a Jeremias, da parte do Senhor, dizendo:' },
      { v: 13, en: '“Yahweh, the God of Israel, says: ‘I made a covenant with your fathers in the day that I brought them out of the land of Egypt, out of the house of bondage, saying,', pt: 'Assim diz o Senhor, Deus de Israel: Eu fiz um pacto com vossos pais, no dia em que os tirei da terra do Egito, da casa da servidão, dizendo:' },
      { v: 14, en: 'At the end of seven years, every man of you shall release his brother who is a Hebrew, who has been sold to you, and has served you six years. You shall let him go free from you; but your fathers didn’t listen to me, and didn’t incline their ear.', pt: 'Ao fim de sete anos libertareis cada um a seu irmão hebreu, que te for vendido, e te houver servido seis anos, e despedi-lo-ás livre de ti; mas vossos pais não me ouviram, nem inclinaram os seus ouvidos.' },
      { v: 15, en: 'You had now turned, and had done that which is right in my eyes, in every man proclaiming liberty to his neighbor. You had made a covenant before me in the house which is called by my name;', pt: 'E vos havíeis hoje arrependido, e tínheis feito o que é reto aos meus olhos, proclamando liberdade cada um ao seu próximo; e tínheis feito diante de mim um pacto, na casa que se chama pelo meu nome;' },
      { v: 16, en: 'but you turned and profaned my name, and every man caused his servant, and every man his handmaid, whom you had let go free at their pleasure, to return. You brought them into subjection, to be to you for servants and for handmaids.’”', pt: 'mudastes, porém, e profanastes o meu nome, e fizestes voltar cada um o seu escravo, e cada um a sua escrava, que havíeis deixado ir livres à vontade deles; e os sujeitastes de novo à servidão.' },
      { v: 17, en: 'Therefore Yahweh says: “You have not listened to me, to proclaim liberty, every man to his brother, and every man to his neighbor. Behold, I proclaim to you a liberty,” says Yahweh, “to the sword, to the pestilence, and to the famine. I will make you be tossed back and forth among all the kingdoms of the earth.', pt: 'Portanto assim diz o Senhor: Vós não me ouvistes a mim, para proclamardes a liberdade, cada um ao seu irmão, e cada um ao seu próximo. Eis, pois, que eu vos proclamo a liberdade, diz o Senhor, para a espada, para a peste e para a fome; e farei que sejais um espetáculo de terror a todos os reinos da terra.' },
      { v: 18, en: 'I will give the men who have transgressed my covenant, who have not performed the words of the covenant which they made before me, when they cut the calf in two and passed between its parts:', pt: 'Entregarei os homens que traspassaram o meu pacto, e não cumpriram as palavras do pacto que fizeram diante de mim com o bezerro que dividiram em duas partes, passando pelo meio das duas porções -' },
      { v: 19, en: 'the princes of Judah, the princes of Jerusalem, the eunuchs, the priests, and all the people of the land, who passed between the parts of the calf;', pt: 'os príncipes de Judá, os príncipes de Jerusalém, os eunucos, os sacerdotes, e todo o povo da terra, os mesmos que passaram pelo meio das porções do bezerro,' },
      { v: 20, en: 'I will even give them into the hand of their enemies, and into the hand of those who seek their life. Their dead bodies will be food for the birds of the sky and for the animals of the earth.', pt: 'entregá-los-ei, digo, na mão de seus inimigos, e na mão dos que procuram a sua morte. Os cadáveres deles servirão de pasto para as aves do céu e para os animais da terra.' },
      { v: 21, en: '“I will give Zedekiah king of Judah and his princes into the hands of their enemies, into the hands of those who seek their life and into the hands of the king of Babylon’s army, who has gone away from you.', pt: 'E a Zedequias, rei de Judá, e seus príncipes entregarei na mão de seus inimigos e na mão dos que procuram a sua morte, e na mão do exército do rei de Babilônia, os quais já se retiraram de vós.' },
      { v: 22, en: 'Behold, I will command,” says Yahweh, “and cause them to return to this city. They will fight against it, take it, and burn it with fire. I will make the cities of Judah a desolation, without inhabitant.”', pt: 'Eis que eu darei ordem, diz o Senhor, e os farei tornar a esta cidade, e pelejarão contra ela, e a tomarão, e a queimarão a fogo; e das cidades de Judá farei uma assolação, de sorte que ninguém habite nelas.' },
    ],
    35: [
      { v: 1, en: 'The word which came to Jeremiah from Yahweh in the days of Jehoiakim the son of Josiah, king of Judah, saying,', pt: 'A palavra que da parte do Senhor veio a Jeremias, nos dias de Jeoiaquim, filho de Josias, rei de Judá, dizendo:' },
      { v: 2, en: '“Go to the house of the Rechabites, and speak to them, and bring them into Yahweh’s house, into one of the rooms, and give them wine to drink.”', pt: 'Vai à casa dos recabitas, e fala com eles, introduzindo-os na casa do Senhor, em uma das câmaras, e lhes oferece vinho a beber.' },
      { v: 3, en: 'Then I took Jaazaniah the son of Jeremiah, the son of Habazziniah, with his brothers, all his sons, and the whole house of the Rechabites;', pt: 'Então tomei a Jaazanias, filho de Jeremias, filho de Habazínias, e a seus irmãos, e a todos os seus filhos, e a toda a casa dos recabitas,' },
      { v: 4, en: 'and I brought them into Yahweh’s house, into the room of the sons of Hanan the son of Igdaliah, the man of God, which was by the room of the princes, which was above the room of Maaseiah the son of Shallum, the keeper of the threshold.', pt: 'e os introduzi na casa do Senhor, na câmara dos filhos de Hanã, filho de Jigdalias, homem de Deus, a qual estava junto à câmara dos príncipes que ficava sobre a câmara de Maaséias, filho de Salum, guarda do vestíbulo;' },
      { v: 5, en: 'I set before the sons of the house of the Rechabites bowls full of wine, and cups; and I said to them, “Drink wine!”', pt: 'e pus diante dos filhos da casa dos recabitas taças cheias de vinho, e copos, e disse-lhes: Bebei vinho.' },
      { v: 6, en: 'But they said, “We will drink no wine; for Jonadab the son of Rechab, our father, commanded us, saying, ‘You shall drink no wine, neither you, nor your sons, forever.', pt: 'Eles, porém, disseram: Não beberemos vinho, porque Jonadabe, filho de Recabe, nosso pai, nos ordenou, dizendo: Nunca jamais bebereis vinho, nem vós nem vossos filhos;' },
      { v: 7, en: 'You shall not build a house, sow seed, plant a vineyard, or have any; but all your days you shall dwell in tents, that you may live many days in the land in which you live as nomads.’', pt: 'não edificareis casa, nem semeareis semente, nem plantareis vinha, nem a possuireis; mas habitareis em tendas todos os vossos dias; para que vivais muitos dias na terra em que andais peregrinando.' },
      { v: 8, en: 'We have obeyed the voice of Jonadab the son of Rechab, our father, in all that he commanded us, to drink no wine all our days, we, our wives, our sons, or our daughters;', pt: 'Obedecemos pois à voz de Jonadabe, filho de Recabe, nosso pai, em tudo quanto nos ordenou, de não bebermos vinho em todos os nossos dias, nem nós, nem nossas mulheres, nem nossos filhos, nem nossas filhas;' },
      { v: 9, en: 'and not to build houses for ourselves to dwell in. We have no vineyard, field, or seed;', pt: 'nem de edificarmos casas para nossa habitação; nem de possuirmos vinha, nem campo, nem semente;' },
      { v: 10, en: 'but we have lived in tents, and have obeyed, and done according to all that Jonadab our father commanded us.', pt: 'mas habitamos em tendas, e assim obedecemos e fazemos conforme tudo quanto nos ordenou Jonadabe, nosso pai.' },
      { v: 11, en: 'But when Nebuchadnezzar king of Babylon came up into the land, we said, ‘Come, and let us go to Jerusalem for fear of the army of the Chaldeans, and for fear of the army of the Syrians; so we will dwell at Jerusalem.’”', pt: 'Sucedeu, porém, que, quando subia Nabucodonozor, rei de Babilônia, contra esta terra, dissemos: Vinde, e vamo-nos a Jerusalém, por causa do exército dos caldeus, e por causa do exército dos sírios; e assim habitamos em Jerusalém.' },
      { v: 12, en: 'Then Yahweh’s word came to Jeremiah, saying,', pt: 'Então veio a palavra do Senhor a Jeremias, dizendo:' },
      { v: 13, en: '“Yahweh of Armies, the God of Israel, says: ‘Go and tell the men of Judah and the inhabitants of Jerusalem, “Will you not receive instruction to listen to my words?” says Yahweh.', pt: 'Assim diz o Senhor dos exércitos, o Deus de Israel: Vai, e dize aos homens de Judá e aos moradores de Jerusalém: Acaso não aceitareis instrução, para ouvirdes as minhas palavras? diz o Senhor.' },
      { v: 14, en: '“The words of Jonadab the son of Rechab that he commanded his sons, not to drink wine, are performed; and to this day they drink none, for they obey their father’s commandment; but I have spoken to you, rising up early and speaking, and you have not listened to me.', pt: 'As palavras de Jonadabe, filho de Recabe, pelas quais ordenou a seus filhos que não bebessem vinho, foram guardadas; pois não o têm bebido até o dia de hoje, porque obedecem o mandamento de seu pai; a mim, porém, que vos tenho falado a vós, com insistência, vós não me ouvistes.' },
      { v: 15, en: 'I have sent also to you all my servants the prophets, rising up early and sending them, saying, ‘Every one of you must return now from his evil way, amend your doings, and don’t go after other gods to serve them, then you will dwell in the land which I have given to you and to your fathers:’ but you have not inclined your ear, nor listened to me.', pt: 'Também vos tenho enviado, insistentemente, todos os meus servos, os profetas, dizendo: Convertei-vos agora, cada um do seu mau caminho, e emendai as vossas ações, e não vades após outros deuses para os servir, e assim habitareis na terra que vos dei a vós e a vossos pais; mas não inclinastes o vosso ouvido, nem me obedecestes a mim.' },
      { v: 16, en: 'The sons of Jonadab the son of Rechab have performed the commandment of their father which he commanded them, but this people has not listened to me.”’', pt: 'Os filhos de Jonadabe, filho de Recabe, guardaram o mandamento de seu pai que ele lhes ordenou, mas este povo não me obedeceu;' },
      { v: 17, en: '“Therefore Yahweh, the God of Armies, the God of Israel, says: ‘Behold, I will bring on Judah and on all the inhabitants of Jerusalem all the evil that I have pronounced against them; because I have spoken to them, but they have not heard; and I have called to them, but they have not answered.’”', pt: 'por isso assim diz o Senhor, o Deus dos exércitos, o Deus de Israel: Eis que trarei sobre Judá, e sobre todos os moradores de Jerusalem, todo o mal que pronunciei contra eles; pois lhes tenho falado, e não ouviram; e clamei a eles, e não responderam.' },
      { v: 18, en: 'Jeremiah said to the house of the Rechabites, “Yahweh of Armies, the God of Israel, says: ‘Because you have obeyed the commandment of Jonadab your father, and kept all his precepts, and done according to all that he commanded you;’', pt: 'E à casa dos recabitas disse Jeremias: Assim diz o Senhor dos exércitos, o Deus de Israel: Pois que obedecestes ao mandamento de Jonadabe, vosso pai, guardando todos os seus mandamentos e fazendo conforme tudo quanto vos ordenou;' },
      { v: 19, en: 'therefore Yahweh of Armies, the God of Israel, says: ‘Jonadab the son of Rechab will not lack a man to stand before me forever.’”', pt: 'portanto assim diz o Senhor dos exércitos, Deus de tsrael: Nunca jamais faltará varão a Jonadabe, filho de Recabe, que assista diante de mim.' },
    ],
    36: [
      { v: 1, en: 'In the fourth year of Jehoiakim the son of Josiah, king of Judah, this word came to Jeremiah from Yahweh, saying,', pt: 'Sucedeu pois no ano quarto de Jeoiaquim, filho de Josias, rei de Judá, que da parte do Senhor veio esta palavra a Jeremias, dizendo:' },
      { v: 2, en: '“Take a scroll of a book, and write in it all the words that I have spoken to you against Israel, and against Judah, and against all the nations, from the day I spoke to you, from the days of Josiah, even to this day.', pt: 'Toma o rolo dum livro, e escreve nele todas as palavras que te hei falado contra Israel, contra Judá e contra todas as nações, desde o dia em que eu te falei, desde os dias de Josias até o dia de hoje.' },
      { v: 3, en: 'It may be that the house of Judah will hear all the evil which I intend to do to them; that they may each return from his evil way; that I may forgive their iniquity and their sin.”', pt: 'Ouvirão talvez os da casa de Judá todo o mal que eu intento fazer-lhes; para que cada qual se converta do seu mau caminho, a fim de que eu perdoe a sua iniqüidade e o seu pecado.' },
      { v: 4, en: 'Then Jeremiah called Baruch the son of Neriah; and Baruch wrote from the mouth of Jeremiah all Yahweh’s words, which he had spoken to him, on a scroll of a book.', pt: 'Então Jeremias chamou a Baruque, filho de Nerias; e escreveu Baruque, no rolo dum livro, enquanto Jeremias lhas ditava, todas as palavras que o Senhor lhe havia falado.' },
      { v: 5, en: 'Jeremiah commanded Baruch, saying, “I am restricted. I can’t go into Yahweh’s house.', pt: 'E Jeremias deu ordem a Banique, dizendo: Eu estou impedido; não posso entrar na casa do Senhor.' },
      { v: 6, en: 'Therefore you go, and read from the scroll which you have written from my mouth, Yahweh’s words, in the ears of the people in Yahweh’s house on the fast day. Also you shall read them in the ears of all Judah who come out of their cities.', pt: 'Entra pois tu e, pelo rolo que escreveste enquanto eu ditava, lê as palavras do Senhor aos ouvidos do povo, na casa do Senhor, no dia de jejum; e também as lerás aos ouvidos de todo o Judá que vem das suas cidades.' },
      { v: 7, en: 'It may be they will present their supplication before Yahweh, and will each return from his evil way; for Yahweh has pronounced great anger and wrath against this people.”', pt: 'Pode ser que caia a sua súplica diante do Senhor, e se converta cada um do seu mau caminho; pois grande é a ira e o furor que o Senhor tem manifestado contra este povo.' },
      { v: 8, en: 'Baruch the son of Neriah did according to all that Jeremiah the prophet commanded him, reading in the book Yahweh’s words in Yahweh’s house.', pt: 'E fez Baruque, filho de Nerias, conforme tudo quanto lhe havia ordenado Jeremias, o profeta, lendo no livro as palavras do Senhor na casa do Senhor.' },
      { v: 9, en: 'Now in the fifth year of Jehoiakim the son of Josiah, king of Judah, in the ninth month, all the people in Jerusalem, and all the people who came from the cities of Judah to Jerusalem, proclaimed a fast before Yahweh.', pt: 'No quinto ano de Jeoiaquim, filho de Josias, rei de Judá, no mês nono, todo o povo em Jerusalém, como também todo o povo que vinha das cidades de Judá a Jerusalém, apregoaram um jejum diante do Senhor.' },
      { v: 10, en: 'Then Baruch read the words of Jeremiah from the book in Yahweh’s house, in the room of Gemariah the son of Shaphan, the scribe, in the upper court, at the entry of the new gate of Yahweh’s house, in the ears of all the people.', pt: 'Leu, pois, Banique no livro as palavras de Jeremias, na casa do Senhor, na câmara de Gemarias, filho de Safã, o escriba, no átrio superior, à entrada da porta nova da casa do Senhor, aos ouvidos de todo o povo.' },
      { v: 11, en: 'When Micaiah the son of Gemariah, the son of Shaphan, had heard out of the book all Yahweh’s words,', pt: 'E, ouvindo Micaías, filho de Gemarias, filho de Safã, todas as palavras do Senhor, naquele livro,' },
      { v: 12, en: 'he went down into the king’s house, into the scribe’s room: and behold, all the princes were sitting there, Elishama the scribe, Delaiah the son of Shemaiah, Elnathan the son of Achbor, Gemariah the son of Shaphan, Zedekiah the son of Hananiah, and all the princes.', pt: 'desceu à casa do rei, à câmara do escriba. E eis que todos os príncipes estavam ali assentados: Elisama, o escriba, e Delaías, filho de Semaías, e Elnatã, filho de Acbor, e Gemarias, filho de Safã, e Zedequias, filho de Hananias, e todos os outros príncipes.' },
      { v: 13, en: 'Then Micaiah declared to them all the words that he had heard, when Baruch read the book in the ears of the people.', pt: 'E Micaías anunciou-lhes todas as palavras que ouvira, quando Baruque leu o livro aos ouvidos do povo.' },
      { v: 14, en: 'Therefore all the princes sent Jehudi the son of Nethaniah, the son of Shelemiah, the son of Cushi, to Baruch, saying, “Take in your hand the scroll in which you have read in the ears of the people, and come.” So Baruch the son of Neriah took the scroll in his hand, and came to them.', pt: 'Então todos os príncipes mandaram Jeúdi, filho de Netanias, filho Selemias, filho de Cuche, a Baruque, para lhe dizer: O rolo que leste aos ouvidos do povo, toma-o na tua mão, e vem. E Banique, filho de Nerias, tomou o rolo na sua mão, e foi ter com eles.' },
      { v: 15, en: 'They said to him, “Sit down now, and read it in our hearing.” So Baruch read it in their hearing.', pt: 'E disseram-lhe: Assenta-te agora, e lê-o aos nossos ouvidos. E Baruque o leu aos ouvidos deles.' },
      { v: 16, en: 'Now when they had heard all the words, they turned in fear one toward another, and said to Baruch, “We will surely tell the king of all these words.”', pt: 'Ouvindo eles todas aquelas palavras, voltaram-se temerosos uns para os outros, e disseram a Banique: Sem dúvida alguma temos que anunciar ao rei todas estas palavras.' },
      { v: 17, en: 'They asked Baruch, saying, “Tell us now, how did you write all these words at his mouth?”', pt: 'E disseram a Baruque: Declara-nos agora como escreveste todas estas palavras. Ele as ditava?' },
      { v: 18, en: 'Then Baruch answered them, “He dictated all these words to me with his mouth, and I wrote them with ink in the book.”', pt: 'E disse-lhes Baruque: Sim, da sua boca ele me ditava todas estas palavras, e eu com tinta as escrevia no livro.' },
      { v: 19, en: 'Then the princes said to Baruch, “You and Jeremiah go hide. Don’t let anyone know where you are.”', pt: 'Então disseram os príncipes a Banique: Vai, esconde-te tu e Jeremias; e ninguém saiba onde estais.' },
      { v: 20, en: 'They went in to the king into the court; but they had laid up the scroll in the room of Elishama the scribe. Then they told all the words in the hearing of the king.', pt: 'E foram ter com o rei ao átrio; mas depositaram o rolo na câmara de Elisama, o escriba, e anunciaram aos ouvidos do rei todas aquelas palavras.' },
      { v: 21, en: 'So the king sent Jehudi to get the scroll; and he took it out of the room of Elishama the scribe. Jehudi read it in the hearing of the king, and in the hearing of all the princes who stood beside the king.', pt: 'Então enviou o rei a Jeúdi para trazer o rolo; e Jeúdi tomou-o da câmara de Elisama, o escriba, e o leu aos ouvidos do rei e aos ouvidos de todos os príncipes que estavam em torno do rei.' },
      { v: 22, en: 'Now the king was sitting in the winter house in the ninth month; and there was a fire in the brazier burning before him.', pt: 'Ora, era o nono mês e o rei estava assentado na casa de inverno, e diante dele estava um braseiro aceso.' },
      { v: 23, en: 'When Jehudi had read three or four leaves, the king cut it with the penknife, and cast it into the fire that was in the brazier, until all the scroll was consumed in the fire that was in the brazier.', pt: 'E havendo Jeúdi lido três ou quatro colunas, o rei as cortava com o canivete do escrivão, e as lançava no fogo que havia no braseiro, até que todo o rolo se consumiu no fogo que estava sobre o braseiro.' },
      { v: 24, en: 'The king and his servants who heard all these words were not afraid, and didn’t tear their garments.', pt: 'E não temeram, nem rasgaram os seus vestidos, nem o rei nem nenhum dos seus servos que ouviram todas aquelas palavras' },
      { v: 25, en: 'Moreover Elnathan and Delaiah and Gemariah had made intercession to the king that he would not burn the scroll; but he would not listen to them.', pt: 'e, posto que Elnatã, Delaías e Gema rias tivessem insistido com o rei que não queimasse o rolo, contudo ele não lhes deu ouvidos.' },
      { v: 26, en: 'The king commanded Jerahmeel the king’s son, and Seraiah the son of Azriel, and Shelemiah the son of Abdeel, to arrest Baruch the scribe and Jeremiah the prophet; but Yahweh hid them.', pt: 'Antes deu ordem o rei a Jerameel, filho do rei, e a Seraías, filho de Azriel, e a Selemias, filho de Abdeel, que prendessem a Baruque, o escrivão, e a Jeremias, o profeta; mas o Senhor os escondera.' },
      { v: 27, en: 'Then Yahweh’s word came to Jeremiah, after the king had burned the scroll, and the words which Baruch wrote at the mouth of Jeremiah, saying,', pt: 'Depois que o rei queimara o rolo com as palavras que Banique escrevera da boca de Jeremias, veio a Jeremias a palavra do Senhor, dizendo:' },
      { v: 28, en: '“Take again another scroll, and write in it all the former words that were in the first scroll, which Jehoiakim the king of Judah has burned.', pt: 'Toma ainda outro rolo, e escreve nele todas aquelas palavras que estavam no primeiro rolo, que Jeoiaquim, rei de Judá, queimou.' },
      { v: 29, en: 'Concerning Jehoiakim king of Judah you shall say, ‘Yahweh says: “You have burned this scroll, saying, “Why have you written therein, saying, ‘The king of Babylon will certainly come and destroy this land, and will cause to cease from there man and animal?’”’', pt: 'E a Jeoiaquim, rei de Judá, dirás: Assim diz o Senhor: Tu queimaste este rolo, dizendo: Por que escreveste nele anunciando: Certamente virá o rei da Babilônia, e destruirá esta terra e fará cessar nela homens e animais?,' },
      { v: 30, en: 'Therefore Yahweh says concerning Jehoiakim king of Judah: “He will have no one to sit on David’s throne. His dead body will be cast out in the day to the heat, and in the night to the frost.', pt: 'Portanto assim diz o Senhor acerca de Jeoiaquim, rei de Judá: Não terá quem se assente sobre o trono de Davi, e será lançado o seu cadáver ao calor de dia, e à geada de noite.' },
      { v: 31, en: 'I will punish him, his offspring, and his servants for their iniquity. I will bring on them, on the inhabitants of Jerusalem, and on the men of Judah, all the evil that I have pronounced against them, but they didn’t listen.”’”', pt: 'E castigá-lo-ei a ele, e a sua descendência e os seus servos, por causa da sua iniqüidade; e trarei sobre ele e sobre os moradores de Jerusalém, e sobre os homens de Judá, todo o mal que tenho pronunciado contra eles, e que não ouviram.' },
      { v: 32, en: 'Then took Jeremiah another scroll, and gave it to Baruch the scribe, the son of Neriah, who wrote therein from the mouth of Jeremiah all the words of the book which Jehoiakim king of Judah had burned in the fire; and many similar words were added to them.', pt: 'Tomou, pois, Jeremias outro rolo, e o deu a Baruque, filho de Nerias, o escrivão, o qual escreveu nele, enquanto Jeremias ditava, todas as palavras do livro que Jeoiaquim, rei de Judá, tinha queimado no fogo; e ainda se lhes acrescentaram muitas palavras semelhantes.' },
    ],
    37: [
      { v: 1, en: 'Zedekiah the son of Josiah reigned as king, instead of Coniah the son of Jehoiakim, whom Nebuchadnezzar king of Babylon made king in the land of Judah.', pt: 'E Zedequias, filho de Josias, a quem Nabucodonozor, rei de Babilônia, constituiu rei na terra de Judá, reinou em lugar de Conias, filho de Jeoiaquim.' },
      { v: 2, en: 'But neither he, nor his servants, nor the people of the land, listened to Yahweh’s words, which he spoke by the prophet Jeremiah.', pt: 'Mas nem ele, nem os seus servos, nem o povo da terra escutaram as palavras do Senhor que este falou por intermédio de Jeremias o profeta.' },
      { v: 3, en: 'Zedekiah the king sent Jehucal the son of Shelemiah, and Zephaniah the son of Maaseiah, the priest, to the prophet Jeremiah, saying, “Pray now to Yahweh our God for us.”', pt: 'Contudo mandou o rei Zedequias a Jeucal filho de Selemias, e a Sofonias, filho de Maaséias, o sacerdote, ao profeta Jeremias, para lhe dizerem: Roga agora por nós ao Senhor nosso Deus,' },
      { v: 4, en: 'Now Jeremiah came in and went out among the people; for they had not put him into prison.', pt: 'Ora, Jeremias entrava e saía entre o povo; pois ainda não o tinham encerrado na prisão.' },
      { v: 5, en: 'Pharaoh’s army had come out of Egypt; and when the Chaldeans who were besieging Jerusalem heard news of them, they broke up from Jerusalem.', pt: 'E o exército de Faraó saíra do Egito; quando, pois, os caldeus que estavam sitiando Jerusalém, ouviram esta notícia, retiraram-se de Jerusalém.' },
      { v: 6, en: 'Then Yahweh’s word came to the prophet Jeremiah, saying,', pt: 'Então veio a Jeremias, o profeta, a palavra do Senhor, dizendo:' },
      { v: 7, en: '“Yahweh, the God of Israel, says, ‘You shall tell the king of Judah, who sent you to me to inquire of me: “Behold, Pharaoh’s army, which has come out to help you, will return to Egypt into their own land.', pt: 'Assim diz o Senhor, Deus de Israel: Assim direis ao rei de Judá, que vos enviou a mim, para me consultar: Eis que o exército de Faraó, que saiu em vosso socorro, voltará para a sua terra no Egito.' },
      { v: 8, en: 'The Chaldeans will come again, and fight against this city. They will take it and burn it with fire.”’', pt: 'E voltarão os caldeus, e pelejarão contra esta cidade, e a tomarão, e a queimarão a fogo.' },
      { v: 9, en: '“Yahweh says, ‘Don’t deceive yourselves, saying, “The Chaldeans will surely depart from us;” for they will not depart.', pt: 'Assim diz o Senhor: Não vos enganeis a vós mesmos, dizendo: Sem dúvida os caldeus se retirarão de nós; pois não se retirarão.' },
      { v: 10, en: 'For though you had struck the whole army of the Chaldeans who fight against you, and there remained but wounded men among them, yes they would each rise up in his tent and burn this city with fire.’”', pt: 'Porque ainda que derrotásseis a todo o exército dos caldeus que peleja contra vós, e entre eles só ficassem homens feridos, contudo se levantariam, cada um na sua tenda, e queimariam a fogo esta cidade.' },
      { v: 11, en: 'When the army of the Chaldeans had broken up from Jerusalem for fear of Pharaoh’s army,', pt: 'Ora, quando se retirou de Jerusalém o exército dos caldeus, por causa do exército de Iearaó,' },
      { v: 12, en: 'then Jeremiah went out of Jerusalem to go into the land of Benjamin, to receive his portion there, in the middle of the people.', pt: 'saiu Jeremias de Jerusalém, a fim de ir à terra de Benjamim, para receber ali a sua parte no meio do povo.' },
      { v: 13, en: 'When he was in Benjamin’s gate, a captain of the guard was there, whose name was Irijah, the son of Shelemiah, the son of Hananiah; and he seized Jeremiah the prophet, saying, “You are defecting to the Chaldeans!”', pt: 'E quando ele estava à porta de Benjamim, achava-se ali um capitão da guarda, cujo nome era Jurias, filho de Selemias, filho de Hananias, o qual prendeu a Jeremias, o profeta, dizendo: Tu estás desertando para os caldeus.' },
      { v: 14, en: 'Then Jeremiah said, “That is false! I am not defecting to the Chaldeans.” But he didn’t listen to him; so Irijah siezed Jeremiah, and brought him to the princes.', pt: 'E Jeremias disse: Isso é falso, não estou desertando para os caldeus. Mas ele não lhe deu ouvidos, de modo que prendeu a Jeremias e o levou aos príncipes.' },
      { v: 15, en: 'The princes were angry with Jeremiah, and struck him, and put him in prison in the house of Jonathan the scribe; for they had made that the prison.', pt: 'E os príncipes ficaram muito irados contra Jeremias, de sorte que o açoitaram e o meteram no cárcere, na casa de Jônatas, o escrivão, porquanto a tinham transformado em cárcere.' },
      { v: 16, en: 'When Jeremiah had come into the dungeon house, and into the cells, and Jeremiah had remained there many days,', pt: 'Tendo Jeremias entrado nas celas do calabouço, e havendo ficado ali muitos dias,' },
      { v: 17, en: 'then Zedekiah the king sent, and had him brought out. The king asked him secretly in his house, “Is there any word from Yahweh?” Jeremiah said, “There is.” He also said, “You will be delivered into the hand of the king of Babylon.”', pt: 'o rei Zedequias mandou soltá-lo e lhe perguntou em sua casa, em segredo: Há alguma palavra da parte do Senhor? Respondeu Jeremias: Há. E acrescentou: Na mão do rei de Babilônia serás entregue.' },
      { v: 18, en: 'Moreover Jeremiah said to king Zedekiah, “How have I sinned against you, against your servants, or against this people, that you have put me in prison?', pt: 'Disse mais Jeremias ao rei Zedequias: Em que tenho pecado contra ti, e contra os teus servos, e contra este povo, para que me pusésseis na prisão?' },
      { v: 19, en: 'Now where are your prophets who prophesied to you, saying, ‘The king of Babylon will not come against you, nor against this land?’', pt: 'Onde estão agora os vossos profetas que vos profetizavam, dizendo: O rei de Babilônia não virá contra vós nem contra esta terra?' },
      { v: 20, en: 'Now please hear, my lord the king: please let my supplication be presented before you, that you not cause me to return to the house of Jonathan the scribe, lest I die there.”', pt: 'Ora, pois, ouve agora, ó rei, meu senhor: seja aceita agora a minha súplica diante de ti; não me faças tornar à casa de Jônatas, o escriba, para que eu não venha a morrer ali.' },
      { v: 21, en: 'Then Zedekiah the king commanded, and they committed Jeremiah into the court of the guard. They gave him daily a loaf of bread out of the bakers’ street, until all the bread in the city was gone. Thus Jeremiah remained in the court of the guard.', pt: 'Então ordenou o rei Zedequias que pusessem a Jeremias no átrio da guarda; e deram-lhe um bolo de pão cada dia, da rua dos padeiros, até que se gastou todo o pão da cidade. Assim ficou Jeremias no átrio da guarda.' },
    ],
    38: [
      { v: 1, en: 'Shephatiah the son of Mattan, and Gedaliah the son of Pashhur, and Jucal the son of Shelemiah, and Pashhur the son of Malchijah, heard the words that Jeremiah spoke to all the people, saying,', pt: 'Ouviram, pois, Sefatias, filho de Matã, e Gedalias, filho de Pasur, e Jeucal, filho de Selemias, e Pasur, filho de Malquias, as palavras que anunciava Jeremias a todo o povo, dizendo:' },
      { v: 2, en: '“Yahweh says, ‘He who remains in this city will die by the sword, by the famine, and by the pestilence; but he who goes out to the Chaldeans will live, and he will escape with his life, and he will live.’', pt: 'Assim diz o Senhor: O que ficar nesta cidade morrerá à espada, de fome e de peste; mas o que sair para os caldeus viverá; pois a sa vida lhe será por despojo, e vivera.' },
      { v: 3, en: 'Yahweh says, ‘This city will surely be given into the hand of the army of the king of Babylon, and he will take it.’”', pt: 'Assim diz o Senhor: Esta cidade infalivelmente será entregue na mão do exército do rei de Babilônia, e ele a tomará.' },
      { v: 4, en: 'Then the princes said to the king, “Please let this man be put to death; because he weakens the hands of the men of war who remain in this city, and the hands of all the people, in speaking such words to them: for this man doesn’t seek the welfare of this people, but harm.”', pt: 'E disseram os príncipes ao rei: Morra este homem, visto que ele assim enfraquece as mãos dos homens de guerra que restam nesta cidade, e as mãos de todo o povo, dizendo-lhes tais palavras; porque este homem não busca a paz para este povo, porem o seu mal.' },
      { v: 5, en: 'Zedekiah the king said, “Behold, he is in your hand; for the king can’t do anything to oppose you.”', pt: 'E disse o rei Zedequias: Eis que ele está na vossa mão; porque não é o rei que possa coisa alguma contra vós.' },
      { v: 6, en: 'Then took they Jeremiah and threw him into the dungeon of Malchijah the king’s son, that was in the court of the guard. They let down Jeremiah with cords. In the dungeon there was no water, but mire; and Jeremiah sank in the mire.', pt: 'Então tomaram a Jeremias, e o lançaram na cisterna de Malquias, filho do rei, que estava no átrio da guarda; e desceram Jeremias com cordas; mas na cisterna não havia água, senão lama, e atolou-se Jeremias na lama.' },
      { v: 7, en: 'Now when Ebedmelech the Ethiopian, a eunuch, who was in the king’s house, heard that they had put Jeremiah in the dungeon (the king was then sitting in Benjamin’s gate),', pt: 'Quando Ebede-Meleque, o etíope, um eunuco que então estava na casa do rei, ouviu que tinham metido Jeremias na cisterna, o rei estava assentado à porta de Benjamim.' },
      { v: 8, en: 'Ebedmelech went out of the king’s house, and spoke to the king, saying,', pt: 'Saiu, pois, Ebede-Meleque da casa do rei, e falou ao rei, dizendo:' },
      { v: 9, en: '“My lord the king, these men have done evil in all that they have done to Jeremiah the prophet, whom they have cast into the dungeon. He is likely to die in the place where he is, because of the famine; for there is no more bread in the city.”', pt: 'o rei, senhor meu, estes homens fizeram mal em tudo quanto fizeram a Jeremias, o profeta, lançando-o na cisterna; de certo morrerá no lugar onde se acha, por causa da fome, pois não há mais pão na cidade.' },
      { v: 10, en: 'Then the king commanded Ebedmelech the Ethiopian, saying, “Take from here thirty men with you, and take up Jeremiah the prophet out of the dungeon, before he dies.”', pt: 'Deu ordem, então, o rei a Ebede-Meleque, o etíope, dizendo: Toma contigo daqui três homens, e tira Jeremias, o profeta, da cisterna, antes que morra.' },
      { v: 11, en: 'So Ebedmelech took the men with him, and went into the house of the king under the treasury, and took from there rags and worn-out garments, and let them down by cords into the dungeon to Jeremiah.', pt: 'Assim Ebede-Meleque tomou consigo os homens, e entrou na casa do rei, debaixo da tesouraria, e tomou dali uns trapos velhos e rotos, e roupas velhas, e desceu-os a Jeremias na cisterna por meio de cordas.' },
      { v: 12, en: 'Ebedmelech the Ethiopian said to Jeremiah, “Now put these rags and worn-out garments under your armpits under the cords.” Jeremiah did so.', pt: 'E disse Ebede-Meleque, o etíope, a Jeremias: Poe agora estes trapos velhos e rotos, debaixo dos teus sovacos, entre os braços e as cordas. E Jeremias assim o fez.' },
      { v: 13, en: 'So they drew up Jeremiah with the cords, and took him up out of the dungeon; and Jeremiah remained in the court of the guard.', pt: 'E tiraram Jeremias com as cordas, e o alçaram da cisterna; e ficou Jeremias no átrio da guarda.' },
      { v: 14, en: 'Then Zedekiah the king sent and took Jeremiah the prophet to himself into the third entry that is in Yahweh’s house. Then the king said to Jeremiah, “I will ask you something. Hide nothing from me.”', pt: 'Então mandou o rei Zedequias e fez vir à sua presença Jeremias, o profeta, à terceira entrada do templo do Senhor; e disse o rei a Jeremias: Vou perguntar-te uma coisa; não me encubras nada.' },
      { v: 15, en: 'Then Jeremiah said to Zedekiah, “If I declare it to you, will you not surely put me to death? If I give you counsel, you will not listen to me.”', pt: 'E disse Jeremias a Zedequias: Se eu ta declarar, acaso não me matarás? E se eu te aconselhar, não me ouvirás.' },
      { v: 16, en: 'So Zedekiah the king swore secretly to Jeremiah, saying, “As Yahweh lives, who made us this soul, I will not put you to death, neither will I give you into the hand of these men who seek your life.”', pt: 'Então jurou o rei Zedequias a Jeremias, em segredo, dizendo: Vive o Senhor, que nos fez esta alma, que não te matarei nem te entregarei na mão destes homens que procuram a tua morte.' },
      { v: 17, en: 'Then Jeremiah said to Zedekiah, “Yahweh, the God of Armies, the God of Israel, says: ‘If you will go out to the king of Babylon’s princes, then your soul will live, and this city will not be burned with fire. You will live, along with your house.', pt: 'Então Jeremias disse a Zedequias: Assim diz o Senhor, Deus dos exércitos, Deus de Israel: Se te renderes aos príncipes do rei de Babilônia, será poupada a tua vida, e esta cidade não se queimará a fogo, e viverás tu e a tua casa.' },
      { v: 18, en: 'But if you will not go out to the king of Babylon’s princes, then this city will be given into the hand of the Chaldeans, and they will burn it with fire, and you won’t escape out of their hand.’”', pt: 'Mas, se não saíres aos príncipes do rei de Babilônia, então será entregue esta cidade na mão dos caldeus, e eles a queimarão a fogo, e tu não escaparás da sua mão.' },
      { v: 19, en: 'Zedekiah the king said to Jeremiah, “I am afraid of the Jews who have defected to the Chaldeans, lest they deliver me into their hand, and they mock me.”', pt: 'E disse o rei Zedequias a Jeremias: Receio-me dos judeus que se passaram para os caldeus, que seja entregue na mão deles, e escarneçam de mim.' },
      { v: 20, en: 'But Jeremiah said, “They won’t deliver you. Obey, I beg you, Yahweh’s voice, in that which I speak to you; so it will be well with you, and your soul will live.', pt: 'Jeremias, porém, disse: Não te entregarão. Ouve, peço-te, a voz do Senhor, conforme a qual eu te falo; e bem te irá, e poupar-se-á a tua vida.' },
      { v: 21, en: 'But if you refuse to go out, this is the word that Yahweh has shown me:', pt: 'Mas, se tu recusares sair, esta é a palavra que me mostrou o Senhor:' },
      { v: 22, en: '‘Behold, all the women who are left in the king of Judah’s house will be brought out to the king of Babylon’s princes, and those women will say, “Your familiar friends have turned on you, and have prevailed over you. Your feet are sunk in the mire, they have turned away from you.”', pt: 'Eis que todas as mulheres que ficaram na casa do rei de Judá serão levadas aos príncipes do rei de Babilônia, e elas mesmas dirão: Os teus pacificadores te incitaram e prevaleceram contra ti; e agora que se atolaram os teus pés na lama, voltaram atrás.' },
      { v: 23, en: 'They will bring out all your wives and your children to the Chaldeans. You won’t escape out of their hand, but will be taken by the hand of the king of Babylon. You will cause this city to be burned with fire.’”', pt: 'Todas as tuas mulheres e os teus filhos serão levados para fora aos caldeus; e tu não escaparás da sua mão, mas pela mão do rei de Babilônia serás preso, e esta cidade será queimada a fogo.' },
      { v: 24, en: 'Then Zedekiah said to Jeremiah, “Let no man know of these words, and you won’t die.', pt: 'Então disse Zedequias a Jeremias: Ninguém saiba estas palavras, e não morrerás.' },
      { v: 25, en: 'But if the princes hear that I have talked with you, and they come to you, and tell you, ‘Declare to us now what you have said to the king; don’t hide it from us, and we will not put you to death; also tell us what the king said to you;’', pt: 'Se os príncipes ouvirem que falei contigo, e vierem ter contigo e te disserem: Declara-nos agora o que disseste ao rei e o que o rei te disse; não no-lo encubras, e não te mataremos;' },
      { v: 26, en: 'then you shall tell them, ‘I presented my supplication before the king, that he would not cause me to return to Jonathan’s house, to die there.’”', pt: 'então lhes dirás: Eu lancei a minha súplica diante do rei, que não me fizesse tornar à casa de Jônatas, para morrer ali.' },
      { v: 27, en: 'Then all the princes came to Jeremiah, and asked him; and he told them according to all these words that the king had commanded. So they stopped speaking with him; for the matter was not perceived.', pt: 'Então vieram todos os principes a Jeremias, e o interrogaram; e ele lhes respondeu conforme todas as palavras que o rei lhe havia ordenado; assim cessaram de falar com ele, pois a coisa não foi percebida.' },
      { v: 28, en: 'So Jeremiah stayed in the court of the guard until the day that Jerusalem was taken.', pt: 'E ficou Jeremias no átrio da guarda, até o dia em que Jerusalém foi tomada.' },
    ],
    39: [
      { v: 1, en: 'In the ninth year of Zedekiah king of Judah, in the tenth month, Nebuchadnezzar king of Babylon and all his army came against Jerusalem, and besieged it.', pt: 'No ano nono de Zedequias, rei de Judá, no décimo mês, veio Nabucodonozor, rei de Babilônia, e todo o seu exército contra Jerusalém, e a cercaram.' },
      { v: 2, en: 'In the eleventh year of Zedekiah, in the fourth month, the ninth day of the month, a breach was made in the city.', pt: 'No ano undécimo de Zedequias, no quarto mês, aos nove do mês, fez-se uma brecha na cidade.' },
      { v: 3, en: 'All the princes of the king of Babylon came in, and sat in the middle gate, Nergal Sharezer, Samgarnebo, Sarsechim, Rabsaris, Nergal Sharezer, Rabmag, with all the rest of the princes of the king of Babylon.', pt: 'E entraram todos os príncipes do rei de Babilônia, e sentaram-se na porta do meio, os quais eram Nergal-Sarezer, Sangar-Nebo, Sarsequim, Rabe-Sáris Nergal Sarezer, Rabe-Maque, juntamente, com todo o resto dos principes do rei de Babilônia' },
      { v: 4, en: 'When Zedekiah the king of Judah and all the men of war saw them, then they fled, and went out of the city by night, by the way of the king’s garden, through the gate between the two walls; and he went out toward the Arabah.', pt: 'E sucedeu que, vendo-os Zedequias, rei de Judá, e todos os homens de guerra, fugiram, saindo da cidade de noite pelo caminho do jardim do rei, pela porta entre os dois muros; e seguiram pelo caminho da Arabá.' },
      { v: 5, en: 'But the army of the Chaldeans pursued them, and overtook Zedekiah in the plains of Jericho. When they had taken him, they brought him up to Nebuchadnezzar king of Babylon to Riblah in the land of Hamath; and he pronounced judgment on him.', pt: 'Mas o exército dos caldeus os perseguiu; e eles alcançaram a Zedequias nas campinas de Jericó; e, prendendo-o, levaram-no a Nabucodonozor rei de Babilônia, a Ribla, na terra de Hamate; e o rei o sentenciou.' },
      { v: 6, en: 'Then the king of Babylon killed Zedekiah’s sons in Riblah before his eyes. The king of Babylon also killed all the nobles of Judah.', pt: 'E o rei de Babilônia matou os filhos de Zedequias em Ribla, à sua vista; também matou o rei de Babilônia a todos os nobres de Judá.' },
      { v: 7, en: 'Moreover he put out Zedekiah’s eyes and bound him in fetters, to carry him to Babylon.', pt: 'Cegou os olhos a Zedequias, e o atou com cadeias de bronze, para levá-lo a Babilônia.' },
      { v: 8, en: 'The Chaldeans burned the king’s house, and the houses of the people, with fire, and broke down the walls of Jerusalem.', pt: 'Os caldeus incendiaram a casa do rei e as casas do povo, e derribaram os muros de Jerusalém.' },
      { v: 9, en: 'Then Nebuzaradan the captain of the guard carried away captive into Babylon the residue of the people who remained in the city, the deserters also who fell away to him, and the residue of the people who remained.', pt: 'Então, ao resto do povo, que ficara na cidade, aos desertores que se tinham passado para ele e ao resto do povo que havia ficado, levou-os Nebuzaradão, capitão da guarda, para Babilônia.' },
      { v: 10, en: 'But Nebuzaradan the captain of the guard left of the poor of the people, who had nothing, in the land of Judah, and gave them vineyards and fields at the same time.', pt: 'Mas aos pobres dentre o povo, que não tinham nada, Nebuzaradão, capitão da guarda, deixou-os ficar na terra de Judá; e ao mesmo tempo lhes deu vinhas e campos.' },
      { v: 11, en: 'Now Nebuchadnezzar king of Babylon commanded Nebuzaradan the captain of the guard concerning Jeremiah, saying,', pt: 'Ora Nabucodonozor, rei de Babilônia, havia ordenado acerca de Jeremias, a Nebuzaradão, capitão dos da guarda, dizendo:' },
      { v: 12, en: '“Take him, and take care of him. Do him no harm; but do to him even as he tells you.”', pt: 'Toma-o, e trata-o bem, e não lhe faças mal algum; mas como ele te disser, assim procederás para com ele.' },
      { v: 13, en: 'So Nebuzaradan the captain of the guard sent, with Nebushazban, Rabsaris, and Nergal Sharezer, Rabmag, and all the chief officers of the king of Babylon;', pt: 'Pelo que Nebuzaradão, capitão da guarda, Nebusazbã, Rabe-Sáris, Nergal-Sarezer, Rabe-Maeue, e todos os príncipes do rei de Babilônia' },
      { v: 14, en: 'they sent, and took Jeremiah out of the court of the guard, and committed him to Gedaliah the son of Ahikam, the son of Shaphan, that he should carry him home. So he lived among the people.', pt: 'mandaram retirar Jeremias do átrio da guarda, e o entregaram a Gedalias, filho de Aicão, filho de Safã, para que o levasse para casa; assim ele habitou entre o povo.' },
      { v: 15, en: 'Now Yahweh’s word came to Jeremiah, while he was shut up in the court of the guard, saying,', pt: 'Ora, a palavra do Senhor viera a Jeremias, estando ele ainda encarcerado no átrio da guarda, dizendo:' },
      { v: 16, en: '“Go, and speak to Ebedmelech the Ethiopian, saying, ‘Yahweh of Armies, the God of Israel, says: “Behold, I will bring my words on this city for evil, and not for good; and they will be accomplished before you in that day.', pt: 'Vai, e fala a Ebede-Meleque, o etíope, dizendo: Assim diz o Senhor dos exércitos, Deus de Israel: Eis que eu cumprirei as minhas palavras sobre esta cidade para mal e não para bem; e se cumprirão diante de ti naquele dia.' },
      { v: 17, en: 'But I will deliver you in that day,” says Yahweh; “and you will not be given into the hand of the men of whom you are afraid.', pt: 'A ti, porém, eu livrarei naquele dia, diz o Senhor, e não serás entregue na mão dos homens a quem temes.' },
      { v: 18, en: 'For I will surely save you, and you won’t fall by the sword, but you will escape with your life; because you have put your trust in me,” says Yahweh.’”', pt: 'Pois certamente te salvarei, e não cairás à espada, mas a tua vida terás por despojo, porquanto confiaste em mim, diz o Senhor.' },
    ],
    40: [
      { v: 1, en: 'The word which came to Jeremiah from Yahweh, after Nebuzaradan the captain of the guard had let him go from Ramah, when he had taken him being bound in chains among all the captives of Jerusalem and Judah, who were carried away captive to Babylon.', pt: 'A palavra que veio a Jeremias da parte do Senhor, depois que Nebuzaradão, capitão da guarda, o deixara ir de Ramá, quando o havia tomado, estando ele atado com cadeias no meio de todos os do cativeiro de Jerusalém e de Judá, que estavam sendo levados cativos para Babilônia.' },
      { v: 2, en: 'The captain of the guard took Jeremiah, and said to him, “Yahweh your God pronounced this evil on this place;', pt: 'Ora o capitão da guarda levou Jeremias, e lhe disse: O Senhor teu Deus pronunciou este mal contra este lugar;' },
      { v: 3, en: 'and Yahweh has brought it, and done according as he spoke. Because you have sinned against Yahweh, and have not obeyed his voice, therefore this thing has come on you.', pt: 'e o Senhor o trouxe, e fez como havia dito; porque pecastes contra o Senhor, e não obedecestes à sua voz, portanto vos sucedeu tudo isto.' },
      { v: 4, en: 'Now, behold, I release you today from the chains which are on your hand. If it seems good to you to come with me into Babylon, come, and I will take care of you; but if it seems bad to you to come with me into Babylon, don’t. Behold, all the land is before you. Where it seems good and right to you to go, there go.”', pt: 'Agora pois, eis que te solto hoje das cadeias que estão sobre as tuas mãos. Se te apraz vir comigo para Babilônia, vem, e eu velarei por ti; mas, se não te apraz vir comigo para Babilônia, deixa de vir. Olha, toda a terra está diante de ti; para onde te parecer bem e conveniente ir, para ali vai.' },
      { v: 5, en: 'Now while he had not yet gone back, “Go back then,” he said, “to Gedaliah the son of Ahikam, the son of Shaphan, whom the king of Babylon has made governor over the cities of Judah, and dwell with him among the people; or go wherever it seems right to you to go.” So the captain of the guard gave him food and a present, and let him go.', pt: 'Se assim quiseres, volta a Gedalias, filho de Aicão filho de Safã e a quem o rei de Babilônia constituiu governador das cidades de Judá, e habita com ele no meio do povo; ou vai para qualquer outra parte que te aprouver ir. E deu-lhe o capitão da guarda sustento para o caminho, e um presente, e o deixou ir.' },
      { v: 6, en: 'Then Jeremiah went to Gedaliah the son of Ahikam to Mizpah, and lived with him among the people who were left in the land.', pt: 'Assim veio Jeremias a Gedalias, filho de Aicão, a Mizpá, e habitou com ele no meio do povo que havia ficado na terra.' },
      { v: 7, en: 'Now when all the captains of the forces who were in the fields, even they and their men, heard that the king of Babylon had made Gedaliah the son of Ahikam governor in the land, and had committed to him men, women, children, and of the poorest of the land, of those who were not carried away captive to Babylon;', pt: 'Ouvindo pois todos os chefes das forças que estavam no campo, eles e os seus homens, que o rei de Babilônia havia constituído a Gedalias, filho de Aicão, governador da terra, e que lhe havia confiado homens, mulheres e crianças, os mais pobres da terra, que não foram levados cativos para Babilônia,' },
      { v: 8, en: 'then Ishmael the son of Nethaniah, and Johanan and Jonathan the sons of Kareah, and Seraiah the son of Tanhumeth, and the sons of Ephai the Netophathite, and Jezaniah the son of the Maacathite, they and their men came to Gedaliah to Mizpah.', pt: 'vieram ter com Gedalias, a Mizpá; e eram: Ismael, filho de Netanias, e Joanã e Jônatas, filhos de Careá, e Seraías, filho de Tanumete, e os filhos de Efai, o netofatita, e Jezanias, filho do maacatita, eles e os seus homens.' },
      { v: 9, en: 'Gedaliah the son of Ahikam the son of Shaphan swore to them and to their men, saying, “Don’t be afraid to serve the Chaldeans. Dwell in the land, and serve the king of Babylon, and it will be well with you.', pt: 'E jurou Gedalias, filho de Aicão, filho de Safã, eles e pos seus homens, dizendo: Não temais servir aos caldeus; habitai na terra, e servi o rei de Babilônia, e bem vos erá.' },
      { v: 10, en: 'As for me, behold, I will dwell at Mizpah, to stand before the Chaldeans who will come to us; but you, gather wine and summer fruits and oil, and put them in your vessels, and dwell in your cities that you have taken.”', pt: 'Quanto a mim, eis que habito em Mizpá, para vos representar diante dos caldeus que vierem a nós; vós, porém, colhei o vinho e os frutos de verão, e o azeite, e metei-os nos vossos vasos, e habitai nas vossas cidades, que tomastes.' },
      { v: 11, en: 'Likewise when all the Jews who were in Moab, and among the children of Ammon, and in Edom, and who were in all the countries, heard that the king of Babylon had left a remnant of Judah, and that he had set over them Gedaliah the son of Ahikam, the son of Shaphan;', pt: 'Do mesmo modo, quando todos os judeus que estavam em Moabe, e entre os filhos de Amom, e em Edom, e os que havia em todos os países, ouviram que o rei de Babilônia havia deixado um resto em Judá, e que havia posto sobre eles a Guedalias, o de Aicão, filho de Safã;' },
      { v: 12, en: 'then all the Jews returned out of all places where they were driven, and came to the land of Judah, to Gedaliah, to Mizpah, and gathered very much wine and summer fruits.', pt: 'voltaram, então, todos os judeus de todos os lugares para onde foram arrojados, e vieram para a terra de Judá, a Gedalias, a Mizpá, e colheram vinho e frutos do verão com muita abundância.' },
      { v: 13, en: 'Moreover Johanan the son of Kareah, and all the captains of the forces who were in the fields, came to Gedaliah to Mizpah,', pt: 'Joanã, filho de Careá, e todos os chefes das forças que estavam no campo vieram ter com Gedalias, a Mizpá,' },
      { v: 14, en: 'and said to him, “Do you know that Baalis the king of the children of Ammon has sent Ishmael the son of Nethaniah to take your life?” But Gedaliah the son of Ahikam didn’t believe them.', pt: 'e disseram-lhe: Sabes que Baalis, rei dos filhos de Amom, enviou a Ismael, filho de Netanias, para te tirar a vida? Mas não lhes deu crédito Gedalias, filho de Aicão.' },
      { v: 15, en: 'Then Johanan the son of Kareah spoke to Gedaliah in Mizpah secretly, saying, “Please let me go, and I will kill Ishmael the son of Nethaniah, and no man will know it. Why should he take your life, that all the Jews who are gathered to you should be scattered, and the remnant of Judah perish?”', pt: 'Todavia Joanã, filho de Careá, falou a Gedalias em segredo, em Mizpá, dizendo: Deixa, peço-te, que eu vá e mate a Ismael, filho de Netanias, sem que ninguém o saiba. Por que razão te tiraria ele a vida, de modo que fossem dispersos todos os judeus que se têm congregado a ti, e perecesse o resto de Judá?' },
      { v: 16, en: 'But Gedaliah the son of Ahikam said to Johanan the son of Kareah, “You shall not do this thing; for you speak falsely of Ishmael.”', pt: 'Mas disse Gedalias, filho de Aicão, a Joanã, filho de Careá: Não faças tal coisa; pois falas falsamente contra Ismael.' },
    ],
    41: [
      { v: 1, en: 'Now in the seventh month, Ishmael the son of Nethaniah, the son of Elishama, of the royal offspring and one of the chief officers of the king, and ten men with him, came to Gedaliah the son of Ahikam to Mizpah; and there they ate bread together in Mizpah.', pt: 'Sucedeu, porém, no mês sétimo, que veio Ismael, filho de Netanias, filho de Elisama, de sangue real, e um dos nobres do rei, e dez homens com ele, a Gedalias, filho de Aicão, a Mizpá; e eles comeram pão juntos ali em Mizpá.' },
      { v: 2, en: 'Then Ishmael the son of Nethaniah arose, and the ten men who were with him, and struck Gedaliah the son of Ahikam the son of Shaphan with the sword and killed him, whom the king of Babylon had made governor over the land.', pt: 'E levantou-se Ismael, filho de Netanias, com os dez homens que estavam com ele, e feriram a Gedalias, filho de Aicão, filho de Safã, à espada, matando assim aquele que o rei de Babilônia havia posto por governador sobre a terra.' },
      { v: 3, en: 'Ishmael also killed all the Jews who were with him, with Gedaliah, at Mizpah, and the Chaldeans who were found there, the men of war.', pt: 'Matou também Ismael a todos os judeus que estavam com Gedalias, em Mizpá, como também aos soldados caldeus que se achavam ali.' },
      { v: 4, en: 'The second day after he had killed Gedaliah, and no man knew it,', pt: 'Sucedeu pois no dia seguinte, depois que ele matara a Gedalias, sem ninguém o saber,' },
      { v: 5, en: 'men came from Shechem, from Shiloh, and from Samaria, even eighty men, having their beards shaved and their clothes torn, and having cut themselves, with meal offerings and frankincense in their hand, to bring them to Yahweh’s house.', pt: 'que vieram de Siquém, de Siló e de Samária, oitenta homens, com a barba rapada, e os vestidos rasgados e tendo as carnes retalhadas, trazendo nas mãos ofertas de cereais e incenso, para os levarem à casa do Senhor.' },
      { v: 6, en: 'Ishmael the son of Nethaniah went out from Mizpah to meet them, weeping all along as he went: and as he met them, he said to them, “Come to Gedaliah the son of Ahikam.”', pt: 'E, saindo-lhes ao encontro Ismael, filho de Netanias, desde Mizpá, ia chorando; e sucedeu que, encontrando-os, lhes disse: Vinde a Gedalias, filho de Aicão.' },
      { v: 7, en: 'It was so, when they came into the middle of the city, that Ishmael the son of Nethaniah killed them, and cast them into the middle of the pit, he, and the men who were with him.', pt: 'Chegando eles, porém, até o meio da cidade, Ismael, filho de Netanias, e os homens que estavam com ele mataram-nos e os lançaram num poço.' },
      { v: 8, en: 'But ten men were found among those who said to Ishmael, “Don’t kill us; for we have stores hidden in the field, of wheat, and of barley, and of oil, and of honey.” So he stopped, and didn’t kill them among their brothers.', pt: 'Mas entre eles se acharam dez homens que disseram a Ismael: Não nos mates a nós, porque temos escondidos no campo depósitos de trigo, cevada, azeite e mel. E ele por isso os deixou, e não os matou entre seus irmãos.' },
      { v: 9, en: 'Now the pit in which Ishmael cast all the dead bodies of the men whom he had killed, by the side of Gedaliah (the same was that which Asa the king had made for fear of Baasha king of Israel), Ishmael the son of Nethaniah filled it with those who were killed.', pt: 'E o poço em que Ismael lançou todos os cadáveres dos homens que matara por causa de Gedalias é o mesmo que fez o rei Asa, por causa de Baasa, rei de Israel; foi esse mesmo que Ismael, filho de Netanias, encheu de mortos.' },
      { v: 10, en: 'Then Ishmael carried away captive all the of the people who were left in Mizpah, even the king’s daughters, and all the people who remained in Mizpah, whom Nebuzaradan the captain of the guard had committed to Gedaliah the son of Ahikam. Ishmael the son of Nethaniah carried them away captive, and departed to go over to the children of Ammon.', pt: 'E Ismael levou cativo a todo o resto do povo que estava em Mizpá: as filhas do rei, e todo o povo que ficara em Mizpá, que Nebuzaradão, capitão da guarda, havia confiado a Gedalias, filho de Aicão; e levou-os cativos Ismael, filho de Netanias, e se foi para passar aos filhos de Amom.' },
      { v: 11, en: 'But when Johanan the son of Kareah, and all the captains of the forces who were with him, heard of all the evil that Ishmael the son of Nethaniah had done,', pt: 'Ouvindo, porém, Joanã, filho de Careá, e todos os chefes das forças que estavam com ele, todo o mal que havia feito Ismael, filho de Netanias,' },
      { v: 12, en: 'then they took all the men, and went to fight with Ishmael the son of Nethaniah, and found him by the great waters that are in Gibeon.', pt: 'tomaram todos os seus homens e foram pelejar contra Ismael, filho de Netanias; e o acharam ao pé das grandes águas que há em Gibeão.' },
      { v: 13, en: 'Now when all the people who were with Ishmael saw Johanan the son of Kareah, and all the captains of the forces who were with him, then they were glad.', pt: 'E todo o povo que estava com Ismael se alegrou quando viu a Joanã, filho de Careá, e a todos os chefes das forças, que vinham com ele.' },
      { v: 14, en: 'So all the people who Ishmael had carried away captive from Mizpah turned about and came back, and went to Johanan the son of Kareah.', pt: 'E todo o povo que Ismael levara cativo de Mizpá virou as costas, e voltou, e foi para Joanã, filho de Careá.' },
      { v: 15, en: 'But Ishmael the son of Nethaniah escaped from Johanan with eight men, and went to the children of Ammon.', pt: 'Mas Ismael, filho de Netanias, com oito homens, escapou de Joanã e se foi para os filhos de Amom.' },
      { v: 16, en: 'Then Johanan the son of Kareah and all the captains of the forces who were with him took all the remnant of the people whom he had recovered from Ishmael the son of Nethaniah, from Mizpah, after he had killed Gedaliah the son of Ahikam, the men of war, with the women, the children, and the eunuchs, whom he had brought back from Gibeon.', pt: 'Então Joanã, filho de Careá, e todos os chefes das forças que estavam com ele, tomaram a todo o resto do povo que Ismael, filho de Netanias, tinha levado cativo de Mizpá, depois que matara Gedalias, filho de Aicão, a saber, aos soldados, as mulheres, aos meninos e aos eunucos, que Joanã havia recobrado de Gibeão,' },
      { v: 17, en: 'They departed and lived in Geruth Chimham, which is by Bethlehem, to go to enter into Egypt', pt: 'e partiram, indo habitar Gerute-Quimã, que está perto de Belém, para dali entrarem no Egito,' },
      { v: 18, en: 'because of the Chaldeans; for they were afraid of them, because Ishmael the son of Nethaniah had killed Gedaliah the son of Ahikam, whom the king of Babylon made governor over the land.', pt: 'por causa dos caldeus; pois os temiam, por ter Ismael, filho de Netanias, matado a Gedalias, filho de Aicão, a quem o rei de Babilônia tinha posto por governador sobre a terra.' },
    ],
    42: [
      { v: 1, en: 'Then all the captains of the forces, and Johanan the son of Kareah, and Jezaniah the son of Hoshaiah, and all the people from the least even to the greatest, came near,', pt: 'Então chegaram todos os chefes das forças, e Joanã, filho de Careá, e Jezanias, filho de Hosaías, e todo o povo, desde o menor até o maior,' },
      { v: 2, en: 'and said to Jeremiah the prophet, “Please let our supplication be presented before you, and pray for us to Yahweh your God, even for all this remnant; for we are left but a few of many, as your eyes see us;', pt: 'e disseram a Jeremias, o profeta: Seja aceita, pedimos-te, a nossa súplica diante de ti, e roga ao Senhor teu Deus, por nós e por todo este resto; porque de muitos restamos somente uns poucos, assim como nos vêem os teus olhos;' },
      { v: 3, en: 'that Yahweh your God may show us the way in which we should walk, and the things that we should do.”', pt: 'para que o Senhor teu Deus nos ensine o caminho por onde havemos de andar e aquilo que havemos de fazer.' },
      { v: 4, en: 'Then Jeremiah the prophet said to them, “I have heard you. Behold, I will pray to Yahweh your God according to your words; and it will happen that whatever thing Yahweh answers you, I will declare it to you. I will keep nothing back from you.”', pt: 'Respondeu-lhes Jeremias o profeta: Eu vos tenho ouvido; eis que orarei ao Senhor vosso Deus conforme as vossas palavras; e o que o Senhor vos responder, eu vo-lo declararei; não vos ocultarei nada.' },
      { v: 5, en: 'Then they said to Jeremiah, “May Yahweh be a true and faithful witness among us, if we don’t do according to all the word with which Yahweh your God sends you to tell us.', pt: 'Então eles disseram a Jeremias: Seja o Senhor entre nós testemunha verdadeira e fiel, se assim não fizermos conforme toda a palavra com que te enviar a nós o Senhor teu Deus.' },
      { v: 6, en: 'Whether it is good, or whether it is bad, we will obey the voice of Yahweh our God, to whom we send you; that it may be well with us, when we obey the voice of Yahweh our God.”', pt: 'Seja ela boa, ou seja má, à voz do Senhor nosso Deus, a quem te enviamos, obedeceremos, para que nos suceda bem, obedecendo à voz do Senhor nosso Deus.' },
      { v: 7, en: 'After ten days, Yahweh’s word came to Jeremiah.', pt: 'Ao fim de dez dias veio a palavra do Senhor a Jeremias.' },
      { v: 8, en: 'Then he called Johanan the son of Kareah, and all the captains of the forces who were with him, and all the people from the least even to the greatest,', pt: 'Então chamou a Joanã, filho de Careá, e a todos os chefes das forças que havia com ele, e a todo o povo, desde o menor até o maior,' },
      { v: 9, en: 'and said to them, “Yahweh, the God of Israel, to whom you sent me to present your supplication before him, says:', pt: 'e lhes disse: Assim diz o Senhor, Deus de Israel, a quem me enviastes para apresentar a vossa súplica diante dele:' },
      { v: 10, en: '‘If you will still live in this land, then I will build you, and not pull you down, and I will plant you, and not pluck you up; for I grieve over the distress that I have brought on you.', pt: 'Se de boa mente habitardes nesta terra, então vos edificarei, e não vos derrubarei; e vos plantarei, e não vos arrancarei; porque estou arrependido do mal que vos tenho feito.' },
      { v: 11, en: 'Don’t be afraid of the king of Babylon, of whom you are afraid. Don’t be afraid of him,’ says Yahweh: ‘for I am with you to save you, and to deliver you from his hand.', pt: 'Não temais o rei de Babilônia, a quem vós temeis; não o temais, diz o Senhor; pois eu sou convosco, para vos salvar e para vos livrar da sua mão.' },
      { v: 12, en: 'I will grant you mercy, that he may have mercy on you, and cause you to return to your own land.', pt: 'E vos concederei misericórdia, para que ele tenha misericórdia de vós, e vos faça habitar na vossa terra.' },
      { v: 13, en: '“‘But if you say, “We will not dwell in this land;” so that you don’t obey Yahweh your God’s voice,', pt: 'Mas se vós disserdes: Não habitaremos nesta terra; não obedecendo à voz do Senhor vosso Deus,' },
      { v: 14, en: 'saying, “No; but we will go into the land of Egypt, where we will see no war, nor hear the sound of the trumpet, nor have hunger of bread; and there will we dwell:”’', pt: 'e dizendo: Não; antes iremos para a terra do Egito, onde não veremos guerra, nem ouviremos o som de trombeta, nem teremos fome de pão, e ali habitaremos;' },
      { v: 15, en: 'now therefore hear Yahweh’s word, O remnant of Judah: Yahweh of Armies, the God of Israel, says, ‘If you indeed set your faces to enter into Egypt, and go to live there;', pt: 'nesse caso ouvi a palavra do Senhor, ó resto de Judá: Assim diz o Senhor dos exércitos, Deus de Israel: Se vós de todo vos propuserdes a entrar no Egito, e entrardes para lá peregrinar,' },
      { v: 16, en: 'then it will happen that the sword, which you fear, will overtake you there in the land of Egypt; and the famine, about which you are afraid, will follow close behind you there in Egypt; and you will die there.', pt: 'então a espada que vós temeis vos alcançará ali na terra do Egito, e a fome que vós receais vos seguirá de perto mesmo no Egito, e ali morrereis.' },
      { v: 17, en: 'So will it be with all the men who set their faces to go into Egypt to live there. They will die by the sword, by the famine, and by the pestilence. None of them will remain or escape from the evil that I will bring on them.’', pt: 'Assim sucederá a todos os homens que se propuserem a entrar no Egito, a fim de lá peregrinarem: morrerão à espada, de fome, e de peste; e deles não haverá quem reste ou escape do mal que eu trarei sobre eles.' },
      { v: 18, en: 'For Yahweh of Armies, the God of Israel, says: ‘As my anger and my wrath has been poured out on the inhabitants of Jerusalem, so my wrath will be poured out on you, when you enter into Egypt; and you will be an object of horror, an astonishment, a curse, and a reproach; and you will see this place no more.’', pt: 'Pois assim diz o Senhor dos exércitos, Deus de Israel: Como se derramou a minha ira e a minha indignação sobre os habitantes de Jerusalém, assim se derramará a minha indignação sobre vós, quando entrardes no Egito. Sereis um espetáculo de execração, e de espanto, e de maldição, e de opróbrio; e não vereis mais este lugar.' },
      { v: 19, en: '“Yahweh has spoken concerning you, remnant of Judah, ‘Don’t go into Egypt!’ Know certainly that I have testified to you today.', pt: 'Falou o Senhor acerca de vós, ó resto de Judá: Não entreis no Egito. Tende por certo que hoje vos tenho avisado.' },
      { v: 20, en: 'For you have dealt deceitfully against your own souls; for you sent me to Yahweh your God, saying, ‘Pray for us to Yahweh our God; and according to all that Yahweh our God says, so declare to us, and we will do it.’', pt: 'Porque vós vos enganastes a vós mesmos; pois me enviastes ao Senhor vosso Deus, dizendo: Roga por nós ao Senhor nosso Deus, e conforme tudo o que disser o Senhor Deus nosso, declara-no-lo assim, e o faremos.' },
      { v: 21, en: 'I have declared it to you today; but you have not obeyed Yahweh your God’s voice in anything for which he has sent me to you.', pt: 'E vo-lo tenho declarado hoje, mas não destes ouvidos à voz do Senhor vosso Deus em coisa alguma pela qual ele me enviou a vos.' },
      { v: 22, en: 'Now therefore know certainly that you will die by the sword, by the famine, and by the pestilence in the place where you desire to go to live there.”', pt: 'Agora pois sabei por certo que morrereis à espada, de fome e de peste no mesmo lugar onde desejais ir para lá peregrinardes.' },
    ],
    43: [
      { v: 1, en: 'When Jeremiah had finished speaking to all the people all the words of Yahweh their God, with which Yahweh their God had sent him to them, even all these words,', pt: 'Tendo Jeremias acabado de falar a todo o povo todas as palavras do Senhor seu Deus, aquelas palavras com as quais o Senhor seu Deus lho havia enviado,' },
      { v: 2, en: 'then Azariah the son of Hoshaiah, Johanan the son of Kareah, and all the proud men spoke, saying to Jeremiah, “You speak falsely. Yahweh our God has not sent you to say, ‘You shall not go into Egypt to live there;’', pt: 'então falaram Azarias, filho de Hosaías, e Joanã, filho de Careá, e todos os homens soberbos, dizendo a Jeremias: Tu dizes mentiras; o Senhor nosso Deus não te enviou a dizer: Não entreis no Egito para ali peregrinardes;' },
      { v: 3, en: 'but Baruch the son of Neriah has turned you against us, to deliver us into the hand of the Chaldeans, that they may put us to death, and carry us away captive to Babylon.”', pt: 'mas Baruque, filho de Nerias, é que te incita contra nós, para nos entregar na mão dos caldeus, para eles nos matarem, ou para nos levarem cativos para Babilônia.' },
      { v: 4, en: 'So Johanan the son of Kareah, and all the captains of the forces, and all the people, didn’t obey Yahweh’s voice, to dwell in the land of Judah.', pt: 'Não obedeceu pois Joanã, filho de Careá, nem nenhum de todos os príncipes dos exércitos, nem o povo todo, à voz do Senhor, para ficarem na terra de Judá.' },
      { v: 5, en: 'But Johanan the son of Kareah, and all the captains of the forces, took all the remnant of Judah, who had returned from all the nations where they had been driven, to live in the land of Judah;', pt: 'Mas Joanã, filho de Careá, e todos os chefes das forças tomaram a todo o resto de Judá, que havia voltado dentre todas as nações, para onde haviam sido arrojados, com o fim de peregrinarem na terra de Judá;' },
      { v: 6, en: 'the men, and the women, and the children, and the king’s daughters, and every person who Nebuzaradan the captain of the guard had left with Gedaliah the son of Ahikam, the son of Shaphan; and Jeremiah the prophet, and Baruch the son of Neriah;', pt: 'aos homens, às mulheres, às crianças, e às filhas do rei, e a toda pessoa que Nebuzaradão, capitão da guarda, deixara com Gedalias, filho de Aicão, filho de Safã, como também a Jeremias, o profeta, e a Baruque, filho de Nerias;' },
      { v: 7, en: 'and they came into the land of Egypt; for they didn’t obey Yahweh’s voice: and they came to Tahpanhes.', pt: 'e entraram na terra do Egito; pois não obedeceram à voz do Senhor; assim vieram até Tapanes.' },
      { v: 8, en: 'Then Yahweh’s word came to Jeremiah in Tahpanhes, saying,', pt: 'Então veio a palavra do Senhor a Jeremias, em Tapanes, dizendo:' },
      { v: 9, en: '“Take great stones in your hand, and hide them in mortar in the brick work, which is at the entry of Pharaoh’s house in Tahpanhes, in the sight of the men of Judah;', pt: 'Toma na tua mão pedras grandes, e esconde-as com barro no pavimento que está à entrada da casa de Faraó em Tapanes, à vista dos homens de Judá;' },
      { v: 10, en: 'and tell them, Yahweh of Armies, the God of Israel, says: ‘Behold, I will send and take Nebuchadnezzar the king of Babylon, my servant, and will set his throne on these stones that I have hidden; and he will spread his royal pavilion over them.', pt: 'e dize-lhes: Assim diz o Senhor dos exércitos, Deus de Israel: Eis que eu enviarei, e tomarei a Nabucodonozor, rei de Babilônia, meu servo, e porei o seu trono sobre estas pedras que escondi; e ele estenderá o seu pavilhão real sobre elas.' },
      { v: 11, en: 'He will come, and will strike the land of Egypt; such as are for death will be put to death, and such as are for captivity to captivity, and such as are for the sword to the sword.', pt: 'Virá, e ferirá a terra do Egito, entregando à morte quem é para a morte, ao cativeiro quem é para o cativeiro, e à espada.' },
      { v: 12, en: 'I will kindle a fire in the houses of the gods of Egypt. He will burn them, and carry them away captive. He will array himself with the land of Egypt, as a shepherd puts on his garment; and he will go out from there in peace.', pt: 'E lançarei fogo às casas dos deuses do Egito; e ele os queimará e os levará cativos; e ornar-se-á da terra do Egito, como se veste o pastor com a sua roupa; e sairá dali em paz.' },
      { v: 13, en: 'He will also break the pillars of Beth Shemesh, that is in the land of Egypt; and he will burn the houses of the gods of Egypt with fire.’”', pt: 'E quebrará as colunas de Bete-Semes, que está na terra do Egito; e as casas dos deuses do Egito queimará a fogo.' },
    ],
    44: [
      { v: 1, en: 'The word that came to Jeremiah concerning all the Jews who lived in the land of Egypt, who lived at Migdol, and at Tahpanhes, and at Memphis, and in the country of Pathros, saying,', pt: 'A palavra que veio a Jeremias, acerca de todos os judeus, que habitavam na terra do Egito, em Migdol, em Tapanes, em Mênfis, e no país de Patros:' },
      { v: 2, en: '“Yahweh of Armies, the God of Israel, says: ‘You have seen all the evil that I have brought on Jerusalem, and on all the cities of Judah. Behold, today they are a desolation, and no man dwells in them,', pt: 'Assim diz o Senhor dos exércitos, Deus de Israel: Vós vistes todo o mal que fiz cair sobre Jerusalém, e sobre todas as cidades de Judá; e eis que elas são hoje uma desolação, e ninguém nelas habita;' },
      { v: 3, en: 'because of their wickedness which they have committed to provoke me to anger, in that they went to burn incense, to serve other gods that they didn’t know, neither they, nor you, nor your fathers.', pt: 'por causa da sua maldade que fizeram, para me irarem, indo queimar incenso, e servir a outros deuses, a quem eles nunca conheceram, nem eles, nem vós, nem vossos pais.' },
      { v: 4, en: 'However I sent to you all my servants the prophets, rising up early and sending them, saying, “Oh, don’t do this abominable thing that I hate.”', pt: 'Todavia eu vos enviei persistentemente todos os meus servos, os profetas, para vos dizer: Ora, não façais esta coisa abominável que odeio!' },
      { v: 5, en: 'But they didn’t listen and didn’t incline their ear. They didn’t turn from their wickedness, to stop burning incense to other gods.', pt: 'Mas eles não escutaram, nem inclinaram os seus ouvidos, para se converterem da sua maldade, para não queimarem incenso a outros deuses.' },
      { v: 6, en: 'Therefore my wrath and my anger was poured out, and was kindled in the cities of Judah and in the streets of Jerusalem; and they are wasted and desolate, as it is today.’', pt: 'Pelo que se derramou a minha indignação e a minha ira, e acendeu-se nas cidades de Judá, e nas ruas de Jerusalém; e elas tornaram-se em deserto e em desolação, como hoje se vê.' },
      { v: 7, en: '“Therefore now Yahweh, the God of Armies, the God of Israel, says: ‘Why do you commit great evil against your own souls, to cut off from yourselves man and woman, infant and nursing child out of the middle of Judah, to leave yourselves no one remaining;', pt: 'Agora, pois, assim diz o Senhor, Deus dos exércitos, Deus de Israel: Por que fazeis vós tão grande mal contra vós mesmos, para desarraigardes o homem e a mulher, a criança e o que mama, dentre vós, do meio de Judá, a fim de não vos deixardes ali resto algum;' },
      { v: 8, en: 'in that you provoke me to anger with the works of your hands, burning incense to other gods in the land of Egypt, where you have gone to live; that you may be cut off, and that you may be a curse and a reproach among all the nations of the earth?', pt: 'irando-me com as obras de vossas mãos, queimando incenso a outros deuses na terra do Egito, aonde vós entrastes para lá peregrinardes, para que sejais exterminados, e para que sirvais de maldição e de opróbrio entre todas as nações da terra?' },
      { v: 9, en: 'Have you forgotten the wickedness of your fathers, and the wickedness of the kings of Judah, and the wickedness of their wives, and your own wickedness, and the wickedness of your wives, which they committed in the land of Judah and in the streets of Jerusalem?', pt: 'Esquecestes já as maldades de vossos pais, as maldades dos reis de Judá, as maldades das suas mulheres, as vossas maldades e as maldades das vossas mulheres, cometidas na terra de Judá e nas ruas de Jerusalém?' },
      { v: 10, en: 'They are not humbled even to this day, neither have they feared, nor walked in my law, nor in my statutes, that I set before you and before your fathers.’', pt: 'Não se humilharam até o dia de hoje, nem temeram, nem andaram na minha lei, nem nos meus estatutos, que pus diante de vós e diante de vossos pais.' },
      { v: 11, en: '“Therefore Yahweh of Armies, the God of Israel, says: ‘Behold, I will set my face against you for evil, even to cut off all Judah.', pt: 'Portanto assim diz o Senhor dos exércitos, Deus de Israel: Eis que eu ponho o meu rosto contra vós para mal, e para desarraigar todo o Judá.' },
      { v: 12, en: 'I will take the remnant of Judah, that have set their faces to go into the land of Egypt to live there, and they will all be consumed. They will fall in the land of Egypt. They will be consumed by the sword and by the famine. They will die, from the least even to the greatest, by the sword and by the famine. They will be an object of horror, an astonishment, and a curse, and a reproach.', pt: 'E tomarei os que restam de Judá, os quais puseram o seu rosto para entrar na terra do Egito, a fim de lá peregrinarem, e todos eles serão consumidos; na terra do Egito cairão; à espada, e de fome serão consumidos; desde o menor até o maior morrerão à espada e de fome; e tornar-se-ão um espetáculo de execração, de espanto, de maldição e de opróbrio.' },
      { v: 13, en: 'For I will punish those who dwell in the land of Egypt, as I have punished Jerusalem, by the sword, by the famine, and by the pestilence;', pt: 'Pois castigarei os que habitam na terra do Egito, como castiguei Jerusalém, com a espada, a fome e a peste.' },
      { v: 14, en: 'so that none of the remnant of Judah, who have gone into the land of Egypt to live there, will escape or be left to return into the land of Judah, to which they have a desire to return to dwell there; for no one will return except those who will escape.’”', pt: 'De maneira que, da parte remanescente de Judá que entrou na terra do Egito a fim de lá peregrinar, não haverá quem escape e fique para tornar à terra de Judá, à qual era seu grande desejo voltar, para ali habitar; mas não voltarão, senão um pugilo de fugitivos.' },
      { v: 15, en: 'Then all the men who knew that their wives burned incense to other gods, and all the women who stood by, a great assembly, even all the people who lived in the land of Egypt, in Pathros, answered Jeremiah, saying,', pt: 'Então responderam a Jeremias todos os homens que sabiam que suas mulheres queimavam incenso a outros deuses, e todas as mulheres que estavam presentes, uma grande multidão, a saber, todo o povo que habitava na terra do Egito, em Patros, dizendo:' },
      { v: 16, en: '“As for the word that you have spoken to us in Yahweh’s name, we will not listen to you.', pt: 'Quanto à palavra que nos anunciaste em nome do Senhor, não te obedeceremos a ti;' },
      { v: 17, en: 'But we will certainly perform every word that has gone out of our mouth, to burn incense to the queen of the sky, and to pour out drink offerings to her, as we have done, we and our fathers, our kings and our princes, in the cities of Judah, and in the streets of Jerusalem; for then had we plenty of food, and were well, and saw no evil.', pt: 'mas certamente cumpriremos toda a palavra que saiu da nossa boca, de queimarmos incenso à rainha do céu, e de lhe oferecermos libações, como nós e nossos pais, nossos reis e nossos príncipes, temos feito, nas cidades de Judá, e nas ruas de Jerusalém; então tínhamos fartura de pão, e prosperávamos, e não vimos mal algum.' },
      { v: 18, en: 'But since we stopped burning incense to the queen of the sky, and pouring out drink offerings to her, we have lacked all things, and have been consumed by the sword and by the famine.', pt: 'Mas desde que cessamos de queimar incenso à rainha do céu, e de lhe oferecer libações, temos tido falta de tudo, e temos sido consumidos pela espada e pela fome.' },
      { v: 19, en: '“When we burned incense to the queen of the sky, and poured out drink offerings to her, did we make her cakes to worship her, and pour out drink offerings to her, without our husbands?”', pt: 'E nós, as mulheres, quando queimávamos incenso à rainha do céu, e lhe oferecíamos libações, acaso lhe fizemos bolos para a adorar e lhe oferecemos libações sem nossos maridos?' },
      { v: 20, en: 'Then Jeremiah said to all the people, to the men, and to the women, even to all the people who had given him an answer, saying,', pt: 'Então disse Jeremias a todo o povo, aos homens e às mulheres, e a todo o povo que lhe havia dado essa resposta, dizendo:' },
      { v: 21, en: '“The incense that you burned in the cities of Judah, and in the streets of Jerusalem, you and your fathers, your kings and your princes, and the people of the land, didn’t Yahweh remember them, and didn’t it come into his mind?', pt: 'Porventura não se lembrou o Senhor, e não lhe veio à mente o incenso que queimastes nas cidades de Judá e nas ruas de Jerusalém, vós e vossos pais, vossos reis e vossos príncipes, como tambem o povo da terra?' },
      { v: 22, en: 'Thus Yahweh could no longer bear it, because of the evil of your doings, and because of the abominations which you have committed. Therefore your land has become a desolation, and an astonishment, and a curse, without inhabitant, as it is today.', pt: 'O Senhor não podia por mais tempo suportar a maldade das vossas ações, as abominações que cometestes; pelo que se tornou a vossa terra em desolação, e em espanto, e em maldição, sem habitantes, como hoje se vê.' },
      { v: 23, en: 'Because you have burned incense, and because you have sinned against Yahweh, and have not obeyed Yahweh’s voice, nor walked in his law, nor in his statutes, nor in his testimonies; therefore this evil has happened to you, as it is today.”', pt: 'Porquanto queimastes incenso, e pecastes contra o Senhor, não obedecendo à voz do Senhor, nem andando na sua lei, nos seus estatutos e nos seus testemunhos; por isso vos sobreveio este mal, como se vê neste dia.' },
      { v: 24, en: 'Moreover Jeremiah said to all the people, including all the women, “Hear Yahweh’s word, all Judah who are in the land of Egypt!', pt: 'Disse mais Jeremias a todo o povo e a todas as mulheres: Ouvi a palavra do Senhor, vós, todo o Judá, que estais na terra do Egito.' },
      { v: 25, en: 'Yahweh of Armies, the God of Israel, says, ‘You and your wives have both spoken with your mouths, and with your hands have fulfilled it, saying, “We will surely perform our vows that we have vowed, to burn incense to the queen of the sky, and to pour out drink offerings to her.” “‘Establish then your vows, and perform your vows.’', pt: 'Assim fala o Senhor dos exércitos, Deus de Israel, dizendo: Vós e vossas mulheres falastes por vossa boca, e com as vossas mãos o cumpristes, dizendo: Certamente cumpriremos os nossos votos que fizemos, de queimarmos incenso à rainha do céu e de lhe derramarmos libações; confirmai, pois, os vossos votos, e cumpri-os!' },
      { v: 26, en: '“Therefore hear Yahweh’s word, all Judah who dwell in the land of Egypt: ‘Behold, I have sworn by my great name,’ says Yahweh, ‘that my name will no more be named in the mouth of any man of Judah in all the land of Egypt, saying, “As the Lord Yahweh lives.”', pt: 'Ouvi, pois, a palavra do Senhor, todos os de Judá que habitais na terra do Egito: Eis que eu juro pelo meu grande nome, diz o Senhor, que nunca mais será pronunciado o meu nome pela boca de nenhum homem de Judá em toda a terra do Egito, dizendo: Como vive o Senhor Deus!' },
      { v: 27, en: 'Behold, I watch over them for evil, and not for good; and all the men of Judah who are in the land of Egypt will be consumed by the sword and by the famine, until they are all gone.', pt: 'Eis que velarei sobre eles para o mal, e não para o bem; e serão consumidos todos os homens de Judá que estão na terra do Egito, pela espada e pela fome, até que de todo se acabem.' },
      { v: 28, en: 'Those who escape the sword will return out of the land of Egypt into the land of Judah few in number. All the remnant of Judah, who have gone into the land of Egypt to live there, will know whose word will stand, mine or theirs.', pt: 'E os que escaparem da espada voltarão da terra do Egito para a terra de Judá, poucos em número; e saberá todo o resto de Judá que entrou na terra do Egito para peregrinar ali, se subsistirá a minha palavra ou a sua.' },
      { v: 29, en: '“‘This will be the sign to you,’ says Yahweh, ‘that I will punish you in this place, that you may know that my words will surely stand against you for evil.’', pt: 'E isto vos servirá de sinal, diz o Senhor, de que eu vos castigarei neste lugar, para que saibais que certamente subsistirão as minhas palavras contra vós para o mal:' },
      { v: 30, en: 'Yahweh says, ‘Behold, I will give Pharaoh Hophra king of Egypt into the hand of his enemies, and into the hand of those who seek his life; as I gave Zedekiah king of Judah into the hand of Nebuchadnezzar king of Babylon, who was his enemy, and sought his life.’”', pt: 'Assim diz o Senhor: Eis que eu entregarei Faraó-Hofra, rei do Egito, na mão de seus inimigos, e na mão dos que procuram a sua morte; como entreguei Zedequias, rei de Judá, na mão de Nabucodonozor, rei de Babilônia, seu inimigo, e que procurava a sua morte.' },
    ],
    45: [
      { v: 1, en: 'The message that Jeremiah the prophet spoke to Baruch the son of Neriah, when he wrote these words in a book at the mouth of Jeremiah, in the fourth year of Jehoiakim the son of Josiah, king of Judah, saying,', pt: 'A palavra que Jeremias, o profeta, falou a Banique, filho de Nerias, quando este escrevia num livro as palavras ditadas por Jeremias, no quarto ano de Jeoiaquim, filho de Josias, rei de Judá:' },
      { v: 2, en: '“Yahweh, the God of Israel, says to you, Baruch:', pt: 'Assim diz o Senhor, Deus de Israel, acerca de ti ó Baruque.' },
      { v: 3, en: '‘You said, “Woe is me now! For Yahweh has added sorrow to my pain! I am weary with my groaning, and I find no rest.”’', pt: 'Disseste: Ai de mim agora! porque me acrescentou o Senhor tristeza à minha dor; estou cansado do meu gemer, e não acho descanso.' },
      { v: 4, en: '“You shall tell him, Yahweh says: ‘Behold, that which I have built, I will break down, and that which I have planted I will pluck up; and this in the whole land.', pt: 'Isto lhe dirás: Assim diz o Senhor: Eis que estou a demolir o que edifiquei, e a arrancar o que plantei, e isso em toda esta terra.' },
      { v: 5, en: 'Do you seek great things for yourself? Don’t seek them; for, behold, I will bring evil on all flesh,’ says Yahweh; ‘but I will let you escape with your life wherever you go.’”', pt: 'E procuras tu grandezas para ti mesmo? Não as busques; pois eis que estou trazendo o mal sobre toda a raça, diz o Senhor; porém te darei a tua vida por despojo, em todos os lugares para onde fores.' },
    ],
    46: [
      { v: 1, en: 'Yahweh’s word which came to Jeremiah the prophet concerning the nations.', pt: 'A palavra do Senhor, que veio a Jeremias, o profeta, acerca das nações.' },
      { v: 2, en: 'Of Egypt: concerning the army of Pharaoh Necoh king of Egypt, which was by the river Euphrates in Carchemish, which Nebuchadnezzar king of Babylon struck in the fourth year of Jehoiakim the son of Josiah, king of Judah.', pt: 'Acerca do Egito: a respeito do exército de Faraó-Neco, rei do Egito, que estava junto ao rio Eufrates em Carquêmis, ao qual Nabucodonozor, rei de Babilônia, derrotou no quarto ano de Jeoiaquim, filho de Josias, rei de Judá.' },
      { v: 3, en: '“Prepare the buckler and shield, and draw near to battle!', pt: 'Preparai o escudo e o pavês, e chegai-vos para a peleja.' },
      { v: 4, en: 'Harness the horses, and get up, you horsemen, and stand up with your helmets. Polish the spears, put on the coats of mail.', pt: 'Aparelhai os cavalos, e montai, cavaleiros! Apresentai-vos com elmos; açacalai as lanças; vesti-vos de couraças.' },
      { v: 5, en: 'Why have I seen it? They are dismayed and are turned backward. Their mighty ones are beaten down, have fled in haste, and don’t look back. Terror is on every side,” says Yahweh.', pt: 'Por que razão os vejo espantados e voltando as costas? Os seus heróis estão abatidos, e vão fugindo, sem olharem para trás; terror há por todos os lados, diz o Senhor.' },
      { v: 6, en: '“Don’t let the swift flee away, nor the mighty man escape. In the north by the river Euphrates they have stumbled and fallen.', pt: 'Não pode fugir o ligeiro, nem escapar o herói; para a banda do norte, junto ao rio Eufrates, tropeçaram e caíram.' },
      { v: 7, en: '“Who is this who rises up like the Nile, whose waters toss themselves like the rivers?', pt: 'Quem é este que vem subindo como o Nilo, como rios cujas águas se agitam?' },
      { v: 8, en: 'Egypt rises up like the Nile, and his waters toss themselves like the rivers. He says, ‘I will rise up. I will cover the earth. I will destroy cities and its inhabitants.’', pt: 'O Egito é que vem subindo como o Nilo, e como rios cujas águas se agitam; e ele diz: Subirei, cobrirei a terra; destruirei a cidade e os que nela habitam.' },
      { v: 9, en: 'Go up, you horses! Rage, you chariots! Let the mighty men go out: Cush and Put, who handle the shield; and the Ludim, who handle and bend the bow.', pt: 'Subi, ó cavalos; e estrondeai, ó carros; e saiam valentes: Cuche e Pute, que manejam o escudo, e os de Lude, que manejam e entesam o arco.' },
      { v: 10, en: 'For that day is of the Lord, Yahweh of Armies, a day of vengeance, that he may avenge himself of his adversaries. The sword will devour and be satiated, and will drink its fill of their blood; for the Lord, Yahweh of Armies, has a sacrifice in the north country by the river Euphrates.', pt: 'Porque aquele dia é o dia do Senhor Deus dos exércitos, dia de vingança para ele se vingar dos seus adversários. A espada devorará, e se fartará, e se embriagará com o sangue deles; pois o Senhor Deus dos exércitos tem um sacrifício na terra do Norte junto ao rio Eufrates.' },
      { v: 11, en: 'Go up into Gilead, and take balm, virgin daughter of Egypt. You use many medicines in vain. There is no healing for you.', pt: 'Sobe a Gileade, e toma bálsamo, ó virgem filha do Egito; debalde multiplicas remédios; não há cura para ti.' },
      { v: 12, en: 'The nations have heard of your shame, and the earth is full of your cry; for the mighty man has stumbled against the mighty, they both fall together.”', pt: 'As nações ouviram falar da tua vergonha, e a terra está cheia do teu clamor; porque o valente tropeçou no valente e ambos juntos cairam.' },
      { v: 13, en: 'The word that Yahweh spoke to Jeremiah the prophet, how that Nebuchadnezzar king of Babylon should come and strike the land of Egypt.', pt: 'A palavra que falou o Senhor a Jeremias, o profeta, acerca da vinda de Nabucodonozor, rei de Babilônia, para ferir a terra do Egito.' },
      { v: 14, en: '“Declare in Egypt, publish in Migdol, and publish in Memphis and in Tahpanhes: say, ‘Stand up, and prepare; for the sword has devoured around you.’', pt: 'Anunciai-o no Egito, proclamai isto em Migdol; proclamai-o também em Mênfis, e em Tapanes; dizei: Apresenta-te, e prepara-te; porque a espada devorará o que está ao redor de ti.' },
      { v: 15, en: 'Why are your strong ones swept away? They didn’t stand, because Yahweh pushed them.', pt: 'Por que está derribado o teu valente? Ele não ficou em pé, porque o Senhor o abateu.' },
      { v: 16, en: 'He made many to stumble. Yes, they fell on one another. They said, ‘Arise, and let us go again to our own people, and to the land of our birth, from the oppressing sword.’', pt: 'Fez tropeçar a multidão; caíram uns sobre os outros, e disseram: Levanta-te, e voltemos para o nosso povo, para a terra do nosso nascimento, por causa da espada que oprime.' },
      { v: 17, en: 'They cried there, ‘Pharaoh king of Egypt is but a noise; he has let the appointed time pass by.’', pt: 'Clamaram ali: Faraó, rei do Egito, é apenas um som; deixou passar o tempo assinalado.' },
      { v: 18, en: '“As I live,” says the King, whose name is Yahweh of Armies, “surely like Tabor among the mountains, and like Carmel by the sea, so he will come.', pt: 'Vivo eu, diz o Rei, cujo nome é o Senhor dos exércitos, que certamente como o Tabor entre os montes, e como o Carmelo junto ao mar, assim ele vira.' },
      { v: 19, en: 'You daughter who dwells in Egypt, furnish yourself to go into captivity; for Memphis will become a desolation, and will be burned up, without inhabitant.', pt: 'Prepara-te para ires para o cativeiro, ó moradora filha do Egito; porque Mênfis será tornada em desolação, e será incendiada, até que ninguém mais aí more.' },
      { v: 20, en: '“Egypt is a very beautiful heifer; but destruction out of the north has come. It has come.', pt: 'Novilha mui formosa é o Egito; mas já lhe vem do Norte um tavão.' },
      { v: 21, en: 'Also her hired men in the middle of her are like calves of the stall; for they also are turned back. They have fled away together. They didn’t stand, for the day of their calamity has come on them, the time of their visitation.', pt: 'Até os seus mercenários no meio dela são como bezerros cevados; mas também eles viraram as costas, fugiram juntos, não ficaram firmes; porque veio sobre eles o dia da sua ruína e o tempo da sua punição.' },
      { v: 22, en: 'It’s sound will go like the serpent; for they will march with an army, and come against her with axes, as wood cutters.', pt: 'A sua voz irá como a da serpente; porque marcharão com um exército, e virão contra ela com machados, como cortadores de lenha.' },
      { v: 23, en: 'They will cut down her forest,” says Yahweh, “though it can’t be searched; because they are more than the locusts, and are innumerable.', pt: 'Cortarão o seu bosque, diz o Senhor, embora seja impenetrável; porque se multiplicaram mais do que os gafanhotos; são inumeraveis.' },
      { v: 24, en: 'The daughter of Egypt will be disappointed; she will be delivered into the hand of the people of the north.”', pt: 'A filha do Egito será envergonhada; será entregue na mão do povo do Norte.' },
      { v: 25, en: 'Yahweh of Armies, the God of Israel, says: “Behold, I will punish Amon of No, and Pharaoh, and Egypt, with her gods, and her kings; even Pharaoh, and those who trust in him.', pt: 'Diz o Senhor dos exércitos, o Deus de Israel: Eis que eu castigarei a Amom de Tebas, e a Faraó, e ao Egito, juntamente com os seus deuses e os seus reis, sim, ao próprio Faraó, e aos que nele confiam.' },
      { v: 26, en: 'I will deliver them into the hand of those who seek their lives, and into the hand of Nebuchadnezzar king of Babylon, and into the hand of his servants. Afterwards it will be inhabited, as in the days of old,” says Yahweh.', pt: 'E os entregarei na mão dos que procuram a sua morte, na mão de Nabucodonozor, rei de Babilônia, e na mão dos seus servos; mas depois será habitada, como nos dias antigos, diz o Senhor.' },
      { v: 27, en: '“But don’t you be afraid, Jacob my servant. Don’t be dismayed, Israel; for, behold, I will save you from afar, and your offspring from the land of their captivity. Jacob will return, and will be quiet and at ease. No one will make him afraid.', pt: 'Mas não temas tu, servo meu, Jacó, nem te espantes, ó Israel; pois eis que te livrarei mesmo de longe, e a tua descendência da terra do seu cativeiro; e Jacó voltará, e ficará tranqüilo e sossegado, e não haverá quem o atemorize.' },
      { v: 28, en: 'Don’t be afraid, O Jacob my servant,” says Yahweh; “for I am with you; for I will make a full end of all the nations where I have driven you; but I will not make a full end of you, but I will correct you in measure, and will in no way leave you unpunished.”', pt: 'Tu não temas, servo meu, Jacó, diz o senhor; porque estou contigo; pois destruirei totalmente todas as nações para onde te arrojei; mas a ti não te destruirei de todo, mas castigar-te-ei com justiça, e de modo algum te deixarei impune.' },
    ],
    47: [
      { v: 1, en: 'Yahweh’s word that came to Jeremiah the prophet concerning the Philistines, before Pharaoh struck Gaza.', pt: 'A palavra do Senhor que veio a Jeremias, o profeta, acerca dos filisteus, antes que Faraó ferisse a Gaza.' },
      { v: 2, en: 'Yahweh says: “Behold, waters rise up out of the north, and will become an overflowing stream, and will overflow the land and all that is therein, the city and those who dwell therein. The men will cry, and all the inhabitants of the land will wail.', pt: 'Assim diz o Senhor: Eis que do Norte se levantam as águas, e tornar-se-ão em torrente trasbordante, e alagarão a terra e quanto há nela, a cidade e os que nela habitam; os homens clamarão, e todos os habitantes da terra uivarão,' },
      { v: 3, en: 'At the noise of the stamping of the hoofs of his strong ones, at the rushing of his chariots, at the rumbling of his wheels, the fathers don’t look back to their children for feebleness of hands;', pt: 'ao ruído estrepitoso das unhas dos seus fortes cavalos, ao barulho de seus carros, ao estrondo das suas rodas; os pais não atendem aos filhos, por causa da fraqueza das mãos,' },
      { v: 4, en: 'because of the day that comes to destroy all the Philistines, to cut off from Tyre and Sidon every helper who remains; for Yahweh will destroy the Philistines, the remnant of the isle of Caphtor.', pt: 'por causa do dia que vem para destruir a todos os filisteus, para cortar de Tiro e de Sidom todo o resto que os socorra; pois o Senhor destruirá os filisteus, o resto da ilha de Caftor.' },
      { v: 5, en: 'Baldness has come on Gaza; Ashkelon is brought to nothing, the remnant of their valley: how long will you cut yourself?', pt: 'A calvicie é vinda sobre Gaza; foi desarraigada Asquelom, bem como o resto do seu vale; até quando te sarjarás?' },
      { v: 6, en: '“‘You sword of Yahweh, how long will it be before you are quiet? Put yourself back into your scabbard; rest, and be still.’', pt: 'Ah espada do Senhor! até quando deixarás de repousar? volta para a tua bainha; descansa, e aquieta-te.' },
      { v: 7, en: '“How can you be quiet, since Yahweh has given you a command? Against Ashkelon, and against the seashore, there has he appointed it.”', pt: 'Como podes estar quieta, se o Senhor te deu uma ordem? Contra Asquelom, e contra o litoral, é que ele a enviou.' },
    ],
    48: [
      { v: 1, en: 'Of Moab. Yahweh of Armies, the God of Israel, says: “Woe to Nebo! For it is laid waste. Kiriathaim is disappointed. It is taken. Misgab is put to shame and broken down.', pt: 'Acerca de Moabe. Assim diz o Senhor dos exércitos, Deus de Israel: Ai de Nebo, porque foi destruída; envergonhada está Quiriataim, já é tomada; Misgabe está envergonhada e espantada.' },
      { v: 2, en: 'The praise of Moab is no more. In Heshbon they have devised evil against her: ‘Come, and let us cut her off from being a nation.’ You also, Madmen, will be brought to silence. The sword will pursue you.', pt: 'O louvor de Moabe já não existe mais; em Hesbom projetaram mal contra ela, dizendo: Vinde, e exterminemo-la, para que não mais seja nação; também tu, ó Madmém, serás destruída; a espada te perseguirá.' },
      { v: 3, en: 'The sound of a cry from Horonaim, desolation and great destruction!', pt: 'Voz de grito de Horonaim, ruína e grande destruição!' },
      { v: 4, en: 'Moab is destroyed. Her little ones have caused a cry to be heard.', pt: 'Está destruído Moabe; seus filhinhos fizeram ouvir um clamor.' },
      { v: 5, en: 'For they will go up by the ascent of Luhith with continual weeping. For at the descent of Horonaim they have heard the distress of the cry of destruction.', pt: 'Pois pela subida de Luíte eles vão subindo com choro contínuo; porque na descida de Horonaim, ouviram a angústia do grito da destruição.' },
      { v: 6, en: 'Flee! Save your lives! Be like the juniper bush in the wilderness.', pt: 'Fugi, salvai a vossa vida! Sede como o asno selvagem no deserto.' },
      { v: 7, en: 'For, because you have trusted in your works and in your treasures, you also will be taken. Chemosh will go out into captivity, his priests and his princes together.', pt: 'Pois, porquanto confiaste nas tuas obras e nos teus tesouros, também tu serás tomada; e Quemós sairá para o cativeiro, os seus sacerdotes e os seus príncipes juntamente.' },
      { v: 8, en: 'The destroyer will come on every city, and no city will escape; the valley also will perish, and the plain will be destroyed; as Yahweh has spoken.', pt: 'Porque virá o destruidor sobre cada uma das cidades e nenhuma escapará, e perecerá o vale, e destruir-se-á a planície, como disse o Senhor.' },
      { v: 9, en: 'Give wings to Moab, that she may fly and get herself away: and her cities will become a desolation, without anyone to dwell in them.', pt: 'Dai asas a Moabe, porque voando sairá; e as suas cidades se tornarão em desolação, sem habitante.' },
      { v: 10, en: '“Cursed is he who does the work of Yahweh negligently; and cursed is he who keeps back his sword from blood.', pt: 'Maldito aquele que fizer a obra do Senhor negligentemente, e maldito aquele que vedar do sangue a sua espada!' },
      { v: 11, en: '“Moab has been at ease from his youth, and he has settled on his lees, and has not been emptied from vessel to vessel, neither has he gone into captivity: therefore his taste remains in him, and his scent is not changed.', pt: 'Moabe tem estado sossegado desde a sua mocidade, e tem repousado como vinho sobre as fezes; não foi deitado de vasilha em vasilha, nem foi para o cativeiro; por isso permanece nele o seu sabor, e o seu cheiro não se altera.' },
      { v: 12, en: 'Therefore behold, the days come,” says Yahweh, “that I will send to him those who pour off, and they will pour him off; and they will empty his vessels, and break their bottles in pieces.', pt: 'Portanto, eis que os dias vêm, diz o Senhor, em que lhe enviarei derramadores que o derramarão; e despejarão as suas vasilhas, e despedaçarão os seus jarros.' },
      { v: 13, en: 'Moab will be ashamed of Chemosh, as the house of Israel was ashamed of Bethel, their confidence.', pt: 'E Moabe terá vergonha de Quemós, como se envergonhou a casa de Israel de Betel, sua confiança.' },
      { v: 14, en: '“How do you say, ‘We are mighty men, and valiant men for the war?’', pt: 'Como direis: Somos valentes e homens fortes para a guerra?' },
      { v: 15, en: 'Moab is laid waste, and they have gone up into his cities, and his chosen young men have gone down to the slaughter,” says the King, whose name is Yahweh of Armies.', pt: 'Já subiu o destruidor de Moabe e das suas cidades, e os seus mancebos escolhidos desceram à matança, diz o Rei, cujo nome é o Senhor dos exércitos.' },
      { v: 16, en: '“The calamity of Moab is near to come, and his affliction hurries fast.', pt: 'A calamidade de Moabe está perto e muito se apressa o seu mal.' },
      { v: 17, en: 'All you who are around him, bemoan him, and all you who know his name; say, ‘How the strong staff is broken, the beautiful rod!’', pt: 'Condoei-vos dele todos os que estais em seu redor, e todos os que sabeis o seu nome; dizei: Como se quebrou a vara forte, o cajado formoso!' },
      { v: 18, en: '“You daughter who dwells in Dibon, come down from your glory, and sit in thirst; for the destroyer of Moab has come up against you. He has destroyed your strongholds.', pt: 'Desce da tua glória, e senta-te no pó, ó moradora, filha de Dibom; porque o destruidor de Moabe subiu contra ti, e desfez as tuas fortalezas.' },
      { v: 19, en: 'Inhabitant of Aroer, stand by the way and watch. Ask him who flees, and her who escapes; say, ‘What has been done?’', pt: 'Põe-te junto ao caminho, e espia, ó moradora do Aroer; pergunta ao que foge, e à que escapa: Que sucedeu?' },
      { v: 20, en: 'Moab is disappointed; for it is broken down. Wail and cry! Tell it by the Arnon, that Moab is laid waste.', pt: 'Moabe está envergonhado, porque foi quebrantado; uivai e gritai; anunciai em Arnom que Moabe está destruído.' },
      { v: 21, en: 'Judgment has come on the plain country, on Holon, on Jahzah, on Mephaath,', pt: 'Também o julgamento é vindo sobre a terra da planície; sobre Holom, Jaza, e Mefaate;' },
      { v: 22, en: 'on Dibon, on Nebo, on Beth Diblathaim,', pt: 'sobre Dibom, Nebo, e Bete-Diblataim;' },
      { v: 23, en: 'on Kiriathaim, on Beth Gamul, on Beth Meon,', pt: 'sobre Quiriataim, Bete-Gamul, e BeteMeom;' },
      { v: 24, en: 'on Kerioth, on Bozrah, and on all the cities of the land of Moab, far or near.', pt: 'sobre Queriote, e Bozra, e todas as cidades da terra de Moabe, as de longe e as de perto.' },
      { v: 25, en: 'The horn of Moab is cut off, and his arm is broken,” says Yahweh.', pt: 'Está cortado o poder de Moabe, e quebrantado o seu braço, diz o senhor.' },
      { v: 26, en: '“Make him drunken; for he magnified himself against Yahweh. Moab will wallow in his vomit, and he also will be in derision.', pt: 'Embriagai-o, porque contra o Senhor se engrandeceu; e Moabe se revolverá no seu vômito, e ele também se tornará objeto de escárnio.' },
      { v: 27, en: 'For wasn’t Israel a derision to you? Was he found among thieves? For as often as you speak of him, you shake your head.', pt: 'Pois não se tornou também Israel objeto de escárnio para ti? Porventura foi achado entre ladrões para que, sempre que falas dele, meneies a cabeça?' },
      { v: 28, en: 'You inhabitants of Moab, leave the cities, and dwell in the rock. Be like the dove that makes her nest over the mouth of the abyss.', pt: 'Deixai as cidades, e habitai no rochedo, ó moradores de Moabe; e sede como a pomba que se aninha nos lados da boca da caverna.' },
      { v: 29, en: '“We have heard of the pride of Moab. He is very proud in his loftiness, his pride, his arrogance, and the haughtiness of his heart.', pt: 'Temos ouvido da soberba de Moabe, que é soberbíssimo; da sua sobrançaria, do seu orgulho, da sua arrogância, e da altivez do seu coração.' },
      { v: 30, en: 'I know his wrath,” says Yahweh, “that it is nothing; his boastings have done nothing.', pt: 'Eu conheço, diz o Senhor, a sua insolência, mas isso nada é; as suas jactâncias nada têm efetuado.' },
      { v: 31, en: 'Therefore I will wail for Moab. Yes, I will cry out for all Moab. They will mourn for the men of Kir Heres.', pt: 'Por isso uivarei por Moabe; sim, gritarei por todo o Moabe; pelos homens de Quir-Heres lamentarei.' },
      { v: 32, en: 'With more than the weeping of Jazer will I weep for you, vine of Sibmah. Your branches passed over the sea. They reached even to the sea of Jazer. The destroyer has fallen on your summer fruits and on your vintage.', pt: 'Com choro maior do que o de Jazer chorar-te-ei, ó vide de Sibma; os teus ramos passaram o mar, chegaram até o mar de Jazer; mas o destruidor caiu sobre os teus frutos de verão, e sobre a tua vindima.' },
      { v: 33, en: 'Gladness and joy is taken away from the fruitful field and from the land of Moab. I have caused wine to cease from the wine presses. No one will tread with shouting. The shouting will be no shouting.', pt: 'Tirou-se, pois, a alegria e o regozijo do campo fértil e da terra de Moabe; e fiz que o vinho cessasse dos lagares; já não pisam uvas com júbilo; o brado não é o de júbilo' },
      { v: 34, en: 'From the cry of Heshbon even to Elealeh, even to Jahaz have they uttered their voice, from Zoar even to Horonaim, to Eglath Shelishiyah; for the waters of Nimrim will also become desolate.', pt: 'O grito de Hesbom e Eleale se ouve até Jaza; fazem ouvir a sua voz desde Zoar até Horonaim, e até Eglate-Selíssia; pois também as águas do Ninrim virão a ser uma desolação.' },
      { v: 35, en: 'Moreover I will cause to cease in Moab,” says Yahweh, “him who offers in the high place, and him who burns incense to his gods.', pt: 'Demais, farei desaparecer de Moabe, diz o Senhor, aquele que sacrifica nos altos, e queima incenso a seus deuses.' },
      { v: 36, en: 'Therefore my heart sounds for Moab like pipes, and my heart sounds like pipes for the men of Kir Heres. Therefore the abundance that he has gotten has perished.', pt: 'Por isso geme como flauta o meu coração por Moabe, e como flauta geme o meu coração pelos homens de Quir-Heres; porquanto a abundância que ajuntou se perdeu.' },
      { v: 37, en: 'For every head is bald, and every beard clipped. There are cuttings on all the hands, and sackcloth on the waist.', pt: 'Pois toda cabeça é tosquiada, e toda barba rapada; sobre todas as mãos há sarjaduras, e sobre os lombos sacos.' },
      { v: 38, en: 'On all the housetops of Moab, and in its streets, there is lamentation everywhere; for I have broken Moab like a vessel in which no one delights,” says Yahweh.', pt: 'Sobre todos os eirados de Moabe e nas suas ruas há um pranto geral; porque quebrei a Moabe, como a um vaso que não agrada, diz o Senhor.' },
      { v: 39, en: '“How it is broken down! How they wail! How Moab has turned the back with shame! So will Moab become a derision and a terror to all who are around him.”', pt: 'Como está quebrantrado! como uivam! como virou Moabe as costas envergonhado! assim se tornou Moabe objeto de escárnio e de espanto para todos os que estão em redor dele.' },
      { v: 40, en: 'For Yahweh says: “Behold, he will fly as an eagle, and will spread out his wings against Moab.', pt: 'Pois assim diz o Senhor: Eis que alguém voará como a águia, e estenderá as suas asas contra Moabe.' },
      { v: 41, en: 'Kerioth is taken, and the strongholds are seized. The heart of the mighty men of Moab at that day will be as the heart of a woman in her pangs.', pt: 'Tomadas serão as cidades, e ocupadas as fortalezas; e naquele dia será o coração dos valentes de Moabe como o coração da mulher em suas dores de parto.' },
      { v: 42, en: 'Moab will be destroyed from being a people, because he has magnified himself against Yahweh.', pt: 'E Moabe será destruído, para que não seja povo, porque se engrandeceu contra o Senhor.' },
      { v: 43, en: 'Terror, the pit, and the snare are on you, inhabitant of Moab,” says Yahweh.', pt: 'Temor, e cova, e laço estão sobre ti, ó morador de Moabe, diz o Senhor.' },
      { v: 44, en: '“He who flees from the terror will fall into the pit; and he who gets up out of the pit will be taken in the snare: for I will bring on him, even on Moab, the year of their visitation,” says Yahweh.', pt: 'O que fugir do temor cairá na cova, e o que sair da cova ficará preso no laço; pois trarei sobre ele, sobre Moabe, o ano do seu castigo, diz o Senhor.' },
      { v: 45, en: '“Those who fled stand without strength under the shadow of Heshbon; for a fire has gone out of Heshbon, and a flame from the middle of Sihon, and has devoured the corner of Moab, and the crown of the head of the tumultuous ones.', pt: 'Os que fugiram ficam parados sem forças à sombra de Hesbom; mas fogo saiu de Hesbom, e a labareda do meio de Siom, e devorou a fronte de Moabe e o alto da cabeça dos turbulentos.' },
      { v: 46, en: 'Woe to you, O Moab! The people of Chemosh are undone; for your sons are taken away captive, and your daughters into captivity.', pt: 'Ai de ti, Moabe! pereceu o povo de Quemós; pois teus filhos foram levados cativos, e tuas filhas para o cativeiro.' },
      { v: 47, en: '“Yet I will reverse the captivity of Moab in the latter days,” says Yahweh. Thus far is the judgment of Moab.', pt: 'Contudo nos últimos dias restaurarei do cativeiro a Moabe, diz o Senhor. Até aqui o juizo de Moabe.' },
    ],
    49: [
      { v: 1, en: 'Of the children of Ammon. Yahweh says: “Has Israel no sons? Has he no heir? Why then does Malcam possess Gad, and his people dwell in its cities?', pt: 'A respeito dos filhos de Amom. Assim diz o Senhor: Acaso Israel não tem filhos? Não tem herdeiro? Por que, então, possui Milcom a Gade, e o seu povo habita nas suas cidades?' },
      { v: 2, en: 'Therefore behold, the days come,” says Yahweh, “that I will cause an alarm of war to be heard against Rabbah of the children of Ammon; and it will become a desolate heap, and her daughters will be burned with fire: then Israel will possess those who possessed him,” says Yahweh.', pt: 'Portanto, eis que vêm os dias, diz o Senhor, em que farei ouvir contra Rabá dos filhos de Amom o alarido de guerra, e tornar-se-á num montão de ruínas, e os seus arrabaldes serão queimados a fogo; então Israel deserdará aos que e deserdaram a ele, diz o Senhor.' },
      { v: 3, en: '“Wail, Heshbon, for Ai is laid waste! Cry, you daughters of Rabbah! Clothe yourself in sackcloth. Lament, and run back and forth among the fences; for Malcam will go into captivity, his priests and his princes together.', pt: 'Uiva, ó Hesbom, porque é destruída Ai; clamai, ó filhas de Rabá, cingi-vos de sacos; lamentai, e dai voltas pelas sebes; porque Milcom irá em cativeiro, juntamente com os seus sacerdotes e os seus príncipes.' },
      { v: 4, en: 'Why do you boast in the valleys, your flowing valley, backsliding daughter? You trusted in her treasures, saying, ‘Who will come to me?’', pt: 'Por que te glorias nos vales, teus luxuriantes vales, ó filha apóstata? que confias nos teus tesouros, dizendo: Quem virá contra mim?' },
      { v: 5, en: 'Behold, I will bring a terror on you,” says the Lord, Yahweh of Armies, “from all who are around you. All of you will be driven completely out, and there will be no one to gather together the fugitives.', pt: 'Eis que farei vir sobre ti pavor, diz o Senhor Deus dos exércitos, de todos os que estão ao redor de ti; e sereis lançados fora, cada um para diante, e ninguém recolherá o desgarrado.' },
      { v: 6, en: '“But afterward I will reverse the captivity of the children of Ammon,” says Yahweh.', pt: 'Mas depois disto farei voltar do cativeiro os filhos de Amom, diz o senhor.' },
      { v: 7, en: 'Of Edom, Yahweh of Armies says: “Is wisdom no more in Teman? Has counsel perished from the prudent? Has their wisdom vanished?', pt: 'A respeito de Edom. Assim diz o Senhor dos exércitos: Acaso não há mais sabedoria em Temã? Pereceu o conselho dos entendidos? Desvaneceu-se-lhes a sabedoria?' },
      { v: 8, en: 'Flee! Turn back! Dwell in the depths, inhabitants of Dedan; for I will bring the calamity of Esau on him when I visit him.', pt: 'Fugi, voltai, habitai em profundezas, ó moradores de Dedã; porque trarei sobre ele a calamidade de Esaú, o tempo em que o punirei.' },
      { v: 9, en: 'If grape gatherers came to you, would they not leave some gleaning grapes? If thieves came by night, wouldn’t they steal until they had enough?', pt: 'Se vindimadores viessem a ti, não deixariam alguns rabiscos? se ladrões de noite, não te danificariam só o quanto lhes bastasse?' },
      { v: 10, en: 'But I have made Esau bare, I have uncovered his secret places, and he will not be able to hide himself. His offspring is destroyed, with his brothers and his neighbors; and he is no more.', pt: 'Mas eu desnudei a Esaú, descobri os seus esconderijos, de modo que ele não se poderá esconder. E despojada a sua descendência, como também seus irmãos e seus vizinhos, e ele já não existe.' },
      { v: 11, en: 'Leave your fatherless children. I will preserve them alive. Let your widows trust in me.”', pt: 'Deixa os teus órfãos, eu os guardarei em vida; e as tuas viúvas confiem em mim.' },
      { v: 12, en: 'For Yahweh says: “Behold, they to whom it didn’t pertain to drink of the cup will certainly drink; and are you he who will altogether go unpunished? You won’t go unpunished, but you will surely drink.', pt: 'Pois assim diz o Senhor: Eis que os que não estavam condenados a beber o copo, certamente o beberão; e ficarias tu inteiramente impune? Não ficarás impune, mas certamente o beberás.' },
      { v: 13, en: 'For I have sworn by myself,” says Yahweh, “that Bozrah will become an astonishment, a reproach, a waste, and a curse. All its cities will be perpetual wastes.”', pt: 'Pois por mim mesmo jurei, diz o Senhor, que Bozra servirá de objeto de espanto, de opróbrio, de ruína, e de maldição; e todas as suas cidades se tornarão em desolações perpétuas.' },
      { v: 14, en: 'I have heard news from Yahweh, and an ambassador is sent among the nations, saying, “Gather yourselves together! Come against her! Rise up to the battle!”', pt: 'Eu ouvi novas da parte do Senhor, que um embaixador é enviado por entre as nações para lhes dizer: Ajuntai-vos, e vinde contra ela, e levantai-vos para a guerra.' },
      { v: 15, en: '“For, behold, I have made you small among the nations, and despised among men.', pt: 'Pois eis que te farei pequeno entre as nações, desprezado entre os homens.' },
      { v: 16, en: 'As for your terror, the pride of your heart has deceived you, O you who dwell in the clefts of the rock, who hold the height of the hill, though you should make your nest as high as the eagle, I will bring you down from there,” says Yahweh.', pt: 'Quanto à tua terribilidade, enganou-te a arrogância do teu coração, ó tu que habitas nas cavernas dos penhascos, que ocupas as alturas dos outeiros; ainda que ponhas o teu ninho no alto como a águia, de lá te derrubarei, diz o Senhor.' },
      { v: 17, en: '“Edom will become an astonishment. Everyone who passes by it will be astonished, and will hiss at all its plagues.', pt: 'E Edom se tornará em objeto de espanto; todo aquele que passar por ela se espantará, e assobiará por causa de todas as suas pragas.' },
      { v: 18, en: 'As in the overthrow of Sodom and Gomorrah and its neighbor cities,” says Yahweh, “no man will dwell there, neither will any son of man live therein.', pt: 'Como na subversão de Sodoma e Gomorra, e das cidades circunvizinhas, diz o Senhor, não habitará ninguém ali, nem peregrinará nela filho de homem.' },
      { v: 19, en: '“Behold, he will come up like a lion from the pride of the Jordan against the strong habitation: for I will suddenly make them run away from it; and whoever is chosen, I will appoint him over it. For who is like me? Who will appoint me a time? Who is the shepherd who will stand before me?”', pt: 'Eis que como leão subirá das margens do Jordão um inimigo contra a morada forte; mas de repente o farei correr dali; e ao escolhido, pô-lo-ei sobre ela. Pois quem é semelhante a mim? e quem me fixará um prazo? e quem é o pastor que me poderá resistir?' },
      { v: 20, en: 'Therefore hear the counsel of Yahweh, that he has taken against Edom; and his purposes, that he has purposed against the inhabitants of Teman: Surely they will drag them away, the little ones of the flock. Surely he will make their habitation desolate over them.', pt: 'Portanto ouvi o conselho do Senhor, que ele decretou contra Edom, e os seus desígnios, que ele intentou contra os moradores de Temã: Até os mais novos do rebanho serão arrastados; certamente ele assolará as suas moradas sobre eles.' },
      { v: 21, en: 'The earth trembles at the noise of their fall; there is a cry, the noise which is heard in the Red Sea.', pt: 'A terra estremecerá com o estrondo da sua queda; o som do seu clamor se ouvirá até o Mar Vermelho.' },
      { v: 22, en: 'Behold, he will come up and fly as the eagle, and spread out his wings against Bozrah. The heart of the mighty men of Edom at that day will be as the heart of a woman in her pangs.', pt: 'Eis que como águia subirá, e voará, e estenderá as suas asas contra Bozra; e o coração do valente de Edom naquele dia se tornará como o coração da mulher que está em dores de parto.' },
      { v: 23, en: 'Of Damascus: “Hamath is confounded, and Arpad; for they have heard evil news. They have melted away. There is sorrow on the sea. It can’t be quiet.', pt: 'A respeito de Damasco. Envergonhadas estão Hamate e Arpade, e se derretem de medo porquanto ouviram más notícias; estão agitadas como o mar, que não pode aquietar-se.' },
      { v: 24, en: 'Damascus has grown feeble, she turns herself to flee, and trembling has seized her. Anguish and sorrows have taken hold of her, as of a woman in travail.', pt: 'Enfraquecida está Damasco, virou as costas para fugir, e o tremor apoderou-se dela; angústia e dores apossaram-se dela como da mulher que está de parto.' },
      { v: 25, en: 'How is the city of praise not forsaken, the city of my joy?', pt: 'Como está abandonada a cidade famosa, a cidade da minha alegria!' },
      { v: 26, en: 'Therefore her young men will fall in her streets, and all the men of war will be brought to silence in that day,” says Yahweh of Armies.', pt: 'Portanto os seus jovens lhe cairão nas ruas, e todos os homens de guerra serão consumidos naquele dia, diz o Senhor dos exércitos.' },
      { v: 27, en: '“I will kindle a fire in the wall of Damascus, and it will devour the palaces of Ben Hadad.”', pt: 'E acenderei fogo no muro de Damasco, o qual consumirá os palácios de Bene-Hadade.' },
      { v: 28, en: 'Of Kedar, and of the kingdoms of Hazor, which Nebuchadnezzar king of Babylon struck. Yahweh says: “Arise, go up to Kedar, and destroy the children of the east.', pt: 'A respeito de Quedar, e dos reinos de Hazor, que Nabucodonozor, rei de Babilônia, feriu. Assim diz o Senhor: Levantai-vos, subi contra Quedar, e destruí os filhos do Oriente.' },
      { v: 29, en: 'They will take their tents and their flocks. they will carry away for themselves their curtains, all their vessels, and their camels; and they will cry to them, ‘Terror on every side!’', pt: 'As suas tendas e os seus rebanhos serão tomados; as suas cortinas serão levadas, como também todos os seus vasos, e os seus camelos; e lhes gritarão: Há terror de todos os lados!' },
      { v: 30, en: 'Flee! Wander far off! Dwell in the depths, you inhabitants of Hazor,” says Yahweh; “for Nebuchadnezzar king of Babylon has taken counsel against you, and has conceived a purpose against you.', pt: 'Fugi, desviai-vos para muito longe, habitai nas profundezas, ó moradores de Hazor, diz o Senhor; porque Nabucodonozor, rei de Babilônia, tomou conselho contra vós, e formou um desígnio contra vós.' },
      { v: 31, en: 'Arise! Go up to a nation that is at ease, that dwells without care,” says Yahweh; “that has neither gates nor bars, that dwells alone.', pt: 'Levantai-vos, subi contra uma nação que está sossegada, que habita descuidada, diz o Senhor; que não tem portas nem ferrolhos, que habita a sós.' },
      { v: 32, en: 'Their camels will be a booty, and the multitude of their livestock a plunder. I will scatter to all winds those who have the corners of their beards cut off; and I will bring their calamity from every side of them,” says Yahweh.', pt: 'E os seus camelos serão para presa e a multidão do seu gado para despojo; e espalharei a todo o vento aqueles que cortam os cantos da sua cabeleira; e de todos os lados lhes trarei a sua calamidade, diz o Senhor.' },
      { v: 33, en: 'Hazor will be a dwelling place of jackals, a desolation forever. No man will dwell there, neither will any son of man live therein.”', pt: 'Assim Hazor se tornará em morada de chacais, em desolação para sempre; ninguém habitará ali, nem peregrinará nela filho de homem.' },
      { v: 34, en: 'Yahweh’s word that came to Jeremiah the prophet concerning Elam, in the beginning of the reign of Zedekiah king of Judah, saying,', pt: 'A palavra do Senhor, que veio a Jeremias, o profeta, acerca de Elão, no princípio do reinado de Zedequias, rei de Judá, dizendo:' },
      { v: 35, en: '“Yahweh of Armies says: ‘Behold, I will break the bow of Elam, the chief of their might.', pt: 'Assim diz o Senhor dos exércitos: Eis que eu quebrarei o arco de Elão, o principal do seu poder.' },
      { v: 36, en: 'I will bring on Elam the four winds from the four quarters of the sky, and will scatter them toward all those winds. There will be no nation where the outcasts of Elam will not come.', pt: 'E trarei sobre Elão os quatro ventos dos quatro cantos dos céus, e os espalharei para todos estes ventos; e não haverá nação aonde não cheguem os fugitivos de Elão.' },
      { v: 37, en: 'I will cause Elam to be dismayed before their enemies, and before those who seek their life. I will bring evil on them, even my fierce anger,’ says Yahweh; ‘and I will send the sword after them, until I have consumed them.', pt: 'E farei que Elão desfaleça diante de seus inimigos e diante dos que procuram a sua morte. Farei vir sobre eles o mal, o furor da minha ira, diz o Senhor; e enviarei após eles a espada, até que eu os tenha consumido.' },
      { v: 38, en: 'I will set my throne in Elam, and will destroy from there king and princes,’ says Yahweh.', pt: 'E porei o meu trono em Elão, e destruirei dali rei e príncipes, diz o Senhor.' },
      { v: 39, en: '‘But it will happen in the latter days that I will reverse the captivity of Elam,’ says Yahweh.”', pt: 'Acontecerá, porém, nos últimos dias, que restaurarei do cativeiro a Elão, diz o Senhor.' },
    ],
    50: [
      { v: 1, en: 'The word that Yahweh spoke concerning Babylon, concerning the land of the Chaldeans, by Jeremiah the prophet.', pt: 'A palavra que falou o Senhor acerca de Babilônia, acerca da terra dos caldeus, por intermédio de Jeremias o profeta.' },
      { v: 2, en: '“Declare among the nations and publish, and set up a standard; publish, and don’t conceal: say, ‘Babylon has been taken, Bel is disappointed, Merodach is dismayed! Her images are disappointed. Her idols are dismayed.’', pt: 'Anunciai entre as nações e publicai, arvorando um estandarte; sim publicai, não encubrais; dizei: Tomada está Babilônia, confundido está Bel, caído está Merodaque, confundidos estão os seus ídolos, e caídos estão os seus deuses.' },
      { v: 3, en: 'For a nation comes up out of the north against her, which will make her land desolate, and no one will dwell in it. They have fled. They are gone, both man and animal.', pt: 'Pois do Norte sobe contra ela uma nação que fará da sua terra uma desolação, e não haverá quem nela habite; tanto os homens como os animais já fugiram e se foram.' },
      { v: 4, en: '“In those days, and in that time,” says Yahweh, “the children of Israel will come, they and the children of Judah together; they will go on their way weeping, and will seek Yahweh their God.', pt: 'Naqueles dias, e naquele tempo, diz o Senhor, os filhos de Israel virão, eles e os filhos de Judá juntamente; andando e chorando virão, e buscarão ao Senhor seu Deus.' },
      { v: 5, en: 'They will inquire concerning Zion with their faces turned toward it, saying, ‘Come, and join yourselves to Yahweh in an everlasting covenant that will not be forgotten.’', pt: 'Acerca de Sião indagarão, tendo os seus rostos voltados para lá e dizendo: Vinde e uni-vos ao Senhor num pacto eterno que nunca será esquecido.' },
      { v: 6, en: 'My people have been lost sheep. Their shepherds have caused them to go astray. They have turned them away on the mountains. They have gone from mountain to hill. They have forgotten their resting place.', pt: 'Ovelhas perdidas têm sido o meu povo; os seus pastores as fizeram errar, e voltar aos montes; de monte para outeiro andaram, esqueceram-se do lugar de seu repouso.' },
      { v: 7, en: 'All who found them have devoured them. Their adversaries said, ‘We are not guilty, because they have sinned against Yahweh, the habitation of righteousness, even Yahweh, the hope of their fathers.’', pt: 'Todos os que as achavam as devoraram, e os seus adversários diziam: Culpa nenhuma teremos; porque pecaram contra o Senhor, a morada da justiça, sim, o Senhor, a esperança de seus pais.' },
      { v: 8, en: '“Flee out of the middle of Babylon! Go out of the land of the Chaldeans, and be as the male goats before the flocks.', pt: 'Fugi do meio de Babilônia, e saí da terra dos caldeus, e sede como os bodes diante do rebanho.' },
      { v: 9, en: 'For, behold, I will stir up and cause to come up against Babylon a company of great nations from the north country; and they will set themselves in array against her. She will be taken from there. Their arrows will be as of an expert mighty man. None of them will return in vain.', pt: 'Pois eis que eu suscitarei e farei subir contra Babilônia uma companhia de grandes nações da terra do Norte; e por-se-ão em ordem contra ela; dali será ela tomada. As suas flechas serão como as de valente herói; nenhuma tornará sem efeito.' },
      { v: 10, en: 'Chaldea will be a prey. All who prey on her will be satisfied,” says Yahweh.', pt: 'E Caldéia servirá de presa; todos os que a saquearem ficarão fartos, diz o Senhor.' },
      { v: 11, en: '“Because you are glad, because you rejoice, O you who plunder my heritage, because you are wanton as a heifer that treads out the grain, and neigh as strong horses;', pt: 'Embora vos alegreis e vos regozijeis, ó saqueadores da minha herança, embora andeis soltos como novilha que pisa a erva, e rincheis como cavalos vigorosos,' },
      { v: 12, en: 'your mother will be utterly disappointed. She who bore you will be confounded. Behold, she will be the least of the nations, a wilderness, a dry land, and a desert.', pt: 'muito envergonhada será vossa mãe, ficará humilhada a que vos deu à luz; eis que ela será a última das nações, um deserto, uma terra seca e uma solidão.' },
      { v: 13, en: 'Because of Yahweh’s wrath she won’t be inhabited, but she will be wholly desolate. Everyone who goes by Babylon will be astonished, and hiss at all her plagues.', pt: 'Por causa da ira do Senhor não será habitada, antes se tornará em total desolação; qualquer que passar por Babilônia se espantará, e assobiará por causa de todas as suas pragas.' },
      { v: 14, en: 'Set yourselves in array against Babylon all around, all you who bend the bow; shoot at her. Spare no arrows; for she has sinned against Yahweh.', pt: 'Ponde-vos em ordem para cercar Babilônia, todos os que armais arcos; atirai-lhe, não poupeis as flechas, porque ela tem pecado contra o Senhor.' },
      { v: 15, en: 'Shout against her all around. She has submitted herself. Her bulwarks have fallen. Her walls have been thrown down, for it is the vengeance of Yahweh. Take vengeance on her. As she has done, do to her.', pt: 'Gritai contra ela rodeando-a; ela já se submeteu; caíram seus baluartes, estão derribados os seus muros. Pois esta é a vingança do Senhor; vingai-vos dela; conforme o que ela fez, assim lhe fazei a ela.' },
      { v: 16, en: 'Cut off the sower from Babylon, and him who handles the sickle in the time of harvest. For fear of the oppressing sword, they will each return to their own people, and they will each flee to their own land.', pt: 'Cortai de Babilônia o que semeia, e o que maneja a foice no tempo da sega; por causa da espada do opressor virar-se-á cada um para o seu povo, e fugirá cada qual para a sua terra.' },
      { v: 17, en: '“Israel is a hunted sheep. The lions have driven him away. First, the king of Assyria devoured him, and now at last Nebuchadnezzar king of Babylon has broken his bones.”', pt: 'Cordeiro desgarrado é Israel, os leões o afugentaram; o primeiro a devorá-lo foi o rei da Assíria, e agora por último Nabucodonozor, rei de Babilônia, lhe quebrou os ossos.' },
      { v: 18, en: 'Therefore Yahweh of Armies, the God of Israel, says: “Behold, I will punish the king of Babylon and his land, as I have punished the king of Assyria.', pt: 'Portanto, assim diz o Senhor dos exércitos, Deus de Israel: Eis que castigarei o rei de Babilônia e a sua terra, como castiguei o rei da Assíria.' },
      { v: 19, en: 'I will bring Israel again to his pasture, and he will feed on Carmel and Bashan. His soul will be satisfied on the hills of Ephraim and in Gilead.', pt: 'E farei voltar Israel para a sua morada, e ele pastará no Carmelo e em Basã, e se fartará nos outeiros de Efraim e em Gileade.' },
      { v: 20, en: 'In those days, and in that time,” says Yahweh, “the iniquity of Israel will be sought for, and there will be none; also the sins of Judah, and they won’t be found; for I will pardon them whom I leave as a remnant.', pt: 'Naqueles dias, e naquele tempo, diz o Senhor, buscar-se-á a iniqüidade em Israel, e não haverá; e o pecado em Judá, e não se achará; pois perdoarei aos que eu deixar de resto.' },
      { v: 21, en: '“Go up against the land of Merathaim, even against it, and against the inhabitants of Pekod. Kill and utterly destroy after them,” says Yahweh, “and do according to all that I have commanded you.', pt: 'Sobe contra a terra de Merataim, sim, contra ela, e contra os moradores de Pecode; mata e inteiramente destrói tudo após eles, diz o Senhor, e faze conforme tudo o que te ordenei.' },
      { v: 22, en: 'A sound of battle is in the land, and of great destruction.', pt: 'Na terra há estrondo de batalha, e de grande destruição.' },
      { v: 23, en: 'How the hammer of the whole earth is cut apart and broken! How Babylon has become a desolation among the nations!', pt: 'Como foi cortado e quebrado o martelo de toda a terra! como se tornou Babilônia em objeto de espanto entre as nações!' },
      { v: 24, en: 'I have laid a snare for you, and you are also taken, Babylon, and you weren’t aware. You are found, and also caught, because you have fought against Yahweh.', pt: 'Laços te armei, e também foste presa, ó Babilônia, e tu não o soubeste; foste achada, e também apanhada, porque contra o Senhor te entremeteste.' },
      { v: 25, en: 'Yahweh has opened his armory, and has brought out the weapons of his indignation; for the Lord, Yahweh of Armies, has a work to do in the land of the Chaldeans.', pt: 'O Senhor abriu o seu arsenal, e tirou os instrumentos da sua indignação; porque o senhor Deus dos exércitos tem uma obra a realizar na terra dos caldeus.' },
      { v: 26, en: 'Come against her from the farthest border. Open her storehouses. Cast her up as heaps. Destroy her utterly. Let nothing of her be left.', pt: 'Vinde contra ela dos confins da terra, abri os seus celeiros; fazei dela montões, e destruí-a de todo; nada lhe fique de resto.' },
      { v: 27, en: 'Kill all her bulls. Let them go down to the slaughter. Woe to them! For their day has come, the time of their visitation.', pt: 'Matai a todos os seus novilhos, desçam ao degoladouro; ai deles! porque é chegado o seu dia, o tempo da sua punição.' },
      { v: 28, en: 'Listen to those who flee and escape out of the land of Babylon, to declare in Zion the vengeance of Yahweh our God, the vengeance of his temple.', pt: 'Eis a voz dos que fogem e escapam da terra de Babilônia para anunciarem em Sião a vingança do Senhor nosso Deus, a vingança do seu templo.' },
      { v: 29, en: '“Call together the archers against Babylon, all those who bend the bow. Encamp against her all around. Let none of it escape. Pay her back according to her work. According to all that she has done, do to her; for she has been proud against Yahweh, against the Holy One of Israel.', pt: 'Convocai contra Babilônia os flecheiros, todos os que armam arcos; acampai-vos contra ela em redor, ninguém escape dela. Pagai-lhe conforme a sua obra; conforme tudo o que ela fez, assim lhe fazei a ela; porque se houve arrogantemente contra o Senhor, contra o Santo de Israel.' },
      { v: 30, en: 'Therefore her young men will fall in her streets. All her men of war will be brought to silence in that day,” says Yahweh.', pt: 'Portanto cairão os seus jovens nas suas praças, e todos os seus homens de guerra serão destruídos naquele dia, diz o Senhor.' },
      { v: 31, en: '“Behold, I am against you, you proud one,” says the Lord, Yahweh of Armies; “for your day has come, the time that I will visit you.', pt: 'Eis que eu sou contra ti, ó soberbo, diz o Senhor Deus dos exércitos; pois o teu dia é chegado, o tempo em que te hei de punir?' },
      { v: 32, en: 'The proud one will stumble and fall, and no one will raise him up. I will kindle a fire in his cities, and it will devour all who are around him.”', pt: 'Então tropeçará o soberbo, e cairá, e ninguém haverá que o levante; e porei fogo às suas cidades, o qual consumirá tudo o que está ao seu redor.' },
      { v: 33, en: 'Yahweh of Armies says: “The children of Israel and the children of Judah are oppressed together. All who took them captive hold them fast. They refuse to let them go.', pt: 'Assim diz o Senhor dos exércitos: Os filhos de Israel e os filhos de Judá são juntamente oprimidos; e todos os que os levaram cativos os retêm, recusam soltá-los.' },
      { v: 34, en: 'Their Redeemer is strong: Yahweh of Armies is his name. He will thoroughly plead their cause, that he may give rest to the earth, and disquiet the inhabitants of Babylon.', pt: 'Mas o seu Redentor é forte; o Senhor dos exércitos é o seu nome. Certamente defenderá em juízo a causa deles, para dar descanso à terra, e inquietar os moradores de Babilônia.' },
      { v: 35, en: '“A sword is on the Chaldeans,” says Yahweh, “and on the inhabitants of Babylon, on her princes, and on her wise men.', pt: 'A espada virá sobre os caldeus, diz o senhor, e sobre os moradores de Babilônia, e sobre os seus príncipes, e sobre os seus sábios.' },
      { v: 36, en: 'A sword is on the boasters, and they will become fools. A sword is on her mighty men, and they will be dismayed.', pt: 'A espada virá sobre os paroleiros, e eles ficarão insensatos; a espada virá sobre os seus valentes, e eles desfalecerão.' },
      { v: 37, en: 'A sword is on their horses, on their chariots, and on all the mixed people who are in the middle of her; and they will become as women. A sword is on her treasures, and they will be robbed.', pt: 'A espada virá sobre os seus cavalos, e sobre os seus carros, e sobre todo o povo misto, que se acha no meio dela, e eles se tornarão como mulheres; a espada virá sobre os seus tesouros, e estes serão saqueados.' },
      { v: 38, en: 'A drought is on her waters, and they will be dried up; for it is a land of engraved images, and they are mad over idols.', pt: 'Cairá a seca sobre as suas águas, e elas secarão; pois é uma terra de imagens esculpidas, e eles pelos seus ídolos fazem-se loucos.' },
      { v: 39, en: 'Therefore the wild animals of the desert with the wolves will dwell there. The ostriches will dwell therein; and it will be inhabited no more forever; neither will it be lived in from generation to generation.', pt: 'Por isso feras do deserto juntamente com lobos habitarão ali; também habitarão nela avestruzes; e nunca mais será povoada, nem será habitada de geração em geração.' },
      { v: 40, en: 'As when God overthrew Sodom and Gomorrah and its neighbor cities,” says Yahweh, “so no man will dwell there, neither will any son of man live therein.', pt: 'Como quando Deus subverteu a Sodoma e a Gomorra, e às suas cidades vizinhas, diz o Senhor, assim ninguém habitará ali, nem peregrinará nela filho de homem.' },
      { v: 41, en: '“Behold, a people comes from the north; and a great nation and many kings will be stirred up from the uttermost parts of the earth.', pt: 'Eis que um povo vem do norte; e uma grande nação e muitos reis se levantam das extremidades da terra.' },
      { v: 42, en: 'They take up bow and spear. They are cruel, and have no mercy. Their voice roars like the sea. They ride on horses, everyone set in array, as a man to the battle, against you, daughter of Babylon.', pt: 'Armam-se de arco e lança; são cruéis, e não têm piedade; a sua voz brama como o mar, e em cavalos vêm montados, dispostos como homens para a batalha, contra ti, ó filha de Babilônia.' },
      { v: 43, en: 'The king of Babylon has heard the news of them, and his hands become feeble: anguish has taken hold of him, pains as of a woman in labor.', pt: 'O rei de Babilônia ouviu a fama deles, e desfaleceram as suas mãos; a angústia se apoderou dele, dores, como da que está de parto.' },
      { v: 44, en: 'Behold, the enemy will come up like a lion from the pride of the Jordan against the strong habitation; for I will suddenly make them run away from it. Whoever is chosen, I will appoint him over it; for who is like me? Who will appoint me a time? Who is the shepherd who can stand before me?”', pt: 'Eis que como leão subirá das margens do Jordão um inimigo contra a morada forte, mas de repente o farei correr dali; e ao escolhido, pô-lo-ei sobre ela. Pois quem é semelhante a mim? e quem me fixará um prazo? Quem é o pastor que me poderá resistir?' },
      { v: 45, en: 'Therefore hear the counsel of Yahweh, that he has taken against Babylon; and his purposes, that he has purposed against the land of the Chaldeans: Surely they will drag them away, even the little ones of the flock. Surely he will make their habitation desolate over them.', pt: 'Portanto ouvi o conselho que o Senhor decretou contra Babilônia, e o propósito que formou contra a terra dos caldeus: Certamente eles, os pequenos do rebanho, serão arrastados; certamente o aprisco ficará apavorado por causa deles.' },
      { v: 46, en: 'At the noise of the taking of Babylon the earth trembles; and the cry is heard among the nations.', pt: 'Ao estrondo da tomada de Babilônia estremece a terra; e o grito se ouve entre as nações.' },
    ],
    51: [
      { v: 1, en: 'Yahweh says: “Behold, I will raise up against Babylon, and against those who dwell in Lebkamai, a destroying wind.', pt: 'Assim diz o Senhor: Eis que levantarei um vento destruidor contra Babilônia, e contra os que habitam na Caldéia.' },
      { v: 2, en: 'I will send to Babylon strangers, who will winnow her. They will empty her land; for in the day of trouble they will be against her all around.', pt: 'E enviarei padejadores contra Babilônia, que a padejarão, e esvaziarão a sua terra, quando vierem contra ela em redor no dia da calamidade.' },
      { v: 3, en: 'Against him who bends, let the archer bend his bow, also against him who lifts himself up in his coat of mail. Don’t spare her young men! Utterly destroy all her army!', pt: 'Não arme o flecheiro o seu arco, nem se levante o que estiver armado da sua couraça; não perdoeis aos seus jovens; destruí completamente todo o seu exército.' },
      { v: 4, en: 'They will fall down slain in the land of the Chaldeans, and thrust through in her streets.', pt: 'Cairão mortos na terra dos caldeus, e feridos nas ruas dela.' },
      { v: 5, en: 'For Israel is not forsaken, nor Judah, by his God, by Yahweh of Armies; though their land is full of guilt against the Holy One of Israel.', pt: 'Pois Israel e Judá não foram abandonados do seu Deus, o Senhor dos exércitos, ainda que a terra deles esteja cheia de culpas contra o Santo de Israel.' },
      { v: 6, en: '“Flee out of the middle of Babylon! Everyone save his own life! Don’t be cut off in her iniquity; for it is the time of Yahweh’s vengeance. He will render to her a recompense.', pt: 'Fugi do meio de Babilônia, e livre cada um a sua vida; não sejais exterminados na sua punição; pois este é o tempo da vingança do Senhor; ele lhe dará o pago.' },
      { v: 7, en: 'Babylon has been a golden cup in Yahweh’s hand, who made all the earth drunk. The nations have drunk of her wine; therefore the nations have gone mad.', pt: 'Na mão do Senhor a Babilônia era um copo de ouro, o qual embriagava a toda a terra; do seu vinho beberam as nações; por isso as nações estão fora de si.' },
      { v: 8, en: 'Babylon has suddenly fallen and been destroyed! Wail for her! Take balm for her pain. Perhaps she may be healed.', pt: 'Repentinamente caiu Babilônia, e ficou arruinada; uivai sobre ela; tomai bálsamo para a sua dor, talvez sare.' },
      { v: 9, en: '“We would have healed Babylon, but she is not healed. Forsake her, and let us each go into his own country; for her judgment reaches to heaven, and is lifted up even to the skies.', pt: 'Queríamos sarar Babilônia, ela, porém, não sarou; abandonai- a, e vamo-nos, cada qual para a sua terra; pois o seu julgamento chega até o céu, e se eleva até as mais altas nuvens.' },
      { v: 10, en: '‘Yahweh has produced our righteousness: come, and let us declare in Zion the work of Yahweh our God.’', pt: 'O Senhor trouxe à luz a nossa justiça; vinde e anunciemos em Sião a obra do Senhor nosso Deus.' },
      { v: 11, en: '“Make the arrows sharp! Hold the shields firmly! Yahweh has stirred up the spirit of the kings of the Medes, because his purpose is against Babylon, to destroy it; for it is the vengeance of Yahweh, the vengeance of his temple.', pt: 'Aguçai as flechas, preperai os escudos; o Senhor despertou o espírito dos reis dos medos; porque o seu intento contra Babilônia é para a destruir; pois esta é a vingança do Senhor, a vingança do seu templo.' },
      { v: 12, en: 'Set up a standard against the walls of Babylon! Make the watch strong! Set the watchmen, and prepare the ambushes; for Yahweh has both purposed and done that which he spoke concerning the inhabitants of Babylon.', pt: 'Arvorai um estandarte sobre os muros de Babilônia, reforçai a guarda, colocai sentinelas, preparai as emboscadas; porque o Senhor tanto intentou como efetuou o que tinha dito acerca dos moradores de Babilônia.' },
      { v: 13, en: 'You who dwell on many waters, abundant in treasures, your end has come, the measure of your covetousness.', pt: 'ç tu, que habitas sobre muitas águas, rica de tesouros! é chegado o teu fim, a medida da tua ganância.' },
      { v: 14, en: 'Yahweh of Armies has sworn by himself, saying, ‘Surely I will fill you with men, as with the canker worm; and they will lift up a shout against you.’', pt: 'Jurou o Senhor dos exércitos por si mesmo, dizendo: Certamente te encherei de homens, como de locustas; e eles levantarão o grito de vitória sobre ti.' },
      { v: 15, en: '“He has made the earth by his power. He has established the world by his wisdom. By his understanding he has stretched out the heavens.', pt: 'É ele quem fez a terra com o seu poder, estabeleceu o mundo com a sua sabedoria, e estendeu os céus com o seu entendimento.' },
      { v: 16, en: 'When he utters his voice, there is a roar of waters in the heavens, and he causes the vapors to ascend from the ends of the earth. He makes lightning for the rain, and brings the wind out of his treasuries.', pt: 'Â sua voz, há grande tumulto de águas nas céus, e ele faz subir os vapores desde as extremidades da terra; faz os relâmpagos para a chuva, e tira o vento dos seus tesouros.' },
      { v: 17, en: '“Every man has become brutish without knowledge. Every goldsmith is disappointed by his image; for his molten image is falsehood, and there is no breath in them.', pt: 'Embruteceu-se todo homem, de modo que não tem conhecimento; todo ourives é envergonhado pelas suas imagens esculpidas; pois as suas imagens de fundição são mentira, e não há espírito em nenhuma delas.' },
      { v: 18, en: 'They are vanity, a work of delusion. In the time of their visitation, they will perish.', pt: 'Vaidade são, obra de enganos; no tempo em que eu as visitar perecerão.' },
      { v: 19, en: 'The portion of Jacob is not like these, for he is the former of all things; including the tribe of his inheritance: Yahweh of Armies is his name.', pt: 'Não é semelhante a estes a porção de Jacó; porque ele é o que forma todas as coisas; e Israel é a tribo da sua herança; o Senhor dos exércitos é o seu nome.' },
      { v: 20, en: '“You are my battle ax and weapons of war. With you I will break the nations into pieces. With you I will destroy kingdoms.', pt: 'Tu me serves de martelo e de armas de guerra; contigo despedaçarei nações, e contigo destruirei os reis;' },
      { v: 21, en: 'With you I will break in pieces the horse and his rider.', pt: 'contigo despedaçarei o cavalo e o seu cavaleiro; contigo despedaçarei e carro e o que nele vai;' },
      { v: 22, en: 'With you I will break in pieces the chariot and him who rides therein. With you I will break in pieces man and woman. With you I will break in pieces the old man and the youth. With you I will break in pieces the young man and the virgin.', pt: 'contigo despedaçarei o homem e a mulher; contigo despedaçarei o velho e o moço; contigo despedaçarei o mancebo e a donzela;' },
      { v: 23, en: 'With you I will break in pieces the shepherd and his flock. With you I will break in pieces the farmer and his yoke. With you will I break in pieces governors and deputies.', pt: 'contigo despedaçarei o pastor e o seu rebanho; contigo despedaçarei o lavrador e a sua junta de bois; e contigo despedaçarei governadores e magistrados.' },
      { v: 24, en: '“I will render to Babylon and to all the inhabitants of Chaldea all their evil that they have done in Zion in your sight,” says Yahweh.', pt: 'Ante os vossos olhos pagarei a Babilônia, e a todos os moradores da Caldéia, toda a sua maldade que fizeram em Sião, diz o Senhor.' },
      { v: 25, en: '“Behold, I am against you, destroying mountain,” says Yahweh, “which destroys all the earth. I will stretch out my hand on you, roll you down from the rocks, and will make you a burned mountain.', pt: 'Eis-me aqui contra ti, ó monte destruidor, diz o Senhor, que destróis toda a terra; estenderei a minha mão contra ti, e te revolverei dos penhascos abaixo, e farei de ti um monte incendiado.' },
      { v: 26, en: 'They won’t take a cornerstone from you, nor a stone for foundations; but you will be desolate for ever,” says Yahweh.', pt: 'E não tomarão de ti pedra para esquina, nem pedra para fundamentos; mas desolada ficarás perpetuamente, diz o Senhor.' },
      { v: 27, en: '“Set up a standard in the land! Blow the trumpet among the nations! Prepare the nations against her! Call together against her the kingdoms of Ararat, Minni, and Ashkenaz! Appoint a marshal against her! Cause the horses to come up as the rough canker worm!', pt: 'Arvorai um estandarte na terra, tocai a trombeta entre as nações, preparai as nações contra ela, convocai contra ela os reinos de Arará, Mini, e Asquenaz; ponde sobre ela um capitão, fazei subir cavalos, como locustas eriçadas.' },
      { v: 28, en: 'Prepare against her the nations, the kings of the Medes, its governors, and all its deputies, and all the land of their dominion!', pt: 'Preparai contra ela as nações, os reis dos medos, os seus governadores e magistrados, e toda a terra do seu domínio.' },
      { v: 29, en: 'The land trembles and is in pain; for the purposes of Yahweh against Babylon stand, to make the land of Babylon a desolation, without inhabitant.', pt: 'E a terra estremece e está angustiada; porque os desígnios do Senhor estão firmes contra Babilônia, para fazer da terra de Babilônia uma desolação, sem habitantes.' },
      { v: 30, en: 'The mighty men of Babylon have stopped fighting, they remain in their strongholds. Their might has failed. They have become as women. Her dwelling places are set on fire. Her bars are broken.', pt: 'Os valentes de Babilônia cessaram de pelejar, ficam nas fortalezas, desfaleceu a sua força, tornaram-se como mulheres; incendiadas são as suas moradas, quebrados os seus ferrolhos.' },
      { v: 31, en: 'One runner will run to meet another, and one messenger to meet another, to show the king of Babylon that his city is taken on every quarter.', pt: 'Um correio corre ao encontro de outro correio, e um mensageiro ao encontro de outro mensageiro, para anunciar ao rei de Babilônia que a sua cidade está tomada de todos os lados.' },
      { v: 32, en: 'So the passages are seized. They have burned the reeds with fire. The men of war are frightened.”', pt: 'E os vaus estão ocupados, os canaviais queimados a fogo, e os homens de guerra assombrados.' },
      { v: 33, en: 'For Yahweh of Armies, the God of Israel says: “The daughter of Babylon is like a threshing floor at the time when it is trodden. Yet a little while, and the time of harvest comes for her.”', pt: 'Pois assim diz o Senhor dos exércitos, o Deus de Israel: A filha de Babilônia é como a eira no tempo da debulha; ainda um pouco, e o tempo da sega lhe virá.' },
      { v: 34, en: '“Nebuchadnezzar the king of Babylon has devoured me. He has crushed me. He has made me an empty vessel. He has, like a monster, swallowed me up. He has filled his mouth with my delicacies. He has cast me out.', pt: 'Nabucodonozor, rei de Babilônia, devorou-me, esmagou-me, fez de mim um vaso vazio, qual monstro tragou-me, encheu o seu ventre do que eu tinha de delicioso; lançou-me fora.' },
      { v: 35, en: 'May the violence done to me and to my flesh be on Babylon!” the inhabitant of Zion will say; and, “May my blood be on the inhabitants of Chaldea!” will Jerusalem say.', pt: 'A violência que se me fez a mim e à minha carne venha sobre Babilônia, diga a moradora de Sião. O meu sangue caia sobre os moradores de Caldéia, diga Jerusalém.' },
      { v: 36, en: 'Therefore Yahweh says: “Behold, I will plead your cause, and take vengeance for you. I will dry up her sea, and make her fountain dry.', pt: 'Pelo que assim diz o Senhor: Eis que defenderei a tua causa, e te vingarei; e secarei o seu mar, e farei que se esgote a sua fonte:' },
      { v: 37, en: 'Babylon will become heaps, a dwelling place for jackals, an astonishment, and a hissing, without inhabitant.', pt: 'E Babilônia se tornará em montões, morada de chacais, objeto de espanto e assobio, sem habitante.' },
      { v: 38, en: 'They will roar together like young lions. They will growl as lions’ cubs.', pt: 'Juntos rugirão como leões novos, bramarão como cachorros de leões.' },
      { v: 39, en: 'When they are heated, I will make their feast, and I will make them drunk, that they may rejoice, and sleep a perpetual sleep, and not wake up,” says Yahweh.', pt: 'Estando eles excitados, preparar-lhes-ei um banquete, e os embriagarei, para que se regozijem, e durmam um perpétuo sono, e não despertem, diz o Senhor.' },
      { v: 40, en: '“I will bring them down like lambs to the slaughter, like rams with male goats.', pt: 'Fá-los-ei descer como cordeiros ao matadouro, como carneiros e bodes.' },
      { v: 41, en: '“How Sheshach is taken! How the praise of the whole earth seized! How Babylon has become a desolation among the nations!', pt: 'Como foi tomada Sesaque, e apanhada de surpresa a glória de toda a terra! como se tornou Babilônia um espetáculo horrendo entre as nações!' },
      { v: 42, en: 'The sea has come up on Babylon. She is covered with the multitude of its waves.', pt: 'O mar subiu sobre Babilônia; coberta está com a multidão das suas ondas.' },
      { v: 43, en: 'Her cities have become a desolation, a dry land, and a desert, a land in which no man dwells. No son of man passes by it.', pt: 'Tornaram-se as suas cidades em ruínas, terra seca e deserta, terra em que ninguém habita, nem passa por ela filho de homem.' },
      { v: 44, en: 'I will execute judgment on Bel in Babylon, and I will bring out of his mouth that which he has swallowed up. The nations will not flow any more to him. Yes, the wall of Babylon will fall.', pt: 'E castigarei a Bel em Babilônia, e tirarei da sua boca o que ele tragou; e nunca mais concorrerão a ele as nações; o muro de Babilônia está caído.' },
      { v: 45, en: '“My people, go away from the middle of her, and each of you save yourselves from Yahweh’s fierce anger.', pt: 'Saí do meio dela, ó povo meu, e salve cada um a sua vida do ardor da ira do Senhor.' },
      { v: 46, en: 'Don’t let your heart faint. Don’t fear for the news that will be heard in the land. For news will come one year, and after that in another year news will come, and violence in the land, ruler against ruler.', pt: 'Não desfaleça o vosso coração, nem temais pelo rumor que se ouvir na terra; pois virá num ano um rumor, e depois noutro ano outro rumor; e haverá violência na terra, dominador contra dominador.' },
      { v: 47, en: 'Therefore behold, the days come that I will execute judgment on the engraved images of Babylon; and her whole land will be confounded. All her slain will fall in the middle of her.', pt: 'Portanto eis que vêm os dias em que executarei juízo sobre as imagens esculpidas de Babilônia; e toda a sua terra ficará envergonhada; e todos os seus traspassados cairão no meio dela.' },
      { v: 48, en: 'Then the heavens and the earth, and all that is therein, will sing for joy over Babylon; for the destroyers will come to her from the north,” says Yahweh.', pt: 'Então o céu e a terra, com tudo quanto neles há, jubilarão sobre Babilônia; pois do norte lhe virão os destruidores, diz o Senhor.' },
      { v: 49, en: '“As Babylon has caused the slain of Israel to fall, so the slain of all the land will fall at Babylon.', pt: 'Babilônia há de cair pelos mortos de Israel, assim como por Babilônia têm caído os mortos de toda a terra.' },
      { v: 50, en: 'You who have escaped the sword, go! Don’t stand still! Remember Yahweh from afar, and let Jerusalem come into your mind.”', pt: 'Vós, que escapastes da espada, ide-vos, não pareis; desde terras longínquas lembrai-vos do Senhor, e suba Jerusalém à vossa mente.' },
      { v: 51, en: '“We are confounded, because we have heard reproach. Confusion has covered our faces, for strangers have come into the sanctuaries of Yahweh’s house.”', pt: 'Envergonhados estamos, porque ouvimos opróbrio; a confusão nos cobriu o rosto; pois entraram estrangeiros nos santuários da casa do Senhor.' },
      { v: 52, en: '“Therefore behold, the days come,” says Yahweh, “that I will execute judgment on her engraved images; and through all her land the wounded will groan.', pt: 'Portanto, eis que vêm os dias, diz o Senhor, em que executarei juízo sobre as suas imagens esculpidas; e em toda a sua terra gemerão os feridos.' },
      { v: 53, en: 'Though Babylon should mount up to the sky, and though she should fortify the height of her strength, yet destroyers will come to her from me,” says Yahweh.', pt: 'Ainda que Babilônia subisse ao céu, e ainda que fortificasse a altura da sua fortaleza, contudo de mim viriam destruidores sobre ela, diz o Senhor.' },
      { v: 54, en: '“The sound of a cry comes from Babylon, and of great destruction from the land of the Chaldeans!', pt: 'Eis um clamor de Babilônia! de grande destruição da terra dos caldeus!' },
      { v: 55, en: 'For Yahweh lays Babylon waste, and destroys out of her the great voice! Their waves roar like many waters. The noise of their voice is uttered.', pt: 'Pois o Senhor está despojando a Babilônia, e emudecendo a sua poderosa voz. Bramam as ondas do inimigo como muitas águas; ouve-se o arruído da sua voz.' },
      { v: 56, en: 'For the destroyer has come on her, even on Babylon. Her mighty men are taken. Their bows are broken in pieces, for Yahweh is a God of retribution. He will surely repay.', pt: 'Porque o destruidor veio sobre ela, sobre Babilônia, e os seus valentes estão presos; já estão despedaçados os seus arcos; pois o Senhor é Deus das recompensas, ele certamente retribuirá.' },
      { v: 57, en: 'I will make her princes, her wise men, her governors, her deputies, and her mighty men drunk. They will sleep a perpetual sleep, and not wake up,” says the King, whose name is Yahweh of Armies.', pt: 'Embriagarei os seus príncipes e os seus sábios, os seus governadores, os seus magistrados, e os seus valentes; e dormirão um sono perpétuo, e jamais acordarão, diz o Rei, cujo nome é o Senhor dos exércitos.' },
      { v: 58, en: 'Yahweh of Armies says: “The wide walls of Babylon will be utterly overthrown. Her high gates will be burned with fire. The peoples will labor for vanity, and the nations for the fire; and they will be weary.”', pt: 'Assim diz o Senhor dos exércitos: O largo muro de Babilônia será de todo derribado, e as suas portas altas serão abrasadas pelo fogo; e trabalharão os povos em vão, e as nações se cansarão só para o fogo.' },
      { v: 59, en: 'The word which Jeremiah the prophet commanded Seraiah the son of Neriah, the son of Mahseiah, when he went with Zedekiah the king of Judah to Babylon in the fourth year of his reign. Now Seraiah was chief quartermaster.', pt: 'A palavra que Jeremias, o profeta, mandou a Seraías, filho de Nerias, filho de Maséias, quando ia com Zedequias, rei de Judá, a Babilônia, no quarto ano do seu reinado. Ora, Seraías era o camareiro-mor.' },
      { v: 60, en: 'Jeremiah wrote in a book all the evil that should come on Babylon, even all these words that are written concerning Babylon.', pt: 'Escreveu, pois, Jeremias num livro todo o mal que havia de vir sobre Babilônia, a saber, todas estas palavras que estão escritas acerca de Babilônia.' },
      { v: 61, en: 'Jeremiah said to Seraiah, “When you come to Babylon, then see that you read all these words,', pt: 'E disse Jeremias a Seraías: Quando chegares a Babilônia, vê que leias todas estas palavras;' },
      { v: 62, en: 'and say, ‘Yahweh, you have spoken concerning this place, to cut it off, that no one will dwell in it, neither man nor animal, but that it will be desolate forever.’', pt: 'e dirás: Tu, Senhor, falaste a respeito deste lugar, que o havias de desarraigar, até não ficar nele morador algum, nem homem nem animal, mas que se tornaria em perpétua desolação.' },
      { v: 63, en: 'It will be, when you have finished reading this book, that you shall bind a stone to it, and cast it into the middle of the Euphrates.', pt: 'E acabando tu de ler este livro, atar-lhe-ás uma pedra e o lançarás no meio do Eufrates;' },
      { v: 64, en: 'Then you shall say, ‘Thus will Babylon sink, and will not rise again because of the evil that I will bring on her; and they will be weary.’” Thus far are the words of Jeremiah.', pt: 'e dirás: Assim será submergida Babilônia, e não se levantará, por causa do mal que vou trazer sobre ela; e eles se cansarão.' },
    ],
    52: [
      { v: 1, en: 'Zedekiah was twenty-one years old when he began to reign. He reigned eleven years in Jerusalem: and his mother’s name was Hamutal the daughter of Jeremiah of Libnah.', pt: 'Era Zedequias da idade de vinte e um anos quando começou a reinar, e reinou onze anos em Jerusalém. O nome de sua mãe era Hamutal, filha de Jeremias, de Libna.' },
      { v: 2, en: 'He did that which was evil in Yahweh’s sight, according to all that Jehoiakim had done.', pt: 'E fez o que era mau aos olhos do Senhor, conforme tudo o que fizera Jeoiaquim.' },
      { v: 3, en: 'For through Yahweh’s anger this happened in Jerusalem and Judah, until he had cast them out from his presence. Zedekiah rebelled against the king of Babylon.', pt: 'Pois por causa da ira do Senhor, chegou-se a tal ponto em Jerusalém e Judá que ele os lançou da sua presença. E Zedequias rebelou-se contra o rei de Babilônia.' },
      { v: 4, en: 'In the ninth year of his reign, in the tenth month, in the tenth day of the month, Nebuchadnezzar king of Babylon came, he and all his army, against Jerusalem, and encamped against it; and they built forts against it round about.', pt: 'No ano nono do seu reinado, no mês décimo, no décimo dia do mês, veio Nabucodonozor, rei de Babilônia, contra Jerusalém, ele e todo o seu exército, e se acamparam contra ela, e contra ela levantaram tranqueiras ao redor.' },
      { v: 5, en: 'So the city was besieged to the eleventh year of king Zedekiah.', pt: 'Assim esteve cercada a cidade, até o ano undécimo do rei Zedequias.' },
      { v: 6, en: 'In the fourth month, in the ninth day of the month, the famine was severe in the city, so that there was no bread for the people of the land.', pt: 'No quarto mês, aos nove do mês, a fome prevalecia na cidade, de tal modo que não havia pão para o povo da terra.' },
      { v: 7, en: 'Then a breach was made in the city, and all the men of war fled, and went out of the city by night by the way of the gate between the two walls, which was by the king’s garden. Now the Chaldeans were against the city all around. The men of war went toward the Arabah,', pt: 'Então foi aberta uma brecha na cidade; e todos os homens de guerra fugiram, e saíram da cidade de noite, pelo caminho da porta entre os dois muros, a qual está junto ao jardim do rei, enquanto os caldeus estavam ao redor da cidade; e foram pelo caminho da Arabá.' },
      { v: 8, en: 'but the army of the Chaldeans pursued the king, and overtook Zedekiah in the plains of Jericho; and all his army was scattered from him.', pt: 'Mas o exército dos caldeus perseguiu o rei, e alcançou a Zedequias nas campinas de Jericó; e todo o seu exército se espalhou, abandonando-o.' },
      { v: 9, en: 'Then they took the king, and carried him up to the king of Babylon to Riblah in the land of Hamath; and he pronounced judgment on him.', pt: 'Prenderam o rei, e o fizeram subir ao rei de Babilônia a Ribla na terra de Hamate, o qual lhe pronunciou a sentença.' },
      { v: 10, en: 'The king of Babylon killed the sons of Zedekiah before his eyes. He also killed all the princes of Judah in Riblah.', pt: 'E o rei de Babilônia matou os filhos de Zedequias à sua vista; e também matou a todos os príncipes de Judá em Ribla.' },
      { v: 11, en: 'He put out the eyes of Zedekiah; and the king of Babylon bound him in fetters, and carried him to Babylon, and put him in prison until the day of his death.', pt: 'E cegou os olhos a Zedequias; e o atou com cadeias; e o rei de Babilônia o levou para Babilônia, e o conservou na prisão até o dia da sua morte.' },
      { v: 12, en: 'Now in the fifth month, in the tenth day of the month, which was the nineteenth year of king Nebuchadnezzar, king of Babylon, Nebuzaradan the captain of the guard, who stood before the king of Babylon, came into Jerusalem.', pt: 'No quinto mês, no décimo dia do mês, que era o décimo nono ano do rei Nabucodonozor, rei de Babilônia, veio a Jerusalém Nebuzaradão, capitão da guarda, que assistia na presença do rei de Babilônia.' },
      { v: 13, en: 'He burned Yahweh’s house, and the king’s house; and all the houses of Jerusalem, even every great house, he burned with fire.', pt: 'E queimou a casa do Senhor, e a casa do rei; como também a todas as casas de Jerusalém, todas as casas importantes, ele as incendiou.' },
      { v: 14, en: 'All the army of the Chaldeans, who were with the captain of the guard, broke down all the walls of Jerusalem all around.', pt: 'E todo o exército dos caldeus, que estava com o capitão da guarda, derribou todos os muros que rodeavam Jerusalém.' },
      { v: 15, en: 'Then Nebuzaradan the captain of the guard carried away captive of the poorest of the people, and the residue of the people who were left in the city, and those who fell away, who fell to the king of Babylon, and the residue of the multitude.', pt: 'E os mais pobres do povo, e o resto do povo que tinha ficado na cidade, e os desertores que se haviam passado para o rei de Babilônia, e o resto dos artífices, Nebuzaradão, capitão da guarda, levou-os cativos.' },
      { v: 16, en: 'But Nebuzaradan the captain of the guard left of the poorest of the land to be vineyard keepers and farmers.', pt: 'Mas dos mais pobres da terra Nebuzaradão, capitão da guarda, deixou ficar alguns, para serem vinhateiros e lavradores.' },
      { v: 17, en: 'The Chaldeans broke the pillars of brass that were in Yahweh’s house, and the bases and the bronze sea that were in Yahweh’s house in pieces, and carried all of their brass to Babylon.', pt: 'Os caldeus despedaçaram as colunas de bronze que estavam na casa do Senhor, e as bases, e o mar de bronze, que estavam na casa do Senhor, e levaram todo o bronze para Babilônia.' },
      { v: 18, en: 'They also took away the pots, the shovels, the snuffers, the basins, the spoons, and all the vessels of brass with which they ministered.', pt: 'Também tomaram as caldeiras, as pás, as espevitadeiras, as bacias, as colheres, e todos os utensílios de bronze, com que se ministrava.' },
      { v: 19, en: 'The captain of the guard took away the cups, the fire pans, the basins, the pots, the lamp stands, the spoons, and the bowls; that which was of gold, in gold, and that which was of silver, in silver.', pt: 'De igual modo o capitão da guarda levou os copos, os braseiros, as bacias, as caldeiras, os castiçais, as colheres, e as tigelas. O que era de ouro, levou como ouro, e o que era de prata, como prata.' },
      { v: 20, en: 'They took the two pillars, the one sea, and the twelve bronze bulls that were under the bases, which king Solomon had made for Yahweh’s house. The brass of all these vessels was without weight.', pt: 'Quanto às duas colunas, ao mar, e aos doze bois de bronze que estavam debaixo das bases, que fizera o rei Salomão para a casa do Senhor, o peso do bronze de todos estes vasos era incalculável.' },
      { v: 21, en: 'As for the pillars, the height of the one pillar was eighteen cubits; and a line of twelve cubits encircled it; and its thickness was four fingers. It was hollow.', pt: 'Dessas colunas, a altura de cada um era de dezoito côvados; doze côvados era a medida da sua circunferência; e era a sua espessura de quatro dedos; e era oca.' },
      { v: 22, en: 'A capital of brass was on it; and the height of the one capital was five cubits, with network and pomegranates on the capital all around, all of brass: and the second pillar also had like these, and pomegranates.', pt: 'E havia sobre ela um capitel de bronze; e a altura dum capitel era de cinco côvados, com uma rede e romãs sobre o capitel ao redor, tudo de bronze; e a segunda coluna tinha as mesmas coisas com as romãs.' },
      { v: 23, en: 'There were ninety-six pomegranates on the sides; all the pomegranates were one hundred on the network all around.', pt: 'E havia noventa e seis romãs aos lados; as romãs todas, sobre a rede ao redor eram cem.' },
      { v: 24, en: 'The captain of the guard took Seraiah the chief priest, and Zephaniah the second priest, and the three keepers of the threshold:', pt: 'Levou também o capitão da guarda a Seraías, o principal sacerdote, e a Sofonias, o segundo sacerdote, e os três guardas da porta;' },
      { v: 25, en: 'and out of the city he took an officer who was set over the men of war; and seven men of those who saw the king’s face, who were found in the city; and the scribe of the captain of the army, who mustered the people of the land; and sixty men of the people of the land, who were found in the middle of the city.', pt: 'e da cidade levou um oficial que tinha a seu cargo os homens de guerra; e a sete homens dos que assistiam ao rei e que se achavam na cidade; como também o escrivão-mor do exército, que registrava o povo da terra; e mais sessenta homens do povo da terra que se achavam no meio da cidade.' },
      { v: 26, en: 'Nebuzaradan the captain of the guard took them, and brought them to the king of Babylon to Riblah.', pt: 'Tomando-os pois Nebuzaradão, capitão da guarda, levou-os ao rei de Babilônia, a Ribla.' },
      { v: 27, en: 'The king of Babylon struck them, and put them to death at Riblah in the land of Hamath. So Judah was carried away captive out of his land.', pt: 'E o rei de Babilônia os feriu e os matou em Ribla, na terra de Hamate. Assim Judá foi levado cativo para fora da sua terra.' },
      { v: 28, en: 'This is the number of the people whom Nebuchadnezzar carried away captive: in the seventh year, three thousand twenty-three Jews;', pt: 'Este é o povo que Nabucodonozor levou cativo: no sétimo ano três mil e vinte e três judeus;' },
      { v: 29, en: 'in the eighteenth year of Nebuchadnezzar, he carried away captive from Jerusalem eight hundred thirty-two persons;', pt: 'no ano décimo oitavo de Nabucodonozor, ele levou cativas de Jerusalém oitocentas e trinta e duas pessoas;' },
      { v: 30, en: 'in the twenty-third year of Nebuchadnezzar Nebuzaradan the captain of the guard carried away captive of the Jews seven hundred forty-five people: all the people were four thousand six hundred.', pt: 'no ano vinte e três de Nabucodonozor, Nebuzaradão, capitão da guarda, levou cativas, dentre os judeus, setecentas e quarenta e cinco pessoas; todas as pessoas foram quatro mil e seiscentas.' },
      { v: 31, en: 'In the thirty-seventh year of the captivity of Jehoiachin king of Judah, in the twelfth month, in the twenty-fifth day of the month, Evilmerodach king of Babylon, in the first year of his reign, lifted up the head of Jehoiachin king of Judah, and released him from prison.', pt: 'No ano trigésimo sétimo do cativeiro de Joaquim, rei de Judá, no mês duodécimo, aos vinte e cinco do mês, Evil-Merodaque, rei de Babilônia, no primeiro ano do seu reinado, levantou a cabeça de Joaquim, rei de Judá, e o tirou do cárcere;' },
      { v: 32, en: 'He spoke kindly to him, and set his throne above the throne of the kings who were with him in Babylon,', pt: 'e falou com ele benignamente, e pôs o trono dele acima dos tronos dos reis que estavam com ele em Babilônia;' },
      { v: 33, en: 'and changed his prison garments. Jehoiachin ate bread before him continually all the days of his life.', pt: 'e lhe fez mudar a roupa da sua prisão; e Joaquim comia pão na presença do rei continuamente, todos os dias da sua vida.' },
      { v: 34, en: 'For his allowance, there was a continual allowance given him by the king of Babylon, every day a portion until the day of his death, all the days of his life.', pt: 'E, quanto à sua ração, foi-lhe dada pelo rei de Babilônia a sua porção quotidiana, até o dia da sua morte, durante todos os dias da sua vida.' },
    ],
  },
};

export default book;
